"use client"

import { useState } from "react"
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card"
import { Badge } from "@/components/ui/badge"
import { Button } from "@/components/ui/button"
import { Dialog, DialogContent, DialogHeader, DialogTitle } from "@/components/ui/dialog"
import type { Achievement } from "@/types/wallet"
import { useIsMobile } from "@/hooks/use-mobile"
import {
  Trophy,
  Gift,
  Sparkles,
  CheckCircle2,
  PartyPopper,
  Award,
  Star,
  Flame,
  Crown,
  Target,
  Zap,
  Gem,
  Medal,
  Shield,
  Rocket,
  Heart,
  Brain,
  Gamepad2,
  Lock,
  TrendingUp
} from "lucide-react"

interface AchievementsProfileProps {
  achievements: Achievement[]
  unlockedAchievements: Achievement[]
  lockedAchievements: Achievement[]
  celebration: {
    show: boolean
    achievement: Achievement | null
  }
  onDismissCelebration: () => void
}

// Custom Circular Progress Component with Premium Styling
const CircularProgressBar = ({
  progress,
  maxProgress,
  size = 180,
  strokeWidth = 12,
  children,
  isUnlocked = false,
  rarity = "common"
}: {
  progress: number
  maxProgress: number
  size?: number
  strokeWidth?: number
  children: React.ReactNode
  isUnlocked?: boolean
  rarity?: "common" | "rare" | "epic" | "legendary"
}) => {
  const radius = (size - strokeWidth) / 2
  const circumference = radius * 2 * Math.PI
  const progressPercent = Math.min((progress / maxProgress) * 100, 100)
  const offset = circumference - (progressPercent / 100) * circumference

  const getRarityGradient = () => {
    switch (rarity) {
      case 'legendary': return 'url(#legendary-gradient)'
      case 'epic': return 'url(#epic-gradient)'
      case 'rare': return 'url(#rare-gradient)'
      default: return 'url(#common-gradient)'
    }
  }

  const getGlowColor = () => {
    if (!isUnlocked) return "transparent"
    switch (rarity) {
      case 'legendary': return "rgba(245, 158, 11, 0.4)"
      case 'epic': return "rgba(139, 92, 246, 0.4)"
      case 'rare': return "rgba(59, 130, 246, 0.4)"
      default: return "rgba(148, 163, 184, 0.4)"
    }
  }

  return (
    <div className="relative inline-flex items-center justify-center group">
      {/* Outer Glow for Legendary/Epic */}
      {isUnlocked && (rarity === 'legendary' || rarity === 'epic') && (
        <div
          className="absolute inset-0 rounded-full blur-xl opacity-0 group-hover:opacity-100 transition-opacity duration-500"
          style={{ backgroundColor: getGlowColor() }}
        />
      )}

      <svg width={size} height={size} className="transform -rotate-90 relative z-10 transition-transform duration-500 group-hover:scale-105">
        <defs>
          <linearGradient id="legendary-gradient" x1="0%" y1="0%" x2="100%" y2="100%">
            <stop offset="0%" stopColor="#fbbf24" />
            <stop offset="50%" stopColor="#f59e0b" />
            <stop offset="100%" stopColor="#ef4444" />
          </linearGradient>
          <linearGradient id="epic-gradient" x1="0%" y1="0%" x2="100%" y2="100%">
            <stop offset="0%" stopColor="#a78bfa" />
            <stop offset="50%" stopColor="#8b5cf6" />
            <stop offset="100%" stopColor="#d946ef" />
          </linearGradient>
          <linearGradient id="rare-gradient" x1="0%" y1="0%" x2="100%" y2="100%">
            <stop offset="0%" stopColor="#60a5fa" />
            <stop offset="50%" stopColor="#3b82f6" />
            <stop offset="100%" stopColor="#06b6d4" />
          </linearGradient>
          <linearGradient id="common-gradient" x1="0%" y1="0%" x2="100%" y2="100%">
            <stop offset="0%" stopColor="#94a3b8" />
            <stop offset="100%" stopColor="#475569" />
          </linearGradient>

          <filter id="glow" x="-20%" y="-20%" width="140%" height="140%">
            <feGaussianBlur stdDeviation="3" result="blur" />
            <feComposite in="SourceGraphic" in2="blur" operator="over" />
          </filter>
        </defs>

        {/* Background circle */}
        <circle
          cx={size / 2}
          cy={size / 2}
          r={radius}
          stroke="currentColor"
          strokeWidth={strokeWidth}
          fill="none"
          className="text-slate-200/50 dark:text-slate-800/50"
        />

        {/* Progress circle */}
        <circle
          cx={size / 2}
          cy={size / 2}
          r={radius}
          stroke={isUnlocked ? getRarityGradient() : "currentColor"}
          strokeWidth={strokeWidth}
          fill="none"
          strokeDasharray={circumference}
          strokeDashoffset={offset}
          strokeLinecap="round"
          filter={isUnlocked ? "url(#glow)" : "none"}
          className={`transition-all duration-1000 ease-in-out ${!isUnlocked && 'text-slate-300 dark:text-slate-700'}`}
        />
      </svg>

      {/* Center content */}
      <div className="absolute inset-0 flex items-center justify-center z-20">
        {children}
      </div>

      {/* Progress percentage overlay for locked ones */}
      {!isUnlocked && progressPercent > 0 && (
        <div className="absolute -bottom-1 left-1/2 transform -translate-x-1/2 z-30">
          <div className="bg-slate-900 text-white text-[10px] font-bold px-2 py-0.5 rounded-full shadow-lg border border-slate-700">
            {Math.round(progressPercent)}%
          </div>
        </div>
      )}
    </div>
  )
}

// Achievement Card Component
const AchievementCard = ({ achievement, onClick }: { achievement: Achievement, onClick: () => void }) => {
  const isUnlocked = achievement.unlocked

  const getIconStyles = () => {
    if (!isUnlocked) return "text-slate-400 dark:text-slate-600 grayscale opacity-50"

    switch (achievement.rarity) {
      case 'legendary': return "text-amber-500 drop-shadow-[0_0_8px_rgba(245,158,11,0.6)]"
      case 'epic': return "text-purple-500 drop-shadow-[0_0_8px_rgba(139,92,246,0.6)]"
      case 'rare': return "text-blue-500 drop-shadow-[0_0_8px_rgba(59,130,246,0.6)]"
      default: return "text-slate-600 dark:text-slate-400"
    }
  }

  const getRarityBorder = () => {
    if (!isUnlocked) return "border-transparent"
    switch (achievement.rarity) {
      case 'legendary': return "border-amber-500/30"
      case 'epic': return "border-purple-500/30"
      case 'rare': return "border-blue-500/30"
      default: return "border-slate-300 dark:border-slate-700"
    }
  }

  return (
    <div
      onClick={onClick}
      className={`
        relative group cursor-pointer p-4 rounded-3xl transition-all duration-500
        hover:bg-white dark:hover:bg-slate-900 border
        ${getRarityBorder()}
        ${isUnlocked ? 'bg-slate-50/50 dark:bg-slate-900/30 shadow-sm' : 'bg-transparent border-transparent opacity-80 hover:opacity-100'}
      `}
    >
      <div className="flex flex-col items-center space-y-4">
        <CircularProgressBar
          progress={achievement.progress}
          maxProgress={achievement.maxProgress}
          size={140}
          strokeWidth={10}
          isUnlocked={isUnlocked}
          rarity={achievement.rarity}
        >
          <div className={`
            w-20 h-20 rounded-full flex items-center justify-center
            ${isUnlocked ? 'bg-white dark:bg-slate-800' : 'bg-slate-100/50 dark:bg-slate-800/50'}
            shadow-inner relative overflow-hidden group-hover:scale-110 transition-transform duration-500
          `}>
            {/* Background pattern for icons */}
            {isUnlocked && (
              <div className="absolute inset-0 opacity-10 pointer-events-none">
                <Sparkles className="w-full h-full p-2" />
              </div>
            )}
            <div className={`text-4xl ${getIconStyles()} transition-all duration-500`}>
              {achievement.icon}
            </div>
          </div>
        </CircularProgressBar>

        <div className="text-center space-y-1">
          <h3 className="font-bold text-sm text-slate-800 dark:text-slate-200 line-clamp-1 group-hover:text-primary transition-colors">
            {achievement.title}
          </h3>
          <div className="flex gap-1.5 justify-center mt-1">
            <Badge
              variant="outline"
              className={`text-[9px] px-1.5 py-0 font-medium ${isUnlocked ? 'border-primary/30 text-primary' : 'text-slate-400 opacity-60'}`}
            >
              {achievement.category}
            </Badge>
            {isUnlocked && (
              <Badge
                className={`text-[9px] px-1.5 py-0 capitalize border-0 font-bold ${achievement.rarity === 'legendary' ? 'bg-amber-500 text-white shadow-sm shadow-amber-500/20' :
                  achievement.rarity === 'epic' ? 'bg-purple-500 text-white shadow-sm shadow-purple-500/20' :
                    achievement.rarity === 'rare' ? 'bg-blue-500 text-white shadow-sm shadow-blue-500/20' :
                      'bg-slate-500 text-white'
                  }`}
              >
                {achievement.rarity}
              </Badge>
            )}
          </div>
        </div>
      </div>

      {/* Unlocked checkmark */}
      {isUnlocked && (
        <div className="absolute top-2 right-2 bg-emerald-500 text-white p-1 rounded-full shadow-lg scale-0 group-hover:scale-100 transition-transform duration-300">
          <CheckCircle2 className="w-3 h-3" />
        </div>
      )}
    </div>
  )
}

export function AchievementsProfile({
  achievements,
  unlockedAchievements,
  lockedAchievements,
  celebration,
  onDismissCelebration
}: AchievementsProfileProps) {
  const [selectedAchievement, setSelectedAchievement] = useState<Achievement | null>(null)
  const [filter, setFilter] = useState("all")
  const isMobile = useIsMobile()

  const categories = Array.from(new Set(achievements.map(a => a.category)))

  const filteredUnlocked = filter === "all"
    ? unlockedAchievements
    : unlockedAchievements.filter(a => a.category === filter)

  const filteredLocked = filter === "all"
    ? lockedAchievements
    : lockedAchievements.filter(a => a.category === filter)

  const totalProgress = achievements.reduce((acc, a) => acc + (a.progress / a.maxProgress), 0)
  const overallPercentage = achievements.length > 0 ? Math.round((totalProgress / achievements.length) * 100) : 0

  return (
    <div className="space-y-8 p-4 md:p-8 max-w-7xl mx-auto">
      {/* Premium Header */}
      <div className="relative overflow-hidden rounded-[2.5rem] bg-slate-900 p-1 md:p-1.5 shadow-2xl">
        <div className="absolute inset-0 bg-gradient-to-br from-indigo-600 via-purple-600 to-pink-600 animate-gradient-xy opacity-90"></div>
        <div className="absolute inset-0 bg-[url('https://www.transparenttextures.com/patterns/carbon-fibre.png')] opacity-10"></div>

        <div className="relative bg-black/20 backdrop-blur-sm rounded-[2.3rem] p-8 text-white overflow-hidden">
          <div className="absolute -top-24 -right-24 w-64 h-64 bg-white/10 rounded-full blur-3xl"></div>
          <div className="absolute -bottom-24 -left-24 w-64 h-64 bg-pink-500/20 rounded-full blur-3xl"></div>

          <div className="relative z-10 flex flex-col md:flex-row items-center justify-between gap-8">
            <div className="text-center md:text-left space-y-2">
              <div className="inline-flex items-center gap-2 px-3 py-1 rounded-full bg-white/10 backdrop-blur-md border border-white/20 text-xs font-bold mb-4 tracking-wider uppercase">
                <Trophy className="w-3 h-3 text-amber-400" />
                Hall of Fame
              </div>
              <h1 className="text-4xl md:text-6xl font-black tracking-tight mb-2 italic">
                Achievements
              </h1>
              <p className="text-white/70 text-lg max-w-md">
                Turn your financial habits into legendary milestones.
              </p>
            </div>

            {/* Overall Progress with Premium Look */}
            <div className="relative">
              <div className="absolute inset-0 bg-white/20 rounded-full blur-xl animate-pulse"></div>
              <CircularProgressBar
                progress={overallPercentage}
                maxProgress={100}
                size={140}
                strokeWidth={10}
                isUnlocked={false}
              >
                <div className="text-center group-hover:scale-110 transition-transform">
                  <div className="text-4xl font-black italic">{overallPercentage}%</div>
                  <div className="text-[10px] uppercase font-bold tracking-widest text-white/60">Legacy</div>
                </div>
              </CircularProgressBar>
            </div>
          </div>
        </div>
      </div>

      {/* Modern Stats Cards */}
      <div className="grid grid-cols-2 lg:grid-cols-4 gap-4 md:gap-6">
        {[
          { label: "Unlocked", val: unlockedAchievements.length, icon: CheckCircle2, color: "emerald", desc: "Lifetime rewards" },
          { label: "Remaining", val: lockedAchievements.length, icon: Target, color: "blue", desc: "New challenges" },
          { label: "Mastery", val: categories.length, icon: Medal, color: "purple", desc: "Active domains" },
          { label: "Elite Tier", val: unlockedAchievements.filter(a => a.rarity === 'legendary' || a.rarity === 'epic').length, icon: Crown, color: "amber", desc: "Rare accomplishments" }
        ].map((stat, i) => (
          <Card key={i} className="relative group overflow-hidden border-slate-200 dark:border-slate-800 bg-white/50 dark:bg-slate-950/50 backdrop-blur-xl hover:shadow-xl transition-all duration-500 rounded-3xl">
            <div className={`absolute top-0 right-0 w-24 h-24 bg-${stat.color}-500/10 rounded-full -mr-8 -mt-8 transition-transform group-hover:scale-150 duration-700`}></div>
            <CardContent className="p-6">
              <div className="flex items-start justify-between mb-4">
                <div className={`p-3 rounded-2xl bg-${stat.color}-500/10 text-${stat.color}-600 dark:text-${stat.color}-400 group-hover:scale-110 transition-transform`}>
                  <stat.icon className="w-6 h-6" />
                </div>
                <div className="text-right">
                  <div className="text-3xl font-black tracking-tighter">{stat.val}</div>
                  <div className="text-[10px] font-bold uppercase tracking-wider text-muted-foreground opacity-70">{stat.label}</div>
                </div>
              </div>
              <p className="text-[11px] text-muted-foreground">{stat.desc}</p>
            </CardContent>
          </Card>
        ))}
      </div>

      {/* Category Filter - Premium Tabs */}
      <div className="flex flex-wrap gap-2 justify-center py-4 bg-slate-100/50 dark:bg-slate-900/50 rounded-full px-4 border border-slate-200 dark:border-slate-800 backdrop-blur-md">
        <button
          onClick={() => setFilter("all")}
          className={`px-6 py-2 rounded-full text-sm font-bold transition-all duration-300 ${filter === "all"
            ? "bg-slate-900 text-white shadow-lg scale-105"
            : "text-slate-500 hover:text-slate-900 dark:hover:text-white"
            }`}
        >
          Overview
        </button>
        {categories.map(category => (
          <button
            key={category}
            onClick={() => setFilter(category)}
            className={`px-6 py-2 rounded-full text-sm font-bold transition-all duration-300 ${filter === category
              ? "bg-primary text-primary-foreground shadow-lg scale-105"
              : "text-slate-500 hover:text-slate-900 dark:hover:text-white"
              }`}
          >
            {category}
          </button>
        ))}
      </div>

      {/* Achievements Grid with Staggered layout */}
      <div className="space-y-12">
        {/* Unlocked Section */}
        {filteredUnlocked.length > 0 && (
          <div className="space-y-6">
            <div className="flex items-center justify-between">
              <div className="flex items-center gap-3">
                <div className="w-10 h-10 rounded-2xl bg-emerald-500/10 flex items-center justify-center">
                  <Sparkles className="w-6 h-6 text-emerald-600" />
                </div>
                <h2 className="text-2xl font-black tracking-tight uppercase italic">
                  Mastered
                </h2>
              </div>
              <Badge className="bg-emerald-600 hover:bg-emerald-700 text-white font-bold px-4 py-1 rounded-lg">
                {filteredUnlocked.length}
              </Badge>
            </div>
            <div className="grid grid-cols-2 md:grid-cols-3 lg:grid-cols-4 xl:grid-cols-5 gap-4">
              {filteredUnlocked.map((achievement) => (
                <AchievementCard
                  key={achievement.id}
                  achievement={achievement}
                  onClick={() => setSelectedAchievement(achievement)}
                />
              ))}
            </div>
          </div>
        )}

        {/* Separator Line */}
        {filteredUnlocked.length > 0 && filteredLocked.length > 0 && (
          <div className="h-px w-full bg-gradient-to-r from-transparent via-slate-300 dark:via-slate-800 to-transparent"></div>
        )}

        {/* Locked Section */}
        {filteredLocked.length > 0 && (
          <div className="space-y-6">
            <div className="flex items-center justify-between">
              <div className="flex items-center gap-3">
                <div className="w-10 h-10 rounded-2xl bg-blue-500/10 flex items-center justify-center">
                  <Lock className="w-5 h-5 text-blue-600" />
                </div>
                <h2 className="text-2xl font-black tracking-tight uppercase italic opa">
                  Next Milestones
                </h2>
              </div>
              <Badge variant="outline" className="font-bold px-4 py-1 rounded-lg border-blue-500/30 text-blue-600 dark:text-blue-400">
                {filteredLocked.length}
              </Badge>
            </div>
            <div className="grid grid-cols-2 md:grid-cols-3 lg:grid-cols-4 xl:grid-cols-5 gap-4">
              {filteredLocked.map((achievement) => (
                <AchievementCard
                  key={achievement.id}
                  achievement={achievement}
                  onClick={() => setSelectedAchievement(achievement)}
                />
              ))}
            </div>
          </div>
        )}
      </div>

      {/* Achievement Detail Dialog - Enhanced */}
      <Dialog open={!!selectedAchievement} onOpenChange={() => setSelectedAchievement(null)}>
        <DialogContent className="sm:max-w-md rounded-[2.5rem] border-0 p-0 overflow-hidden bg-white dark:bg-slate-950">
          <DialogTitle className="sr-only">Achievement Details</DialogTitle>
          {selectedAchievement ? (
            <div className="relative">
              {/* Header Gradient */}
              <div className={`h-48 w-full bg-gradient-to-br ${selectedAchievement.rarity === 'legendary' ? 'from-amber-600 to-orange-600' :
                selectedAchievement.rarity === 'epic' ? 'from-purple-600 to-violet-600' :
                  selectedAchievement.rarity === 'rare' ? 'from-blue-600 to-cyan-600' :
                    'from-slate-600 to-slate-800'
                } opacity-20 absolute top-0 left-0`}></div>

              <div className="flex flex-col items-center space-y-6 p-8 relative z-10">
                <div className="mt-4 hover:scale-105 transition-transform duration-500">
                  <CircularProgressBar
                    progress={selectedAchievement.progress}
                    maxProgress={selectedAchievement.maxProgress}
                    size={200}
                    strokeWidth={14}
                    isUnlocked={selectedAchievement.unlocked}
                    rarity={selectedAchievement.rarity}
                  >
                    <div className={`
                      w-32 h-32 rounded-full flex items-center justify-center
                      ${selectedAchievement.unlocked ? 'bg-white dark:bg-slate-900 shadow-xl' : 'bg-slate-100/80 dark:bg-slate-800/80'}
                    `}>
                      <div className={`text-7xl ${selectedAchievement.unlocked ? 'grayscale-0' : 'grayscale opacity-50'
                        }`}>
                        {selectedAchievement.icon}
                      </div>
                    </div>
                  </CircularProgressBar>
                </div>

                <div className="text-center space-y-4 w-full">
                  <div className="space-y-1">
                    <Badge variant="secondary" className="px-3 py-0.5 rounded-full text-[10px] font-bold uppercase tracking-widest bg-slate-100 dark:bg-slate-800">
                      {selectedAchievement.category}
                    </Badge>
                    <h3 className="text-3xl font-black tracking-tight">{selectedAchievement.title}</h3>
                  </div>

                  <p className="text-muted-foreground leading-relaxed">
                    {selectedAchievement.description}
                  </p>

                  {/* Progress Tracking */}
                  <div className="bg-slate-50 dark:bg-slate-900 p-6 rounded-[2rem] border border-slate-100 dark:border-slate-800">
                    <div className="flex justify-between items-end mb-3">
                      <div className="text-left">
                        <div className="text-[10px] font-bold uppercase tracking-wider text-muted-foreground">Current Status</div>
                        <div className="text-xl font-black">
                          {selectedAchievement.progress.toLocaleString()} <span className="text-sm font-normal text-muted-foreground">/ {selectedAchievement.maxProgress.toLocaleString()}</span>
                        </div>
                      </div>
                      <Badge className={`font-bold ${selectedAchievement.unlocked ? 'bg-emerald-500' : 'bg-blue-500'}`}>
                        {selectedAchievement.unlocked ? 'UNLOCKED' : `${Math.round((selectedAchievement.progress / selectedAchievement.maxProgress) * 100)}%`}
                      </Badge>
                    </div>
                    <div className="w-full bg-slate-200 dark:bg-slate-800 rounded-full h-3 overflow-hidden">
                      <div
                        className={`h-full bg-gradient-to-r transition-all duration-1000 ${selectedAchievement.rarity === 'legendary' ? 'from-amber-400 to-orange-500' :
                          selectedAchievement.rarity === 'epic' ? 'from-purple-400 to-violet-500' :
                            selectedAchievement.rarity === 'rare' ? 'from-blue-400 to-cyan-500' :
                              'from-slate-400 to-slate-600'
                          }`}
                        style={{ width: `${(selectedAchievement.progress / selectedAchievement.maxProgress) * 100}%` }}
                      >
                        <div className="w-full h-full bg-[linear-gradient(45deg,rgba(255,255,255,0.15)_25%,transparent_25%,transparent_50%,rgba(255,255,255,0.15)_50%,rgba(255,255,255,0.15)_75%,transparent_75%,transparent)] bg-[length:20px_20px] animate-[progress-bar-stripes_1s_linear_infinite]"></div>
                      </div>
                    </div>
                  </div>

                  <Button
                    onClick={() => setSelectedAchievement(null)}
                    className="w-full h-14 rounded-2xl font-bold bg-slate-900 dark:bg-white dark:text-slate-900 hover:scale-95 transition-transform"
                    size="lg"
                  >
                    Got It
                  </Button>
                </div>
              </div>
            </div>
          ) : null}
        </DialogContent>
      </Dialog>

      {/* Celebration Dialog - CORRECTED and PREMIUM */}
      <Dialog open={celebration.show} onOpenChange={onDismissCelebration}>
        <DialogContent className="sm:max-w-md rounded-[3rem] border-0 p-0 overflow-hidden bg-slate-950 text-white shadow-[0_0_100px_rgba(245,158,11,0.2)]">
          <DialogTitle className="sr-only">Achievement Unlocked</DialogTitle>
          <div className="absolute inset-0 bg-gradient-to-br from-indigo-900/40 via-purple-900/40 to-pink-900/40 animate-pulse"></div>

          {celebration.achievement && (
            <div className="flex flex-col items-center space-y-8 p-10 relative z-10 text-center">
              <div className="relative">
                {/* Orbital Glow rings */}
                <div className="absolute inset-0 bg-amber-500/20 rounded-full scale-[1.5] blur-3xl animate-pulse"></div>
                <div className="absolute inset-0 bg-orange-500/20 rounded-full scale-[2] blur-3xl animate-pulse delay-700"></div>

                <CircularProgressBar
                  progress={celebration.achievement.maxProgress}
                  maxProgress={celebration.achievement.maxProgress}
                  size={240}
                  strokeWidth={16}
                  isUnlocked={true}
                  rarity={celebration.achievement.rarity}
                >
                  <div className="w-40 h-40 rounded-full bg-white/5 backdrop-blur-xl flex items-center justify-center shadow-2xl border border-white/10 overflow-hidden group">
                    <div className="text-8xl animate-bounce-slow transform-gpu drop-shadow-[0_0_20px_rgba(255,255,255,0.4)]">
                      {celebration.achievement.icon}
                    </div>
                  </div>
                </CircularProgressBar>

                <div className="absolute -top-4 -right-4 animate-spin-slow">
                  <Star className="w-12 h-12 text-amber-400 fill-amber-400 drop-shadow-[0_0_8px_rgba(251,191,36,0.6)]" />
                </div>
                <div className="absolute -bottom-4 -left-4 animate-spin-slow-reverse">
                  <Sparkles className="w-10 h-10 text-pink-400 drop-shadow-[0_0_8px_rgba(244,114,182,0.6)]" />
                </div>
              </div>

              <div className="space-y-4">
                <div className="inline-flex items-center gap-2 px-4 py-1.5 rounded-full bg-emerald-500/20 text-emerald-400 border border-emerald-500/30 text-xs font-black tracking-widest uppercase">
                  <Sparkles className="w-3 h-3" />
                  New Rank Achieved
                </div>
                <h3 className="text-5xl font-black italic tracking-tighter bg-gradient-to-r from-amber-400 via-orange-400 to-pink-500 bg-clip-text text-transparent">
                  {celebration.achievement.title}
                </h3>
                <p className="text-white/60 text-lg font-medium leading-relaxed max-w-sm">
                  {celebration.achievement.description}
                </p>

                <div className="flex gap-4 justify-center pt-2">
                  <div className="px-6 py-2 rounded-2xl bg-white/5 border border-white/10 flex flex-col items-center">
                    <span className="text-[10px] font-bold text-white/40 uppercase">Rarity</span>
                    <span className="font-black text-amber-400 uppercase tracking-tighter">{celebration.achievement.rarity}</span>
                  </div>
                  <div className="px-6 py-2 rounded-2xl bg-white/5 border border-white/10 flex flex-col items-center">
                    <span className="text-[10px] font-bold text-white/40 uppercase">Category</span>
                    <span className="font-black uppercase tracking-tighter">{celebration.achievement.category}</span>
                  </div>
                </div>
              </div>

              <Button
                onClick={onDismissCelebration}
                className="w-full h-16 rounded-[2rem] bg-gradient-to-r from-amber-500 via-orange-600 to-pink-600 hover:scale-105 transition-all duration-300 font-black text-lg shadow-[0_10px_40px_-10px_rgba(245,158,11,0.5)] border-0"
                size="lg"
              >
                Continue Your Journey
              </Button>
            </div>
          )}
        </DialogContent>
      </Dialog>
    </div>
  )
}

"use client"

import type React from "react"

import { useState, useMemo, useEffect } from "react"
import { Dialog, DialogContent, DialogFooter, DialogHeader, DialogTitle } from "@/components/ui/dialog"
import { Button } from "@/components/ui/button"
import { Input } from "@/components/ui/input"
import { Label } from "@/components/ui/label"
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from "@/components/ui/select"
import { Checkbox } from "@/components/ui/checkbox"
import { Badge } from "@/components/ui/badge"
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card"
import { Collapsible, CollapsibleContent, CollapsibleTrigger } from "@/components/ui/collapsible"
import { Target, Clock, Plus, X, DollarSign, Calendar, Shield, Tag, Search, Lightbulb, ChevronDown } from "lucide-react"
import { useWalletData } from "@/contexts/wallet-data-context"
import { getCurrencySymbol } from "@/lib/currency"
import { getDefaultCategoryNames } from "@/lib/categories"
import type { UserProfile, Budget } from "@/types/wallet"

interface BudgetDialogProps {
  open: boolean
  onOpenChange: (open: boolean) => void
  userProfile: UserProfile
  onAddBudget: (budget: any) => void
  editingBudget?: Budget
  onUpdateBudget?: (id: string, updates: Partial<Budget>) => void
}

const periods = ["weekly", "monthly", "yearly"]

export function BudgetDialog({ open, onOpenChange, userProfile, onAddBudget, editingBudget, onUpdateBudget }: BudgetDialogProps) {
  const { categories, addCategory } = useWalletData()
  const [amount, setAmount] = useState("")
  const [budgetName, setBudgetName] = useState("")
  const [period, setPeriod] = useState("monthly")
  const [selectedCategories, setSelectedCategories] = useState<string[]>([])
  const [customCategory, setCustomCategory] = useState("")
  const [emergencyUses, setEmergencyUses] = useState("3")
  const [searchTerm, setSearchTerm] = useState("")
  const [errors, setErrors] = useState<{ [key: string]: string }>({})
  const [showTips, setShowTips] = useState(false)

  // Populate form when editing
  useEffect(() => {
    if (editingBudget) {
      setAmount(editingBudget.limit.toString())
      setBudgetName(editingBudget.name)
      setPeriod(editingBudget.period)
      setSelectedCategories(editingBudget.categories || [])
      setEmergencyUses(editingBudget.emergencyUses?.toString() || "3")
      setCustomCategory("")
      setSearchTerm("")
      setErrors({})
    } else {
      // Reset form for new budget
      setAmount("")
      setBudgetName("")
      setSelectedCategories([])
      setPeriod("monthly")
      setEmergencyUses("3")
      setCustomCategory("")
      setSearchTerm("")
      setErrors({})
    }
  }, [editingBudget])

  // Get expense categories from the context, falling back to default categories
  const expenseCategories = useMemo(() => {
    const contextCategories = categories
      .filter((cat) => cat.type === "expense")
      .map((cat) => cat.name)

    // If no categories in context, use default categories
    if (contextCategories.length === 0) {
      return getDefaultCategoryNames("expense")
    }

    return contextCategories.sort()
  }, [categories])

  // Get currency symbol
  const currencySymbol = useMemo(() => {
    return getCurrencySymbol(userProfile?.currency || "USD", (userProfile as any)?.customCurrency)
  }, [userProfile?.currency, (userProfile as any)?.customCurrency])

  // Filter categories based on search term
  const filteredCategories = useMemo(() => {
    if (!searchTerm) return expenseCategories
    return expenseCategories.filter(category =>
      category.toLowerCase().includes(searchTerm.toLowerCase())
    )
  }, [expenseCategories, searchTerm])

  const timeEquivalentBreakdown = useMemo(() => {
    if (!amount || !userProfile) return null
    const { getTimeEquivalentBreakdown } = require("@/lib/wallet-utils")
    return getTimeEquivalentBreakdown(Number.parseFloat(amount), userProfile)
  }, [amount, userProfile])

  const timeText = timeEquivalentBreakdown ? timeEquivalentBreakdown.formatted.userFriendly : "0m"

  const handleCategoryToggle = (category: string) => {
    setSelectedCategories((prev) =>
      prev.includes(category) ? prev.filter((c) => c !== category) : [...prev, category],
    )
  }

  const addCustomCategory = () => {
    if (customCategory.trim() && !selectedCategories.includes(customCategory.trim())) {
      // Add the category to the global categories if it doesn't exist
      const existingCategory = categories.find(
        (cat) => cat.name.toLowerCase() === customCategory.trim().toLowerCase() && cat.type === "expense"
      )

      if (!existingCategory && addCategory) {
        addCategory({
          name: customCategory.trim(),
          type: "expense",
          color: "#3b82f6",
          isDefault: false,
        })
      }

      setSelectedCategories((prev) => [...prev, customCategory.trim()])
      setCustomCategory("")
    }
  }

  const removeCategory = (category: string) => {
    setSelectedCategories((prev) => prev.filter((c) => c !== category))
  }

  const validateForm = () => {
    const newErrors: { [key: string]: string } = {}

    if (!budgetName.trim()) {
      newErrors.budgetName = "Budget name is required"
    }

    if (!amount || Number.parseFloat(amount) <= 0) {
      newErrors.amount = "Please enter a valid positive amount"
    }

    if (selectedCategories.length === 0) {
      newErrors.categories = "Please select at least one category"
    }

    setErrors(newErrors)
    return Object.keys(newErrors).length === 0
  }

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault()

    if (!validateForm()) return

    const budgetData = {
      name: budgetName.trim(),
      limit: Number.parseFloat(amount),
      categories: selectedCategories,
      period,
      emergencyUses: Number.parseInt(emergencyUses),
      ...(editingBudget ? {} : { createdAt: new Date().toISOString() }),
    }

    if (editingBudget && onUpdateBudget) {
      onUpdateBudget(editingBudget.id, budgetData as Partial<Budget>)
    } else {
      onAddBudget(budgetData)
    }

    // Reset form
    setAmount("")
    setBudgetName("")
    setSelectedCategories([])
    setPeriod("monthly")
    setEmergencyUses("3")
    setSearchTerm("")
    setErrors({})
    onOpenChange(false)
  }

  return (
    <Dialog open={open} onOpenChange={onOpenChange}>
      <DialogContent className="sm:max-w-2xl max-h-[90vh] overflow-hidden flex flex-col">
        <DialogHeader>
          <DialogTitle className="flex items-center gap-2">
            <Target className="w-5 h-5 text-primary" />
            {editingBudget ? "Edit Budget" : "Create Smart Budget"}
          </DialogTitle>
        </DialogHeader>

        <form onSubmit={handleSubmit} className="flex min-h-0 flex-1 flex-col">
          <div className="min-h-0 flex-1 space-y-6 overflow-y-auto pr-1">
            <Card>
            <CardContent className="space-y-4">
              <div className="space-y-2">
                <Label htmlFor="budget-name" className="flex items-center gap-2">
                  Budget Name
                </Label>
                <Input
                  id="budget-name"
                  type="text"
                  placeholder="e.g., Monthly Expenses, School Budget"
                  value={budgetName}
                  onChange={(e) => {
                    setBudgetName(e.target.value)
                    if (errors.budgetName) {
                      setErrors(prev => ({ ...prev, budgetName: "" }))
                    }
                  }}
                  className={errors.budgetName ? "border-destructive" : ""}
                  required
                />
                {errors.budgetName && (
                  <p className="text-sm text-destructive">{errors.budgetName}</p>
                )}
              </div>

              <div className="space-y-2">
                <Label htmlFor="budget-amount" className="flex items-center gap-2">
                  Budget Amount
                </Label>
                <div className="relative">
                  <span className="absolute left-3 top-1/2 transform -translate-y-1/2 text-muted-foreground font-medium">
                    {currencySymbol}
                  </span>
                  <Input
                    id="budget-amount"
                    type="number"
                    step="0.01"
                    placeholder="0.00"
                    value={amount}
                    onChange={(e) => {
                      setAmount(e.target.value)
                      if (errors.amount) {
                        setErrors(prev => ({ ...prev, amount: "" }))
                      }
                    }}
                    className={`pl-10 ${errors.amount ? "border-destructive" : ""}`}
                    required
                  />
                </div>
                {errors.amount && (
                  <p className="text-sm text-destructive">{errors.amount}</p>
                )}

                {amount && (
                  <div className="flex items-center gap-2 text-sm text-muted-foreground bg-muted/50 p-3 rounded-md border">
                    <Clock className="w-4 h-4" />
                    <span>This budget represents <strong>{timeText}</strong> of work time</span>
                  </div>
                )}
              </div>
              <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                <div className="space-y-2">
                  <Label htmlFor="budget-period">Period</Label>
                  <Select value={period} onValueChange={setPeriod}>
                    <SelectTrigger>
                      <SelectValue />
                    </SelectTrigger>
                    <SelectContent>
                      {periods.map((p) => (
                        <SelectItem key={p} value={p}>
                          {p.charAt(0).toUpperCase() + p.slice(1)}
                        </SelectItem>
                      ))}
                    </SelectContent>
                  </Select>
                </div>

                <div className="space-y-2">
                  <Label className="flex items-center gap-2">
                    Emergency Uses Allowed
                  </Label>
                  <Select value={emergencyUses} onValueChange={setEmergencyUses}>
                    <SelectTrigger>
                      <SelectValue />
                    </SelectTrigger>
                    <SelectContent>
                      <SelectItem value="1">1 emergency use</SelectItem>
                      <SelectItem value="2">2 emergency uses</SelectItem>
                      <SelectItem value="3">3 emergency uses</SelectItem>
                      <SelectItem value="5">5 emergency uses</SelectItem>
                    </SelectContent>
                  </Select>
                </div>
              </div>
            </CardContent>
            </Card>
            <Card>
            <CardHeader className="pb-3">
              <CardTitle className="flex items-center gap-2 text-lg">
                <Tag className="w-5 h-5 text-primary" />
                Supported Categories
              </CardTitle>
              <p className="text-sm text-muted-foreground">Select which expense categories this budget should cover</p>
            </CardHeader>
            <CardContent className="space-y-4">
              <div className="relative">
                <Search className="absolute left-3 top-1/2 transform -translate-y-1/2 w-4 h-4 text-muted-foreground" />
                <Input
                  placeholder="Search categories..."
                  value={searchTerm}
                  onChange={(e) => setSearchTerm(e.target.value)}
                  className="pl-10"
                />
              </div>

              <div className="grid grid-cols-1 sm:grid-cols-2 gap-3 max-h-32 sm:max-h-48 overflow-y-auto border rounded-md p-3">
                {filteredCategories.length > 0 ? (
                  filteredCategories.map((category) => (
                    <div key={category} className="flex items-center space-x-3 p-2 rounded-md hover:bg-muted/50 transition-colors">
                      <Checkbox
                        id={category}
                        checked={selectedCategories.includes(category)}
                        onCheckedChange={() => handleCategoryToggle(category)}
                      />
                      <Label htmlFor={category} className="text-sm font-normal cursor-pointer flex-1">
                        {category}
                      </Label>
                    </div>
                  ))
                ) : (
                  <div className="col-span-full text-center py-8 text-muted-foreground">
                    <Search className="w-8 h-8 mx-auto mb-2 opacity-50" />
                    <p>No categories found matching "{searchTerm}"</p>
                  </div>
                )}
              </div>

              <div className="flex gap-2 pt-2 border-t">
                <Input
                  placeholder="Add custom category"
                  value={customCategory}
                  onChange={(e) => setCustomCategory(e.target.value)}
                  onKeyPress={(e) => e.key === "Enter" && (e.preventDefault(), addCustomCategory())}
                  className="flex-1"
                />
                <Button type="button" size="sm" onClick={addCustomCategory} variant="outline">
                  <Plus className="w-4 h-4" />
                </Button>
              </div>

              {selectedCategories.length > 0 && (
                <div className="space-y-3 pt-2 border-t">
                  <Label className="text-sm font-medium">Selected Categories ({selectedCategories.length})</Label>
                  <div className="flex flex-wrap gap-2">
                    {selectedCategories.map((category) => (
                      <Badge key={category} variant="secondary" className="flex items-center gap-2 px-3 py-1">
                        {category}
                        <X
                          className="w-3 h-3 cursor-pointer hover:text-destructive transition-colors"
                          onClick={() => removeCategory(category)}
                        />
                      </Badge>
                    ))}
                  </div>
                </div>
              )}

              {errors.categories && (
                <p className="text-sm text-destructive">{errors.categories}</p>
              )}
            </CardContent>
            </Card>
          </div>

          <DialogFooter className="mt-4 flex flex-row gap-2 border-t bg-background pt-3 pb-[calc(env(safe-area-inset-bottom)+0.75rem)] justify-end">
            <Button type="button" variant="outline" onClick={() => onOpenChange(false)} className="flex-1">
              Cancel
            </Button>
            <Button
              type="submit"
              disabled={!amount || !budgetName || selectedCategories.length === 0}
              className="flex-1"
            >
              {editingBudget ? "Update Budget" : "Create Budget"}
            </Button>
          </DialogFooter>
        </form>
      </DialogContent>
    </Dialog>
  )
}

"use client"

import { useState, useMemo } from "react"
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card"
import { Button } from "@/components/ui/button"
import { Progress } from "@/components/ui/progress"
import { Badge } from "@/components/ui/badge"
import { Alert, AlertDescription } from "@/components/ui/alert"
import { Input } from "@/components/ui/input"
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from "@/components/ui/select"
import { Collapsible, CollapsibleContent, CollapsibleTrigger } from "@/components/ui/collapsible"
import {
  PlusCircle,
  Target,
  AlertTriangle,
  CheckCircle,
  Clock,
  Shield,
  Trash2,
  Search,
  Filter,
  ChevronDown,
  ChevronUp,
  SortAsc,
  SortDesc,
  Calendar,
  Edit,
} from "lucide-react"
import { Checkbox } from "@/components/ui/checkbox"
import { BudgetDialog } from "./budget-dialog"
import type { Budget, UserProfile } from "@/types/wallet"
import { formatCurrency } from "@/lib/utils"
import { getCurrencySymbol } from "@/lib/currency"
import { getTimeEquivalentBreakdown } from "@/lib/wallet-utils"

interface BudgetsListProps {
  budgets: Budget[]
  userProfile: UserProfile
  onAddBudget: (budget: any) => void
  onUpdateBudget?: (id: string, updates: Partial<Budget>) => void
  onDeleteBudget: (id: string) => void
}

export function BudgetsList({ budgets, userProfile, onAddBudget, onUpdateBudget, onDeleteBudget }: BudgetsListProps) {
  const [dialogOpen, setDialogOpen] = useState(false)
  const [editingBudget, setEditingBudget] = useState<Budget | null>(null)
  const [selectedBudgets, setSelectedBudgets] = useState<Set<string>>(new Set())

  // Get currency symbol
  const currencySymbol = useMemo(() => {
    return getCurrencySymbol(userProfile?.currency || "USD", (userProfile as any)?.customCurrency)
  }, [userProfile?.currency, (userProfile as any)?.customCurrency])
  const [searchQuery, setSearchQuery] = useState("")
  const [statusFilter, setStatusFilter] = useState("all")
  const [sortBy, setSortBy] = useState("name")
  const [sortOrder, setSortOrder] = useState<"asc" | "desc">("asc")
  const [expandedBudgets, setExpandedBudgets] = useState<Set<string>>(new Set())

  const getBudgetStatus = (budget: Budget) => {
    const percentage = (budget.spent / budget.limit) * 100
    if (percentage >= 100) return { status: "exceeded", color: "text-red-600", icon: AlertTriangle }
    if (percentage >= 80) return { status: "warning", color: "text-amber-600", icon: AlertTriangle }
    return { status: "good", color: "text-primary", icon: CheckCircle }
  }

  const filteredAndSortedBudgets = useMemo(() => {
    const filtered = budgets.filter((budget) => {
      const matchesSearch =
        (budget.name?.toLowerCase()?.includes(searchQuery.toLowerCase()) ?? false) ||
        (budget.categories?.some((cat) => cat?.toLowerCase()?.includes(searchQuery.toLowerCase())) ?? false)

      if (!matchesSearch) return false

      if (statusFilter === "all") return true

      const { status } = getBudgetStatus(budget)
      return status === statusFilter
    })

    filtered.sort((a, b) => {
      let aValue: any, bValue: any

      switch (sortBy) {
        case "name":
          aValue = a.name?.toLowerCase() || ""
          bValue = b.name?.toLowerCase() || ""
          break
        case "spent":
          aValue = a.spent
          bValue = b.spent
          break
        case "limit":
          aValue = a.limit
          bValue = b.limit
          break
        case "percentage":
          aValue = (a.spent / a.limit) * 100
          bValue = (b.spent / b.limit) * 100
          break
        default:
          return 0
      }

      if (sortOrder === "asc") {
        return aValue < bValue ? -1 : aValue > bValue ? 1 : 0
      } else {
        return aValue > bValue ? -1 : aValue < bValue ? 1 : 0
      }
    })

    return filtered
  }, [budgets, searchQuery, statusFilter, sortBy, sortOrder])


  const handleAddBudget = (budgetData: any) => {
    onAddBudget(budgetData)
    setDialogOpen(false)
  }

  const handleUpdateBudget = (id: string, budgetData: any) => {
    onUpdateBudget?.(id, budgetData)
    setDialogOpen(false)
    setEditingBudget(null)
  }

  const handleEditBudget = (budget: Budget) => {
    setEditingBudget(budget)
    setDialogOpen(true)
  }

  const handleSelectAll = (checked: boolean | "indeterminate") => {
    if (checked === true) {
      setSelectedBudgets(new Set(filteredAndSortedBudgets.map(b => b.id)))
    } else {
      setSelectedBudgets(new Set())
    }
  }

  const handleSelectBudget = (budgetId: string, checked: boolean | "indeterminate") => {
    const isChecked = checked === true
    const newSelected = new Set(selectedBudgets)
    if (isChecked) {
      newSelected.add(budgetId)
    } else {
      newSelected.delete(budgetId)
    }
    setSelectedBudgets(newSelected)
  }

  const handleBulkDelete = () => {
    selectedBudgets.forEach(id => onDeleteBudget(id))
    setSelectedBudgets(new Set())
  }

  const toggleExpanded = (budgetId: string) => {
    const newExpanded = new Set(expandedBudgets)
    newExpanded.has(budgetId) ? newExpanded.delete(budgetId) : newExpanded.add(budgetId)
    setExpandedBudgets(newExpanded)
  }

  return (
    <div className="space-y-6">
      {/* Header */}
      <div className="flex items-center justify-between">
        <h3 className="text-lg font-semibold flex items-center gap-2">
          <Target className="w-5 h-5" />
          Budgets ({filteredAndSortedBudgets.length})
        </h3>
        <div className="flex items-center gap-2">
          {selectedBudgets.size > 0 && (
            <Button variant="destructive" onClick={handleBulkDelete} className="flex items-center gap-2">
              <Trash2 className="w-4 h-4" />
              Delete Selected ({selectedBudgets.size})
            </Button>
          )}
          <Button onClick={() => { setEditingBudget(null); setDialogOpen(true) }} className="flex items-center gap-2">
            <PlusCircle className="w-4 h-4" />
            New Budget
          </Button>
        </div>
      </div>

      {/* Filters & Controls */}
      {budgets.length > 0 && (
        <div className="flex flex-col sm:flex-row gap-3">
          <div className="relative flex-1">
            <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-muted-foreground w-4 h-4" />
            <Input
              placeholder="Search budgets or categories..."
              value={searchQuery}
              onChange={(e) => setSearchQuery(e.target.value)}
              className="pl-10"
            />
          </div>

          <div className="flex gap-2">
            <Select value={statusFilter} onValueChange={setStatusFilter}>
              <SelectTrigger className="w-[140px]">
                <Filter className="w-4 h-4 mr-2" />
                <SelectValue placeholder="Filter Status" />
              </SelectTrigger>
              <SelectContent>
                <SelectItem value="all">All Status</SelectItem>
                <SelectItem value="good">On Track</SelectItem>
                <SelectItem value="warning">Near Limit</SelectItem>
                <SelectItem value="exceeded">Over Budget</SelectItem>
              </SelectContent>
            </Select>

            <Select value={sortBy} onValueChange={setSortBy}>
              <SelectTrigger className="w-[130px]">
                <SelectValue placeholder="Sort By" />
              </SelectTrigger>
              <SelectContent>
                <SelectItem value="name">Name</SelectItem>
                <SelectItem value="spent">Spent</SelectItem>
                <SelectItem value="limit">Budget</SelectItem>
                <SelectItem value="percentage">Usage %</SelectItem>
              </SelectContent>
            </Select>

            <Button
              variant="outline"
              size="icon"
              onClick={() => setSortOrder(sortOrder === "asc" ? "desc" : "asc")}
            >
              {sortOrder === "asc" ? <SortAsc className="w-4 h-4" /> : <SortDesc className="w-4 h-4" />}
            </Button>
          </div>
        </div>
      )}

      {/* Select All Section */}
      {filteredAndSortedBudgets.length > 0 && (
        <div className="flex items-center gap-2 p-2 bg-muted/30 rounded-lg">
          <Checkbox
            checked={selectedBudgets.size === filteredAndSortedBudgets.length && filteredAndSortedBudgets.length > 0}
            onCheckedChange={handleSelectAll}
          />
          <span className="text-sm text-muted-foreground">
            {selectedBudgets.size === 0
              ? "Select all budgets"
              : `${selectedBudgets.size} of ${filteredAndSortedBudgets.length} budgets selected`}
          </span>
        </div>
      )}

      {/* States */}
      {budgets.length === 0 ? (
        <Card className="text-center p-8">
          <CardContent>
            <Target className="w-12 h-12 mx-auto text-muted-foreground mb-4" />
            <h3 className="text-lg font-semibold">No budgets yet</h3>
            <p className="text-muted-foreground mb-4">Start by creating your first smart budget today.</p>
            <Button onClick={() => setDialogOpen(true)} className=" gap-2">
              <PlusCircle className="w-4 h-4" />
              Create Budget
            </Button>
          </CardContent>
        </Card>
      ) : filteredAndSortedBudgets.length === 0 ? (
        <Card className="text-center p-8">
          <CardContent>
            <Search className="w-12 h-12 mx-auto text-muted-foreground mb-4" />
            <h3 className="text-lg font-semibold">No results found</h3>
            <p className="text-muted-foreground mb-4">Try adjusting your search or filters.</p>
            <Button variant="outline" onClick={() => { setSearchQuery(""); setStatusFilter("all") }}>
              Clear Filters
            </Button>
          </CardContent>
        </Card>
      ) : (
        <div className="grid gap-4">
          {filteredAndSortedBudgets.map((budget) => {
            const { status, color, icon: StatusIcon } = getBudgetStatus(budget)
            const percentage = Math.min((budget.spent / budget.limit) * 100, 100)
            const remaining = Math.max(budget.limit - budget.spent, 0)
            const isOverBudget = budget.spent > budget.limit
            const isExpanded = expandedBudgets.has(budget.id)

            const budgetTimeBreakdown = getTimeEquivalentBreakdown(budget.limit, userProfile)
            const spentTimeBreakdown = getTimeEquivalentBreakdown(budget.spent, userProfile)

            return (
              <Card key={budget.id} className={`transition border ${isOverBudget ? "border-red-200 bg-red-50/50" : ""}`}>
                {isOverBudget && (
                  <Alert className="m-4 mb-0 border-red-200 bg-red-50">
                    <AlertTriangle className="h-4 w-4 text-red-600" />
                      <AlertDescription className="text-red-800">
                      <strong>Budget Exceeded!</strong> You have spent {formatCurrency(budget.spent - budget.limit, userProfile.currency, userProfile.customCurrency)} over your limit.
                      {budget.emergencyUses > 0 && (
                        <span className="block mt-1">
                          Emergency uses remaining: <Badge variant="destructive">{budget.emergencyUses}</Badge>
                        </span>
                      )}
                    </AlertDescription>
                  </Alert>
                )}

                <Collapsible open={isExpanded} onOpenChange={() => toggleExpanded(budget.id)}>
                  <CardHeader className="pb-3">
                    <div className="flex items-center justify-between">
                      <div className="flex items-center gap-2">
                        <Checkbox
                          checked={selectedBudgets.has(budget.id)}
                          onCheckedChange={(checked) => handleSelectBudget(budget.id, checked as boolean)}
                        />
                        <CollapsibleTrigger asChild>
                          <div className="flex items-center gap-2 cursor-pointer flex-1">
                            <Target className="w-5 h-5 text-primary" />
                            <CardTitle className="text-lg">{budget.name}</CardTitle>
                            {isExpanded ? <ChevronUp className="w-4 h-4" /> : <ChevronDown className="w-4 h-4" />}
                          </div>
                        </CollapsibleTrigger>
                      </div>
                      <div className="flex items-center gap-2">
                        <Badge
                          variant={status === "exceeded" ? "destructive" : status === "warning" ? "secondary" : "default"}
                          className="flex items-center gap-1"
                        >
                          <StatusIcon className="w-3 h-3" />
                          {status === "exceeded" ? "Over Budget" : status === "warning" ? "Near Limit" : "On Track"}
                        </Badge>
                        <Button
                          variant="ghost"
                          size="sm"
                          onClick={() => handleEditBudget(budget)}
                          className="text-muted-foreground hover:text-primary"
                        >
                          <Edit className="w-4 h-4" />
                        </Button>
                        <Button
                          variant="ghost"
                          size="sm"
                          onClick={() => onDeleteBudget(budget.id)}
                          className="text-muted-foreground hover:text-destructive"
                        >
                          <Trash2 className="w-4 h-4" />
                        </Button>
                      </div>
                    </div>

                    <div className="space-y-2 mt-3">
                      <div className="flex justify-between text-sm">
                          <span className="flex items-center gap-1">
                          Spent: {formatCurrency(budget.spent, userProfile.currency, userProfile.customCurrency)}
                        </span>
                        <span>Budget: {formatCurrency(budget.limit, userProfile.currency, userProfile.customCurrency)}</span>
                      </div>
                      <Progress value={percentage} className="h-2 rounded-full" />
                      <div className="flex justify-between text-xs text-muted-foreground">
                        <span>{percentage.toFixed(1)}% used</span>
                        <span>
                          {remaining > 0
                            ? `${formatCurrency(remaining, userProfile.currency, userProfile.customCurrency)} remaining`
                            : `${formatCurrency(Math.abs(remaining), userProfile.currency, userProfile.customCurrency)} over`}
                        </span>
                      </div>
                    </div>
                  </CardHeader>

                  <CollapsibleContent>
                    <CardContent className="space-y-4 pt-0">
                      {/* Time Investment */}
                      <div className="bg-muted/50 p-3 rounded-lg space-y-2">
                        <div className="flex items-center gap-2 text-sm font-medium">
                          <Clock className="w-4 h-4 text-amber-600" />
                          Time Investment
                        </div>
                        <div className="grid grid-cols-1 sm:grid-cols-2 gap-4 text-sm">
                          <div>
                            <p className="text-muted-foreground">Budget represents</p>
                            <p className="font-medium">{budgetTimeBreakdown ? budgetTimeBreakdown.formatted.userFriendly : "0m"} of work</p>
                          </div>
                          <div>
                            <p className="text-muted-foreground">Already spent</p>
                            <p className="font-medium">{spentTimeBreakdown ? spentTimeBreakdown.formatted.userFriendly : "0m"} of work</p>
                          </div>
                        </div>
                      </div>

                      {/* Categories */}
                      <div className="space-y-2">
                        <div className="flex items-center gap-2 text-sm font-medium">
                          <Shield className="w-4 h-4 text-blue-600" />
                          Covered Categories
                        </div>
                        <div className="flex flex-wrap gap-1">
                          {budget.categories?.map((category) => (
                            <Badge key={category} variant="outline" className="text-xs">
                              {category}
                            </Badge>
                          ))}
                        </div>
                      </div>

                      {/* Meta Info */}
                      <div className="grid grid-cols-1 sm:grid-cols-2 gap-4 text-sm">
                        <div className="flex items-center gap-2">
                          <Calendar className="w-4 h-4 text-muted-foreground" />
                          <span>Period: {budget.period}</span>
                        </div>
                        <div className="flex items-center gap-2">
                          <Shield className="w-4 h-4 text-muted-foreground" />
                          <span>Emergency uses: {budget.emergencyUses || 3}</span>
                        </div>
                      </div>
                    </CardContent>
                  </CollapsibleContent>
                </Collapsible>
              </Card>
            )
          })}
        </div>
      )}

      {/* Dialog */}
      <BudgetDialog
        open={dialogOpen}
        onOpenChange={(open) => { setDialogOpen(open); if (!open) setEditingBudget(null) }}
        userProfile={userProfile}
        onAddBudget={handleAddBudget}
        editingBudget={editingBudget || undefined}
        onUpdateBudget={handleUpdateBudget}
      />
    </div>
  )
}

"use client"

import { useState, useMemo } from "react"
import { Card, CardContent } from "@/components/ui/card"
import { Button } from "@/components/ui/button"
import { Input } from "@/components/ui/input"
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from "@/components/ui/select"
import { Tabs, TabsContent, TabsList, TabsTrigger } from "@/components/ui/tabs"
import { Checkbox } from "@/components/ui/checkbox"

import { Plus, BarChart3, FolderOpen, Search, Filter, Calendar, Target, Trash2 } from "lucide-react"
import { getCurrencySymbol } from "@/lib/utils"
import { CategoryProgressCard } from "./category-progress-card"
import { CreateCategoryModal } from "./create-category-modal"
import { DeleteCategoryDialog } from "./delete-category-dialog"
import type { Category, Transaction, UserProfile } from "@/types/wallet"

interface CategoriesManagementProps {
  categories: Category[]
  transactions: Transaction[]
  userProfile: UserProfile
  onAddCategory?: (category: Omit<Category, "id" | "createdAt" | "totalSpent" | "transactionCount">) => Category
  onUpdateCategory?: (id: string, updates: Partial<Category>) => void
  onDeleteCategory?: (id: string) => void
  onUpdateCategoryStats?: () => void
}

export function CategoriesManagement({
  categories,
  transactions,
  userProfile,
  onAddCategory,
  onUpdateCategory,
  onDeleteCategory,
  onUpdateCategoryStats,
}: CategoriesManagementProps) {
  const [searchTerm, setSearchTerm] = useState("")
  const [filterType, setFilterType] = useState<"all" | "income" | "expense">("all")
  const [sortBy, setSortBy] = useState<"usage" | "amount" | "transactions" | "name">("usage")
  const [isAddDialogOpen, setIsAddDialogOpen] = useState(false)
  const [editingCategory, setEditingCategory] = useState<Category | null>(null)
  const [deletingCategory, setDeletingCategory] = useState<Category | null>(null)
  const [selectedCategories, setSelectedCategories] = useState<Set<string>>(new Set())
  const [bulkDeleteMode, setBulkDeleteMode] = useState(false)
  const [disabledCategories, setDisabledCategories] = useState<Set<string>>(new Set())

  const currencySymbol = getCurrencySymbol(userProfile?.currency, (userProfile as any)?.customCurrency)

  // Calculate enhanced category statistics
  const categoryStats = useMemo(() => {
    const now = new Date()
    const oneWeekAgo = new Date(now.getTime() - 7 * 24 * 60 * 60 * 1000)
    const oneMonthAgo = new Date(now.getTime() - 30 * 24 * 60 * 60 * 1000)

    return categories.map((category) => {
      const categoryTransactions = transactions.filter((t) => t.category === category.name)
      const totalSpent = categoryTransactions.reduce((sum, t) => sum + t.amount, 0)
      const transactionCount = categoryTransactions.length

      // Calculate percentage of total spending for progress bars
      const totalExpenses = transactions.filter((t) => t.type === "expense").reduce((sum, t) => sum + t.amount, 0)
      const percentage = totalExpenses > 0 ? (totalSpent / totalExpenses) * 100 : 0

      // Calculate monthly average
      const monthsOfData = Math.max(
        1,
        Math.ceil(
          (now.getTime() - new Date(categoryTransactions[0]?.date || now).getTime()) / (30 * 24 * 60 * 60 * 1000),
        ),
      )
      const monthlyAverage = totalSpent / monthsOfData

      // Calculate weekly trend
      const thisWeekTransactions = categoryTransactions.filter((t) => new Date(t.date) >= oneWeekAgo)
      const lastWeekTransactions = categoryTransactions.filter((t) => {
        const date = new Date(t.date)
        return date >= new Date(oneWeekAgo.getTime() - 7 * 24 * 60 * 60 * 1000) && date < oneWeekAgo
      })

      const thisWeekSpent = thisWeekTransactions.reduce((sum, t) => sum + t.amount, 0)
      const lastWeekSpent = lastWeekTransactions.reduce((sum, t) => sum + t.amount, 0)
      const weeklyTrend = lastWeekSpent > 0 ? ((thisWeekSpent - lastWeekSpent) / lastWeekSpent) * 100 : 0

      // Last transaction date
      const lastTransactionDate =
        categoryTransactions.length > 0
          ? categoryTransactions.sort((a, b) => new Date(b.date).getTime() - new Date(a.date).getTime())[0].date
          : undefined

      return {
        ...category,
        totalSpent,
        transactionCount,
        percentage: Math.min(percentage, 100),
        monthlyAverage,
        weeklyTrend,
        lastTransactionDate,
      }
    })
  }, [categories, transactions])

  // Filter and sort categories
  const filteredCategories = useMemo(() => {
    const filtered = categoryStats.filter((category) => {
      const matchesSearch = category.name.toLowerCase().includes(searchTerm.toLowerCase())
      const matchesType = filterType === "all" || category.type === filterType
      const isEnabled = !disabledCategories.has(category.id)
      return matchesSearch && matchesType && isEnabled
    })

    // Sort categories
    filtered.sort((a, b) => {
      switch (sortBy) {
        case "usage":
          return b.percentage - a.percentage
        case "amount":
          return b.totalSpent - a.totalSpent
        case "transactions":
          return b.transactionCount - a.transactionCount
        case "name":
          return a.name.localeCompare(b.name)
        default:
          return 0
      }
    })

    return filtered
  }, [categoryStats, searchTerm, filterType, sortBy])

  // Separate default and custom categories
  const defaultCategories = filteredCategories.filter((c) => c.isDefault)
  const customCategories = filteredCategories.filter((c) => !c.isDefault)


  const handleDeleteCategory = (category: Category) => {
    setDeletingCategory(category)
  }

  const handleConfirmDelete = (categoryId: string) => {
    if (!onDeleteCategory) return
    onDeleteCategory(categoryId)
    setDeletingCategory(null)
  }

  const handleToggleCategory = (categoryId: string) => {
    setDisabledCategories(prev => {
      const newSet = new Set(prev)
      if (newSet.has(categoryId)) {
        newSet.delete(categoryId)
      } else {
        newSet.add(categoryId)
      }
      return newSet
    })
  }

  const handleSelectCategory = (categoryId: string) => {
    setSelectedCategories(prev => {
      const newSet = new Set(prev)
      if (newSet.has(categoryId)) {
        newSet.delete(categoryId)
      } else {
        newSet.add(categoryId)
      }
      return newSet
    })
  }

  const handleSelectAll = () => {
    if (selectedCategories.size === customCategories.length) {
      setSelectedCategories(new Set())
    } else {
      setSelectedCategories(new Set(customCategories.map(c => c.id)))
    }
  }

  const handleBulkDelete = () => {
    if (selectedCategories.size === 0) return

    // Check if any selected categories are in use
    const categoriesInUse = Array.from(selectedCategories).filter(categoryId => {
      const category = categories.find(c => c.id === categoryId)
      if (!category) return false
      return transactions.some(t => t.category === category.name)
    })

    if (categoriesInUse.length > 0) {
      alert(`Cannot delete ${categoriesInUse.length} category(ies) that are currently in use. Please remove them from transactions first.`)
      return
    }

    if (confirm(`Are you sure you want to delete ${selectedCategories.size} selected categories? This action cannot be undone.`)) {
      selectedCategories.forEach(categoryId => {
        if (onDeleteCategory) {
          onDeleteCategory(categoryId)
        }
      })
      setSelectedCategories(new Set())
      setBulkDeleteMode(false)
    }
  }

  return (
    <div className="space-y-6">
      {/* Header Actions */}
      <div className="flex flex-row gap-2 sm:gap-4 items-center justify-between">
        <h3 className="text-lg font-semibold flex items-center gap-2">
          <BarChart3 className="w-5 h-5" />
          Category
        </h3>

        <div className="flex items-center gap-2">
          {bulkDeleteMode && customCategories.length > 0 && (
            <div className="flex items-center gap-2">
              <Checkbox
                checked={selectedCategories.size === customCategories.length}
                onCheckedChange={handleSelectAll}
                aria-label="Select all categories"
                className="hidden sm:flex"
              />
              <span className="text-sm text-muted-foreground hidden sm:inline">
                {selectedCategories.size} of {customCategories.length} selected
              </span>
              {selectedCategories.size > 0 && (
                <Button
                  variant="destructive"
                  size="sm"
                  onClick={handleBulkDelete}
                  className="flex items-center gap-2"
                >
                  <Trash2 className="w-3 h-3" />
                  <span className="hidden sm:inline">Delete Selected ({selectedCategories.size})</span>
                </Button>
              )}
              <Button
                variant="outline"
                size="sm"
                onClick={() => {
                  setBulkDeleteMode(false)
                  setSelectedCategories(new Set())
                }}
              >
                <span className="hidden sm:inline">Cancel</span>
                <span className="sm:hidden">✕</span>
              </Button>
            </div>
          )}

          {!bulkDeleteMode && (
            <>
              {customCategories.length > 0 && (
                <Button
                  variant="outline"
                  size="sm"
                  onClick={() => setBulkDeleteMode(true)}
                  className="flex items-center gap-2"
                >
                  <Trash2 className="w-3 h-3" />
                  <span className="hidden sm:inline">Bulk Delete</span>
                </Button>
              )}
              <Button
                onClick={() => setIsAddDialogOpen(true)}
                className="flex items-center gap-2"
              >
                <Plus className="w-4 h-4" />
                <span className="hidden sm:inline">Add Category</span>
              </Button>
            </>
          )}
        </div>
      </div>

      {/* Search and Filters */}
      <div className="flex flex-col sm:flex-row gap-3">
        {/* Search Bar */}
        <div className="relative flex-1 max-w-md">
          <Search className="absolute left-3.5 top-1/2 transform -translate-y-1/2 w-4 h-4 text-muted-foreground" />
          <Input
            placeholder="Search categories..."
            value={searchTerm}
            onChange={(e) => setSearchTerm(e.target.value)}
            className="pl-10 h-10 rounded-xl border-border/60 bg-background/50 backdrop-blur-sm focus:border-primary/50 focus:ring-primary/20 font-medium shadow-sm"
          />
        </div>

        {/* Filter Controls */}
        <div className="flex gap-2">
          <Select value={filterType} onValueChange={(value: "all" | "income" | "expense") => setFilterType(value)}>
            <SelectTrigger className="w-[140px] h-10 rounded-xl border-border/60 bg-background/50 font-medium shadow-sm">
              <Filter className="w-3.5 h-3.5 mr-2 text-muted-foreground" />
              <SelectValue />
            </SelectTrigger>
            <SelectContent className="rounded-xl">
              <SelectItem value="all">All Types</SelectItem>
              <SelectItem value="income">Income Only</SelectItem>
              <SelectItem value="expense">Expense Only</SelectItem>
            </SelectContent>
          </Select>

          <Select
            value={sortBy}
            onValueChange={(value: "usage" | "amount" | "transactions" | "name") => setSortBy(value)}
          >
            <SelectTrigger className="w-[140px] h-10 rounded-xl border-border/60 bg-background/50 font-medium shadow-sm">
              <SelectValue />
            </SelectTrigger>
            <SelectContent className="rounded-xl">
              <SelectItem value="usage">By Usage %</SelectItem>
              <SelectItem value="amount">By Amount</SelectItem>
              <SelectItem value="transactions">By Count</SelectItem>
              <SelectItem value="name">By Name</SelectItem>
            </SelectContent>
          </Select>
        </div>
      </div>

      {/* Summary Stats */}
      <div className="grid grid-cols-2 md:grid-cols-3 gap-3 sm:gap-4 mb-6 sm:mb-8">
        <Card className="bg-gradient-to-br from-primary/15 via-primary/5 to-transparent border-primary/20 shadow-xl relative overflow-hidden group col-span-2 md:col-span-1">
          <CardContent className="p-4 sm:p-5 relative z-10">
            <div className="flex items-center justify-between mb-2">
              <p className="text-[10px] font-bold uppercase tracking-widest text-foreground/60">Enabled Categories</p>
              <div className="p-1.5 bg-primary/10 rounded-lg text-primary">
                <FolderOpen className="w-3.5 h-3.5" />
              </div>
            </div>
            <div className="flex items-end gap-2">
              <p className="text-2xl sm:text-3xl font-black font-mono tracking-tight">
                {categories.filter(c => !disabledCategories.has(c.id)).length}
              </p>
              <span className="text-xs font-bold text-muted-foreground mb-1.5 uppercase tracking-wider">
                / {categories.length} Total
              </span>
            </div>
            <div className="mt-3 w-full bg-primary/10 h-1 rounded-full overflow-hidden">
              <div
                className="bg-primary h-full transition-all duration-500 rounded-full"
                style={{ width: `${(categories.filter(c => !disabledCategories.has(c.id)).length / categories.length) * 100}%` }}
              />
            </div>
          </CardContent>
          {/* Ambient Glow */}
          <div className="absolute -bottom-10 -right-10 w-24 h-24 bg-primary/20 blur-3xl rounded-full pointer-events-none" />
        </Card>

        <Card className="bg-card/40 backdrop-blur-sm border-muted/50 shadow-md">
          <CardContent className="p-4 sm:p-5">
            <div className="flex items-center justify-between mb-2">
              <p className="text-[10px] font-bold uppercase tracking-widest text-muted-foreground">Active Usage</p>
              <Target className="w-3.5 h-3.5 text-primary opacity-60" />
            </div>
            <p className="text-xl sm:text-2xl font-black font-mono">
              {categoryStats.filter((c) => c.transactionCount > 0 && !disabledCategories.has(c.id)).length}
            </p>
            <div className="mt-1 flex items-center gap-1.5">
              <div className="w-2 h-2 rounded-full bg-success animate-pulse" />
              <span className="text-[10px] font-bold text-muted-foreground uppercase tracking-tight">With transactions</span>
            </div>
          </CardContent>
        </Card>

        <Card className="bg-card/40 backdrop-blur-sm border-muted/50 shadow-md">
          <CardContent className="p-4 sm:p-5">
            <div className="flex items-center justify-between mb-2">
              <p className="text-[10px] font-bold uppercase tracking-widest text-muted-foreground">Top Spender</p>
              <BarChart3 className="w-3.5 h-3.5 text-warning opacity-80" />
            </div>
            <p className="text-sm font-black truncate leading-tight">
              {categoryStats.length > 0
                ? categoryStats.sort((a, b) => b.totalSpent - a.totalSpent)[0]?.name
                : "None"}
            </p>
            <p className="text-[10px] font-bold text-muted-foreground mt-1 uppercase tracking-wider">
              {categoryStats.length > 0 && categoryStats.sort((a, b) => b.totalSpent - a.totalSpent)[0]
                ? currencySymbol + (categoryStats.sort((a, b) => b.totalSpent - a.totalSpent)[0].totalSpent).toLocaleString()
                : "-"}
            </p>
          </CardContent>
        </Card>
      </div>

      {/* Categories Display */}
      <div className="space-y-8">
        {/* Custom Categories Section */}
        <div className="space-y-3">
          <div className="flex items-center gap-2 mb-2">
            <FolderOpen className="w-4 h-4 text-primary" />
            <h4 className="font-semibold text-sm uppercase tracking-wider text-muted-foreground">Custom Categories</h4>
            <span className="text-xs font-medium px-2 py-0.5 rounded-full bg-muted text-muted-foreground">
              {customCategories.filter(c => !disabledCategories.has(c.id)).length}
            </span>
          </div>

          {customCategories.length === 0 ? (
            <Card className="border-dashed border-2 bg-muted/20">
              <CardContent className="flex flex-col items-center justify-center py-8">
                <FolderOpen className="w-10 h-10 text-muted-foreground/50 mb-3" />
                <h3 className="text-base font-medium mb-1">No Custom Categories</h3>
                <p className="text-sm text-muted-foreground text-center mb-4 max-w-xs">
                  Create your own to organize transactions exactly how you want.
                </p>
                <Button onClick={() => setIsAddDialogOpen(true)} variant="outline" size="sm">
                  <Plus className="w-3.5 h-3.5 mr-2" />
                  Create Category
                </Button>
              </CardContent>
            </Card>
          ) : (
            <div className="space-y-3">
              {customCategories.map((category) => (
                <CategoryProgressCard
                  key={category.id}
                  category={category}
                  userProfile={userProfile}
                  onViewDetails={() => {
                    /* TODO: Implement details view */
                  }}
                  onEdit={() => setEditingCategory(category)}
                  onDelete={() => handleDeleteCategory(category)}
                  showActions={!bulkDeleteMode}
                  selectionMode={bulkDeleteMode}
                  isSelected={selectedCategories.has(category.id)}
                  onSelect={() => handleSelectCategory(category.id)}
                  isDisabled={disabledCategories.has(category.id)}
                  onToggleVisibility={() => handleToggleCategory(category.id)}
                />
              ))}
            </div>
          )}
        </div>

        {/* Default Categories Section */}
        <div className="space-y-3">
          <div className="flex items-center gap-2 mb-2">
            <BarChart3 className="w-4 h-4 text-primary" />
            <h4 className="font-semibold text-sm uppercase tracking-wider text-muted-foreground">Default Categories</h4>
            <span className="text-xs font-medium px-2 py-0.5 rounded-full bg-muted text-muted-foreground">
              {defaultCategories.filter(c => !disabledCategories.has(c.id)).length}
            </span>
          </div>

          <div className="space-y-3">
            {defaultCategories.map((category) => (
              <CategoryProgressCard
                key={category.id}
                category={category}
                userProfile={userProfile}
                onViewDetails={() => {
                  /* TODO: Implement details view */
                }}
                onEdit={() => setEditingCategory(category)}
                onDelete={() => handleDeleteCategory(category)}
                showActions={true}
                isDisabled={disabledCategories.has(category.id)}
                onToggleVisibility={() => handleToggleCategory(category.id)}
              />
            ))}
          </div>
        </div>
      </div>

      {/* Edit Category Modal */}
      {
        editingCategory && (
          <CreateCategoryModal
            isOpen={!!editingCategory}
            onClose={() => setEditingCategory(null)}
            onCreateCategory={(categoryData) => {
              if (!onUpdateCategory || !editingCategory) return

              onUpdateCategory(editingCategory.id, {
                name: categoryData.name,
                color: categoryData.color,
                icon: categoryData.icon,
              })
              setEditingCategory(null)
            }}
            categoryType={editingCategory.type}
          />
        )
      }

      {/* New Modern Category Creation Modal */}
      <CreateCategoryModal
        isOpen={isAddDialogOpen}
        onClose={() => setIsAddDialogOpen(false)}
        onCreateCategory={(categoryData) => {
          if (!onAddCategory) return

          // Check if category already exists
          const exists = categories.some(
            (c) => c.name.toLowerCase() === categoryData.name.toLowerCase() && c.type === categoryData.type,
          )

          if (exists) {
            alert("A category with this name already exists for this type")
            return
          }

          onAddCategory({
            name: categoryData.name,
            type: categoryData.type,
            color: categoryData.color,
            icon: categoryData.icon,
            isDefault: false,
          })
        }}
        categoryType="expense"
      />

      {/* Delete Category Confirmation Dialog */}
      <DeleteCategoryDialog
        isOpen={!!deletingCategory}
        onClose={() => setDeletingCategory(null)}
        category={deletingCategory}
        transactions={transactions}
        onConfirmDelete={handleConfirmDelete}
      />
    </div >
  )
}

"use client"

import { useState } from "react"
import { Badge } from "@/components/ui/badge"
import { Button } from "@/components/ui/button"
import { Checkbox } from "@/components/ui/checkbox"
import { Collapsible, CollapsibleContent, CollapsibleTrigger } from "@/components/ui/collapsible"
import { TrendingUp, TrendingDown, Clock, Target, Calendar, BarChart3, Trash2, Edit, ChevronDown, Eye, EyeOff } from "lucide-react"
import { formatCurrency, getCurrencySymbol } from "@/lib/utils"
import type { Category, UserProfile } from "@/types/wallet"
import { cn } from "@/lib/utils"

interface CategoryProgressCardProps {
  category: Category & {
    totalSpent: number
    transactionCount: number
    percentage: number
    monthlyAverage: number
    weeklyTrend: number
    lastTransactionDate?: string
  }
  userProfile: UserProfile
  onViewDetails?: () => void
  onEdit?: () => void
  onDelete?: () => void
  showActions?: boolean

  // New props for enhanced list management
  selectionMode?: boolean
  isSelected?: boolean
  onSelect?: () => void
  isDisabled?: boolean
  onToggleVisibility?: () => void
}

export function CategoryProgressCard({
  category,
  userProfile,
  onViewDetails,
  onEdit,
  onDelete,
  showActions = false,
  selectionMode = false,
  isSelected = false,
  onSelect,
  isDisabled = false,
  onToggleVisibility
}: CategoryProgressCardProps) {
  const [isOpen, setIsOpen] = useState(false)

  // Calculate time equivalent
  const { getTimeEquivalentBreakdown } = require("@/lib/wallet-utils")
  const timeBreakdown = getTimeEquivalentBreakdown(category.totalSpent, userProfile)
  const timeEquivalent = timeBreakdown ? timeBreakdown.formatted.userFriendly : "0m"

  const categoryColor = category.color || "#3b82f6"

  const getProgressColor = () => {
    if (category.percentage > 100) return "bg-destructive"
    if (category.percentage > 85) return "bg-red-500"
    if (category.percentage > 50) return "bg-amber-500"
    return "bg-primary"
  }

  const getTrendIcon = () => {
    if (category.weeklyTrend > 0) return <TrendingUp className="w-3.5 h-3.5 text-red-500" />
    if (category.weeklyTrend < 0) return <TrendingDown className="w-3.5 h-3.5 text-emerald-500" />
    return <BarChart3 className="w-3.5 h-3.5 text-muted-foreground" />
  }

  return (
    <Collapsible
      open={isOpen}
      onOpenChange={setIsOpen}
      className={cn(
        "group rounded-2xl border transition-all duration-300 overflow-hidden",
        isOpen ? "shadow-lg border-primary/20 bg-card/60 backdrop-blur-md" : "hover:bg-muted/10 hover:shadow-md border-muted/50 bg-card/40 backdrop-blur-sm",
        isSelected && "border-primary bg-primary/5 hover:bg-primary/10",
        isDisabled && "opacity-60 grayscale-[0.5]"
      )}
    >
      <div className="flex items-center p-3 sm:p-4 gap-3 sm:gap-4">
        {selectionMode && (
          <Checkbox
            checked={isSelected}
            onCheckedChange={() => onSelect && onSelect()}
            onClick={(e) => e.stopPropagation()}
            className="shrink-0"
          />
        )}

        <CollapsibleTrigger asChild>
          <div className="flex items-center justify-between cursor-pointer gap-2 sm:gap-4 w-full select-none">
            <div className="flex gap-3 sm:gap-4 items-center min-w-0 flex-1">
              {/* Icon Container */}
              <div
                className="w-10 h-10 sm:w-12 sm:h-12 rounded-xl flex items-center justify-center font-black text-lg shadow-sm border shrink-0 transition-transform group-hover:scale-105 relative overflow-hidden"
                style={{
                  backgroundColor: `${categoryColor}15`,
                  borderColor: `${categoryColor}30`,
                  color: categoryColor
                }}
              >
                {category.icon ? (
                  <span className="relative z-10">{category.icon}</span>
                ) : (
                  <div className="w-4 h-4 rounded-full" style={{ backgroundColor: categoryColor }} />
                )}
              </div>

              <div className="flex flex-col min-w-0 text-left">
                <div className="flex items-center gap-2 flex-wrap">
                  <h4 className="font-extrabold text-sm sm:text-base tracking-tight truncate flex items-center gap-2">
                    {category.name}
                    {isDisabled && (
                      <Badge variant="outline" className="text-[9px] h-3.5 px-1 font-bold uppercase tracking-widest border-muted-foreground/30 text-muted-foreground">Disabled</Badge>
                    )}
                  </h4>
                  <Badge
                    variant="outline"
                    className={cn(
                      "text-[9px] h-4 px-1.5 font-bold uppercase tracking-widest border-muted-foreground/20",
                      category.type === 'income'
                        ? "bg-emerald-500/10 text-emerald-600 border-emerald-500/20"
                        : "bg-red-500/10 text-red-600 border-red-500/20"
                    )}
                  >
                    {category.type}
                  </Badge>
                  {!isDisabled && category.isDefault && (
                    <Badge variant="secondary" className="text-[9px] h-4 px-1.5 font-bold uppercase tracking-widest opacity-60">
                      Default
                    </Badge>
                  )}
                </div>

                <div className="flex items-center gap-2 mt-0.5 text-xs text-muted-foreground font-medium">
                  <span className="flex items-center gap-1">
                    <Target className="w-3 h-3" /> {category.transactionCount} txns
                  </span>
                  {!isDisabled && (
                    <>
                      <span>•</span>
                      <span className="flex items-center gap-1">
                        {getTrendIcon()}
                        <span className={cn(
                          category.weeklyTrend > 0 ? "text-red-500" : category.weeklyTrend < 0 ? "text-emerald-500" : ""
                        )}>
                          {Math.abs(category.weeklyTrend).toFixed(1)}%
                        </span>
                      </span>
                    </>
                  )}
                </div>
              </div>
            </div>

            <div className="flex items-center gap-3 sm:gap-6 shrink-0">
              <div className="text-right">
                <div className="font-black text-sm sm:text-lg tracking-tighter font-mono leading-tight">
                  {formatCurrency(category.totalSpent, userProfile.currency, userProfile.customCurrency)}
                </div>
                <div className="text-[10px] sm:text-xs text-muted-foreground font-bold flex items-center justify-end gap-1">
                  <Clock className="w-3 h-3" />
                  {timeEquivalent}
                </div>
              </div>

              <div className={cn(
                "w-8 h-8 rounded-full flex items-center justify-center bg-muted/50 transition-transform duration-300",
                isOpen && "rotate-180 bg-primary/10 text-primary"
              )}>
                <ChevronDown className="w-4 h-4" />
              </div>
            </div>
          </div>
        </CollapsibleTrigger>
      </div>

      <CollapsibleContent>
        <div className="px-4 pb-4 pt-0 space-y-4 animate-in slide-in-from-top-2 duration-300">
          <div className="pt-4 border-t border-dashed border-muted-foreground/20">
            {/* Progress Section */}
            <div className="space-y-2 mb-4">
              <div className="flex items-end justify-between text-xs sm:text-sm">
                <span className="text-muted-foreground font-bold uppercase tracking-wider text-[10px]">Budget Usage</span>
                <span className={cn("font-black", category.percentage > 100 ? "text-destructive" : "")}>
                  {category.percentage.toFixed(1)}%
                </span>
              </div>
              <div className="relative h-2 w-full bg-secondary/50 rounded-full overflow-hidden">
                <div
                  className={cn("absolute top-0 left-0 h-full rounded-full transition-all duration-500 ease-out", getProgressColor())}
                  style={{ width: `${Math.min(category.percentage, 100)}%` }}
                />
              </div>
            </div>

            <div className="grid grid-cols-2 gap-4">
              <div className="space-y-1 p-3 rounded-xl bg-muted/20 border border-muted/30">
                <div className="text-[10px] uppercase tracking-wider font-bold text-muted-foreground flex items-center gap-1.5">
                  <Calendar className="w-3 h-3" /> Monthly Avg
                </div>
                <div className="font-black text-sm sm:text-base font-mono">
                  {formatCurrency(category.monthlyAverage, userProfile.currency, userProfile.customCurrency)}
                </div>
              </div>

              <div className="space-y-1 p-3 rounded-xl bg-muted/20 border border-muted/30">
                <div className="text-[10px] uppercase tracking-wider font-bold text-muted-foreground flex items-center gap-1.5">
                  <Clock className="w-3 h-3" /> Last Txn
                </div>
                <div className="font-black text-sm sm:text-base">
                  {category.lastTransactionDate
                    ? new Date(category.lastTransactionDate).toLocaleDateString(undefined, { month: 'short', day: 'numeric', year: 'numeric' })
                    : "Never"
                  }
                </div>
              </div>
            </div>
          </div>

          {/* Action Buttons */}
          <div className="flex gap-2 pt-1">
            {showActions ? (
              <>
                <Button
                  variant="outline"
                  size="sm"
                  onClick={(e) => {
                    e.stopPropagation();
                    onEdit && onEdit();
                  }}
                  className="flex-1 h-9 font-bold hover:bg-background hover:text-primary hover:border-primary/50 transition-all"
                >
                  <Edit className="w-3.5 h-3.5 mr-2" />
                  Edit
                </Button>

                {onToggleVisibility && (
                  <Button
                    variant="outline"
                    size="sm"
                    onClick={(e) => {
                      e.stopPropagation();
                      onToggleVisibility();
                    }}
                    className={cn(
                      "flex-1 h-9 font-bold transition-all",
                      isDisabled ? "bg-muted text-muted-foreground" : "hover:bg-background hover:text-primary hover:border-primary/50"
                    )}
                  >
                    {isDisabled ? (
                      <>
                        <Eye className="w-3.5 h-3.5 mr-2" /> Enable
                      </>
                    ) : (
                      <>
                        <EyeOff className="w-3.5 h-3.5 mr-2" /> Disable
                      </>
                    )}
                  </Button>
                )}

                <Button
                  variant="outline"
                  size="sm"
                  onClick={(e) => {
                    e.stopPropagation();
                    onDelete && onDelete();
                  }}
                  className="flex-1 h-9 font-bold text-destructive/80 hover:bg-destructive/10 hover:text-destructive hover:border-destructive/50 transition-all border-destructive/20"
                >
                  <Trash2 className="w-3.5 h-3.5 mr-2" />
                  Delete
                </Button>
              </>
            ) : (
              <Button
                variant="secondary"
                size="sm"
                onClick={onViewDetails}
                className="w-full h-9 font-bold bg-muted/50 hover:bg-primary hover:text-primary-foreground transition-all"
              >
                View Full Analysis
              </Button>
            )}
          </div>
        </div>
      </CollapsibleContent>
    </Collapsible>
  )
}

"use client"

import { Card, CardContent } from "@/components/ui/card"
import { Button } from "@/components/ui/button"
import {
  TrendingUp,
  TrendingDown,
  PiggyBank,
  Clock
} from "lucide-react"
import { useWalletData } from "@/contexts/wallet-data-context"
import { TimeTooltip } from "@/components/ui/time-tooltip"
import BalanceCard from "@/components/dashboard/balance-card-component"
import { useMemo, useState, useRef, useEffect } from "react"
import { getTimeEquivalentBreakdown } from "@/lib/wallet-utils"
import { getCurrencySymbol } from "@/lib/currency"
import { useIsMobile } from "@/hooks/use-mobile"
import type { Transaction, ShareTransaction } from "@/types/wallet"

export function CombinedBalanceCard() {
  const { balance, userProfile, transactions, debtAccounts, creditAccounts, emergencyFund, balanceChange } =
    useWalletData()

  const [showBalance, setShowBalance] = useState(true)
  const [currentCardIndex, setCurrentCardIndex] = useState(0)
  const [incomeExpenseRange, setIncomeExpenseRange] = useState<"monthly" | "all-time">("monthly")
  const isMobile = useIsMobile()
  const scrollContainerRef = useRef<HTMLDivElement>(null)

  // Scroll state management
  const scrollStateRef = useRef({
    scrollTimeout: null as NodeJS.Timeout | null,
    lastScrollLeft: 0,
    scrollVelocity: 0,
    lastScrollTime: Date.now()
  })

  // Optimize calculations with useMemo and better logic
  const { monthlyIncome, monthlyExpenses, allTimeIncome, allTimeExpenses } = useMemo(() => {
    const now = new Date()
    const currentMonth = now.getMonth()
    const currentYear = now.getFullYear()

    const initialAcc = { monthlyIncome: 0, monthlyExpenses: 0, allTimeIncome: 0, allTimeExpenses: 0 }
    const txResult = (transactions || []).reduce(
      (acc: typeof initialAcc, transaction: Transaction) => {
        const fullAmount = transaction.amount
        if (!transaction || typeof fullAmount !== "number" || fullAmount < 0) {
          return acc
        }
        const txDate = new Date(transaction.date)
        if (Number.isNaN(txDate.getTime())) {
          return acc
        }
        const isTrueExpense =
          transaction.type === "expense" &&
          transaction.allocationType !== "goal"

        if (transaction.type === "income") {
          acc.allTimeIncome += fullAmount
          if (txDate.getMonth() === currentMonth && txDate.getFullYear() === currentYear) {
            acc.monthlyIncome += fullAmount
          }
        } else if (isTrueExpense) {
          acc.allTimeExpenses += fullAmount
          if (txDate.getMonth() === currentMonth && txDate.getFullYear() === currentYear) {
            acc.monthlyExpenses += fullAmount
          }
        }

        return acc
      },
      { ...initialAcc },
    )
    return txResult
  }, [transactions])

  const totalIncome = incomeExpenseRange === "monthly" ? monthlyIncome : allTimeIncome
  const totalExpenses = incomeExpenseRange === "monthly" ? monthlyExpenses : allTimeExpenses

  const totalDebt = useMemo(() => {
    return debtAccounts?.reduce((sum, debt) => sum + debt.balance, 0) || 0
  }, [debtAccounts])

  const totalCreditUsed = useMemo(() => {
    return creditAccounts?.reduce((sum, credit) => sum + credit.balance, 0) || 0
  }, [creditAccounts])

  const totalCreditLimit = useMemo(() => {
    return creditAccounts?.reduce((sum, credit) => sum + credit.creditLimit, 0) || 0
  }, [creditAccounts])

  const availableCredit = totalCreditLimit - totalCreditUsed
  const netWorth = balance + availableCredit - totalDebt
  const creditUtilization = totalCreditLimit > 0 ? (totalCreditUsed / totalCreditLimit) * 100 : 0
  const currencySymbol = useMemo(() => {
    return getCurrencySymbol(userProfile?.currency || "USD", (userProfile as any)?.customCurrency)
  }, [userProfile?.currency, (userProfile as any)?.customCurrency])

  const isPositive = balance >= 0
  const absoluteBalance = Math.abs(balance)
  const timeEquivalentBreakdown = useMemo(() => {
    if (!userProfile || balance <= 0) return null
    return getTimeEquivalentBreakdown(balance, userProfile)
  }, [balance, userProfile])
  const formatCurrency = (amount: number) => {
    const numberFormat = typeof window !== 'undefined' ? (localStorage.getItem("wallet_number_format") || "us") : "us"
    const locale = numberFormat === 'us' ? 'en-US' : numberFormat === 'eu' ? 'de-DE' : 'en-IN'
    return `${currencySymbol}${amount.toLocaleString(locale, { 
      minimumFractionDigits: 0, 
      maximumFractionDigits: 2 
    })}`
  }

  const getThemeBasedBackground = () => {
    const savedColorTheme = (typeof window !== 'undefined' ? localStorage.getItem("wallet_color_theme") : null) || "emerald"
    const useGradient = (typeof window !== 'undefined' ? localStorage.getItem("wallet_use_gradient") : null) !== "false" // Default to true
    const themeColors = {
      emerald: { gradient: "bg-gradient-to-br from-emerald-600 via-emerald-500 to-green-400", solid: "bg-emerald-600" },
      blue: { gradient: "bg-gradient-to-br from-blue-600 via-blue-500 to-indigo-400", solid: "bg-blue-600" },
      purple: { gradient: "bg-gradient-to-br from-purple-600 via-purple-500 to-pink-400", solid: "bg-purple-600" },
      orange: { gradient: "bg-gradient-to-br from-orange-600 via-orange-500 to-red-400", solid: "bg-orange-600" },
      rose: { gradient: "bg-gradient-to-br from-rose-600 via-rose-500 to-pink-400", solid: "bg-rose-600" }
    }

    const themeColor = themeColors[savedColorTheme as keyof typeof themeColors] || themeColors.emerald

    // For negative balance, always use red regardless of theme
    if (!isPositive) {
      return useGradient ? "bg-gradient-to-br from-red-600 via-red-500 to-red-400" : "bg-red-600"
    }

    // Return gradient or solid based on user preference
    return useGradient ? themeColor.gradient : themeColor.solid
  }

  const getCreditUtilizationColor = () => {
    if (creditUtilization >= 90) return "text-red-600 dark:text-red-400"
    if (creditUtilization >= 70) return "text-amber-600 dark:text-amber-400"
    if (creditUtilization >= 30) return "text-blue-600 dark:text-blue-400"
    return "text-emerald-600 dark:text-emerald-400"
  }

  const netWorthEnabled = totalDebt > 0 || totalCreditUsed > 0

  // Enhanced touch and scroll handling
  useEffect(() => {
    const container = scrollContainerRef.current
    if (container && isMobile && netWorthEnabled) {
      let touchStartX = 0
      let touchStartY = 0
      let isScrolling = false

      const handleTouchStart = (e: TouchEvent) => {
        touchStartX = e.touches[0].clientX
        touchStartY = e.touches[0].clientY
        isScrolling = false
      }

      const handleTouchMove = (e: TouchEvent) => {
        if (!touchStartX || !touchStartY) return

        const touchEndX = e.touches[0].clientX
        const touchEndY = e.touches[0].clientY
        const diffX = touchStartX - touchEndX
        const diffY = touchStartY - touchEndY

        // Determine if this is a horizontal scroll
        if (Math.abs(diffX) > Math.abs(diffY) && Math.abs(diffX) > 10) {
          isScrolling = true
        }
      }

      const handleTouchEnd = () => {
        touchStartX = 0
        touchStartY = 0
        if (isScrolling) {
          // Add a small delay to let momentum scrolling finish
          setTimeout(() => {
            isScrolling = false
          }, 150)
        }
      }

      // Add touch event listeners for better touch handling
      container.addEventListener('touchstart', handleTouchStart, { passive: true })
      container.addEventListener('touchmove', handleTouchMove, { passive: true })
      container.addEventListener('touchend', handleTouchEnd, { passive: true })

      // Scroll handler using shared state
      const scrollHandler = () => {
        const state = scrollStateRef.current

        // Clear existing timeout
        if (state.scrollTimeout) {
          clearTimeout(state.scrollTimeout)
        }

        if (!container) return

        const now = Date.now()
        const scrollLeft = container.scrollLeft
        const timeDelta = now - state.lastScrollTime

        // Calculate scroll velocity for momentum
        if (timeDelta > 0) {
          state.scrollVelocity = (scrollLeft - state.lastScrollLeft) / timeDelta
        }

        state.lastScrollLeft = scrollLeft
        state.lastScrollTime = now

        // Update indicator with smooth interpolation
        state.scrollTimeout = setTimeout(() => {
          if (!container) return

          const cardWidth = 336 // w-80 (320px) + gap-4 (16px)
          const currentScroll = container.scrollLeft

          // Calculate which card is most visible
          const progress = currentScroll / cardWidth
          const currentIndex = Math.round(progress)
          const clampedIndex = Math.min(Math.max(currentIndex, 0), 1)

          // Smooth transition for indicator
          if (Math.abs(currentCardIndex - clampedIndex) > 0.1) {
            setCurrentCardIndex(clampedIndex)
          }

          // Enhanced momentum-based snapping
          const shouldSnap = Math.abs(state.scrollVelocity) < 0.5 // Low velocity threshold
          if (shouldSnap) {
            const nearestCard = Math.round(currentScroll / cardWidth)
            const targetPosition = Math.min(Math.max(nearestCard, 0), 1) * cardWidth

            // Only snap if we're not already very close to the target
            if (Math.abs(currentScroll - targetPosition) > 10) {
              container.scrollTo({
                left: targetPosition,
                behavior: 'smooth'
              })
            }
          }
        }, 100) // Reduced frequency for better performance
      }

      container.addEventListener('scroll', scrollHandler, { passive: true })

      return () => {
        container.removeEventListener('touchstart', handleTouchStart)
        container.removeEventListener('touchmove', handleTouchMove)
        container.removeEventListener('touchend', handleTouchEnd)
        container.removeEventListener('scroll', scrollHandler)
      }
    }
  }, [isMobile, netWorthEnabled, currentCardIndex])

  const mainBalance = isMobile && netWorthEnabled ? (
    <div>
      <div
        ref={scrollContainerRef}
        className="overflow-x-auto pb-2 hide-scrollbars"
        style={{
          scrollBehavior: 'smooth',
          WebkitOverflowScrolling: 'touch', // Better iOS scrolling
          scrollSnapType: 'x mandatory',
          scrollPadding: '0 16px'
        }}
      >
        <div className="flex gap-4 min-w-max pl-2 pr-4">
          <div className="w-88 flex-shrink-0" style={{ scrollSnapAlign: 'start' }}>
            <BalanceCard
              balanceChange={balanceChange}
              balance={balance}
              showBalance={showBalance}
              setShowBalance={setShowBalance}
              absoluteBalance={absoluteBalance}
              isPositive={isPositive}
              timeEquivalentBreakdown={timeEquivalentBreakdown}
              emergencyFund={emergencyFund}
              formatCurrency={formatCurrency}
              getThemeBasedBackground={getThemeBasedBackground}
              isMobile={true}
            />
          </div>

          {/* Net Worth Card */}
          <div className="w-88 flex-shrink-0" style={{ scrollSnapAlign: 'start' }}>
            <Card className={`border-2 transition-all duration-200 ${netWorth >= 0
              ? "border-emerald-200 dark:border-emerald-800 bg-gradient-to-br from-emerald-50 to-green-50 dark:from-emerald-950/20 dark:to-green-950/20"
              : "border-red-200 dark:border-red-800 bg-gradient-to-br from-red-50 to-pink-50 dark:from-red-950/20 dark:to-pink-950/20"
              }`}>
              <CardContent className="p-6 text-center">
                <div className="flex items-center justify-center gap-2 mb-2">
                  <PiggyBank className={`w-5 h-5 ${netWorth >= 0 ? "text-emerald-600 dark:text-emerald-400" : "text-red-600 dark:text-red-400"}`} />
                  <p className="text-sm font-medium text-muted-foreground uppercase tracking-wide">Net Worth</p>
                </div>
                <p className={`text-3xl font-bold mb-2 text-center ${netWorth >= 0
                  ? "text-emerald-600 dark:text-emerald-400"
                  : "text-red-600 dark:text-red-400"
                  }`}>
                  {netWorth < 0 && "-"}
                  {showBalance ? formatCurrency(Math.abs(netWorth)) : "••••••"}
                </p>
                <p className="text-xs text-muted-foreground max-w-xs mx-auto">
                  Balance + Available Credit - Total Debt
                </p>

                {/* Time Equivalent for Net Worth */}
                {showBalance && netWorth > 0 && timeEquivalentBreakdown && (
                  <div className="flex items-center justify-center gap-1 text-xs bg-emerald-50/80 dark:bg-emerald-950/50 backdrop-blur-sm rounded-lg px-2 py-1 mt-2">
                    <Clock className="w-3 h-3 text-emerald-600 dark:text-emerald-400" />
                    <span className="font-medium text-emerald-700 dark:text-emerald-300">
                      {(() => {
                        // Calculate time equivalent for net worth
                        const netWorthTimeBreakdown = userProfile ? getTimeEquivalentBreakdown(netWorth, userProfile) : null
                        return netWorthTimeBreakdown?.formatted?.userFriendly || timeEquivalentBreakdown.formatted.userFriendly
                      })()}
                    </span>
                  </div>
                )}
              </CardContent>
            </Card>
          </div>
        </div>
      </div>

      {/* Enhanced Scroll Indicators */}
      <div className="flex justify-center gap-3 mt-3">
        {[0, 1].map((index) => (
          <button
            key={index}
            onClick={() => {
              setCurrentCardIndex(index)
              if (scrollContainerRef.current) {
                const cardWidth = 336 // Updated to match the new calculation
                scrollContainerRef.current.scrollTo({
                  left: index * cardWidth,
                  behavior: 'smooth'
                })
              }
            }}
            className={`relative transition-all duration-300 ease-out ${currentCardIndex === index
              ? 'w-6 h-2 bg-primary scale-110'
              : 'w-2 h-2 bg-muted-foreground/40 hover:bg-muted-foreground/60 hover:scale-105'
              } rounded-full focus:outline-none focus:ring-2 focus:ring-primary/50 focus:ring-offset-2`}
            aria-label={`Go to ${index === 0 ? 'balance' : 'net worth'} card`}
          >
            {/* Active indicator glow effect */}
            {currentCardIndex === index && (
              <div className="absolute inset-0 bg-primary/30 rounded-full animate-pulse" />
            )}
          </button>
        ))}
      </div>
    </div>
  ) : (
    <BalanceCard
      balanceChange={balanceChange}
      balance={balance}
      showBalance={showBalance}
      setShowBalance={setShowBalance}
      absoluteBalance={absoluteBalance}
      isPositive={isPositive}
      timeEquivalentBreakdown={timeEquivalentBreakdown}
      emergencyFund={emergencyFund}
      formatCurrency={formatCurrency}
      getThemeBasedBackground={getThemeBasedBackground}
    />
  )

  return (
    <div className="space-y-6">
      {mainBalance}

      {/* Income & Expenses Row */}
      <div className="flex items-center justify-between gap-3">
        <p className="text-xs sm:text-sm text-muted-foreground font-medium">
          {incomeExpenseRange === "monthly" ? "This Month" : "All Time"} Summary
        </p>
        <div className="inline-flex items-center rounded-lg border bg-muted/30 p-1">
          <Button
            variant={incomeExpenseRange === "monthly" ? "default" : "ghost"}
            size="sm"
            className="h-7 px-2 text-xs"
            onClick={() => setIncomeExpenseRange("monthly")}
          >
            Monthly
          </Button>
          <Button
            variant={incomeExpenseRange === "all-time" ? "default" : "ghost"}
            size="sm"
            className="h-7 px-2 text-xs"
            onClick={() => setIncomeExpenseRange("all-time")}
          >
            All Time
          </Button>
        </div>
      </div>
      <div className="grid grid-cols-2 gap-2 sm:gap-4">
        <Card className="group hover:shadow-md transition-all duration-200 border-green-200/50 dark:border-green-800/50">
          <CardContent className="p-3 sm:p-5">
            <div className="flex items-center gap-2 sm:gap-4">
              <div className="w-8 h-8 sm:w-12 sm:h-12 rounded-xl bg-gradient-to-br from-green-500 to-emerald-600 flex items-center justify-center shadow-lg">
                <TrendingUp className="w-4 h-4 sm:w-6 sm:h-6 text-white" />
              </div>
              <div className="flex-1 min-w-0">
                <p className="text-xs font-medium text-muted-foreground uppercase tracking-wide">Income</p>
                <TimeTooltip amount={totalIncome}>
                  <p className="text-lg sm:text-xl font-bold text-green-600 dark:text-green-400 truncate">
                    {showBalance ? formatCurrency(totalIncome) : "••••••"}
                  </p>
                </TimeTooltip>
                <p className="text-[10px] sm:text-xs text-muted-foreground">
                  {incomeExpenseRange === "monthly" ? "This month" : "All time"}
                </p>
              </div>
            </div>
          </CardContent>
        </Card>

        <Card className="group hover:shadow-md transition-all duration-200 border-red-200/50 dark:border-red-800/50">
          <CardContent className="p-3 sm:p-5">
            <div className="flex items-center gap-2 sm:gap-4">
              <div className="w-8 h-8 sm:w-12 sm:h-12 rounded-xl bg-gradient-to-br from-red-500 to-pink-600 flex items-center justify-center shadow-lg">
                <TrendingDown className="w-4 h-4 sm:w-6 sm:h-6 text-white" />
              </div>
              <div className="flex-1 min-w-0">
                <p className="text-xs font-medium text-muted-foreground uppercase tracking-wide">Expenses</p>
                <TimeTooltip amount={totalExpenses}>
                  <p className="text-lg sm:text-xl font-bold text-red-600 dark:text-red-400 truncate">
                    {showBalance ? formatCurrency(totalExpenses) : "••••••"}
                  </p>
                </TimeTooltip>
                <p className="text-[10px] sm:text-xs text-muted-foreground">
                  {incomeExpenseRange === "monthly" ? "This month" : "All time"}
                </p>
              </div>
            </div>
          </CardContent>
        </Card>
      </div>

      {/* Net Worth Summary - Only show on desktop or when not in mobile row */}
      {(totalDebt > 0 || totalCreditUsed > 0) && !(isMobile && netWorthEnabled) && (
        <Card className={`border-2 transition-all duration-200 ${netWorth >= 0
          ? "border-emerald-200 dark:border-emerald-800 bg-gradient-to-br from-emerald-50 to-green-50 dark:from-emerald-950/20 dark:to-green-950/20"
          : "border-red-200 dark:border-red-800 bg-gradient-to-br from-red-50 to-pink-50 dark:from-red-950/20 dark:to-pink-950/20"
          }`}>
          <CardContent className="p-6 text-center">
            <div className="flex items-center justify-center gap-2 mb-2">
              <PiggyBank className={`w-5 h-5 ${netWorth >= 0 ? "text-emerald-600 dark:text-emerald-400" : "text-red-600 dark:text-red-400"}`} />
              <p className="text-sm font-medium text-muted-foreground uppercase tracking-wide">Net Worth</p>
            </div>
            <p className={`text-3xl font-bold mb-2 text-center ${netWorth >= 0
              ? "text-emerald-600 dark:text-emerald-400"
              : "text-red-600 dark:text-red-400"
              }`}>
              {netWorth < 0 && "-"}
              {showBalance ? formatCurrency(Math.abs(netWorth)) : "••••••"}
            </p>
            <p className="text-xs text-muted-foreground max-w-xs mx-auto">
              Balance + Available Credit - Total Debt
            </p>


          </CardContent>
        </Card>
      )}
    </div>
  )
}

"use client"

import React, { useCallback, useEffect, useRef, useState } from "react"
import {
  ArrowLeftRight,
  Loader2,
  Sparkles,
  ArrowRight,
  RefreshCcw,
  Coins,
  History,
  Info,
  Check,
  ChevronDown,
  Search
} from "lucide-react"
import { toast } from "sonner"
import { Button } from "@/components/ui/button"
import { Input } from "@/components/ui/input"
import { Label } from "@/components/ui/label"
import {
  Dialog,
  DialogContent,
  DialogHeader,
  DialogTitle,
  DialogDescription
} from "@/components/ui/dialog"
import {
  Command,
  CommandEmpty,
  CommandGroup,
  CommandInput,
  CommandItem,
  CommandList,
} from "@/components/ui/command"
import {
  Popover,
  PopoverContent,
  PopoverTrigger,
} from "@/components/ui/popover"
import { Card, CardContent } from "@/components/ui/card"
import { Badge } from "@/components/ui/badge"
import { cn } from "@/lib/utils"

interface CurrencyConverterDialogProps {
  isOpen: boolean
  onOpenChange: (open: boolean) => void
}

const CONVERSION_CACHE_TTL_MS = 5 * 60 * 1000

const CURRENCIES = [
  { code: "USD", name: "US Dollar", flag: "🇺🇸" },
  { code: "NPR", name: "Nepalese Rupee", flag: "🇳🇵" },
  { code: "INR", name: "Indian Rupee", flag: "🇮🇳" },
  { code: "EUR", name: "Euro", flag: "🇪🇺" },
  { code: "GBP", name: "British Pound", flag: "🇬🇧" },
  { code: "AUD", name: "Australian Dollar", flag: "🇦🇺" },
  { code: "CAD", name: "Canadian Dollar", flag: "🇨🇦" },
  { code: "JPY", name: "Japanese Yen", flag: "🇯🇵" },
  { code: "AED", name: "UAE Dirham", flag: "🇦🇪" },
  { code: "QAR", name: "Qatari Rial", flag: "🇶🇦" },
  { code: "MYR", name: "Malaysian Ringgit", flag: "🇲🇾" },
  { code: "SGD", name: "Singapore Dollar", flag: "🇸🇬" },
  { code: "CNY", name: "Chinese Yuan", flag: "🇨🇳" },
  { code: "HKD", name: "Hong Kong Dollar", flag: "🇭🇰" },
  { code: "NZD", name: "New Zealand Dollar", flag: "🇳🇿" },
  { code: "THB", name: "Thai Baht", flag: "🇹🇭" },
  { code: "KRW", name: "South Korean Won", flag: "🇰🇷" },
  { code: "SAR", name: "Saudi Riyal", flag: "🇸🇦" },
  { code: "CHF", name: "Swiss Franc", flag: "🇨🇭" },
  { code: "SEK", name: "Swedish Krona", flag: "🇸🇪" },
  { code: "DKK", name: "Danish Krone", flag: "🇩🇰" },
]

export function CurrencyConverterDialog({ isOpen, onOpenChange }: CurrencyConverterDialogProps) {
  const [fromCurrency, setFromCurrency] = useState("USD")
  const [toCurrency, setToCurrency] = useState("NPR")
  const [convertAmount, setConvertAmount] = useState("1")
  const [convertedAmount, setConvertedAmount] = useState<number | null>(null)
  const [conversionRate, setConversionRate] = useState<number | null>(null)
  const [conversionDate, setConversionDate] = useState("")
  const [lastRateSource, setLastRateSource] = useState<"cache" | "network" | null>(null)
  const [isConverting, setIsConverting] = useState(false)
  const [isSwapping, setIsSwapping] = useState(false)

  const conversionCacheRef = useRef<Map<string, { rate: number; date: string; fetchedAt: number }>>(new Map())

  const getExchangeRate = useCallback(async (from: string, to: string) => {
    if (from === to) {
      return {
        rate: 1,
        date: new Date().toISOString().slice(0, 10),
        source: "cache" as const,
      }
    }

    const cacheKey = `${from}_${to}`
    const cached = conversionCacheRef.current.get(cacheKey)
    const isFresh = !!cached && Date.now() - cached.fetchedAt < CONVERSION_CACHE_TTL_MS
    if (isFresh && cached) {
      return { rate: cached.rate, date: cached.date, source: "cache" as const }
    }

    const url = `/api/currency/convert?from=${from}&to=${to}`
    const response = await fetch(url)

    if (!response.ok) {
      let message = `Conversion request failed (${response.status})`
      try {
        const errorData = await response.json()
        if (typeof errorData?.error === "string") {
          message = errorData.error
        }
      } catch {
        // Ignore parse errors and keep default message.
      }
      throw new Error(message)
    }

    const data = await response.json()
    const rate = typeof data?.rate === "number" ? data.rate : null
    if (typeof rate !== "number") {
      throw new Error("Could not read conversion rate")
    }
    const date = typeof data?.date === "string" ? data.date : ""
    conversionCacheRef.current.set(cacheKey, { rate, date, fetchedAt: Date.now() })
    return { rate, date, source: "network" as const }
  }, [])

  const handleCurrencyConversion = useCallback(async (showToast = true) => {
    const amountNumber = Number(convertAmount)
    if (!Number.isFinite(amountNumber) || amountNumber <= 0) {
      if (showToast) toast.error("Enter a valid amount greater than 0")
      return
    }

    const from = fromCurrency.toUpperCase()
    const to = toCurrency.toUpperCase()

    setIsConverting(true)
    try {
      const { rate, date, source } = await getExchangeRate(from, to)
      setConversionRate(rate)
      setConvertedAmount(amountNumber * rate)
      setConversionDate(date)
      setLastRateSource(source)

      if (showToast) {
        toast.success(source === "cache" ? "Used cached live rate" : "Updated with latest live rate")
      }
    } catch (error) {
      console.error("Currency conversion failed:", error)
      toast.error(error instanceof Error ? error.message : "Conversion failed. Try again.")
    } finally {
      setIsConverting(false)
    }
  }, [convertAmount, fromCurrency, toCurrency, getExchangeRate])

  useEffect(() => {
    if (!isOpen) return
    const timeout = setTimeout(() => {
      handleCurrencyConversion(false)
    }, 100)
    return () => clearTimeout(timeout)
  }, [isOpen, fromCurrency, toCurrency, handleCurrencyConversion])

  const handleSwap = () => {
    setIsSwapping(true)
    const oldFrom = fromCurrency
    const oldTo = toCurrency
    setFromCurrency(oldTo)
    setToCurrency(oldFrom)
    setConvertedAmount(null)
    setConversionRate(null)
    setTimeout(() => setIsSwapping(false), 500)
  }

  return (
    <Dialog open={isOpen} onOpenChange={onOpenChange}>
      <DialogContent
        className="sm:max-w-[480px] h-[90vh] sm:h-[650px] p-0 flex flex-col gap-0 overflow-hidden border-0 shadow-[0_32px_64px_-12px_rgba(0,0,0,0.2)] dark:shadow-[0_32px_64px_-12px_rgba(0,0,0,0.4)] bg-background/95 backdrop-blur-xl"
        onOpenAutoFocus={(e) => e.preventDefault()}
      >
        <div className="absolute inset-0 bg-gradient-to-br from-primary/5 via-transparent to-primary/5 pointer-events-none" />

        {/* Fixed Header */}
        <DialogHeader className="p-6 pb-4 relative z-10 shrink-0 border-b border-muted/20 bg-background/50 backdrop-blur-md">
          <div className="flex items-center justify-between">
            <div className="flex items-center gap-3 text-left">
              <div className="p-2.5 rounded-2xl bg-primary/10 text-primary ring-1 ring-inset ring-primary/20 shadow-sm">
                <Coins className="h-5 w-5" />
              </div>
              <div>
                <DialogTitle className="text-xl font-bold tracking-tight text-foreground">Currency Converter</DialogTitle>
                <DialogDescription className="text-sm font-medium text-muted-foreground/80 flex items-center gap-1.5 mt-0.5">
                  <span className="inline-block w-1.5 h-1.5 rounded-full bg-emerald-500 animate-pulse" />
                  Live Market Rates
                </DialogDescription>
              </div>
            </div>
          </div>
        </DialogHeader>

        {/* Scrollable Content Body */}
        <div className="flex-1 overflow-y-auto relative z-10 custom-scrollbar overscroll-contain">
          <div className="p-6 space-y-8 min-h-full">
            <div className="space-y-4">
              {/* Amount & From */}
              <div className="relative group">
                <Card className="border-2 border-muted/50 group-focus-within:border-primary/40 transition-all duration-300 bg-background/50 backdrop-blur-sm overflow-visible rounded-2xl shadow-none">
                  <CardContent className="p-4 space-y-3">
                    <div className="flex justify-between items-center">
                      <Label className="text-[10px] uppercase font-bold tracking-widest text-muted-foreground/70">From Amount</Label>
                      <Badge variant="outline" className="text-[10px] font-bold px-2 py-0 h-5 bg-muted/30 border-none opacity-0 group-hover:opacity-100 transition-opacity">
                        {CURRENCIES.find(c => c.code === fromCurrency)?.name}
                      </Badge>
                    </div>
                    <div className="flex items-center gap-3">
                      <Input
                        id="converter-amount"
                        type="text"
                        inputMode="decimal"
                        value={convertAmount}
                        onChange={(e) => {
                          const val = e.target.value.replace(/[^0-9.]/g, '')
                          setConvertAmount(val)
                        }}
                        className="border-0 p-0 text-2xl h-auto font-bold focus-visible:ring-0 bg-transparent placeholder:text-muted-foreground/30 shadow-none ring-0 focus-visible:ring-offset-0 ring-primary/40"
                        placeholder="1,000"
                      />
                      <CurrencySelector
                        value={fromCurrency}
                        onChange={setFromCurrency}
                      />
                    </div>
                  </CardContent>
                </Card>

                {/* Swap Button */}
                <div className="absolute left-1/2 -translate-x-1/2 -translate-y-1/2 top-full z-20">
                  <Button
                    variant="secondary"
                    size="icon"
                    onClick={handleSwap}
                    className={cn(
                      "rounded-2xl h-11 w-11 shadow-lg border-4 border-background hover:scale-110 active:scale-95 transition-all duration-300 group/swap bg-primary text-primary-foreground",
                      isSwapping && "rotate-180"
                    )}
                  >
                    <RefreshCcw className="h-5 w-5" />
                  </Button>
                </div>
              </div>

              {/* To Section */}
              <Card className="border-2 border-muted/50 bg-background/50 backdrop-blur-sm overflow-visible rounded-2xl group transition-all duration-300 hover:border-primary/20 shadow-none">
                <CardContent className="p-4 space-y-3">
                  <div className="flex justify-between items-center">
                    <Label className="text-[10px] uppercase font-bold tracking-widest text-muted-foreground/70">To Currency</Label>
                    <Badge variant="outline" className="text-[10px] font-bold px-2 py-0 h-5 bg-muted/30 border-none opacity-0 group-hover:opacity-100 transition-opacity">
                      {CURRENCIES.find(c => c.code === toCurrency)?.name}
                    </Badge>
                  </div>
                  <div className="flex items-center gap-2">
                    <div className="flex-1">
                      {isConverting ? (
                        <div className="flex items-center gap-2">
                          <Loader2 className="h-6 w-6 animate-spin text-primary/40" />
                          <span className="text-muted-foreground/40 font-bold text-2xl animate-pulse">Calculating...</span>
                        </div>
                      ) : convertedAmount !== null ? (
                        <span className="text-2xl font-bold tracking-tight bg-gradient-to-br from-foreground to-foreground/70 bg-clip-text">
                          {convertedAmount.toLocaleString(undefined, { maximumFractionDigits: 4 })}
                        </span>
                      ) : (
                        <span className="text-2xl font-bold text-muted-foreground/30 tracking-tight">0.00</span>
                      )}
                    </div>
                    <CurrencySelector
                      value={toCurrency}
                      onChange={setToCurrency}
                    />
                  </div>
                </CardContent>
              </Card>
            </div>


            {/* Info Section */}
            <div className="space-y-3">
              {conversionDate && !isConverting && (
                <div className="flex items-center justify-center gap-1.5 text-[11px] font-medium text-muted-foreground/50 animate-in fade-in duration-500">
                  <History className="h-3 w-3" />
                  Rate updated on {new Date(conversionDate).toLocaleDateString(undefined, { month: 'short', day: 'numeric', year: 'numeric' })}
                </div>
              )}

              <div className="flex items-center gap-2 p-2 px-3 rounded-xl bg-yellow-500/5 text-yellow-600 dark:text-yellow-400/80 ring-1 ring-yellow-500/10">
                <Info className="h-3.5 w-3.5 shrink-0" />
                <p className="text-[10px] font-medium leading-tight text-pretty">
                  Market rates provided for informational purposes only. Actual rates may vary by bank or service provider.
                </p>
              </div>
            </div>

            <div className="flex gap-3">
              <Button
                type="button"
                variant="outline"
                className="flex-1 h-12 rounded-2xl font-bold border-muted/50 hover:bg-muted/30 transition-all active:scale-95"
                onClick={() => onOpenChange(false)}
              >
                CANCEL
              </Button>
              <Button
                type="button"
                className="flex-[2] h-12 rounded-2xl font-bold bg-primary hover:opacity-90 active:scale-[0.98] transition-all shadow-lg shadow-primary/20"
                onClick={() => handleCurrencyConversion(true)}
                disabled={isConverting}
              >
                {isConverting ? (
                  <span className="flex items-center gap-2">
                    <Loader2 className="h-5 w-5 animate-spin" />
                    UPDATING...
                  </span>
                ) : (
                  <span className="flex items-center gap-2">
                    <RefreshCcw className="h-4 w-4" />
                    CONVERT
                  </span>
                )}
              </Button>
            </div>
          </div>
        </div>
      </DialogContent>
    </Dialog>
  )
}

function CurrencySelector({
  value,
  onChange
}: {
  value: string,
  onChange: (val: string) => void
}) {
  const [open, setOpen] = useState(false)
  const selectedCurrency = CURRENCIES.find((c) => c.code === value)

  return (
    <Popover open={open} onOpenChange={setOpen}>
      <PopoverTrigger asChild>
        <Button
          variant="outline"
          role="combobox"
          aria-expanded={open}
          className="w-[110px] h-10 rounded-xl bg-muted/40 border-0 justify-between font-bold hover:bg-muted/60 transition-colors focus:ring-0 focus:ring-offset-0 shrink-0"
        >
          <span className="flex items-center gap-2 overflow-hidden">
            <span>{selectedCurrency?.flag}</span>
            <span className="font-bold tracking-tight">{value}</span>
          </span>
          <ChevronDown className="ml-1 h-3 w-3 shrink-0 opacity-50" />
        </Button>
      </PopoverTrigger>
      <PopoverContent
        className="w-[200px] p-0 rounded-2xl border-muted/40 overflow-hidden shadow-2xl backdrop-blur-xl bg-background/95 z-[100]"
        onOpenAutoFocus={(e) => e.preventDefault()}
      >
        <Command className="bg-transparent" loop>
          <CommandInput placeholder="Search currency..." className="h-10" />
          <CommandList className="max-h-[280px] custom-scrollbar">
            <CommandEmpty>No currency found.</CommandEmpty>
            <CommandGroup heading="Currencies">
              {CURRENCIES.map((currency) => (
                <CommandItem
                  key={currency.code}
                  value={currency.code + " " + currency.name}
                  onSelect={() => {
                    onChange(currency.code)
                    setOpen(false)
                  }}
                  className="flex items-center justify-between p-2.5 rounded-lg cursor-pointer mx-1 my-0.5 data-[selected=true]:bg-primary/10 data-[selected=true]:text-primary"
                >
                  <div className="flex items-center gap-3">
                    <span className="text-lg">{currency.flag}</span>
                    <div className="flex flex-col">
                      <span className="font-bold text-sm leading-none">{currency.code}</span>
                      <span className="text-[10px] text-muted-foreground font-medium">{currency.name}</span>
                    </div>
                  </div>
                  {value === currency.code && (
                    <Check className="h-4 w-4 text-primary" />
                  )}
                </CommandItem>
              ))}
            </CommandGroup>
          </CommandList>
        </Command>
      </PopoverContent>
    </Popover>
  )
}

