                                </Button>
                                <Button
                                  size="sm"
                                  variant="outline"
                                  onClick={() => setCreditDetailsDialog({ open: true, accountId: credit.id })}
                                  className="flex-1"
                                >
                                  💳 Details
                                </Button>
                              </div>

