                                    <Button
                                      size="sm"
                                      variant="ghost"
                                      onClick={() => setCreditDetailsDialog({ open: true, accountId: credit.id })}
                                      className="text-[10px] sm:text-xs h-6 px-2"
                                    >
                                      View All
                                    </Button>
