                                          <p className="text-xs text-muted-foreground">
                                            {new Date(tx.date).toLocaleDateString()}
                                          </p>
                                        </div>
                                        <div className="text-right">
                                          <p className={`font-semibold ${tx.type === 'payment' ? 'text-green-600' : 'text-red-600'}`}>
