      setGoalCreationMode("template")
    }

    setSelectedTemplateName("")
    setErrors({})
  }, [editingGoal, isOpen])

  const validateForm = () => {
    const newErrors: Record<string, string> = {}

    if (!formData.title.trim()) {
      newErrors.title = "Goal name is required."
    }

    if (!formData.targetAmount || Number.parseFloat(formData.targetAmount) <= 0) {
      newErrors.targetAmount = "Enter a valid target amount."
    }

    if (!formData.targetDate) {
      newErrors.targetDate = "Target date is required."
    } else {
      const targetDate = new Date(formData.targetDate)
      const today = new Date()
      today.setHours(0, 0, 0, 0)
      if (targetDate <= today) {
        newErrors.targetDate = "Target date must be in the future."
      }
    }

    if (formData.autoContribute && (!formData.contributionAmount || Number.parseFloat(formData.contributionAmount) <= 0)) {
      newErrors.contributionAmount = "Enter a valid contribution amount."
    }

    setErrors(newErrors)
    return Object.keys(newErrors).length === 0
  }

  const applyTemplate = (template: (typeof GOAL_TEMPLATES)[0]) => {
    const targetDate = new Date()
    targetDate.setMonth(targetDate.getMonth() + ("targetMonths" in template && template.targetMonths ? template.targetMonths : 12))

    setFormData((prev) => ({
      ...prev,
      title: template.name,
      targetAmount: template.targetAmount.toString(),
      targetDate: targetDate.toISOString().split("T")[0],
      description: template.description,
      category: template.category,
      priority: template.priority,
      autoContribute: "autoContribute" in template ? Boolean(template.autoContribute) : prev.autoContribute,
      contributionAmount: "contributionAmount" in template && template.contributionAmount
        ? template.contributionAmount.toString()
        : "",
      contributionFrequency: "contributionFrequency" in template && template.contributionFrequency
        ? template.contributionFrequency
        : "monthly",
      challengeMode: template.name === "Hard Plan Challenge" ? "easy" : prev.challengeMode,
    }))
    setSelectedTemplateName(template.name)
    setGoalCreationMode("custom")
  }

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault()
    if (!validateForm()) return

    const goalData = {
      title: formData.title.trim(),
      targetAmount: Number.parseFloat(formData.targetAmount),
      targetDate: formData.targetDate,
      description: formData.description.trim(),
      category: formData.category,
      priority: formData.priority,
      autoContribute: formData.autoContribute,
      ...(formData.autoContribute && {
        contributionAmount: Number.parseFloat(formData.contributionAmount),
        contributionFrequency: formData.contributionFrequency,
      }),
      ...((selectedTemplateName === "Hard Plan Challenge" || editingGoal?.challengePlan) && {
        challengePlan: {
          type: "hard-plan" as const,
          mode: formData.challengeMode,
          baseTargetAmount: Number.parseFloat(formData.targetAmount),
          penaltyAmount: 50,
          graceMonths: 1,
          allocation: {
            nepalPercent: 50,
            ukPercent: 50,
          },
          hardModeRewardPoints: 10,
        },
      }),
    }

    if (editingGoal) {
      updateGoal(editingGoal.id, goalData)
    } else {
      addGoal({
        ...goalData,
        createdAt: new Date().toISOString(),
      } as any)
    }

    onClose()
  }

  const isTemplateMode = !editingGoal && goalCreationMode === "template"
  const isFormMode = !!editingGoal || goalCreationMode === "custom"

  return (
    <Dialog open={isOpen} onOpenChange={(open) => !open && onClose()}>
      <DialogContent className="sm:max-w-2xl max-h-[90vh] overflow-hidden flex flex-col">
        <DialogHeader>
          <DialogTitle className="flex items-center gap-2 text-lg font-semibold">
            <Target className="w-5 h-5 text-primary" />
            {editingGoal ? "Edit Goal" : "Create Savings Goal"}
          </DialogTitle>
          <p className="text-sm text-muted-foreground">
            {editingGoal
              ? "Update your goal details and keep your plan on track."
              : "Choose a template or be creative"}
          </p>
        </DialogHeader>

        <form onSubmit={handleSubmit} className="flex min-h-0 flex-1 flex-col">
          <div className="min-h-0 flex-1 space-y-6 overflow-y-auto pr-1">
            {!editingGoal && (
              <Card>
                <CardContent className="pt-5">
                  <div className="flex flex-col gap-3 sm:flex-row sm:items-center sm:justify-between">
                    <div className="space-y-1">
                      <p className="text-sm font-medium">How do you want to start?</p>
                      <p className="text-xs text-muted-foreground">Templates are fast. Custom gives full control.</p>
                    </div>
                    <div className="grid grid-cols-2 gap-2 w-full sm:w-auto">
                      <Button
                        type="button"
                        variant={goalCreationMode === "template" ? "default" : "outline"}
                        onClick={() => setGoalCreationMode("template")}
                      >
                        Templates
                      </Button>
                      <Button
                        type="button"
                        variant={goalCreationMode === "custom" ? "default" : "outline"}
                        onClick={() => setGoalCreationMode("custom")}
                      >
                        Custom
                      </Button>
                    </div>
                  </div>
                </CardContent>
              </Card>
            )}

            {!editingGoal && goalCreationMode === "template" && (
              <Card>
                <CardHeader className="pb-3">
                  <CardTitle className="text-base">Goal Templates</CardTitle>
                  <p className="text-sm text-muted-foreground">Tap a template to pre-fill the form, then adjust anything.</p>
                </CardHeader>
                <CardContent>
                  <div className="grid grid-cols-2 sm:grid-cols-2 gap-3">
                    {GOAL_TEMPLATES.map((template) => {
                      const category = GOAL_CATEGORIES.find((c) => c.id === template.category)
                      const IconComponent = category?.icon || Target
                      return (
                        <button
                          key={template.name}
                          type="button"
                          onClick={() => applyTemplate(template)}
                          className="text-left rounded-lg border p-3 transition hover:bg-muted/40"
                        >
                          <div className="flex items-center gap-2">
                            <div className={cn("rounded-md border p-1.5", category?.color)}>
                              <IconComponent className="w-4 h-4" />
                            </div>
                            <p className="font-medium text-sm">{template.name}</p>
                          </div>
                          <p className="mt-2 text-sm font-semibold text-primary">
                            {currencySymbol}
                            {template.targetAmount.toLocaleString()}
                          </p>
                          <p className="mt-1 text-xs text-muted-foreground line-clamp-2">{template.description}</p>
                        </button>
                      )
                    })}
                  </div>
                </CardContent>
              </Card>
            )}

            {!editingGoal && goalCreationMode === "custom" && selectedTemplateName && (
              <div className="rounded-md border bg-muted/30 px-3 py-2 text-sm text-muted-foreground">
                Using template: <span className="font-medium text-foreground">{selectedTemplateName}</span>
              </div>
            )}

            {((!editingGoal && goalCreationMode === "custom" && selectedTemplateName === "Hard Plan Challenge") || editingGoal?.challengePlan) && (
              <Card className="border-primary/20 bg-primary/5">
                <CardContent className="pt-5">
                  <div className="space-y-3">
                    <p className="text-sm font-semibold text-foreground">Hard plan rules</p>
                    <p className="text-xs text-muted-foreground">
                      Save toward the target on time. If the active deadline is missed, the plan adds an extra 50 and gives one more month to complete.
                    </p>
                    <p className="text-xs text-muted-foreground">
                      Suggested split after funding: 50% for NEP and 50% for UK.
                    </p>
                    <div className="grid gap-3 sm:grid-cols-2">
                      <div className="space-y-2">
                        <Label>Challenge mode</Label>
                        <Select
                          value={formData.challengeMode}
                          onValueChange={(value: "easy" | "hard") => setFormData((prev) => ({ ...prev, challengeMode: value }))}
                        >
                          <SelectTrigger>
                            <SelectValue />
                          </SelectTrigger>
                          <SelectContent>
                            <SelectItem value="easy">Easy mode</SelectItem>
                            <SelectItem value="hard">Hard mode</SelectItem>
                          </SelectContent>
                        </Select>
                      </div>
                      <div className="rounded-md border bg-background/80 p-3 text-xs text-muted-foreground">
                        {formData.challengeMode === "easy"
                          ? "Easy mode: using the fund for investment does not reduce saved progress."
                          : "Hard mode: investment usage counts like expense, reduces saved progress, and earns 10 points per use."}
                      </div>
                    </div>
                    {challengePreview && (
                      <div className="grid gap-3 sm:grid-cols-3">
                        <div className="rounded-md border bg-background/80 p-3">
                          <p className="text-[11px] text-muted-foreground">Current target</p>
                          <p className="mt-1 text-sm font-semibold">
                            {currencySymbol}{challengePreview.effectiveTargetAmount.toLocaleString()}
                          </p>
                        </div>
                        <div className="rounded-md border bg-background/80 p-3">
                          <p className="text-[11px] text-muted-foreground">Penalty rule</p>
                          <p className="mt-1 text-sm font-semibold">
                            {currencySymbol}{challengePreview.plan.penaltyAmount} every {challengePreview.plan.graceMonths} month
                          </p>
                        </div>
                        <div className="rounded-md border bg-background/80 p-3">
                          <p className="text-[11px] text-muted-foreground">Utilization split</p>
                          <p className="mt-1 text-sm font-semibold">
                            {challengePreview.utilization.nepalPercent}% NEP / {challengePreview.utilization.ukPercent}% UK
                          </p>
                        </div>
                      </div>
                    )}
                  </div>
                </CardContent>
              </Card>
            )}

            {isFormMode && (
              <>
                <Card>
                  <CardContent className="space-y-4 pt-5">
                    <div className="grid grid-cols-1 sm:grid-cols-2 gap-4">
                      <div className="space-y-2">
                        <Label htmlFor="title" className="flex items-center gap-2">
                          <Target className="w-4 h-4 text-primary" />
                          Goal Name
                        </Label>
                        <Input
                          id="title"
                          value={formData.title}
                          onChange={(e) => {
                            setFormData((prev) => ({ ...prev, title: e.target.value }))
                            if (errors.title) setErrors((prev) => ({ ...prev, title: "" }))
                          }}
                          placeholder="e.g., Emergency fund, New bike, Family trip"
                          className={errors.title ? "border-destructive" : ""}
                        />
                        {errors.title && <p className="text-sm text-destructive">{errors.title}</p>}
                      </div>

                      <div className="space-y-2">
                        <Label htmlFor="targetAmount" className="flex items-center gap-2">
                          <DollarSign className="w-4 h-4 text-primary" />
                          Target Amount
                        </Label>
                        <div className="relative">
                          <span className="absolute left-3 top-1/2 -translate-y-1/2 text-muted-foreground font-medium">
                            {currencySymbol}
                          </span>
                          <Input
                            id="targetAmount"
                            type="number"
                            step="0.01"
                            min="0"
                            value={formData.targetAmount}
                            onChange={(e) => {
                              setFormData((prev) => ({ ...prev, targetAmount: e.target.value }))
                              if (errors.targetAmount) setErrors((prev) => ({ ...prev, targetAmount: "" }))
                            }}
                            placeholder="0.00"
                            className={cn("pl-10", errors.targetAmount && "border-destructive")}
                          />
                        </div>
                        {errors.targetAmount && <p className="text-sm text-destructive">{errors.targetAmount}</p>}
                      </div>
                    </div>

                    <div className="grid grid-cols-2 sm:grid-cols-2 gap-4">
                      <div className="space-y-2">
                        <Label htmlFor="targetDate" className="flex items-center gap-2">
                          <Calendar className="w-4 h-4 text-primary" />
                          Target Date
                        </Label>
                        <Input
                          id="targetDate"
                          type="date"
                          value={formData.targetDate}
                          onChange={(e) => {
                            setFormData((prev) => ({ ...prev, targetDate: e.target.value }))
                            if (errors.targetDate) setErrors((prev) => ({ ...prev, targetDate: "" }))
                          }}
                          min={new Date().toISOString().split("T")[0]}
                          className={errors.targetDate ? "border-destructive" : ""}
                        />
                        {errors.targetDate && <p className="text-sm text-destructive">{errors.targetDate}</p>}
                      </div>

                      <div className="space-y-2">
                        <Label htmlFor="category">Category</Label>
                        <Select
                          value={formData.category}
                          onValueChange={(value) => setFormData((prev) => ({ ...prev, category: value }))}
                        >
                          <SelectTrigger id="category">
                            <SelectValue placeholder="Select category" />
                          </SelectTrigger>
                          <SelectContent>
                            {GOAL_CATEGORIES.map((category) => (
                              <SelectItem key={category.id} value={category.id}>
                                <div className="flex items-center gap-2">
                                  <category.icon className="w-4 h-4" />
                                  <span>{category.name}</span>
                                </div>
                              </SelectItem>
                            ))}
                          </SelectContent>
                        </Select>
                        <p className="text-xs text-muted-foreground">
                          {GOAL_CATEGORIES.find((c) => c.id === formData.category)?.description}
                        </p>
                      </div>
                    </div>

                    <div className="space-y-2">
                      <Label htmlFor="description">Note (Optional)</Label>
                      <Textarea
                        id="description"
                        value={formData.description}
                        onChange={(e) => setFormData((prev) => ({ ...prev, description: e.target.value }))}
                        placeholder="Why this goal matters to you, or your saving plan."
                        rows={3}
                      />
                    </div>
                  </CardContent>
                </Card>

                <div className="grid grid-cols-1 sm:grid-cols-2 gap-3">
                  <Card>
                    <CardContent className="pt-2.5 space-y-1.5">
                      <div className="flex items-center gap-3">
                        <Label htmlFor="priority" className="shrink-0">Priority</Label>
                        <Select
                          value={formData.priority}
                          onValueChange={(value: "low" | "medium" | "high") =>
                            setFormData((prev) => ({ ...prev, priority: value }))
                          }
                        >
                          <SelectTrigger id="priority" className="h-9">
                            <SelectValue />
                          </SelectTrigger>
                          <SelectContent>
                            {PRIORITY_LEVELS.map((priority) => (
                              <SelectItem key={priority.id} value={priority.id}>
                                {priority.name}
                              </SelectItem>
                            ))}
                          </SelectContent>
                        </Select>
                      </div>
                      <p className="text-[11px] text-muted-foreground">
                        {PRIORITY_LEVELS.find((p) => p.id === formData.priority)?.description}
                      </p>
                    </CardContent>
                  </Card>

                  <Card>
                    <CardContent className="pt-2.5 space-y-3">
                      <div className="flex items-center justify-between gap-3">
                        <div>
                          <Label htmlFor="auto-contribute">Auto-contribute</Label>
                          <p className="text-[11px] text-muted-foreground">Add money automatically on a schedule.</p>
                        </div>
                        <Switch
                          id="auto-contribute"
                          checked={formData.autoContribute}
                          onCheckedChange={(checked) => setFormData((prev) => ({ ...prev, autoContribute: checked }))}
                        />
                      </div>

                      {formData.autoContribute && (
                        <div className="space-y-2 rounded-md border bg-muted/20 p-2.5">
                          <div className="grid grid-cols-1 sm:grid-cols-2 gap-2">
                            <div className="relative">
                              <span className="absolute left-3 top-1/2 -translate-y-1/2 text-muted-foreground font-medium">
                                {currencySymbol}
                              </span>
                              <Input
                                id="contributionAmount"
                                type="number"
                                step="0.01"
                                min="0"
                                value={formData.contributionAmount}
                                onChange={(e) => {
                                  setFormData((prev) => ({ ...prev, contributionAmount: e.target.value }))
                                  if (errors.contributionAmount) setErrors((prev) => ({ ...prev, contributionAmount: "" }))
                                }}
                                placeholder="Contribution amount"
                                className={cn("pl-10", errors.contributionAmount && "border-destructive")}
                              />
                            </div>
                            <Select
                              value={formData.contributionFrequency}
                              onValueChange={(value: "daily" | "weekly" | "monthly") =>
                                setFormData((prev) => ({ ...prev, contributionFrequency: value }))
                              }
                            >
                              <SelectTrigger>
                                <SelectValue />
                              </SelectTrigger>
                              <SelectContent>
                                <SelectItem value="daily">Daily</SelectItem>
                                <SelectItem value="weekly">Weekly</SelectItem>
                                <SelectItem value="monthly">Monthly</SelectItem>
                              </SelectContent>
                            </Select>
                          </div>
                          {errors.contributionAmount && <p className="text-sm text-destructive">{errors.contributionAmount}</p>}
                        </div>
                      )}
                    </CardContent>
                  </Card>
                </div>

                {goalInsights && formData.targetAmount && formData.targetDate && (
                  <Card className="border-primary/20 bg-primary/5">
                    <CardHeader className="pb-2">
                      <CardTitle className="text-base flex items-center gap-2">
                        <TrendingUp className="w-4 h-4 text-primary" />
                        Savings Plan
                      </CardTitle>
                    </CardHeader>
                    <CardContent>
                      <div className="grid grid-cols-3 sm:grid-cols-3 gap-3">
                        <div className="rounded-md border bg-background p-3 text-center">
                          <p className="text-xs text-muted-foreground">Time left</p>
                          <p className="text-lg font-semibold text-primary">{goalInsights.monthsToGoal} months</p>
                        </div>
                        <div className="rounded-md border bg-background p-3 text-center">
                          <p className="text-xs text-muted-foreground">Per month</p>
                          <p className="text-lg font-semibold">
                            {currencySymbol}
                            {Math.round(goalInsights.monthlyContribution).toLocaleString()}
                          </p>
                        </div>
                        <div className="rounded-md border bg-background p-3 text-center">
                          <p className="text-xs text-muted-foreground">Per week</p>
                          <p className="text-lg font-semibold">
                            {currencySymbol}
                            {Math.round(goalInsights.weeklyContribution).toLocaleString()}
                          </p>
                        </div>
                      </div>
                    </CardContent>
                  </Card>
                )}
              </>
            )}
          </div>

          <DialogFooter className="mt-4 flex flex-row gap-2 border-t bg-background pt-3 pb-[calc(env(safe-area-inset-bottom)+0.75rem)] justify-end">
            <Button type="button" variant="outline" onClick={onClose} className="flex-1">
              Cancel
            </Button>
            {isTemplateMode ? (
              <Button type="button" onClick={() => setGoalCreationMode("custom")} className="flex-1">
                Continue with Custom Goal
              </Button>
            ) : (
              <Button type="submit" className="flex-1" disabled={!formData.title || !formData.targetAmount || !formData.targetDate}>
                {editingGoal ? "Save Changes" : "Create Goal"}
              </Button>
            )}
          </DialogFooter>
        </form>
      </DialogContent>
    </Dialog>
  )
}

"use client"

import { useState, useMemo } from "react"
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card"
import { Button } from "@/components/ui/button"
import { Progress } from "@/components/ui/progress"
import { Badge } from "@/components/ui/badge"
import { Input } from "@/components/ui/input"
import { Textarea } from "@/components/ui/textarea"
import { Dialog, DialogContent, DialogHeader, DialogTitle } from "@/components/ui/dialog"
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from "@/components/ui/select"
import { Collapsible, CollapsibleContent, CollapsibleTrigger } from "@/components/ui/collapsible"
import {
  Target,
  Plus,
  Calendar,
  Send,
  ArrowRight,
  Search,
  Filter,
  ChevronDown,
  TrendingUp,
  AlertCircle,
  AlertTriangle,
  CheckCircle2,
  Edit,
  Trash2,
  MoreHorizontal,
  PiggyBank,
  Home,
  Car,
  GraduationCap,
  Heart,
  Plane,
  ShoppingBag,
  Briefcase,
  Zap,
  Trophy,
  Star,
  Clock,
  Sparkles,
} from "lucide-react"
import { GoalDialog } from "./goal-dialog"
import { useWalletData } from "@/contexts/wallet-data-context"
import type { Goal, UserProfile } from "@/types/wallet"
import { cn, formatCurrency } from "@/lib/utils"
import { getCurrencySymbol } from "@/lib/currency"
import { getGoalChallengeSummary, getGoalEffectiveProgress, getGoalEffectiveRemainingAmount, getGoalEffectiveTargetAmount } from "@/lib/goal-challenge"
import { DropdownMenu, DropdownMenuContent, DropdownMenuItem, DropdownMenuTrigger } from "@/components/ui/dropdown-menu"
import { Checkbox } from "@/components/ui/checkbox"
import { Tabs, TabsContent, TabsList, TabsTrigger } from "@/components/ui/tabs"
import { GoalProgressVisualization } from "./goal-progress-visualization"
import { ScenarioPlanningCalculator } from "./scenario-planning-calculator"

interface EnhancedGoalsListProps {
  goals: Goal[]
  userProfile: UserProfile
}

type FilterType = "all" | "active" | "completed" | "overdue"
type SortType = "progress" | "target-date" | "amount" | "name"

export function EnhancedGoalsList({ goals, userProfile }: EnhancedGoalsListProps) {
  const { transferToGoal, balance, updateGoal, deleteGoal, useGoalForInvestment } = useWalletData()

  // Get currency symbol
  const currencySymbol = useMemo(() => {
    return getCurrencySymbol(userProfile?.currency || "USD", (userProfile as any)?.customCurrency)
  }, [userProfile?.currency, (userProfile as any)?.customCurrency])
  const [isDialogOpen, setIsDialogOpen] = useState(false)
  const [editingGoal, setEditingGoal] = useState<Goal | null>(null)
  const [selectedGoals, setSelectedGoals] = useState<Set<string>>(new Set())
  const [transferDialog, setTransferDialog] = useState<{ open: boolean; goalId: string; goalName: string }>({
    open: false,
    goalId: "",
    goalName: "",
  })
  const [transferAmount, setTransferAmount] = useState("")
  const [investmentDialog, setInvestmentDialog] = useState<{ open: boolean; goalId: string; goalName: string }>({
    open: false,
    goalId: "",
    goalName: "",
  })
  const [investmentAmount, setInvestmentAmount] = useState("")
  const [investmentMarket, setInvestmentMarket] = useState<"nepal" | "uk" | "split">("split")
  const [investmentNotes, setInvestmentNotes] = useState("")

  const [searchQuery, setSearchQuery] = useState("")
  const [filterType, setFilterType] = useState<FilterType>("all")
  const [sortType, setSortType] = useState<SortType>("progress")
  const [expandedGoals, setExpandedGoals] = useState<Set<string>>(new Set())

  const filteredAndSortedGoals = useMemo(() => {

    const filtered = goals.filter((goal) => {
      const matchesSearch =
        goal.name?.toLowerCase()?.includes(searchQuery.toLowerCase()) ||
        (goal.category?.toLowerCase()?.includes(searchQuery.toLowerCase()) ?? false)

      const progress = getGoalEffectiveProgress(goal)
      const isCompleted = progress >= 100
      const isOverdue = new Date(goal.targetDate) < new Date() && !isCompleted


      switch (filterType) {
        case "active":
          return !isCompleted && !isOverdue && matchesSearch
        case "completed":
          return isCompleted && matchesSearch
        case "overdue":
          return isOverdue && matchesSearch
        default:
          return matchesSearch
      }
    })


    const sorted = filtered.sort((a, b) => {
      switch (sortType) {
        case "progress":
          const progressA = getGoalEffectiveProgress(a)
          const progressB = getGoalEffectiveProgress(b)
          return progressB - progressA
        case "target-date":
          return new Date(a.targetDate).getTime() - new Date(b.targetDate).getTime()
        case "amount":
          return b.targetAmount - a.targetAmount
        case "name":
          const aName = a.title || a.name || ""
          const bName = b.title || b.name || ""
          return aName.localeCompare(bName)
        default:
          return 0
      }
    })
    return sorted
  }, [goals, searchQuery, filterType, sortType])

  const handleEditGoal = (goal: Goal) => {
    setEditingGoal(goal)
    setIsDialogOpen(true)
  }

  const handleDeleteGoal = (goalId: string) => {
    if (confirm("Are you sure you want to delete this goal? This action cannot be undone.")) {
      deleteGoal(goalId)
      const newSelected = new Set(selectedGoals)
      newSelected.delete(goalId)
      setSelectedGoals(newSelected)
    }
  }

  const handleBulkDelete = () => {
    if (selectedGoals.size === 0) return

    const count = selectedGoals.size
    if (
      confirm(`Are you sure you want to delete ${count} goal${count > 1 ? "s" : ""}? This action cannot be undone.`)
    ) {
      selectedGoals.forEach((goalId) => deleteGoal(goalId))
      setSelectedGoals(new Set())
    }
  }

  const handleSelectGoal = (goalId: string, checked: boolean) => {
    const newSelected = new Set(selectedGoals)
    if (checked) {
      newSelected.add(goalId)
    } else {
      newSelected.delete(goalId)
    }
    setSelectedGoals(newSelected)
  }

  const handleSelectAll = (checked: boolean) => {
    if (checked) {
      setSelectedGoals(new Set(filteredAndSortedGoals.map((goal) => goal.id)))
    } else {
      setSelectedGoals(new Set())
    }
  }

  const formatTimeEquivalent = (amount: number) => {
    const { getTimeEquivalentBreakdown } = require("@/lib/wallet-utils")
    const breakdown = getTimeEquivalentBreakdown(amount, userProfile)
    return breakdown ? breakdown.formatted.userFriendly : "0m"
  }

  const handleTransfer = async () => {
    const amount = Number.parseFloat(transferAmount)
    if (amount <= 0 || amount > balance) return

    try {
      const result = await transferToGoal(transferDialog.goalId, amount)
      if (result && result.success) {
        setTransferDialog({ open: false, goalId: "", goalName: "" })
        setTransferAmount("")
      } else {
        alert(result?.error || "Transfer failed")
      }
    } catch (error) {
      alert("Transfer failed: " + (error instanceof Error ? error.message : "Unknown error"))
    }
  }

  const handleInvestmentUse = async () => {
    const amount = Number.parseFloat(investmentAmount)
    if (amount <= 0) return

    try {
      const result = await useGoalForInvestment(investmentDialog.goalId, amount, {
        market: investmentMarket,
        notes: investmentNotes.trim() || undefined,
      })
      if (result?.success) {
        setInvestmentDialog({ open: false, goalId: "", goalName: "" })
        setInvestmentAmount("")
        setInvestmentMarket("split")
        setInvestmentNotes("")
      } else {
        alert(result?.error || "Investment action failed")
      }
    } catch (error) {
      alert("Investment action failed: " + (error instanceof Error ? error.message : "Unknown error"))
    }
  }

  const toggleGoalExpansion = (goalId: string) => {
    const newExpanded = new Set(expandedGoals)
    if (newExpanded.has(goalId)) {
      newExpanded.delete(goalId)
    } else {
      newExpanded.add(goalId)
    }
    setExpandedGoals(newExpanded)
  }

  const getGoalStatus = (goal: Goal) => {
    const progress = getGoalEffectiveProgress(goal)
    const isCompleted = progress >= 100
    const isOverdue = new Date(goal.targetDate) < new Date() && !isCompleted

    if (isCompleted) return { status: "completed", color: "bg-primary", icon: CheckCircle2 }
    if (isOverdue) return { status: "overdue", color: "bg-red-600", icon: AlertCircle }
    if (progress > 75) return { status: "near-completion", color: "bg-amber-600", icon: TrendingUp }
    return { status: "active", color: "bg-blue-600", icon: Target }
  }

  const getCategoryIcon = (category?: string) => {
    switch (category) {
      case "emergency": return AlertTriangle
      case "savings": return PiggyBank
      case "house": return Home
      case "car": return Car
      case "education": return GraduationCap
      case "health": return Heart
      case "travel": return Plane
      case "shopping": return ShoppingBag
      case "business": return Briefcase
      default: return Target
    }
  }

  const getPriorityColor = (priority?: string) => {
    switch (priority) {
      case "high": return "text-red-600 bg-red-50 border-red-200"
      case "medium": return "text-amber-600 bg-amber-50 border-amber-200"
      case "low": return "text-blue-600 bg-blue-50 border-blue-200"
      default: return "text-gray-600 bg-gray-50 border-gray-200"
    }
  }

  const getProgressColor = (progress: number) => {
    if (progress >= 100) return "bg-emerald-500"
    if (progress >= 75) return "bg-blue-500"
    if (progress >= 50) return "bg-amber-500"
    if (progress >= 25) return "bg-orange-500"
    return "bg-red-500"
  }

  return (
    <div className="space-y-4">
      <Tabs defaultValue="goals" className="w-full">
        <TabsList className="grid w-full grid-cols-3">
          <TabsTrigger value="goals">Goals</TabsTrigger>
          <TabsTrigger value="progress">Progress</TabsTrigger>
          <TabsTrigger value="planning">Planning</TabsTrigger>
        </TabsList>

        <TabsContent value="goals" className="space-y-6 mt-6">
          <div className="flex items-center justify-between">
            <h3 className="text-lg font-semibold flex items-center gap-2">
              <Target className="w-5 h-5" />
              Financial Goals ({filteredAndSortedGoals.length})
            </h3>
            <div className="flex items-center gap-2">
              {selectedGoals.size > 0 && (
                <Button variant="destructive" size="sm" onClick={handleBulkDelete} className="flex items-center gap-2">
                  <Trash2 className="w-4 h-4" />
                  Delete ({selectedGoals.size})
                </Button>
              )}
              <Button
                onClick={() => {
                  setEditingGoal(null)
                  setIsDialogOpen(true)
                }}
                className="flex items-center gap-2"
              >
                <Plus className="w-4 h-4" />
                Add Goal
              </Button>
            </div>
          </div>

          {goals.length > 0 && (
            <>
              <div className="flex flex-col sm:flex-row gap-3">
                <div className="relative flex-1">
                  <Search className="absolute left-3 top-1/2 transform -translate-y-1/2 text-muted-foreground w-4 h-4" />
                  <Input
                    placeholder="Search goals..."
                    value={searchQuery}
                    onChange={(e) => setSearchQuery(e.target.value)}
                    className="pl-10"
                  />
                </div>

                <div className="flex gap-2">
                  <Select value={filterType} onValueChange={(value: FilterType) => setFilterType(value)}>
                    <SelectTrigger className="w-32">
                      <Filter className="w-4 h-4 mr-2" />
                      <SelectValue />
                    </SelectTrigger>
                    <SelectContent>
                      <SelectItem value="all">All Goals</SelectItem>
                      <SelectItem value="active">Active</SelectItem>
                      <SelectItem value="completed">Completed</SelectItem>
                      <SelectItem value="overdue">Overdue</SelectItem>
                    </SelectContent>
                  </Select>

                  <Select value={sortType} onValueChange={(value: SortType) => setSortType(value)}>
                    <SelectTrigger className="w-36">
                      <SelectValue />
                    </SelectTrigger>
                    <SelectContent>
                      <SelectItem value="progress">By Progress</SelectItem>
                      <SelectItem value="target-date">By Date</SelectItem>
                      <SelectItem value="amount">By Amount</SelectItem>
                      <SelectItem value="name">By Name</SelectItem>
                    </SelectContent>
                  </Select>
                </div>
              </div>

              {filteredAndSortedGoals.length > 0 && (
                <div className="flex items-center gap-2 p-2 bg-muted/30 rounded-lg">
                  <Checkbox checked={selectedGoals.size === filteredAndSortedGoals.length} onCheckedChange={handleSelectAll} />
                  <span className="text-sm text-muted-foreground">
                    {selectedGoals.size === 0
                      ? "Select all goals"
                      : `${selectedGoals.size} of ${filteredAndSortedGoals.length} goals selected`}
                  </span>
                </div>
              )}
            </>
          )}

          {filteredAndSortedGoals.length === 0 ? (
            <Card>
              <CardContent className="text-center py-12">
                <Target className="w-12 h-12 text-muted-foreground mx-auto mb-4" />
                <h3 className="text-lg font-semibold mb-2">{goals.length === 0 ? "No Goals Yet" : "No Goals Found"}</h3>
                <p className="text-muted-foreground mb-4">
                  {goals.length === 0
                    ? "Set financial goals to track your progress and stay motivated!"
                    : "Try adjusting your search or filter criteria."}
                </p>
                {goals.length === 0 && <Button onClick={() => setIsDialogOpen(true)}>Create Your First Goal</Button>}
              </CardContent>
            </Card>
          ) : (
            <div className="grid gap-4 md:gap-6">
              {filteredAndSortedGoals.map((goal) => {
                const challengeSummary = getGoalChallengeSummary(goal)
                const effectiveTargetAmount = getGoalEffectiveTargetAmount(goal)
                const progress = getGoalEffectiveProgress(goal)
                const remaining = getGoalEffectiveRemainingAmount(goal)
                const isCompleted = progress >= 100
                const isExpanded = expandedGoals.has(goal.id)
                const goalStatus = getGoalStatus(goal)
                const StatusIcon = goalStatus.icon
                const CategoryIcon = getCategoryIcon(goal.category)
                const isSelected = selectedGoals.has(goal.id)
                const activeDeadline = challengeSummary?.currentDeadline || new Date(goal.targetDate)
                const daysRemaining = Math.max(0, Math.ceil((new Date(activeDeadline).getTime() - new Date().getTime()) / (1000 * 60 * 60 * 24)))

                return (
                  <Card
                    key={goal.id}
                    className={`relative overflow-hidden transition-all duration-300 hover:shadow-lg ${isCompleted
                      ? "border-emerald-200 bg-gradient-to-r from-emerald-50/50 to-blue-50/50 dark:from-emerald-950/20 dark:to-blue-950/20"
                      : isSelected
                        ? "ring-2 ring-blue-500 shadow-md"
                        : "hover:border-primary/30"
                      }`}
                  >
                    {/* Priority indicator stripe */}
                    {goal.priority && (
                      <div className={`absolute top-0 left-0 w-1 h-full ${getPriorityColor(goal.priority).split(' ')[0].replace('text-', 'bg-')}`} />
                    )}

                    <Collapsible open={isExpanded} onOpenChange={() => toggleGoalExpansion(goal.id)}>
                      <CollapsibleTrigger asChild>
                        <CardHeader className="pb-2 md:pb-4 cursor-pointer hover:bg-muted/30 transition-colors">
                          <div className="flex flex-col md:flex-row md:items-start md:justify-between gap-2 md:gap-0">
                            <div className="flex items-start gap-2 md:gap-4 flex-1">
                              <Checkbox
                                checked={isSelected}
                                onCheckedChange={(checked) => handleSelectGoal(goal.id, checked as boolean)}
                                onClick={(e) => e.stopPropagation()}
                                className="mt-1"
                              />

                              <div className="flex items-center gap-2 md:gap-3 flex-1">
                                <div className={`p-1 md:p-2 rounded-lg ${isCompleted ? 'bg-emerald-100 text-emerald-600' : 'bg-muted'}`}>
                                  <CategoryIcon className="w-4 h-4 md:w-5 md:h-5" />
                                </div>

                                <div className="flex-1 min-w-0">
                                  <div className="flex items-center gap-2 mb-1">
                                    <CardTitle className="text-base md:text-lg truncate">
                                      {goal.title || goal.name}
                                    </CardTitle>
                                    {goal.priority && (
                                      <Badge variant="outline" className={`text-xs ${getPriorityColor(goal.priority)}`}>
                                        {goal.priority.toUpperCase()}
                                      </Badge>
                                    )}
                                  </div>

                                  <div className="flex items-center gap-2 md:gap-4 text-xs md:text-sm text-muted-foreground">
                                    <div className="flex items-center gap-1">
                                      <StatusIcon className="w-3 h-3 md:w-4 md:h-4" />
                                      <span className="font-medium">{progress.toFixed(1)}% complete</span>
                                    </div>
                                    <div className="flex items-center gap-1">
                                      <Calendar className="w-3 h-3 md:w-4 md:h-4" />
                                      <span>{daysRemaining} days left</span>
                                    </div>
                                  </div>
                                </div>
                              </div>
                            </div>

                            <div className="flex items-center justify-between md:justify-end gap-2 md:gap-3">
                              <div className="text-left md:text-right flex-1 md:flex-none">
                                <p className="text-xs text-muted-foreground">Target</p>
                                <p className="font-bold text-base md:text-lg">
                                  {formatCurrency(effectiveTargetAmount, userProfile.currency, userProfile.customCurrency)}
                                </p>
                                <p className="text-xs text-muted-foreground">
                                  {formatCurrency(goal.currentAmount, userProfile.currency, userProfile.customCurrency)} saved
                                </p>
                              </div>

                              <DropdownMenu>
                                <DropdownMenuTrigger asChild onClick={(e) => e.stopPropagation()}>
                                  <Button variant="ghost" size="sm" className="h-8 w-8 p-0 hover:bg-muted">
                                    <MoreHorizontal className="w-4 h-4" />
                                  </Button>
                                </DropdownMenuTrigger>
                                <DropdownMenuContent align="end" className="w-48">
                                  <DropdownMenuItem onClick={() => handleEditGoal(goal)} className="cursor-pointer">
                                    <Edit className="w-4 h-4 mr-2" />
                                    Edit Goal
                                  </DropdownMenuItem>
                                  {!isCompleted && (
                                    <DropdownMenuItem
                                      onClick={() => setTransferDialog({ open: true, goalId: goal.id, goalName: goal.title || goal.name || "" })}
                                      className="cursor-pointer"
                                    >
                                      <Send className="w-4 h-4 mr-2" />
                                      Add Money
                                    </DropdownMenuItem>
                                  )}
                                  <DropdownMenuItem
                                    onClick={() => handleDeleteGoal(goal.id)}
                                    className="text-red-600 focus:text-red-600 cursor-pointer"
                                  >
                                    <Trash2 className="w-4 h-4 mr-2" />
                                    Delete Goal
                                  </DropdownMenuItem>
                                </DropdownMenuContent>
                              </DropdownMenu>

                              <ChevronDown className={`w-4 h-4 md:w-5 md:h-5 transition-transform duration-200 ${isExpanded ? "rotate-180" : ""}`} />
                            </div>
                          </div>

                          {/* Enhanced Progress Bar */}
                          <div className="mt-2 md:mt-4 ml-8 md:ml-12">
                            <div className="flex items-center justify-between mb-2">
                              <div className="flex items-center gap-2">
                                <div className={`w-3 h-3 rounded-full ${getProgressColor(progress)}`} />
                                <span className="text-xs md:text-sm font-medium">
                                  {isCompleted ? "Goal Achieved! 🎉" : `${formatCurrency(remaining, userProfile.currency, userProfile.customCurrency)} remaining`}
                                </span>
                              </div>
                              <span className="text-xs md:text-sm text-muted-foreground">
                                {progress.toFixed(1)}%
                              </span>
                            </div>
                            <div className="relative">
                              <Progress value={Math.min(progress, 100)} className="h-2" />
                              {progress > 100 && (
                                <div className="absolute top-0 left-0 w-full h-2 bg-emerald-500 rounded-full opacity-75" />
                              )}
                            </div>
                          </div>
                        </CardHeader>
                      </CollapsibleTrigger>

                      <CollapsibleContent>
                        <CardContent className="space-y-4 md:space-y-6">
                          {/* Goal Overview */}
                          <div className="grid grid-cols-2 md:grid-cols-2 gap-2 md:gap-4">
                            <div className="text-center p-2 md:p-4 bg-blue-50 dark:bg-blue-950/20 rounded-lg border">
                              <div className="flex items-center justify-center mb-1 md:mb-2">
                                <div className="p-1 md:p-2 bg-blue-100 dark:bg-blue-900/30 rounded-full">
                                  <Target className="w-4 h-4 md:w-5 md:h-5 text-blue-600" />
                                </div>
                              </div>
                              <p className="text-xs md:text-sm text-muted-foreground mb-1">Current Progress</p>
                              <p className="text-lg md:text-xl font-bold text-blue-600">{progress.toFixed(1)}%</p>
                            </div>

                            <div className="text-center p-2 md:p-4 bg-green-50 dark:bg-green-950/20 rounded-lg border">
                              <div className="flex items-center justify-center mb-1 md:mb-2">
                                <div className="p-1 md:p-2 bg-green-100 dark:bg-green-900/30 rounded-full">
                                  <TrendingUp className="w-4 h-4 md:w-5 md:h-5 text-green-600" />
                                </div>
                              </div>
                              <p className="text-xs md:text-sm text-muted-foreground mb-1">Amount Saved</p>
                              <p className="text-lg md:text-xl font-bold text-green-600">
                                {formatCurrency(goal.currentAmount, userProfile.currency, userProfile.customCurrency)}
                              </p>
                            </div>


                          </div>

                          {challengeSummary && (
                            <div className="grid grid-cols-1 md:grid-cols-3 gap-2 md:gap-4">
                              <div className="rounded-lg border bg-muted/20 p-3">
                                <p className="text-xs text-muted-foreground">Challenge mode</p>
                                <p className="mt-1 text-sm font-semibold capitalize">{challengeSummary.plan.mode}</p>
                              </div>
                              <div className="rounded-lg border bg-muted/20 p-3">
                                <p className="text-xs text-muted-foreground">Penalty status</p>
                                <p className="mt-1 text-sm font-semibold">
                                  {challengeSummary.penaltiesApplied > 0
                                    ? `${challengeSummary.penaltiesApplied} active`
                                    : "No penalty yet"}
                                </p>
                              </div>
                              <div className="rounded-lg border bg-muted/20 p-3">
                                <p className="text-xs text-muted-foreground">Investment split</p>
                                <p className="mt-1 text-sm font-semibold">
                                  {challengeSummary.utilization.nepalPercent}% NEP / {challengeSummary.utilization.ukPercent}% UK
                                </p>
                              </div>
                            </div>
                          )}

                          {challengeSummary && (
                            <div className="grid grid-cols-1 md:grid-cols-2 gap-2 md:gap-4">
                              <div className="rounded-lg border bg-blue-50 dark:bg-blue-950/20 p-3">
                                <p className="text-xs text-muted-foreground">Challenge points</p>
                                <p className="mt-1 text-lg font-bold text-blue-600">{challengeSummary.points.total}</p>
                                <p className="mt-1 text-xs text-muted-foreground">
                                  Hard mode investment rewards are saved here.
                                </p>
                              </div>
                              <div className="rounded-lg border bg-muted/20 p-3">
                                <p className="text-xs text-muted-foreground">Penalty total added</p>
                                <p className="mt-1 text-lg font-bold">
                                  {formatCurrency(challengeSummary.penaltyTotal, userProfile.currency, userProfile.customCurrency)}
                                </p>
                                <p className="mt-1 text-xs text-muted-foreground">
                                  Based on missed deadlines and one-month grace cycles.
                                </p>
                              </div>
                            </div>
                          )}

                          {/* Goal Insights */}
                          {!isCompleted && (
                            <div className="p-2 md:p-4 bg-gradient-to-r from-amber-50 to-orange-50 dark:from-amber-950/20 dark:to-orange-950/20 border border-amber-200 dark:border-amber-800 rounded-lg">
                              <div className="flex items-center gap-2 mb-2 md:mb-3">
                                <Zap className="w-3 h-3 md:w-4 md:h-4 text-amber-600" />
                                <h4 className="font-semibold text-sm md:text-base text-amber-700 dark:text-amber-300">Goal Insights</h4>
                              </div>
                              <div className="grid grid-cols-1 md:grid-cols-2 gap-2 md:gap-4 text-xs md:text-sm">
                                <div>
                                  <p className="text-amber-700 dark:text-amber-300 mb-1">💰 Amount Still Needed</p>
                                  <p className="font-semibold text-amber-800 dark:text-amber-200">
                                    {formatCurrency(remaining, userProfile.currency, userProfile.customCurrency)}
                                  </p>
                                </div>
                                <div>
                                  <p className="text-amber-700 dark:text-amber-300 mb-1">⏰ Time Equivalent</p>
                                  <p className="font-semibold text-amber-800 dark:text-amber-200">
                                    {formatTimeEquivalent(remaining)}
                                  </p>
                                </div>
                                <div>
                                  <p className="text-amber-700 dark:text-amber-300 mb-1">Target Date</p>
                                  <p className="text-amber-700 dark:text-amber-300 mb-1">
                                    {new Date(activeDeadline).toLocaleDateString()}
                                  </p>
                                </div>
                                <div>
                                  <p className="text-amber-700 dark:text-amber-300 mb-1">📅 Days Remaining</p>
                                  <p className="font-semibold text-amber-800 dark:text-amber-200">{daysRemaining} days</p>
                                </div>
                              </div>
                              <div className="mt-2 md:mt-3 p-1 md:p-2 bg-amber-100 dark:bg-amber-900/30 rounded text-xs md:text-sm">
                                <p className="text-amber-800 dark:text-amber-200">
                                  💡 <strong>Tip:</strong> Save {formatCurrency(remaining / Math.max(daysRemaining, 1), userProfile.currency, userProfile.customCurrency)} per day to reach your goal on time!
                                </p>
                              </div>
                              {challengeSummary && (
                                <div className="mt-2 md:mt-3 rounded bg-background/70 p-2 text-xs md:text-sm text-amber-900 dark:text-amber-100">
                                  <p>
                                    Penalty adds {formatCurrency(challengeSummary.plan.penaltyAmount, userProfile.currency, userProfile.customCurrency)}
                                    {" "}after each missed deadline, with {challengeSummary.plan.graceMonths} month grace.
                                  </p>
                                  <p className="mt-1">
                                    {challengeSummary.utilization.countsInvestmentAsExpense
                                      ? `Hard mode: investment usage reduces saved progress and earns ${challengeSummary.utilization.hardModeRewardPoints} points per use.`
                                      : "Easy mode: investment usage does not reduce saved progress."}
                                  </p>
                                </div>
                              )}
                            </div>
                          )}

                          {/* Goal Description */}
                          {goal.description && (
                            <div className="p-2 md:p-4 bg-muted/30 rounded-lg border">
                              <div className="flex items-center gap-2 mb-1 md:mb-2">
                                <AlertCircle className="w-3 h-3 md:w-4 md:h-4 text-muted-foreground" />
                                <h4 className="font-medium text-sm md:text-base text-muted-foreground">Goal Description</h4>
                              </div>
                              <p className="text-xs md:text-sm leading-relaxed">{goal.description}</p>
                            </div>
                          )}

                          {/* Action Buttons */}
                          {!isCompleted && (
                            <div className="flex flex-col sm:flex-row gap-2 md:gap-3">
                              <Button
                                onClick={() => setTransferDialog({ open: true, goalId: goal.id, goalName: goal.title || goal.name || "" })}
                                className="flex items-center gap-2 flex-1 text-sm md:text-base"
                                disabled={balance <= 0}
                              >
                                <Send className="w-3 h-3 md:w-4 md:h-4" />
                                Add Money to Goal
                                <Badge variant="secondary" className="ml-auto text-xs md:text-sm">
                                  {formatCurrency(balance, userProfile.currency, userProfile.customCurrency)} available
                                </Badge>
                              </Button>

                              {challengeSummary && (
                                <Button
                                  variant="secondary"
                                  onClick={() => {
                                    setInvestmentDialog({ open: true, goalId: goal.id, goalName: goal.title || goal.name || "" })
                                    setInvestmentAmount("")
                                    setInvestmentMarket("split")
                                    setInvestmentNotes("")
                                  }}
                                  className="flex items-center gap-2 text-sm md:text-base"
                                >
                                  <TrendingUp className="w-3 h-3 md:w-4 md:h-4" />
                                  Use for Investment
                                </Button>
                              )}

                              <Button
                                variant="outline"
                                onClick={() => handleEditGoal(goal)}
                                className="flex items-center gap-2 text-sm md:text-base"
                              >
                                <Edit className="w-3 h-3 md:w-4 md:h-4" />
                                Edit Goal
                              </Button>
                            </div>
                          )}

                          {challengeSummary && challengeSummary.penaltyHistory.length > 0 && (
                            <div className="p-2 md:p-4 bg-muted/30 rounded-lg border">
                              <div className="flex items-center gap-2 mb-2">
                                <Clock className="w-4 h-4 text-muted-foreground" />
                                <h4 className="font-medium text-sm md:text-base text-muted-foreground">Penalty History</h4>
                              </div>
                              <div className="space-y-2">
                                {challengeSummary.penaltyHistory.slice().reverse().map((snapshot) => (
                                  <div key={snapshot.id} className="rounded-md border bg-background/80 p-2 text-xs md:text-sm">
                                    <p className="font-medium">
                                      Cycle {snapshot.cycleNumber}: +{formatCurrency(snapshot.penaltyAmount, userProfile.currency, userProfile.customCurrency)}
                                    </p>
                                    <p className="mt-1 text-muted-foreground">
                                      Missed {new Date(snapshot.previousDeadline).toLocaleDateString()} and extended to {new Date(snapshot.newDeadline).toLocaleDateString()}.
                                    </p>
                                    <p className="text-muted-foreground">
                                      Target became {formatCurrency(snapshot.effectiveTargetAmount, userProfile.currency, userProfile.customCurrency)}.
                                    </p>
                                  </div>
                                ))}
                              </div>
                            </div>
                          )}

                          {challengeSummary && challengeSummary.points.history.length > 0 && (
                            <div className="p-2 md:p-4 bg-muted/30 rounded-lg border">
                              <div className="flex items-center gap-2 mb-2">
                                <Sparkles className="w-4 h-4 text-muted-foreground" />
                                <h4 className="font-medium text-sm md:text-base text-muted-foreground">Challenge Points History</h4>
                              </div>
                              <div className="space-y-2">
                                {challengeSummary.points.history.slice().reverse().map((entry) => (
                                  <div key={entry.id} className="rounded-md border bg-background/80 p-2 text-xs md:text-sm">
                                    <p className="font-medium">+{entry.points} points</p>
                                    <p className="mt-1 text-muted-foreground">
                                      {new Date(entry.awardedAt).toLocaleDateString()} {entry.description ? `• ${entry.description}` : ""}
                                    </p>
                                  </div>
                                ))}
                              </div>
                            </div>
                          )}

                          {/* Goal Metadata */}
                          <div className="flex flex-wrap items-center gap-1 md:gap-2 pt-2 border-t">
                            {goal.category && (
                              <Badge variant="outline" className="flex items-center gap-1 text-xs md:text-sm">
                                <CategoryIcon className="w-3 h-3" />
                                {goal.category.charAt(0).toUpperCase() + goal.category.slice(1)}
                              </Badge>
                            )}
                            {goal.priority && (
                              <Badge className={`${getPriorityColor(goal.priority)} text-xs md:text-sm`}>
                                {goal.priority.toUpperCase()} Priority
                              </Badge>
                            )}
                            <Badge variant="secondary" className="text-xs md:text-sm">
                              Created {new Date(goal.createdAt).toLocaleDateString()}
                            </Badge>
                          </div>
                        </CardContent>
                      </CollapsibleContent>
                    </Collapsible>
                  </Card>
                )
              })}
            </div>
          )}
        </TabsContent>

        <TabsContent value="progress" className="space-y-4 mt-6">
          <GoalProgressVisualization goals={goals} userProfile={userProfile} />
        </TabsContent>

        <TabsContent value="planning" className="space-y-4 mt-6">
          <ScenarioPlanningCalculator
            goals={goals}
            userProfile={userProfile}
            currentBalance={balance}
            monthlyIncome={userProfile.monthlyEarning}
          />
        </TabsContent>
      </Tabs>

      {/* Dialogs outside of tabs */}
      <GoalDialog
        isOpen={isDialogOpen}
        onClose={() => {
          setIsDialogOpen(false)
          setEditingGoal(null)
        }}
        userProfile={userProfile}
        editingGoal={editingGoal}
      />

      <Dialog open={transferDialog.open} onOpenChange={(open) => setTransferDialog({ ...transferDialog, open })}>
        <DialogContent className="sm:max-w-md">
          <DialogHeader>
            <DialogTitle className="flex items-center gap-2">
              <Send className="w-5 h-5 text-primary" />
              Transfer to Goal
            </DialogTitle>
          </DialogHeader>

          <div className="space-y-3">
            <div className="p-3 bg-muted/50 rounded-lg">
              <p className="text-sm text-muted-foreground">Transferring to:</p>
              <p className="font-semibold">{transferDialog.goalName}</p>
            </div>

            {/* Transfer Amount */}
            <div className="space-y-2">
              <div className="flex items-center justify-between">
                <label className="text-sm font-medium">Transfer Amount</label>
                <span className="text-xs text-muted-foreground">
                  Available: {formatCurrency(balance, userProfile.currency, userProfile.customCurrency)}
                </span>
              </div>
              <div className="relative">
                <span className="absolute left-3 top-1/2 transform -translate-y-1/2 text-muted-foreground">
                  {getCurrencySymbol(userProfile.currency, (userProfile as any).customCurrency)}
                </span>
                <Input
                  type="number"
                  step="0.01"
                  min="0"
                  max={balance}
                  value={transferAmount}
                  onChange={(e) => setTransferAmount(e.target.value)}
                  placeholder="0.00"
                  className="pl-8"
                />
              </div>

              {/* Quick Amount Buttons */}
              <div className="flex gap-1">
                {[50, 100, 500, 1000].map((amount) => (
                  <Button
                    key={amount}
                    variant="outline"
                    size="sm"
                    onClick={() => setTransferAmount(amount.toString())}
                    disabled={amount > balance}
                    className="flex-1 text-xs"
                  >
                    {formatCurrency(amount, userProfile.currency, userProfile.customCurrency)}
                  </Button>
                ))}
              </div>
            </div>

            <div className="flex gap-2">
              <Button
                variant="outline"
                onClick={() => setTransferDialog({ open: false, goalId: "", goalName: "" })}
                className="flex-1"
              >
                Cancel
              </Button>
              <Button
                onClick={handleTransfer}
                disabled={
                  !transferAmount ||
                  Number.parseFloat(transferAmount) <= 0 ||
                  Number.parseFloat(transferAmount) > balance
                }
                className="flex-1"
              >
                <ArrowRight className="w-4 h-4 mr-2" />
                Transfer
              </Button>
            </div>
          </div>
        </DialogContent>
      </Dialog>

      <Dialog open={investmentDialog.open} onOpenChange={(open) => setInvestmentDialog({ ...investmentDialog, open })}>
        <DialogContent className="sm:max-w-md">
          <DialogHeader>
            <DialogTitle className="flex items-center gap-2">
              <TrendingUp className="w-5 h-5 text-primary" />
              Use for Investment
            </DialogTitle>
          </DialogHeader>

          <div className="space-y-3">
            <div className="p-3 bg-muted/50 rounded-lg">
              <p className="text-sm text-muted-foreground">Using goal fund:</p>
              <p className="font-semibold">{investmentDialog.goalName}</p>
            </div>

            <div className="space-y-2">
              <label className="text-sm font-medium">Investment amount</label>
              <div className="relative">
                <span className="absolute left-3 top-1/2 transform -translate-y-1/2 text-muted-foreground">
                  {getCurrencySymbol(userProfile.currency, (userProfile as any).customCurrency)}
                </span>
                <Input
                  type="number"
                  step="0.01"
                  min="0"
                  value={investmentAmount}
                  onChange={(e) => setInvestmentAmount(e.target.value)}
                  placeholder="0.00"
                  className="pl-8"
                />
              </div>
            </div>

            <div className="space-y-2">
              <label className="text-sm font-medium">Market allocation</label>
              <Select value={investmentMarket} onValueChange={(value: "nepal" | "uk" | "split") => setInvestmentMarket(value)}>
                <SelectTrigger>
                  <SelectValue />
                </SelectTrigger>
                <SelectContent>
                  <SelectItem value="split">50 / 50 Split</SelectItem>
                  <SelectItem value="nepal">Nepal Only</SelectItem>
                  <SelectItem value="uk">UK Only</SelectItem>
                </SelectContent>
              </Select>
            </div>

            <div className="space-y-2">
              <label className="text-sm font-medium">Notes</label>
              <Textarea
                value={investmentNotes}
                onChange={(e) => setInvestmentNotes(e.target.value)}
                placeholder="Optional note about this investment use"
                rows={3}
              />
            </div>

            <div className="rounded-lg border bg-primary/5 p-3 text-xs text-muted-foreground">
              Easy mode keeps goal savings unchanged. Hard mode reduces saved balance and awards challenge points automatically.
            </div>

            <div className="flex gap-2">
              <Button
                variant="outline"
                onClick={() => setInvestmentDialog({ open: false, goalId: "", goalName: "" })}
                className="flex-1"
              >
                Cancel
              </Button>
              <Button
                onClick={handleInvestmentUse}
                disabled={!investmentAmount || Number.parseFloat(investmentAmount) <= 0}
                className="flex-1"
              >
                <TrendingUp className="w-4 h-4 mr-2" />
                Confirm
              </Button>
            </div>
          </div>
        </DialogContent>
      </Dialog>
    </div>
  )
}

"use client"

import { useMemo } from "react"
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card"
import { Progress } from "@/components/ui/progress"
import { Badge } from "@/components/ui/badge"
import { Tooltip, TooltipContent, TooltipProvider, TooltipTrigger } from "@/components/ui/tooltip"
import { Award, TrendingUp, Target, Shield, Star, Trophy, AlertTriangle, CheckCircle, Sparkles, PlusCircle, HelpCircle, BarChart3 } from "lucide-react"
import { Accordion, AccordionContent, AccordionItem, AccordionTrigger } from "@/components/ui/accordion"
import type { Transaction, UserProfile, Budget, Goal, DebtAccount } from "@/types/wallet"
import { formatCurrency } from "@/lib/utils"
import { Button } from "../ui/button"

interface HealthMetric {
  id: string
  name: string
  score: number
  maxScore: number
  status: 'excellent' | 'good' | 'fair' | 'poor' | 'setup'
  description: string
  details: string
  actionTip: string
  icon: React.ReactNode
  isOptional?: boolean
  isSetupRequired?: boolean
}

export function useFinancialHealthScore(
  transactions: Transaction[],
  userProfile: UserProfile,
  budgets: Budget[],
  goals: Goal[],
  debtAccounts: DebtAccount[],
  balance: number = 0
) {
  const healthMetrics = useMemo(() => {
    // Basic Aggregates
    const now = new Date()
    const last30Days = transactions.filter(t => {
      const d = new Date(t.date)
      return (now.getTime() - d.getTime()) <= (30 * 24 * 60 * 60 * 1000)
    })

    const monthlyIncome = last30Days.filter(t => t.type === 'income').reduce((sum, t) => sum + t.amount, 0) || userProfile.monthlyEarning || 1
    const monthlyExpenses = last30Days.filter(t => t.type === 'expense').reduce((sum, t) => sum + t.amount, 0)

    // 50/30/20 Classification
    const needsCategories = ["Housing", "Bills & Utilities", "Transportation", "Healthcare", "Groceries", "Education", "Insurance"]
    const wantsCategories = ["Food & Dining", "Shopping", "Entertainment", "Travel", "Other"]

    const needsSpending = last30Days.filter(t => t.type === 'expense' && needsCategories.includes(t.category)).reduce((sum, t) => sum + t.amount, 0)
    const wantsSpending = last30Days.filter(t => t.type === 'expense' && wantsCategories.includes(t.category)).reduce((sum, t) => sum + t.amount, 0)
    const savingsAndDebt = Math.max(0, monthlyIncome - monthlyExpenses)

    const needsRatio = (needsSpending / monthlyIncome) * 100
    const wantsRatio = (wantsSpending / monthlyIncome) * 100
    const savingsRatio = (savingsAndDebt / monthlyIncome) * 100

    // 1. Metric: Survival Buffer (Liquidity)
    const emergencyGoals = goals.filter(g => {
      const searchStr = `${g.title || ""} ${g.name || ""} ${g.category || ""}`.toLowerCase()
      return searchStr.includes('emergency') ||
        searchStr.includes('emanergency') ||
        searchStr.includes('safety fund') ||
        searchStr.includes('safety') ||
        searchStr.includes('buffer')
    })
    const hasEmergencyGoal = emergencyGoals.length > 0

    // We count ALL goal savings + main balance as liquid assets for the buffer, 
    // but we still require an explicit 'Emergency' goal to be defined to satisfy the metric.
    const totalLiquidAssets = goals.reduce((sum, g) => sum + g.currentAmount, 0) + balance
    const monthsOfBuffer = needsSpending > 0
      ? totalLiquidAssets / needsSpending
      : (totalLiquidAssets / (monthlyIncome * 0.5))

    const survivalScore = hasEmergencyGoal ? Math.min(100, (monthsOfBuffer / 6) * 100) : 0

    // 2. Metric: 50/30/20 Hygiene
    // Add logic to penalize if there are very few transactions (lack of data)
    const categorizedTransactions = last30Days.filter(t => t.category && t.category !== 'Other').length
    const dataDensityScore = Math.min(100, (categorizedTransactions / 15) * 100) // Target 15+ categorized tx/month

    const needsScore = needsRatio <= 50 ? 100 : Math.max(0, 100 - (needsRatio - 50) * 4)
    const wantsScore = wantsRatio <= 30 ? 100 : Math.max(0, 100 - (wantsRatio - 30) * 4)
    const savingsGoalScore = savingsRatio >= 20 ? 100 : (savingsRatio / 20) * 100

    const allocationScore = (needsScore + wantsScore + savingsGoalScore) / 3
    // Weighted: 20% Data quality, 80% Allocation quality
    const ruleScore = (dataDensityScore * 0.2) + (allocationScore * 0.8)

    // 3. Metric: Debt Health
    const totalDebt = debtAccounts.reduce((sum, d) => sum + d.balance, 0)
    const annualIncome = monthlyIncome * 12
    const dtiRatio = annualIncome > 0 ? (totalDebt / annualIncome) * 100 : 0
    // Standard DTI Rating: < 20% is excellent, 20-36% is good, 36-43% is manageable, > 43% is critical
    let debtScore = 100
    if (totalDebt > 0) {
      if (dtiRatio <= 20) debtScore = 100
      else if (dtiRatio <= 36) debtScore = 80 + (1 - (dtiRatio - 20) / 16) * 10
      else if (dtiRatio <= 43) debtScore = 50 + (1 - (dtiRatio - 36) / 7) * 30
      else debtScore = Math.max(0, 50 - (dtiRatio - 43) * 2)
    }

    // 4. Metric: Budget Discipline
    const hasBudgets = budgets.length >= 3
    const overBudgetCount = budgets.filter(b => b.spent > b.limit).length
    const adherenceRate = budgets.length > 0 ? ((budgets.length - overBudgetCount) / budgets.length) : 0

    // Logic: 20pts for having 3+ budgets, 80pts for adherence
    const budgetBaseScore = hasBudgets ? 20 : (budgets.length / 3) * 20
    const budgetPerformanceScore = adherenceRate * 80
    const budgetScore = budgets.length > 0 ? budgetBaseScore + budgetPerformanceScore : 0

    // 5. Metric: Goal Momentum
    // Logic: 20pts for setup, 40pts for consistency (last 30d funding), 40pts for progress
    const hasGoals = goals.length > 0
    const goalBaseScore = hasGoals ? 20 : 0

    // Approximate funding activity from transaction descriptions or metadata
    const recentlyFundedGoalsCount = goals.filter(g => {
      const gTitle = (g.title || g.name || "").toLowerCase()
      return transactions.some(t => {
        const isRecent = (now.getTime() - new Date(t.date).getTime()) <= (30 * 24 * 60 * 60 * 1000)
        const isForGoal = t.allocationType === 'goal' && t.allocationTarget === g.id
        const matchesName = t.description.toLowerCase().includes(gTitle) && gTitle.length > 3
        return isRecent && (isForGoal || matchesName)
      })
    }).length

    const averageProgress = goals.length > 0
      ? goals.reduce((sum, g) => {
        const target = g.targetAmount || 1
        const current = g.currentAmount || 0
        return sum + Math.min(100, (current / target) * 100)
      }, 0) / goals.length
      : 0

    const goalConsistencyScore = goals.length > 0 ? (recentlyFundedGoalsCount / goals.length) * 40 : 0
    const goalProgressScore = (averageProgress / 100) * 40

    const goalScore = hasGoals ? goalBaseScore + goalConsistencyScore + goalProgressScore : 0

    const metrics: HealthMetric[] = [
      {
        id: "liquidity",
        name: "Emergency Fund",
        score: survivalScore,
        maxScore: 100,
        status: hasEmergencyGoal ? (survivalScore >= 80 ? 'excellent' : survivalScore >= 50 ? 'good' : survivalScore >= 20 ? 'fair' : 'poor') : 'setup',
        description: hasEmergencyGoal ? `${monthsOfBuffer.toFixed(1)} months of absolute needs covered` : "Safety net not established",
        details: "Checks your ability to survive a financial shock without income. We calculate this by comparing your liquid savings (Goals) against your essential monthly expenses (Housing, Utilities, Groceries, etc.).",
        actionTip: hasEmergencyGoal ? "Target 6 months of absolute needs. Keep this in a liquid, low-risk account." : "Establish an explicit 'Emergency Fund' goal to start tracking your safety net.",
        icon: <Shield className="w-4 h-4" />,
        isSetupRequired: !hasEmergencyGoal
      },
      {
        id: "hygiene",
        name: "50/30/20 Balance",
        score: ruleScore,
        maxScore: 100,
        status: ruleScore >= 85 ? 'excellent' : ruleScore >= 70 ? 'good' : ruleScore >= 50 ? 'fair' : 'poor',
        description: `Needs: ${needsRatio.toFixed(0)}%, Wants: ${wantsRatio.toFixed(0)}%, Save: ${savingsRatio.toFixed(0)}%`,
        details: "Evaluates your income allocation (80%) and data quality (20%). The score rewards categorizing at least 15 transactions monthly using the 50% Needs, 30% Wants, and 20% Savings framework.",
        actionTip: categorizedTransactions < 15 ? "Categorize at least 15 transactions this month to improve the accuracy of this score." : "If 'Needs' are over 50%, look for ways to reduce fixed costs like rent or utilities.",
        icon: <TrendingUp className="w-4 h-4" />
      },
      {
        id: "debt",
        name: "Debt Ceiling",
        score: debtScore,
        maxScore: 100,
        status: debtScore >= 90 ? 'excellent' : debtScore >= 70 ? 'good' : debtScore >= 40 ? 'fair' : 'poor',
        description: totalDebt > 0 ? `Debt is ${dtiRatio.toFixed(1)}% of annual income` : "Debt-free",
        details: "Measures your total debt relative to your annual income. A high ratio indicates that a large portion of your future earnings is already committed elsewhere.",
        actionTip: "Focus on high-interest debt first (the Avalanche method) to increase your score.",
        icon: <AlertTriangle className="w-4 h-4" />
      },
      {
        id: "budget",
        name: "Budget Integrity",
        score: budgetScore,
        maxScore: 100,
        status: budgets.length > 0 ? (budgetScore >= 90 ? 'excellent' : budgetScore >= 70 ? 'good' : budgetScore >= 50 ? 'fair' : 'poor') : 'setup',
        description: budgets.length > 0 ? `${overBudgetCount} budgets exceeded this period` : "No active budgets set",
        details: "Analyzes how well you stick to your limits. Score is based on having at least 3 active categories (20%) and staying within those limits (80%).",
        actionTip: budgets.length >= 3 ? (overBudgetCount > 0 ? "Review your over-budget categories. Are the limits too low, or is the spending too high?" : "Perfect discipline! Consider lowering your limits to save even more.") : "Create at least 3 budget categories to fully track your financial discipline.",
        icon: <Target className="w-4 h-4" />,
        isSetupRequired: budgets.length === 0
      },
      {
        id: "momentum",
        name: "Goal Momentum",
        score: goalScore,
        maxScore: 100,
        status: goals.length > 0 ? (goalScore >= 90 ? 'excellent' : goalScore >= 70 ? 'good' : goalScore >= 40 ? 'fair' : 'poor') : 'setup',
        description: goals.length > 0 ? `${(averageProgress).toFixed(0)}% average progress across ${goals.length} goals` : "No financial goals established",
        details: "Measures progress toward your dreams. Score factors in setup (20%), consistent monthly funding (40%), and overall target completion (40%).",
        actionTip: recentlyFundedGoalsCount < goals.length ? "You have stagnant goals. Try to contribute something every month to keep the momentum alive." : "Great job! You are consistently funding all your goals.",
        icon: <Trophy className="w-4 h-4" />,
        isSetupRequired: goals.length === 0
      }
    ]

    return metrics
  }, [transactions, userProfile, budgets, goals, debtAccounts])

  const overallScore = useMemo(() => {
    const totalScore = healthMetrics.reduce((sum, metric) => sum + metric.score, 0)
    const averageScore = totalScore / healthMetrics.length

    let grade: string
    let description: string
    let color: string
    let icon: React.ReactNode

    if (averageScore >= 90) {
      grade = "A+"
      description = "Peak Financial Performance"
      color = "text-emerald-600 bg-emerald-50 border-emerald-200"
      icon = <Trophy className="w-6 h-6" />
    } else if (averageScore >= 80) {
      grade = "A"
      description = "Solid Financial Foundation"
      color = "text-emerald-600 bg-emerald-50 border-emerald-200"
      icon = <Award className="w-6 h-6" />
    } else if (averageScore >= 70) {
      grade = "B"
      description = "Health Stability - Minor Gaps"
      color = "text-blue-600 bg-blue-50 border-blue-200"
      icon = <Star className="w-6 h-6" />
    } else if (averageScore >= 55) {
      grade = "C"
      description = "Average - Vulnerable to Shocks"
      color = "text-amber-600 bg-amber-50 border-amber-200"
      icon = <Target className="w-6 h-6" />
    } else {
      grade = "D"
      description = "Critical - Needs Restructuring"
      color = "text-red-600 bg-red-50 border-red-200"
      icon = <AlertTriangle className="w-6 h-6" />
    }

    return { score: averageScore, grade, description, color, icon }
  }, [healthMetrics])

  const getStatusColor = (status: HealthMetric['status']) => {
    switch (status) {
      case 'excellent': return 'text-emerald-600 bg-emerald-50 border-emerald-200'
      case 'good': return 'text-blue-600 bg-blue-50 border-blue-200'
      case 'fair': return 'text-amber-600 bg-amber-50 border-amber-200'
      case 'poor': return 'text-red-600 bg-red-50 border-red-200'
      case 'setup': return 'text-slate-500 bg-slate-50 border-slate-200'
    }
  }

  const getStatusIcon = (status: HealthMetric['status']) => {
    switch (status) {
      case 'excellent': return <Trophy className="w-4 h-4" />
      case 'good': return <Star className="w-4 h-4" />
      case 'fair': return <Target className="w-4 h-4" />
      case 'poor': return <AlertTriangle className="w-4 h-4" />
      case 'setup': return <PlusCircle className="w-4 h-4" />
    }
  }

  return { healthMetrics, overallScore, getStatusColor, getStatusIcon }
}

interface FinancialHealthScoreProps {
  transactions: Transaction[]
  userProfile: UserProfile
  budgets: Budget[]
  goals: Goal[]
  debtAccounts: DebtAccount[]
  balance: number
  compact?: boolean
  onNavigate?: (tab: string) => void
}

export function FinancialHealthScore({
  transactions,
  userProfile,
  budgets,
  goals,
  debtAccounts,
  balance,
  compact = false,
  onNavigate
}: FinancialHealthScoreProps) {
  const { healthMetrics, overallScore, getStatusColor, getStatusIcon } = useFinancialHealthScore(
    transactions,
    userProfile,
    budgets,
    goals,
    debtAccounts,
    balance
  )

  const content = (
    <div className="space-y-6">
      {/* Overall Score */}
      <div className="text-center p-5 bg-gradient-to-r from-blue-50 to-purple-50 dark:from-blue-950/20 dark:to-purple-950/20 border border-blue-200 dark:border-blue-800 rounded-lg">
        <div className="flex items-center justify-center mb-3">
          <div className={`p-3 rounded-full ${overallScore.color.split(' ')[1]} border ${overallScore.color.split(' ')[2]}`}>
            {overallScore.icon}
          </div>
        </div>
        <div className="text-4xl font-bold text-primary mb-2">{overallScore.score.toFixed(0)}</div>
        <div className="text-2xl font-semibold mb-2">{overallScore.grade}</div>
        <p className="text-muted-foreground mb-4">{overallScore.description}</p>

        {/* Achievement Badges */}
        <TooltipProvider>
          <div className="flex justify-center gap-2 flex-wrap">
            {healthMetrics
              .filter(metric => metric.status === 'excellent')
              .map((metric) => (
                <Tooltip key={metric.name}>
                  <TooltipTrigger asChild>
                    <div className="p-2 bg-emerald-100 dark:bg-emerald-900/30 rounded-full cursor-help hover:bg-emerald-200 dark:hover:bg-emerald-900/50 transition-colors">
                      {getStatusIcon(metric.status)}
                    </div>
                  </TooltipTrigger>
                  <TooltipContent>
                    <p className="font-medium">{metric.name}</p>
                    <p className="text-sm text-muted-foreground capitalize">{metric.status}</p>
                  </TooltipContent>
                </Tooltip>
              ))}
          </div>
        </TooltipProvider>
      </div>
      {/* Smart Recommendations: Finding the Lowest Metric */}
      <div className="p-4 bg-muted/30 border-dashed border-2 rounded-2xl">
        <h4 className="font-bold flex items-center gap-2 mb-3">
          <Sparkles className="w-4 h-4 text-primary" />
          Personalized Action Plan
        </h4>
        <div className="space-y-4">
          {healthMetrics
            .sort((a, b) => a.score - b.score)
            .slice(0, 2)
            .map((metric) => (
              <div key={metric.name} className="flex gap-3">
                <div className="mt-1">{getStatusIcon(metric.status)}</div>
                <div className="space-y-1">
                  <p className="text-sm font-bold">Focus: {metric.name}</p>
                  <p className="text-xs text-muted-foreground leading-relaxed">
                    {metric.name === "Emergency Fund" && metric.score < 80 ? "Your safety net is thin. Try to set aside 10% of every paycheck into your emergency goal until you have 6 months of expenses covered." : ""}
                    {metric.name === "50/30/20 Balance" && metric.score < 80 ? "Your ratios are off. Review your 'Wants' categories and try to redirect that spending toward debt or savings." : ""}
                    {metric.name === "Debt Ceiling" && metric.score < 70 ? "Your debt load is relatively high. Look into a 'Debt Snowball' or 'Avalanche' method to speed up repayment." : ""}
                    {metric.name === "Budget Integrity" && metric.score < 70 ? "Multiple budgets are bleeding over. Set up push notifications for category limits and check them before every purchase." : ""}
                    {metric.name === "Goal Momentum" && metric.score < 70 ? "Some goals are stagnant. It's better to fund one goal perfectly than five goals poorly. Consolidate your efforts." : ""}
                    {metric.score >= 80 ? "You're excelling here! Maintain this discipline to reach financial independence faster." : ""}
                  </p>
                </div>
              </div>
            ))}
        </div>
      </div>

      {/* Health Metrics Breakdown with Accordion */}
      <div className="space-y-4">
        <h4 className="font-bold flex items-center gap-2 text-sm">
          <BarChart3 className="w-4 h-4 text-primary" />
          Heuristic Breakdown
        </h4>

        <Accordion type="single" collapsible className="space-y-3">
          {healthMetrics.map((metric) => (
            <AccordionItem key={metric.id} value={metric.id} className="border border-border/50 rounded-2xl px-4 overflow-hidden bg-card/50">
              <AccordionTrigger className="hover:no-underline py-4">
                <div className="flex items-center justify-between w-full pr-4 text-left">
                  <div className="flex items-center gap-3">
                    <div className={`p-2 rounded-xl border ${getStatusColor(metric.status)}`}>
                      {getStatusIcon(metric.status)}
                    </div>
                    <div>
                      <h5 className="font-bold text-sm leading-none mb-1">{metric.name}</h5>
                      <p className="text-[10px] text-muted-foreground uppercase font-black">{metric.isSetupRequired ? 'Action Required' : metric.status}</p>
                    </div>
                  </div>
                  <div className="flex flex-col items-end gap-1">
                    <span className="text-lg font-black font-mono leading-none">
                      {metric.isSetupRequired ? "--" : metric.score.toFixed(0)}
                    </span>
                    {!metric.isSetupRequired && <Progress value={metric.score} className="w-16 h-1 mt-1" />}
                  </div>
                </div>
              </AccordionTrigger>
              <AccordionContent className="pb-4 pt-2 border-t border-dashed">
                <div className="space-y-4">
                  <div className="bg-muted/30 p-3 rounded-xl border border-border/50">
                    <p className="text-xs leading-relaxed font-medium">
                      <HelpCircle className="w-3 h-3 inline mr-1 text-primary" />
                      {metric.details}
                    </p>
                  </div>

                  <div className="flex items-start gap-2 text-sm">
                    <div className="p-1.5 bg-primary/10 rounded-lg shrink-0 mt-0.5">
                      <Sparkles className="w-3 h-3 text-primary" />
                    </div>
                    <div>
                      <p className="font-bold text-xs uppercase tracking-tight text-primary">Pro Tip</p>
                      <p className="text-xs text-muted-foreground leading-snug">{metric.actionTip}</p>
                      {metric.isSetupRequired && onNavigate && (
                        <Button
                          variant="link"
                          className="p-0 h-auto text-xs mt-1 text-primary font-bold"
                          onClick={() => onNavigate(metric.name.toLowerCase().includes('budget') ? 'budgets' : 'goals')}
                        >
                          Go to {metric.name.toLowerCase().includes('budget') ? 'Budgets' : 'Goals'} →
                        </Button>
                      )}
                    </div>
                  </div>
                </div>
              </AccordionContent>
            </AccordionItem>
          ))}
        </Accordion>
      </div>



    </div>
  )

  if (compact) {
    return content
  }

  return (
    <Card>
      <CardHeader>
        <CardTitle className="flex items-center gap-2">
          <Award className="w-5 h-5" />
          Financial Health Score
        </CardTitle>
      </CardHeader>
      <CardContent>
        {content}
      </CardContent>
    </Card>
  )
}

"use client"

import { useState } from "react"
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card"
import { Button } from "@/components/ui/button"
import { Badge } from "@/components/ui/badge"
import { TrendingUp, TrendingDown, Clock, Download, PieChart, BarChart3, Target, AlertTriangle, ArrowRight, Sparkles, Shield, ChevronDown, ChevronUp } from "lucide-react"
import { useMemo } from "react"
import { Dialog, DialogContent, DialogHeader, DialogTitle } from "@/components/ui/dialog"
import { useFinancialHealthScore, FinancialHealthScore } from "./financial-health-score"
import type { Transaction, UserProfile, Budget, Goal, DebtAccount } from "@/types/wallet"
import { formatCurrency } from "@/lib/utils"
import { getTimeEquivalentBreakdown } from "@/lib/wallet-utils"
import { SpendingTrendsAnalysis } from "./spending-trends-analysis"
import { CategoryPerformanceDashboard } from "./category-performance-dashboard"

interface InsightsPanelProps {
  transactions: Transaction[]
  userProfile: UserProfile
  budgets: Budget[]
  goals: Goal[]
  debtAccounts: DebtAccount[]
  balance: number
  onExportData: () => void
  calculateTimeEquivalent: (amount: number) => number
  onNavigate?: (tab: string) => void
  onAddGoal?: (goal: Omit<Goal, "id">) => void
  onAddBudget?: (budget: Omit<Budget, "id">) => void
}

export function InsightsPanel({
  transactions,
  userProfile,
  budgets,
  goals,
  debtAccounts,
  balance,
  onExportData,
  calculateTimeEquivalent: _calculateTimeEquivalent,
  onNavigate,
  onAddGoal,
  onAddBudget,
}: InsightsPanelProps) {
  const [isAdvisorOpen, setIsAdvisorOpen] = useState(false)

  const isTimeWalletEnabled =
    userProfile.monthlyEarning > 0 &&
    userProfile.workingDaysPerMonth > 0 &&
    userProfile.workingHoursPerDay > 0

  // Calculate insights
  // Helper: true-expense filter excludes debt repayments and goal contributions
  const isTrueExpense = (t: Transaction) =>
    t.type === "expense" &&
    t.status !== "repayment" &&
    t.allocationType !== "goal"

  const totalIncome = transactions.filter((t) => t.type === "income").reduce((sum, t) => sum + t.amount, 0)
  const totalExpenses = transactions.filter(isTrueExpense).reduce((sum, t) => sum + t.amount, 0)
  const netWorth = totalIncome - totalExpenses
  const now = new Date()
  const currentMonth = now.getMonth()
  const currentYear = now.getFullYear()
  const lastMonthDate = new Date(currentYear, currentMonth - 1, 1)
  const lastMonth = lastMonthDate.getMonth()
  const lastMonthYear = lastMonthDate.getFullYear()

  const isSameMonth = (date: Date, month: number, year: number) =>
    date.getMonth() === month && date.getFullYear() === year

  const parseDate = (value: string) => {
    const parsed = new Date(value)
    return isNaN(parsed.getTime()) ? null : parsed
  }

  const thisMonthTransactions = transactions.filter((t) => {
    const date = parseDate(t.date)
    return date ? isSameMonth(date, currentMonth, currentYear) : false
  })
  const lastMonthTransactions = transactions.filter((t) => {
    const date = parseDate(t.date)
    return date ? isSameMonth(date, lastMonth, lastMonthYear) : false
  })

  const thisMonthIncome = thisMonthTransactions.filter((t) => t.type === "income").reduce((sum, t) => sum + t.amount, 0)
  const thisMonthExpenses = thisMonthTransactions.filter(isTrueExpense).reduce((sum, t) => sum + t.amount, 0)
  const lastMonthExpenses = lastMonthTransactions.filter(isTrueExpense).reduce((sum, t) => sum + t.amount, 0)
  const expenseChangePercent = lastMonthExpenses > 0 ? ((thisMonthExpenses - lastMonthExpenses) / lastMonthExpenses) * 100 : 0

  const atRiskBudgets = budgets
    .filter((b) => b.limit > 0)
    .map((b) => ({ ...b, usage: (b.spent / b.limit) * 100 }))
    .filter((b) => b.usage >= 80)
    .sort((a, b) => b.usage - a.usage)
    .slice(0, 3)

  const topGoals = goals
    .filter((g) => g.targetAmount > 0)
    .map((g) => ({ ...g, progress: (g.currentAmount / g.targetAmount) * 100 }))
    .sort((a, b) => b.progress - a.progress)
    .slice(0, 3)

  // Use the same calculation method as balance card for consistency
  const calculateTimeFromAmount = (amount: number) => {
    if (!userProfile || !amount || !isTimeWalletEnabled) return 0
    const hourlyRate = userProfile.monthlyEarning / (userProfile.workingDaysPerMonth * userProfile.workingHoursPerDay)
    return (amount / hourlyRate) * 60 // Convert hours to minutes
  }

  const totalWorkTimeEarned = transactions
    .filter((t) => t.type === "income")
    .reduce((sum, t) => sum + calculateTimeFromAmount(t.amount), 0)
  const totalWorkTimeSpent = transactions
    .filter(isTrueExpense)
    .reduce((sum, t) => sum + calculateTimeFromAmount(t.amount), 0)

  // Category breakdown (excludes debt repayments & goal contributions)
  const expensesByCategory = transactions
    .filter(isTrueExpense)
    .reduce(
      (acc, t) => {
        acc[t.category] = (acc[t.category] || 0) + t.amount
        return acc
      },
      {} as Record<string, number>,
    )

  const topCategories = Object.entries(expensesByCategory)
    .sort(([, a], [, b]) => b - a)
    .slice(0, 5)

  const formatTime = (minutes: number) => {
    if (!minutes || minutes < 0 || !userProfile || !isTimeWalletEnabled) return "0m"

    // Calculate equivalent currency amount using the same method as balance card
    const hours = minutes / 60
    const equivalentAmount = hours * (userProfile.monthlyEarning / (userProfile.workingDaysPerMonth * userProfile.workingHoursPerDay))

    const breakdown = getTimeEquivalentBreakdown(equivalentAmount, userProfile)
    return breakdown ? breakdown.formatted.userFriendly : "0m"
  }

  const savingsRate = totalIncome > 0 ? ((totalIncome - totalExpenses) / totalIncome) * 100 : 0

  // Financial Health Score Modal Logic
  const [isModalOpen, setIsModalOpen] = useState(false)

  const { overallScore } = useFinancialHealthScore(transactions, userProfile, budgets, goals, debtAccounts, balance)

  // Smart Advisor Logic
  const daysInMonth = new Date(now.getFullYear(), now.getMonth() + 1, 0).getDate()
  const dayOfMonth = now.getDate()
  const daysRemaining = Math.max(1, daysInMonth - dayOfMonth)

  const dailySpendingThisMonth = thisMonthExpenses / (dayOfMonth || 1)
  const projectedMonthEndExpenses = dailySpendingThisMonth * daysInMonth
  const potentialSavings = Math.max(0, thisMonthIncome - projectedMonthEndExpenses)

  const incomeRemaining = thisMonthIncome - thisMonthExpenses
  const dailySafetyBudget = incomeRemaining > 0 ? (incomeRemaining / daysRemaining) : 0

  const smartInsights = useMemo(() => {
    const items = []

    // --- 1. CRITICAL: Budget & Overspending ---
    atRiskBudgets.forEach(b => {
      const remainingDays = daysRemaining
      const burnRate = b.spent / (dayOfMonth || 1)
      const projectedTotal = burnRate * daysInMonth

      if (b.usage >= 100) {
        items.push({
          id: `budget-over-${b.id}`,
          type: 'warning',
          icon: <AlertTriangle className="w-5 h-5 text-red-500" />,
          title: `${b.category} Over Limit!`,
          description: `You've exceeded your ${b.category} budget by ${formatCurrency(b.spent - b.limit, userProfile.currency, userProfile.customCurrency)}. Pause non-essential spending here.`,
          action: 'Adjust Budget',
          tab: 'budgets'
        })
      } else {
        items.push({
          id: `budget-risk-${b.id}`,
          type: 'warning',
          icon: <AlertTriangle className="w-5 h-5 text-amber-500" />,
          title: `${b.category} Risk`,
          description: `At your current rate, you'll exceed the ${b.category} budget in ${Math.max(0, (b.limit - b.spent) / (burnRate || 1)).toFixed(0)} days.`,
          action: 'Slow Down',
          tab: 'budgets'
        })
      }
    })

    // --- 2. LIQUIDITY: Emergency Fund Milestones ---
    const emergencyGoals = goals.filter(g =>
      (g.title || "").toLowerCase().includes('emergency') ||
      (g.category || "").toLowerCase() === 'emergency'
    )
    const hasExplicitEfGoal = emergencyGoals.length > 0
    const emergencyBalance = emergencyGoals.reduce((sum, g) => sum + g.currentAmount, 0) + balance
    const monthlyNeeds = thisMonthExpenses || (userProfile.monthlyEarning * 0.5)
    const monthsCovered = emergencyBalance / (monthlyNeeds || 1)

    if (monthsCovered < 1) {
      items.push({
        id: 'ef-critical',
        type: 'warning',
        icon: <Shield className="w-5 h-5 text-red-500" />,
        title: 'Vulnerable Savings',
        description: "You have less than 1 month of expenses covered. Prioritize your Emergency Fund before any 'Wants' spending.",
        action: 'Create Fund',
        actionId: 'setup_ef',
        tab: 'goals'
      })
    } else if (!hasExplicitEfGoal) {
      items.push({
        id: 'ef-missing',
        type: 'info',
        icon: <Shield className="w-5 h-5 text-amber-500" />,
        title: 'Missing Safety Net',
        description: `You have ${monthsCovered.toFixed(1)} months of liquidity, but no dedicated 'Emergency Fund'. Ring-fence this money to prevent accidental spending.`,
        action: 'Create Goal',
        actionId: 'setup_ef',
        tab: 'goals'
      })
    } else if (monthsCovered >= 6) {
      items.push({
        id: 'ef-optimal',
        type: 'success',
        icon: <Shield className="w-5 h-5 text-emerald-500" />,
        title: 'Financial Fortress',
        description: `Unstoppable! You have ${monthsCovered.toFixed(1)} months of expenses covered. You can now aggressively invest or pay off debt.`,
        action: 'View Portfolio',
        tab: 'portfolio'
      })
    }

    // --- 3. GOALS: Velocity & ETAs ---
    topGoals.forEach(g => {
      // Find contributions to this goal in the last 30 days
      const recentFunding = transactions.filter(t =>
        (t.allocationType === 'goal' && t.allocationTarget === g.id) ||
        (t.description.toLowerCase().includes((g.title || "").toLowerCase()) && (g.title || "").length > 3)
      ).filter(t => (now.getTime() - new Date(t.date).getTime()) <= (30 * 24 * 60 * 60 * 1000))
        .reduce((sum, t) => sum + Math.abs(t.amount), 0)

      const remainingAmount = g.targetAmount - g.currentAmount
      if (remainingAmount > 0 && recentFunding > 0) {
        const monthsToGoal = remainingAmount / recentFunding
        if (monthsToGoal < 3) {
          items.push({
            id: `goal-finish-${g.id}`,
            type: 'success',
            icon: <Target className="w-5 h-5 text-emerald-500" />,
            title: 'Victory in Sight!',
            description: `At your current velocity, "${g.title || g.name}" will be finished in ~${monthsToGoal.toFixed(1)} months. Stay focused!`,
            action: 'Add Extra',
            tab: 'goals'
          })
        }
      } else if (remainingAmount > 0 && recentFunding === 0 && g.progress > 0) {
        items.push({
          id: `goal-stagnant-${g.id}`,
          type: 'info',
          icon: <Clock className="w-5 h-5 text-slate-400" />,
          title: 'Stagnant Goal',
          description: `You haven't contributed to "${g.title || g.name}" this month. Even a small amount keeps the habit alive.`,
          action: 'Transfer Now',
          tab: 'goals'
        })
      }
    })

    // --- 4. DEBT: Avalanche/Snowball Insights ---
    const activeDebts = debtAccounts.filter(d => d.balance > 0)
    if (activeDebts.length > 0) {
      const highestInterestDebt = [...activeDebts].sort((a, b) => b.interestRate - a.interestRate)[0]
      if (highestInterestDebt.interestRate > 15) {
        items.push({
          id: 'debt-avalanche',
          type: 'warning',
          icon: <TrendingUp className="w-5 h-5 text-red-500" />,
          title: 'High Interest Debt',
          description: `"${highestInterestDebt.name}" is costing you ${highestInterestDebt.interestRate}% interest. Pay this off first (Avalanche Method).`,
          action: 'Repay Now',
          tab: 'debt-credit'
        })
      }
    }

    // --- 5. TRENDS: Lifestyle Creep Detection ---
    if (expenseChangePercent > 20 && thisMonthIncome <= totalIncome / (transactions.length > 0 ? 12 : 1)) {
      items.push({
        id: 'lifestyle-creep',
        type: 'warning',
        icon: <TrendingUp className="w-5 h-5 text-amber-500" />,
        title: 'Lifestyle Creep Detected',
        description: "Your spending is rising significantly faster than your income. Watch out for recurring costs that bleed your net worth.",
        action: 'Audit Costs',
        tab: 'categories'
      })
    }

    // --- 6. CATEGORY: Anomaly Detection ---
    topCategories.forEach(([cat, amt]) => {
      // Find average spending for this category in previous months (simple heuristic)
      const previousTotal = transactions
        .filter(t => t.type === 'expense' && t.category === cat && !isSameMonth(new Date(t.date), currentMonth, currentYear))
        .reduce((sum, t) => sum + t.amount, 0)

      const categoryMonthsCount = new Set(transactions.map(t => {
        const d = new Date(t.date)
        return `${d.getFullYear()}-${d.getMonth()}`
      })).size - 1

      const avgMonthlyForCat = categoryMonthsCount > 0 ? previousTotal / categoryMonthsCount : amt

      if (avgMonthlyForCat > 0 && amt > avgMonthlyForCat * 1.5) {
        items.push({
          id: `anomaly-${cat}`,
          type: 'info',
          icon: <BarChart3 className="w-5 h-5 text-blue-500" />,
          title: `Spike in ${cat}`,
          description: `You've spent ${((amt / avgMonthlyForCat - 1) * 100).toFixed(0)}% more on ${cat} than your usual average. Was this planned?`,
          action: 'Review Breakdown',
          tab: 'transactions'
        })
      }
    })

    // --- 7. REWARD: No-Spend Streaks ---
    const last3Days = transactions.filter(t =>
      t.type === 'expense' &&
      (now.getTime() - new Date(t.date).getTime()) <= (3 * 24 * 60 * 60 * 1000)
    ).length

    if (last3Days === 0 && dayOfMonth > 3) {
      items.push({
        id: 'no-spend-streak',
        type: 'success',
        icon: <Sparkles className="w-5 h-5 text-emerald-500" />,
        title: 'No-Spend Streak! 🔥',
        description: "3 days without an expense! You're building incredible financial discipline.",
        action: 'Keep Going',
        tab: 'transactions'
      })
    }

    // --- 8. SETUP: Missing Defaults ---
    if (budgets.length === 0) {
      items.push({
        id: 'setup-budgets',
        type: 'info',
        icon: <PieChart className="w-5 h-5 text-purple-500" />,
        title: 'Complete Setup',
        description: "You haven't set any budgets yet. Create default budgets (Needs/Wants/Savings) to start tracking.",
        action: 'Add Defaults',
        actionId: 'setup_defaults',
        tab: 'budgets'
      })
    }

    // --- 9. SETUP: No Goals ---
    if (goals.length === 0) {
      items.push({
        id: 'setup-goals-starter',
        type: 'info',
        icon: <Target className="w-5 h-5 text-blue-500" />,
        title: 'Start Dreaming',
        description: "You haven't defined any financial targets. Set up a few starter goals to give your money a purpose.",
        action: 'Add Goal Starters',
        actionId: 'setup_goals_defaults',
        tab: 'goals'
      })
    }

    return items
  }, [atRiskBudgets, expenseChangePercent, savingsRate, isTimeWalletEnabled, topGoals, dailySpendingThisMonth, dailySafetyBudget, totalWorkTimeEarned, totalWorkTimeSpent, userProfile, transactions, balance, goals, debtAccounts, daysInMonth, dayOfMonth, daysRemaining, thisMonthExpenses, thisMonthIncome, budgets])

  const handleSmartAction = (insight: any) => {
    if (insight.actionId === 'setup_ef') {
      const monthlyNeeds = thisMonthExpenses || (userProfile.monthlyEarning * 0.5)
      if (onAddGoal) {
        onAddGoal({
          title: "Emergency Fund",
          targetAmount: monthlyNeeds * 6,
          currentAmount: 0,
          category: "emergency",
          priority: "high",
          targetDate: new Date(new Date().setFullYear(new Date().getFullYear() + 1)).toISOString(),
          description: "Safety net for unexpected expenses (6 months of needs)",
          autoContribute: false,
          createdAt: new Date().toISOString()
        })
        onNavigate?.('goals')
      }
    } else if (insight.actionId === 'setup_goals_defaults') {
      if (onAddGoal) {
        // 1. Emergency Fund
        const monthlyNeeds = thisMonthExpenses || (userProfile.monthlyEarning * 0.5)
        onAddGoal({
          title: "Emergency Fund",
          targetAmount: monthlyNeeds * 6,
          currentAmount: 0,
          category: "emergency",
          priority: "high",
          targetDate: new Date(new Date().setFullYear(new Date().getFullYear() + 1)).toISOString(),
          description: "Safety net for unexpected expenses",
          autoContribute: false,
          createdAt: new Date().toISOString()
        })
        // 2. General Savings / Vacation
        onAddGoal({
          title: "Dream Vacation",
          targetAmount: userProfile.monthlyEarning * 2, // Approx 2 months salary
          currentAmount: 0,
          category: "travel",
          priority: "medium",
          targetDate: new Date(new Date().setFullYear(new Date().getFullYear() + 1)).toISOString(),
          description: "Something to look forward to!",
          autoContribute: false,
          createdAt: new Date().toISOString()
        })
        onNavigate?.('goals')
      }
    } else if (insight.actionId === 'setup_defaults') {
      const defaults = [
        { name: "Housing", category: "Housing", limit: userProfile.monthlyEarning * 0.3 },
        { name: "Food", category: "Food & Dining", limit: userProfile.monthlyEarning * 0.15 },
        { name: "Transport", category: "Transportation", limit: userProfile.monthlyEarning * 0.1 },
      ]
      if (onAddBudget) {
        defaults.forEach(d => {
          onAddBudget({
            ...d,
            period: 'monthly',
            alertThreshold: 80,
            categories: [d.category],
            emergencyUses: 0,
            allowDebt: false,
            createdAt: new Date().toISOString(),
            spent: 0
          })
        })
        onNavigate?.('budgets')
      }
    } else if (insight.tab) {
      onNavigate?.(insight.tab)
    }
  }

  return (
    <div className="space-y-8 max-w-7xl mx-auto pb-10">
      {/* Hero Section: Financial Health Advisor */}
      <div className="relative overflow-hidden rounded-3xl bg-gradient-to-br from-primary/10 via-background to-primary/5 border border-primary/20 p-6 md:p-8 shadow-2xl">
        <div className="absolute top-0 right-0 p-8 opacity-10 pointer-events-none">
          <Sparkles className="w-32 h-32 text-primary" />
        </div>

        <div className="flex flex-col md:flex-row items-center gap-8 relative z-10">
          <div className="flex-1 space-y-4 text-center md:text-left">
            <Badge variant="outline" className="px-3 py-1 bg-white/50 dark:bg-black/20 border-primary/30 text-primary font-bold tracking-wider rounded-full">
              FINANCIAL PERFORMANCE
            </Badge>
            <h2 className="text-xl sm:text-3xl md:text-5xl font-black tracking-tight bg-gradient-to-r from-primary to-primary/60 bg-clip-text text-transparent leading-tight">
              {overallScore.description}
            </h2>
            <p className="text-muted-foreground text-lg max-w-xl">
              {thisMonthIncome > thisMonthExpenses
                ? `You're on track to save ${formatCurrency(potentialSavings, userProfile.currency, userProfile.customCurrency)} this month. Keep your daily spending below ${formatCurrency(dailySafetyBudget, userProfile.currency, userProfile.customCurrency)}.`
                : "Your expenses currently exceed your income. Let's look for ways to optimize your spending for the rest of the month."}
            </p>
            <div className="flex flex-wrap gap-3 justify-center md:justify-start">
              <Button onClick={() => setIsModalOpen(true)} className="rounded-full px-6 font-bold shadow-lg shadow-primary/20">
                View Score Breakdown
              </Button>
              <Button variant="outline" className="rounded-full px-6 font-bold bg-white/50 dark:bg-black/20" onClick={onExportData}>
                <Download className="w-4 h-4 mr-2" />
                Export Report
              </Button>
            </div>
          </div>

          <div
            className="w-48 h-48 md:w-56 md:h-56 rounded-full border-[12px] border-primary/10 flex items-center justify-center relative cursor-pointer group"
            onClick={() => setIsModalOpen(true)}
          >
            <div className="absolute inset-0 bg-primary/20 rounded-full blur-3xl opacity-0 group-hover:opacity-100 transition-opacity"></div>
            <div className="text-center relative z-10">
              <span className="block text-5xl md:text-7xl font-black text-primary leading-none">{overallScore.score.toFixed(0)}</span>
              <span className="text-xl md:text-2xl font-black text-primary/60">{overallScore.grade}</span>
            </div>
            {/* Simple Animated Ring */}
            <svg className="absolute inset-0 -rotate-90 w-full h-full">
              <circle
                cx="50%"
                cy="50%"
                r="46%"
                fill="none"
                stroke="currentColor"
                strokeWidth="12"
                strokeDasharray="290"
                strokeDashoffset={290 - (290 * (Number.isNaN(overallScore.score) ? 0 : overallScore.score) / 100)}
                className="text-primary transition-all duration-1000 ease-out"
              />
            </svg>
          </div>
        </div>
      </div>

      {/* Actionable Insights: Smart Advisor Feed */}
      <div className="space-y-4">
        <div className="flex items-center justify-between px-2">
          <h3 className="text-xl font-bold flex items-center gap-2">
            <Sparkles className="w-5 h-5 text-primary" />
            Smart Advisor
          </h3>
          <div className="flex items-center gap-2">
            <Badge variant="secondary" className="rounded-full">{smartInsights.length} Suggestions</Badge>
            <Button
              variant="ghost"
              size="icon"
              className="md:hidden h-8 w-8"
              onClick={() => setIsAdvisorOpen(!isAdvisorOpen)}
            >
              {isAdvisorOpen ? <ChevronUp className="w-4 h-4" /> : <ChevronDown className="w-4 h-4" />}
            </Button>
          </div>
        </div>

        <div className={`${isAdvisorOpen ? 'flex' : 'hidden'} md:flex overflow-x-auto pb-4 gap-4 md:grid md:grid-cols-2 lg:grid-cols-3 md:pb-0 snap-x snap-mandatory scrollbar-hide -mx-4 px-4 md:mx-0 md:px-0`}>
          {smartInsights.length > 0 ? (
            smartInsights.map((insight) => (
              <Card key={insight.id} className="flex-none w-[85vw] md:w-auto snap-center md:snap-align-none group border-primary/10 hover:border-primary/30 transition-all duration-300 hover:shadow-xl hover:-translate-y-1 bg-gradient-to-br from-card to-background relative overflow-hidden">
                <div className={`absolute top-0 left-0 w-1 h-full ${insight.type === 'warning' ? 'bg-amber-500' : insight.type === 'success' ? 'bg-emerald-500' : 'bg-primary'}`} />
                <CardHeader className="pb-2">
                  <div className="flex items-center gap-3 mb-1">
                    <div className="p-2 rounded-xl bg-muted/50 group-hover:bg-primary/10 transition-colors">
                      {insight.icon}
                    </div>
                    <CardTitle className="text-base font-black">{insight.title}</CardTitle>
                  </div>
                </CardHeader>
                <CardContent className="space-y-4">
                  <p className="text-sm text-muted-foreground leading-relaxed">
                    {insight.description}
                  </p>
                  <Button
                    variant="ghost"
                    size="sm"
                    className="w-full justify-between font-bold text-primary group-hover:bg-primary group-hover:text-primary-foreground rounded-lg transition-all"
                    onClick={() => handleSmartAction(insight)}
                  >
                    {insight.action}
                    <ArrowRight className="w-4 h-4 ml-1" />
                  </Button>
                </CardContent>
              </Card>
            ))
          ) : (
            <Card className="col-span-full border-dashed p-10 flex flex-col items-center justify-center text-center text-muted-foreground">
              <BarChart3 className="w-12 h-12 mb-4 opacity-20" />
              <p className="text-lg font-bold">Collecting Data...</p>
              <p className="text-sm">Add more transactions to unlock AI-driven insights.</p>
            </Card>
          )}
        </div>
      </div>

      {/* Core Metrics Grid */}
      <div className="flex overflow-x-auto pb-4 gap-4 md:grid md:grid-cols-4 md:pb-0 snap-x snap-mandatory scrollbar-hide -mx-4 px-4 md:mx-0 md:px-0">
        <Card className="flex-none w-[75vw] sm:w-[45vw] md:w-auto snap-center bg-emerald-500/10 dark:bg-emerald-500/5 border-emerald-500/20 overflow-hidden group">
          <CardContent className="p-4 md:p-5 relative">
            <div className="flex items-center gap-2 mb-1">
              <Target className="w-4 h-4 text-emerald-600 dark:text-emerald-400" />
              <p className="text-[10px] font-bold text-emerald-600 dark:text-emerald-400 uppercase tracking-widest">Safe Daily Spend</p>
            </div>
            <p className="text-xl md:text-2xl font-black font-mono truncate" title={formatCurrency(dailySafetyBudget, userProfile.currency, userProfile.customCurrency)}>
              {formatCurrency(dailySafetyBudget, userProfile.currency, userProfile.customCurrency)}
            </p>
            <p className="text-[10px] text-muted-foreground mt-1 truncate">To stay within income</p>
          </CardContent>
        </Card>

        <Card className="flex-none w-[75vw] sm:w-[45vw] md:w-auto snap-center bg-blue-500/10 dark:bg-blue-500/5 border-blue-500/20 overflow-hidden group">
          <CardContent className="p-4 md:p-5 relative">
            <div className="flex items-center gap-2 mb-1">
              <TrendingUp className="w-4 h-4 text-blue-600 dark:text-blue-400" />
              <p className="text-[10px] font-bold text-blue-600 dark:text-blue-400 uppercase tracking-widest">Savings Prowess</p>
            </div>
            <p className="text-xl md:text-2xl font-black font-mono">{savingsRate.toFixed(0)}%</p>
            <p className="text-[10px] text-muted-foreground mt-1">Rate of net income saved</p>
          </CardContent>
        </Card>

        <Card className="flex-none w-[75vw] sm:w-[45vw] md:w-auto snap-center bg-purple-500/10 dark:bg-purple-500/5 border-purple-500/20 overflow-hidden group">
          <CardContent className="p-4 md:p-5 relative">
            <div className="flex items-center gap-2 mb-1">
              <Clock className="w-4 h-4 text-purple-600 dark:text-purple-400" />
              <p className="text-[10px] font-bold text-purple-600 dark:text-purple-400 uppercase tracking-widest">Time Buffer</p>
            </div>
            <p className="text-xl md:text-2xl font-black font-mono truncate">{formatTime(Math.max(0, totalWorkTimeEarned - totalWorkTimeSpent))}</p>
            <p className="text-[10px] text-muted-foreground mt-1">Total 'Life Hours' banked</p>
          </CardContent>
        </Card>

        <Card className="flex-none w-[75vw] sm:w-[45vw] md:w-auto snap-center bg-primary/10 border-primary/20 overflow-hidden group">
          <CardContent className="p-4 md:p-5 relative">
            <div className="flex items-center gap-2 mb-1">
              <Sparkles className="w-4 h-4 text-primary" />
              <p className="text-[10px] font-bold text-primary uppercase tracking-widest">Projected Win</p>
            </div>
            <p className="text-xl md:text-2xl font-black font-mono truncate" title={formatCurrency(potentialSavings, userProfile.currency, userProfile.customCurrency)}>
              {formatCurrency(potentialSavings, userProfile.currency, userProfile.customCurrency)}
            </p>
            <p className="text-[10px] text-muted-foreground mt-1 truncate">Est. month-end surplus</p>
          </CardContent>
        </Card>
      </div>

      {/* Main Analytics Section */}
      <div className="grid grid-cols-1 lg:grid-cols-3 gap-8 pt-4">
        <div className="lg:col-span-2 space-y-8">
          {/* Spending Trends Analysis */}
          <SpendingTrendsAnalysis
            transactions={transactions}
            userProfile={userProfile}
          />

          {/* Category Performance Dashboard */}
          <CategoryPerformanceDashboard
            transactions={transactions}
            userProfile={userProfile}
          />
        </div>

        <div className="space-y-8">
          {/* Top Spending Categories: Compact & Visual */}
          <Card className="border-primary/10 h-fit">
            <CardHeader className="pb-2">
              <CardTitle className="text-lg font-black flex items-center justify-between">
                <span>Top Categories</span>
                <PieChart className="w-4 h-4 text-primary opacity-50" />
              </CardTitle>
            </CardHeader>
            <CardContent>
              {topCategories.length > 0 ? (
                <div className="space-y-5">
                  {topCategories.slice(0, 5).map(([category, amount]) => {
                    const percentage = totalExpenses > 0 ? (amount / totalExpenses) * 100 : 0
                    return (
                      <div key={category} className="space-y-1.5 group">
                        <div className="flex justify-between items-end">
                          <span className="text-xs font-bold uppercase tracking-wide truncate max-w-[120px]">{category}</span>
                          <span className="text-xs font-black font-mono">{formatCurrency(amount, userProfile.currency, userProfile.customCurrency)}</span>
                        </div>
                        <div className="h-1.5 w-full bg-muted rounded-full overflow-hidden">
                          <div
                            className="h-full bg-primary group-hover:bg-primary/80 transition-all duration-500"
                            style={{ width: `${percentage}%` }}
                          />
                        </div>
                        <div className="flex justify-between text-[10px] font-medium text-muted-foreground">
                          <span>{percentage.toFixed(0)}% of total</span>
                          {isTimeWalletEnabled && <span>{formatTime(calculateTimeFromAmount(amount))} work</span>}
                        </div>
                      </div>
                    )
                  })}
                </div>
              ) : (
                <div className="text-center py-10 opacity-30">
                  <PieChart className="w-10 h-10 mx-auto mb-2" />
                  <p className="text-xs font-bold uppercase">No Expenses Yet</p>
                </div>
              )}
            </CardContent>
          </Card>
        </div>
      </div>

      <Dialog open={isModalOpen} onOpenChange={setIsModalOpen}>
        <DialogContent className="max-w-4xl max-h-[85vh] overflow-hidden flex flex-col p-0 border-primary/20 bg-background/95 backdrop-blur-xl">
          <DialogHeader className="p-6 border-b border-primary/10">
            <DialogTitle className="text-2xl font-black tracking-tight">Financial Health Analysis</DialogTitle>
          </DialogHeader>
          <div className="flex-1 overflow-y-auto p-6 scrollbar-hide">
            <FinancialHealthScore
              transactions={transactions}
              userProfile={userProfile}
              budgets={budgets}
              goals={goals}
              debtAccounts={debtAccounts}
              balance={balance}
              onNavigate={onNavigate}
              compact
            />
          </div>
        </DialogContent>
      </Dialog>
    </div>
  )
}

"use client"

import { useState, useRef } from 'react';
import { Button } from '@/components/ui/button';
import { Input } from '@/components/ui/input';
import { Label } from '@/components/ui/label';
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from '@/components/ui/select';
import { Card, CardContent, CardDescription, CardHeader, CardTitle } from '@/components/ui/card';
import { Checkbox } from '@/components/ui/checkbox';
import { Avatar, AvatarFallback, AvatarImage } from '@/components/ui/avatar';
import { toast } from 'sonner';
import { useRouter } from 'next/navigation';
import {
  Wallet,
  Clock,
  TrendingUp,
  Shield,
  Lock,
  BarChart3,
  PiggyBank,
  ArrowRight,
  CheckCircle,
  ArrowLeft,
  User,
  DollarSign,
  Calendar,
  Sparkles,
  Camera,
  ImageIcon,
  X
} from 'lucide-react';
import type { UserProfile } from '@/types/wallet';
import { ONBOARDING_CURRENCIES } from '@/lib/currency';
import { SecurePinManager } from '@/lib/secure-pin-manager';
import { SessionManager } from '@/lib/session-manager';
import { InputOTP, InputOTPGroup, InputOTPSlot } from '@/components/ui/input-otp';
import { compressImageToDataUrl } from '@/lib/image-utils';

interface OnboardingProps {
  onComplete: (userProfile: UserProfile) => void;
}

const steps = [
  {
    id: 0,
    title: "Welcome to MyWallet",
    subtitle: "Your time-aware financial companion",
    icon: Wallet,
    description: "Your time-aware financial companion"
  },
  {
    id: 1,
    title: "Let's Get Personal",
    subtitle: "Your name & profile",
    icon: User,
    description: "Set your name and profile picture"
  },
  {
    id: 2,
    title: "How do you want to use MyWallet?",
    subtitle: "Choose your style",
    icon: Clock,
    description: "Pick the experience that fits you best"
  },
  {
    id: 3,
    title: "How are you paid?",
    subtitle: "Your pay details",
    icon: DollarSign,
    description: "Enter monthly or hourly pay to personalize time-based insights"
  },
  {
    id: 4,
    title: "Tell us about your work schedule",
    subtitle: "Daily and weekly routine",
    icon: Calendar,
    description: "How many hours per day and days per week do you work?"
  },
  {
    id: 5,
    title: "Keep your wallet secure",
    subtitle: "Your privacy matters",
    icon: Shield,
    description: "Add a PIN to protect your financial data"
  },
  {
    id: 6,
    title: "You're all set! 🎉",
    subtitle: "Welcome aboard!",
    icon: Sparkles,
    description: "Ready to take control of your finances"
  }
];

const features = [
  {
    icon: Clock,
    title: 'Time-Aware Spending',
    description: 'See purchases in work hours',
    color: 'text-blue-500',
    bgColor: 'bg-blue-50 dark:bg-blue-950/20'
  },
  {
    icon: Shield,
    title: 'Bank-Level Security',
    description: 'AES-256 local encryption',
    color: 'text-green-500',
    bgColor: 'bg-green-50 dark:bg-green-950/20'
  },
  {
    icon: BarChart3,
    title: 'Smart Analytics',
    description: 'Track patterns & trends',
    color: 'text-purple-500',
    bgColor: 'bg-purple-50 dark:bg-purple-950/20'
  },
  {
    icon: PiggyBank,
    title: 'Goal Tracking',
    description: 'Achieve savings milestones',
    color: 'text-orange-500',
    bgColor: 'bg-orange-50 dark:bg-orange-950/20'
  },
];

export default function Onboarding({ onComplete }: OnboardingProps) {
  const router = useRouter();
  const [step, setStep] = useState(0);
  const [isLoading, setIsLoading] = useState(false);
  const [formData, setFormData] = useState({
    name: '',
    avatar: null as string | null,
    walletType: 'timed' as 'timed' | 'normal',
    payInputMode: 'monthly' as 'monthly' | 'hourly',
    monthlyEarning: '',
    hourlyEarning: '',
    currency: 'NPR',
    workingHoursPerDay: '',
    workingDaysPerWeek: '',
    enableSecurity: true,
    pin: '',
    confirmPin: '',
  });

  const fileInputRef = useRef<HTMLInputElement>(null);
  const cameraInputRef = useRef<HTMLInputElement>(null);

  const currentStep = steps.find(s => s.id === step) || steps[0];
  const maxStep = formData.enableSecurity ? 6 : 5;

  const validateStep = () => {
    switch (step) {
      case 1:
        if (!formData.name.trim()) {
          toast.error('Please enter your name');
          return false;
        }
        break;
      case 2:
        break;
      case 3:
        if (formData.payInputMode === 'monthly') {
          const monthly = parseFloat(formData.monthlyEarning);
          if (!Number.isFinite(monthly) || monthly <= 0) {
            toast.error('Please enter a valid monthly earning');
            return false;
          }
        } else {
          const hourly = parseFloat(formData.hourlyEarning);
          if (!Number.isFinite(hourly) || hourly <= 0) {
            toast.error('Please enter a valid hourly earning');
            return false;
          }
        }
        break;
      case 4:
        const hours = parseFloat(formData.workingHoursPerDay);
        const daysPerWeek = parseFloat(formData.workingDaysPerWeek);
        if (
          !Number.isFinite(hours) ||
          hours <= 0 ||
          hours > 24 ||
          !Number.isFinite(daysPerWeek) ||
          daysPerWeek <= 0 ||
          daysPerWeek > 7
        ) {
          toast.error('Please enter valid working hours and days per week');
          return false;
        }
        break;
      case 5:
        if (formData.enableSecurity) {
          if (formData.pin.length !== 6) {
            toast.error('Please enter a 6-digit PIN');
            return false;
          }
          if (formData.pin !== formData.confirmPin) {
            toast.error('PINs do not match');
            return false;
          }
        }
        break;
    }
    return true;
  };

  const handleNext = () => {
    if (!validateStep()) return;

    if (formData.walletType === 'normal') {
      // Skip Earnings and Schedule for normal wallet
      if (step === 2) {
        setStep(5); // Skip to Security
      } else if (step === 5 && !formData.enableSecurity) {
        setStep(6); // Skip to Complete
      } else {
        setStep(Math.min(step + 1, maxStep));
      }
    } else {
      // For timed wallet, proceed normally
      if (step === 5 && !formData.enableSecurity) {
        setStep(6); // Skip to Complete
      } else {
        setStep(Math.min(step + 1, maxStep));
      }
    }
  };

  const handleBack = () => {
    if (formData.walletType === 'normal') {
      if (step === 5) {
        setStep(2);
      } else {
        setStep(Math.max(step - 1, 0));
      }
    } else {
      if (step === 6 && !formData.enableSecurity) {
        setStep(5); // Back to Security
      } else {
        setStep(Math.max(step - 1, 0));
      }
    }
  };

  const handleImageSelect = (event: React.ChangeEvent<HTMLInputElement>) => {
    const file = event.target.files?.[0]
    if (file) {
      // Validate file type
      if (!file.type.startsWith('image/')) {
        toast.error('Please select a valid image file.')
        return
      }

      // Validate file size (max 5MB)
      if (file.size > 5 * 1024 * 1024) {
        toast.error('Please select an image smaller than 5MB.')
        return
      }

      void (async () => {
        try {
          const result = await compressImageToDataUrl(file, {
            maxSize: 512,
            maxBytes: 500 * 1024,
            mimeType: "image/jpeg",
            quality: 0.9,
          })
          setFormData({ ...formData, avatar: result })
        } catch {
          toast.error('Failed to process image. Please try another.')
        }
      })()
    }
  }

  const handleFileUpload = () => {
    if (fileInputRef.current) fileInputRef.current.click()
  }

  const handleCameraCapture = () => {
    if (cameraInputRef.current) cameraInputRef.current.click()
  }

  const handleRemoveAvatar = () => {
    setFormData({ ...formData, avatar: null })
  }

  const getInitials = () => {
    return formData.name
      ? formData.name
        .split(" ")
        .map((n: string) => n[0])
        .join("")
        .toUpperCase()
        .slice(0, 2)
      : "U"
  }

  const handleComplete = async () => {
    setIsLoading(true);

    try {
      // Set up PIN if security is enabled
      if (formData.enableSecurity && formData.pin) {
        const pinSetupSuccess = await SecurePinManager.setupPin(formData.pin);
        if (!pinSetupSuccess) {
          toast.error('Failed to set up PIN. Please try again.');
          return;
        }

        // Create initial session after PIN setup for consistent behavior
        SessionManager.createSession();
      }

      // Get PIN data from localStorage if security is enabled
      let pinData = {};
      if (formData.enableSecurity && formData.pin) {
        const pinHash = localStorage.getItem('wallet_pin_hash');
        const pinSalt = localStorage.getItem('wallet_pin_salt');
        if (pinHash && pinSalt) {
          pinData = {
            pin: pinHash,
            pinSalt: pinSalt
          };
        }
      }

      const parsedHoursPerDay = parseFloat(formData.workingHoursPerDay) || 0;
      const parsedDaysPerWeek = parseFloat(formData.workingDaysPerWeek) || 0;
      const parsedDaysPerMonth = parsedDaysPerWeek > 0 ? parsedDaysPerWeek * 4.333 : 0;
      const parsedHourly = parseFloat(formData.hourlyEarning) || 0;
      const parsedMonthly = parseFloat(formData.monthlyEarning) || 0;
      const resolvedMonthly = formData.payInputMode === 'hourly'
        ? parsedHourly * parsedHoursPerDay * parsedDaysPerMonth
        : parsedMonthly;
      const resolvedHourly = formData.payInputMode === 'hourly'
        ? parsedHourly
        : (parsedHoursPerDay > 0 && parsedDaysPerMonth > 0 ? resolvedMonthly / (parsedHoursPerDay * parsedDaysPerMonth) : 0);

      const userProfile: UserProfile = {
        name: formData.name.trim(),
        monthlyEarning: resolvedMonthly,
        currency: formData.currency,
        workingHoursPerDay: parsedHoursPerDay,
        workingDaysPerMonth: parsedDaysPerMonth,
        createdAt: new Date().toISOString(),
        hourlyRate: resolvedHourly,
        securityEnabled: formData.enableSecurity,
        avatar: formData.avatar || undefined,
        ...pinData
      };

      onComplete(userProfile);
      toast.success(`Welcome, ${userProfile.name}! Your financial journey begins now.`);
    } catch (error) {
      console.error('Onboarding completion error:', error);
      toast.error('Setup failed. Please try again.');
    } finally {
      setIsLoading(false);
    }
  };

  const handleSkip = () => {
    const defaultProfile: UserProfile = {
      name: 'Guest User',
      monthlyEarning: 0,
      currency: 'NPR',
      workingHoursPerDay: 8,
      workingDaysPerMonth: 22,
      createdAt: new Date().toISOString(),
      hourlyRate: 0,
      securityEnabled: false,
    };
    onComplete(defaultProfile);
    toast.info("Welcome! You can complete your profile later in Settings.");
  };

  const parsedHoursPerDay = parseFloat(formData.workingHoursPerDay) || 0;
  const parsedDaysPerWeek = parseFloat(formData.workingDaysPerWeek) || 0;
  const parsedDaysPerMonth = parsedDaysPerWeek > 0 ? parsedDaysPerWeek * 4.333 : 0;
  const parsedMonthly = parseFloat(formData.monthlyEarning) || 0;
  const parsedHourly = parseFloat(formData.hourlyEarning) || 0;
  const derivedHourlyRate = parsedMonthly > 0 && parsedHoursPerDay > 0 && parsedDaysPerMonth > 0
    ? parsedMonthly / (parsedHoursPerDay * parsedDaysPerMonth)
    : 0;
  const resolvedHourlyRate = formData.payInputMode === 'hourly' ? parsedHourly : derivedHourlyRate;
  const resolvedMonthlyEarning = formData.payInputMode === 'hourly'
    ? parsedHourly * parsedHoursPerDay * parsedDaysPerMonth
    : parsedMonthly;
  const hourlyRate = resolvedHourlyRate.toFixed(2);

  const progress = (step / maxStep) * 100;

  return (
    <div className="min-h-screen bg-gradient-to-br from-background via-background to-muted/20 flex items-center justify-center p-3">
      <div className="w-full max-w-md">

        {/* Main Card */}
        <Card className="border-0 shadow-xl bg-card/600 backdrop-blur-sm border border-border/60 relative overflow-hidden">
          <CardHeader className="text-center pb-3">
            {step === 0 && (
              <Button
                variant="ghost"
                size="sm"
                className="absolute left-2 top-2 text-muted-foreground hover:text-foreground z-10"
                onClick={() => router.push('/welcome')}
                disabled={isLoading}
              >
                <ArrowLeft className="w-4 h-4 mr-1" />
                Back
              </Button>
            )}
            {step < maxStep && (
              <Button
                variant="ghost"
                size="sm"
                className="absolute right-2 top-2 text-muted-foreground hover:text-foreground z-10"
                onClick={handleSkip}
                disabled={isLoading}
              >
                Skip
              </Button>
            )}
            <div className="flex items-center justify-center gap-3 mb-3">
              <div className="w-16 h-16 bg-gradient-to-br from-primary/20 via-primary/10 to-primary/5 rounded-xl flex items-center justify-center shadow-lg">
                <currentStep.icon className="w-8 h-8 text-primary drop-shadow-sm" />
              </div>
            </div>
            <CardTitle className="text-xl font-bold">
              {currentStep.title}
            </CardTitle>
            <CardDescription className="text-sm">
              {currentStep.description}
            </CardDescription>
          </CardHeader>

          <CardContent className="pt-0">
            {/* Step 0 - Welcome Screen */}
            {step === 0 && (
              <div className="space-y-6 text-center">
                {/* Hero Section */}
                <div className="w-12 h-0.5 bg-gradient-to-r from-primary to-primary/60 rounded-full mx-auto mt-3" />


                {/* Journey Message */}
                <div className="space-y-4">
                  <div className="relative">
                    <p className="text-base text-foreground/90 font-medium leading-relaxed">
                      Let's start your journey to
                    </p>
                    <p className="text-lg font-bold bg-gradient-to-r from-primary via-primary/80 to-primary text-transparent bg-clip-text">
                      financial freedom
                    </p>
                  </div>

                  {/* Feature Showcase */}
                  <div className="grid grid-cols-2 gap-3 mt-6">
                    {features.map((feature, index) => (
                      <div key={index} className="group relative p-3 rounded-lg bg-card/50 border border-border/30 backdrop-blur-md hover:bg-card/70 hover:border-border/50 transition-all duration-300 hover:scale-105 hover:shadow-lg">
                        <div className="absolute inset-0 bg-gradient-to-br from-primary/5 to-transparent rounded-lg opacity-0 group-hover:opacity-100 transition-opacity duration-300" />
                        <div className="relative z-10">
                          <div className={`inline-flex items-center justify-center w-8 h-8 rounded-md ${feature.bgColor} mb-2 group-hover:scale-110 transition-transform duration-300`}>
                            <feature.icon className={`w-4 h-4 ${feature.color}`} />
                          </div>
                          <h3 className="font-semibold text-xs text-foreground group-hover:text-foreground/95 transition-colors">
                            {feature.title}
                          </h3>
                          <p className="text-xs text-muted-foreground group-hover:text-foreground/80 transition-colors leading-tight">
                            {feature.description}
                          </p>
                        </div>
                      </div>
                    ))}
                  </div>
                </div>
              </div>
            )}

            {/* Step 1 - Profile Setup */}
            {step === 1 && (
              <div className="space-y-8">
                {/* Avatar Section */}
                <div className="flex flex-col items-center gap-4">
                  <div className="relative group">
                    {/* Hidden file inputs */}
                    <input
                      ref={fileInputRef}
                      type="file"
                      accept="image/*"
                      onChange={handleImageSelect}
                      className="hidden"
                      aria-label="Upload avatar image"
                    />
                    <input
                      ref={cameraInputRef}
                      type="file"
                      accept="image/*"
                      capture="environment"
                      onChange={handleImageSelect}
                      className="hidden"
                      aria-label="Take photo"
                    />

                    {/* Avatar with hover overlay */}
                    <div
                      className="relative cursor-pointer"
                      onClick={() => !formData.avatar && handleFileUpload()}
                    >
                      <Avatar className="w-24 h-24 ring-2 ring-primary/20 shadow-md transition-all duration-300 group-hover:ring-primary/40 group-hover:shadow-lg">
                        <AvatarImage
                          src={formData.avatar || undefined}
                          className="object-cover"
                        />
                        <AvatarFallback className="bg-gradient-to-br from-primary/15 to-primary/10 text-primary font-bold text-2xl">
                          {getInitials()}
                        </AvatarFallback>
                      </Avatar>

                      {/* Hover overlay with options */}
                      <div className="absolute inset-0 bg-black/50 rounded-full opacity-0 group-hover:opacity-100 transition-opacity duration-300 flex items-center justify-center">
                        <div className="flex gap-1">
                          {!formData.avatar ? (
                            <>
                              <button
                                onClick={(e) => {
                                  e.stopPropagation();
                                  handleFileUpload();
                                }}
                                className="w-8 h-8 bg-white/90 rounded-full flex items-center justify-center text-gray-700 hover:bg-white transition-colors shadow-sm"
                                title="Upload from gallery"
                              >
                                <ImageIcon className="w-4 h-4" />
                              </button>
                              <button
                                onClick={(e) => {
                                  e.stopPropagation();
                                  handleCameraCapture();
                                }}
                                className="w-8 h-8 bg-white/90 rounded-full flex items-center justify-center text-gray-700 hover:bg-white transition-colors shadow-sm"
                                title="Take photo"
                              >
                                <Camera className="w-4 h-4" />
                              </button>
                            </>
                          ) : (
                            <button
                              onClick={(e) => {
                                e.stopPropagation();
                                handleRemoveAvatar();
                              }}
                              className="w-8 h-8 bg-red-500/90 rounded-full flex items-center justify-center text-white hover:bg-red-500 transition-colors shadow-sm"
                              title="Remove avatar"
                            >
                              <X className="w-4 h-4" />
                            </button>
                          )}
                        </div>
                      </div>
                    </div>
                  </div>

                  <div className="text-center space-y-1">
                    <p className="text-sm text-muted-foreground font-medium">
                      {formData.avatar
                        ? "✨ Profile picture set! Hover to change"
                        : "📸 Add a profile picture (optional)"
                      }
                    </p>
                    {!formData.avatar && (
                      <p className="text-xs text-muted-foreground/80">
                        Or continue with beautiful auto-generated initials
                      </p>
                    )}
                  </div>
                </div>
                {/* Name Input Section */}
                <div className="space-y-3">
                  <Label htmlFor="name" className="text-sm font-semibold text-foreground/90">What should we call you?</Label>
                  <Input
                    id="name"
                    placeholder="Enter your name"
                    value={formData.name}
                    onChange={(e) => setFormData({ ...formData, name: e.target.value })}
                    className="h-12 text-base border-2 border-border/50 focus:border-primary/50 transition-colors"
                  />
                </div>
              </div>
            )}

            {/* Step 2 - Wallet Type */}
            {step === 2 && (
              <div className="space-y-6">
                <div className="space-y-4">
                  <Label className="text-sm font-semibold text-foreground/90">Choose your wallet type</Label>
                  <div className="grid grid-cols-2 gap-3">
                    <button
                      onClick={() => setFormData({ ...formData, walletType: 'timed' })}
                      className={`p-4 rounded-lg border-2 transition-all duration-300 text-center ${formData.walletType === 'timed'
                        ? 'border-primary bg-primary/10 shadow-md'
                        : 'border-border/20 bg-background-secondary hover:border-primary/50 hover:bg-primary/5'
                        }`}
                    >
                      <div className="flex flex-col items-center gap-2">
                        <div className={`w-4 h-4 rounded-full border-2 ${formData.walletType === 'timed' ? 'border-primary bg-primary' : 'border-muted-foreground'
                          }`}>
                          {formData.walletType === 'timed' && <div className="w-2 h-2 bg-primary-foreground rounded-full mx-auto mt-0.5" />}
                        </div>
                        <div>
                          <h3 className="text-sm font-semibold">Timed Wallet</h3>
                          <p className="text-xs text-muted-foreground">See how much your purchases cost in work hours</p>
                        </div>
                      </div>
                    </button>
                    <button
                      onClick={() => setFormData({ ...formData, walletType: 'normal' })}
                      className={`p-4 rounded-lg border-2 transition-all duration-300 text-center ${formData.walletType === 'normal'
                        ? 'border-primary bg-primary/10 shadow-md'
                        : 'border-border/20 bg-background-secondary hover:border-primary/50 hover:bg-primary/5'
                        }`}
                    >
                      <div className="flex flex-col items-center gap-2">
                        <div className={`w-4 h-4 rounded-full border-2 ${formData.walletType === 'normal' ? 'border-primary bg-primary' : 'border-muted-foreground'
                          }`}>
                          {formData.walletType === 'normal' && <div className="w-2 h-2 bg-primary-foreground rounded-full mx-auto mt-0.5" />}
                        </div>
                        <div>
                          <h3 className="text-sm font-semibold">Normal Wallet</h3>
                          <p className="text-xs text-muted-foreground">Standard wallet without time tracking features</p>
                        </div>
                      </div>
                    </button>
                  </div>
                </div>
              </div>
            )}

            {/* Step 3 - Earnings */}
            {step === 3 && (
              <div className="space-y-4">
                <div className="space-y-3">
                  <Label className="text-sm font-medium">How do you want to enter your pay?</Label>
                  <div className="grid grid-cols-2 gap-2">
                    <button
                      type="button"
                      onClick={() => setFormData({ ...formData, payInputMode: 'monthly' })}
                      className={`p-3 rounded-lg border text-sm font-medium transition-colors ${formData.payInputMode === 'monthly'
                        ? 'border-primary bg-primary/10 text-primary'
                        : 'border-border/40 bg-background-secondary text-foreground/80'
                        }`}
                    >
                      Monthly pay
                    </button>
                    <button
                      type="button"
                      onClick={() => setFormData({ ...formData, payInputMode: 'hourly' })}
                      className={`p-3 rounded-lg border text-sm font-medium transition-colors ${formData.payInputMode === 'hourly'
                        ? 'border-primary bg-primary/10 text-primary'
                        : 'border-border/40 bg-background-secondary text-foreground/80'
                        }`}
                    >
                      Hourly pay
                    </button>
                  </div>
                </div>
                <div className="space-y-3">
                  <div className="space-y-2">
                    <Label className="text-sm font-medium">
                      {formData.payInputMode === 'hourly' ? 'Hourly Income' : 'Monthly Income'}
                    </Label>
                    <div className="flex gap-2">
                      <Select value={formData.currency} onValueChange={(value) => setFormData({ ...formData, currency: value })}>
                        <SelectTrigger className="w-20 h-10">
                          <SelectValue />
                        </SelectTrigger>
                        <SelectContent>
                          {ONBOARDING_CURRENCIES.map((currency) => (
                            <SelectItem key={currency.value} value={currency.value}>
                              {currency.label}
                            </SelectItem>
                          ))}
                        </SelectContent>
                      </Select>
                      <Input
                        type="number"
                        placeholder="5000"
                        value={formData.payInputMode === 'hourly' ? formData.hourlyEarning : formData.monthlyEarning}
                        onChange={(e) => setFormData({
                          ...formData,
                          ...(formData.payInputMode === 'hourly'
                            ? { hourlyEarning: e.target.value }
                            : { monthlyEarning: e.target.value })
                        })}
                        className="flex-1 h-10"
                      />
                    </div>
                    <p className="text-xs text-muted-foreground">
                      {formData.payInputMode === 'hourly'
                        ? 'Enter your pay per hour. Monthly earnings will be estimated from your schedule.'
                        : 'Enter your monthly income. Hourly rate will be derived from your schedule.'}
                    </p>
                  </div>
                </div>
              </div>
            )}

            {/* Step 4 - Schedule */}
            {step === 4 && (
              <div className="space-y-4">
                <div className="text-center space-y-2">
                  <p className="text-sm text-muted-foreground">
                    Tell us your daily and weekly work schedule for better pay calculations
                  </p>
                </div>

                <div className="grid grid-cols-1 gap-4">
                  <div className="space-y-2">
                    <Label className="text-sm font-medium">How many hours do you work per day?</Label>
                    <Input
                      type="number"
                      min="1"
                      max="24"
                      placeholder="e.g., 8"
                      value={formData.workingHoursPerDay}
                      onChange={(e) => setFormData({ ...formData, workingHoursPerDay: e.target.value })}
                      className="h-12 text-base"
                    />
                    <p className="text-xs text-muted-foreground">
                      Typical work hours per day (e.g., 8 for full-time)
                    </p>
                  </div>
                  <div className="space-y-2">
                    <Label className="text-sm font-medium">How many days do you work per week?</Label>
                    <Input
                      type="number"
                      min="1"
                      max="7"
                      placeholder="e.g., 5"
                      value={formData.workingDaysPerWeek}
                      onChange={(e) => setFormData({ ...formData, workingDaysPerWeek: e.target.value })}
                      className="h-12 text-base"
                    />
                    <p className="text-xs text-muted-foreground">
                      Working days in a typical week (e.g., 5 excluding weekends)
                    </p>
                  </div>
                </div>

                {(formData.workingHoursPerDay && formData.workingDaysPerWeek) && (
                  <div className="p-4 bg-primary/10 rounded-lg border border-primary/20">
                    <div className="text-center space-y-2">
                      <div className="text-lg font-bold text-primary">
                        Your hourly rate: {formData.currency} {hourlyRate}/hr
                      </div>
                      <div className="text-sm text-muted-foreground">
                        Based on {(parsedHoursPerDay * parsedDaysPerMonth).toFixed(1)} working hours per month
                      </div>
                      <div className="text-xs text-muted-foreground/80">
                        Estimated monthly income: {formData.currency} {resolvedMonthlyEarning.toFixed(2)}
                      </div>
                    </div>
                  </div>
                )}
              </div>
            )}

            {/* Step 5 - Security */}
            {step === 5 && (
              <div className="space-y-4">

                <div className="space-y-3">
                  <div className="flex items-center justify-between p-3 bg-background-secondary rounded-lg border">
                    <div className="flex items-center gap-3">
                      <div className="w-8 h-8 bg-primary/10 rounded-lg flex items-center justify-center">
                        <Lock className="w-4 h-4 text-primary" />
                      </div>
                      <div>
                        <p className="font-medium text-sm">PIN Protection</p>
                        <p className="text-xs text-muted-foreground">Secure your wallet</p>
                      </div>
                    </div>
                    <Checkbox
                      id="enable-security"
                      checked={formData.enableSecurity}
                      onCheckedChange={(checked) => setFormData({ ...formData, enableSecurity: !!checked })}
                    />
                  </div>

                  {formData.enableSecurity && (
                    <div className="space-y-3 animate-in slide-in-from-top-2 duration-300">
                      <div className="space-y-2">
                        <Label className="text-sm font-medium">Create PIN (6 digits)</Label>
                        <div className="flex justify-center">
                          <InputOTP
                            maxLength={6}
                            value={formData.pin}
                            onChange={(value) => setFormData({ ...formData, pin: value })}
                          >
                            <InputOTPGroup className="gap-1">
                              {Array.from({ length: 6 }).map((_, i) => (
                                <InputOTPSlot key={i} index={i} className="w-10 h-10 text-sm" />
                              ))}
                            </InputOTPGroup>
                          </InputOTP>
                        </div>
                      </div>

                      <div className="space-y-2">
                        <Label className="text-sm font-medium">Confirm PIN</Label>
                        <div className="flex justify-center">
                          <InputOTP
                            maxLength={6}
                            value={formData.confirmPin}
                            onChange={(value) => setFormData({ ...formData, confirmPin: value })}
                          >
                            <InputOTPGroup className="gap-1">
                              {Array.from({ length: 6 }).map((_, i) => (
                                <InputOTPSlot key={i} index={i} className="w-10 h-10 text-sm" />
                              ))}
                            </InputOTPGroup>
                          </InputOTP>
                        </div>
                      </div>

                      {formData.pin && formData.confirmPin && formData.pin !== formData.confirmPin && (
                        <p className="text-sm text-destructive text-center">PINs do not match</p>
                      )}
                    </div>
                  )}
                </div>
              </div>
            )}

            {/* Step 6 - Perfect! */}
            {step === 6 && (
              <div className="space-y-4">
                <div className="grid grid-cols-2 gap-3">
                  {features.map((feature, index) => (
                    <div key={index} className="p-3 rounded-lg bg-background-secondary border">
                      <feature.icon className={`w-5 h-5 ${feature.color} mb-2`} />
                      <h3 className="font-semibold text-sm">{feature.title}</h3>
                      <p className="text-xs text-muted-foreground">{feature.description}</p>
                    </div>
                  ))}
                </div>

                <div className="p-3 bg-primary/10 rounded-lg border border-primary/20">
                  <div className="text-center">
                    <p className="text-sm font-medium text-primary">
                      Welcome, {formData.name}! 👋
                    </p>
                    <p className="text-xs text-muted-foreground mt-1">
                      Your hourly rate: {formData.currency} {hourlyRate}
                    </p>
                  </div>
                </div>
              </div>
            )}

            {/* Navigation */}
            <div className="flex gap-3 mt-6">
              {step > 0 && (
                <Button
                  variant="outline"
                  onClick={handleBack}
                  className="flex-1 h-10"
                  disabled={isLoading}
                >
                  <ArrowLeft className="w-4 h-4 mr-2" />
                  Back
                </Button>
              )}

              {step < maxStep ? (
                <Button
                  onClick={handleNext}
                  className="flex-1 h-10 bg-primary hover:bg-primary-light"
                  disabled={isLoading}
                >
                  Continue
                  <ArrowRight className="w-4 h-4 ml-2" />
                </Button>
              ) : (
                <Button
                  onClick={handleComplete}
                  className="flex-1 h-10 bg-primary hover:bg-primary-light"
                  disabled={isLoading}
                >
                  {isLoading ? (
                    <div className="w-4 h-4 border-2 border-white/30 border-t-white rounded-full animate-spin mr-2" />
                  ) : (
                    <Sparkles className="w-4 h-4 mr-2" />
                  )}
                  {isLoading ? 'Setting up...' : 'Start Journey'}
                </Button>
              )}
            </div>
          </CardContent>
        </Card>

        {/* Step Indicators */}
        <div className="flex justify-center mt-6">
          <div className="flex gap-2">
            {Array.from({ length: maxStep + 1 }).map((_, i) => {
              const stepNum = i;
              const isActive = stepNum === step;
              const isCompleted = stepNum < step;

              return (
                <div
                  key={stepNum}
                  className={`w-2 h-2 rounded-full transition-all duration-300 ${isActive
                    ? 'bg-primary scale-125'
                    : isCompleted
                      ? 'bg-primary/70'
                      : 'bg-muted-foreground/30'
                    }`}
                />
              );
            })}
          </div>
        </div>
      </div>
    </div>
  );
}

"use client"

import { UpcomingIPO } from "@/types/wallet"
import {
    Dialog,
    DialogContent,
    DialogHeader,
    DialogTitle,
} from "@/components/ui/dialog"
import { Badge } from "@/components/ui/badge"
import {
    Calendar,
    Info,
    Clock,
    ExternalLink,
    X,
    Activity,
    LayoutGrid,
    Sparkles,
    CreditCard,
    ArrowRight,
    CheckCircle2,
    AlertCircle,
    BellRing,
    History
} from "lucide-react"
import { cn } from "@/lib/utils"
import { Button } from "@/components/ui/button"
import { useWalletData } from "@/contexts/wallet-data-context"
import { toast } from "sonner"
import { useEffect, useRef, useState } from "react"
import { useRouter } from "next/navigation"

interface IPODetailModalProps {
    ipo: UpcomingIPO | null
    open: boolean
    onOpenChange: (open: boolean) => void
}

export function IPODetailModal({ ipo, open, onOpenChange }: IPODetailModalProps) {
    const router = useRouter()
    const { userProfile, checkIPOAllotment, applyMeroShareIPO } = useWalletData()
    const [isApplying, setIsApplying] = useState(false)
    const [isCheckingResult, setIsCheckingResult] = useState(false)
    const [hasAppliedInSession, setHasAppliedInSession] = useState(false)
    const autoApplySessionRef = useRef<string | null>(null)
    const hasMeroShareCredentials = Boolean(
        userProfile?.meroShare?.dpId &&
        userProfile?.meroShare?.username &&
        userProfile?.meroShare?.password &&
        userProfile?.meroShare?.crn &&
        userProfile?.meroShare?.pin
    )
    const canAutomate = Boolean(
        userProfile?.meroShare?.shareFeaturesEnabled &&
        userProfile?.meroShare?.isAutomatedEnabled &&
        hasMeroShareCredentials
    )
    const applyMode = userProfile?.meroShare?.applyMode || "on-demand"
    const normalizeIpoName = (value?: string) =>
        (value || "")
            .toLowerCase()
            .replace(/\b(limited|ltd|public|private|pvt|co|company|inc)\b/g, "")
            .replace(/[().,-]/g, "")
            .replace(/\s+/g, " ")
            .trim()
    const hasAppliedLog = Boolean(
        userProfile?.meroShare?.applicationLogs?.some(
            (log) =>
                log.action === "apply" &&
                log.status === "success" &&
                normalizeIpoName(log.ipoName) === normalizeIpoName(ipo?.company)
        )
    )
    const isAppliedForIpo = hasAppliedInSession || hasAppliedLog
    const openMeroShareSettings = () => {
        onOpenChange(false)
        router.push("/settings?tab=meroshare")
    }

    const handleAutomatedApply = async (
        showBrowser = false,
        source: "live-apply" | "live-auto" = "live-apply",
        closeOnSuccess = true
    ) => {
        const credentials = userProfile?.meroShare
        if (!canAutomate) {
            toast.error("MeroShare automation setup is incomplete.", {
                description: "Open Settings > MeroShare to enable automation and complete credentials."
            })
            return
        }
        if (!credentials?.dpId || !credentials.username || !credentials.password || !credentials.crn || !credentials.pin) {
            toast.error("Missing Mero Share credentials. Please complete your setup in Settings.")
            return
        }

        setIsApplying(true)
        const promise = applyMeroShareIPO(
            credentials,
            ipo?.company || "",
            10,
            source,
            { showBrowser: showBrowser || Boolean(userProfile?.meroShare?.showLiveBrowser) }
        )

        toast.promise(promise, {
            loading: source === "live-auto"
                ? `Auto-applying for ${ipo?.company}...`
                : `Applying for ${ipo?.company}... This may take a few seconds.`,
            success: (data) => {
                setIsApplying(false)
                setHasAppliedInSession(true)
                if (closeOnSuccess) onOpenChange(false)
                if (data?.alreadyApplied) {
                    return data.message || "Already applied earlier. No new apply action was submitted."
                }
                return data.message || "Applied successfully!"
            },
            error: (err) => {
                setIsApplying(false)
                return err.message
            }
        })
    }

    useEffect(() => {
        if (!open || !ipo || ipo.status !== "open" || !canAutomate || applyMode !== "automatic" || isAppliedForIpo) return
        const key = `${ipo.company}|${ipo.status}|${open}`
        if (autoApplySessionRef.current === key || isApplying || isCheckingResult) return
        autoApplySessionRef.current = key
        void handleAutomatedApply(false, "live-auto", false)
    }, [open, ipo?.company, ipo?.status, canAutomate, applyMode, isApplying, isCheckingResult, isAppliedForIpo])

    const handleCheckAllotment = async () => {
        const credentials = userProfile?.meroShare
        if (!canAutomate) {
            toast.error("Mero Share setup required", { description: "Please setup your credentials in Settings to check allotment." })
            return
        }
        if (!credentials) {
            toast.error("Missing Mero Share credentials. Please complete your setup in Settings.")
            return
        }

        setIsCheckingResult(true)
        const promise = checkIPOAllotment(credentials, ipo?.company || "", "live-check")

        toast.promise(promise, {
            loading: `Checking allotment for ${ipo?.company}...`,
            success: (data) => {
                setIsCheckingResult(false)
                if (data.isAllotted) {
                    return `Congratulations! You were allotted ${data.allottedQuantity} units.`
                } else {
                    return `Not Allotted: ${data.status}`
                }
            },
            error: (err) => {
                setIsCheckingResult(false)
                return err.message
            }
        })
    }

    // Determine status colors and labels
    const statusLabel = ipo?.status === 'open' ? 'Closing in' :
        ipo?.status === 'upcoming' ? 'Opening in' :
            'Closed';

    const statusColor = ipo?.status === 'open' ? 'text-success bg-success/10 border-success/20' :
        ipo?.status === 'upcoming' ? 'text-info bg-info/10 border-info/20' :
            'text-muted-foreground bg-muted/20 border-muted/30';

    // Helper to get actionable advice based on status
    const getActionableAdvice = () => {
        if (!ipo) return null;
        switch (ipo.status) {
            case 'open':
                if (isAppliedForIpo) {
                    return {
                        title: "Already Applied",
                        description: "This IPO is already applied from your account. You can check result/status now.",
                        icon: <CheckCircle2 className="w-5 h-5 text-success" />,
                        bgColor: "bg-success/5",
                        borderColor: "border-success/20"
                    };
                }
                return {
                    title: "Application is Live!",
                    description: canAutomate
                        ? `You can apply now for 10 units of ${ipo.company}.`
                        : "Set up MeroShare automation once, then apply from this screen in one click.",
                    icon: <CheckCircle2 className="w-5 h-5 text-success" />,
                    bgColor: "bg-success/5",
                    borderColor: "border-success/20"
                };
            case 'upcoming':
                return {
                    title: "Ready to invest?",
                    description: `Opens on ${ipo.openingDay || 'the scheduled date'}. Keep NPR 1,000 ready in your account.`,
                    icon: <BellRing className="w-5 h-5 text-info animate-bounce" />,
                    bgColor: "bg-info/5",
                    borderColor: "border-info/20"
                };
            case 'closed':
            default:
                return {
                    title: "Check Results",
                    description: "The subscription has ended. You can now use our automation to check if you've been allotted any units.",
                    icon: <History className="w-5 h-5 text-indigo-500" />,
                    bgColor: "bg-indigo-500/5",
                    borderColor: "border-indigo-500/20"
                };
        }
    };

    const advice = getActionableAdvice();

    return (
        <Dialog open={open} onOpenChange={onOpenChange}>
            {ipo && (
                <DialogContent className="max-w-md rounded-3xl border-primary/20 bg-card/95 backdrop-blur-xl shadow-2xl p-0 overflow-hidden flex flex-col gap-0 max-h-[85vh] sm:max-h-[90vh]" showCloseButton={false}>
                    {/* Visual Decor */}
                    <div className="absolute top-0 right-0 w-24 h-24 bg-primary/10 rounded-full blur-2xl -mr-12 -mt-12 pointer-events-none" />

                    <DialogHeader className="p-4 pb-3 sm:p-6 sm:pb-4 bg-gradient-to-br from-primary/10 via-transparent to-transparent relative z-20 shrink-0 border-b border-primary/5">
                        <Button
                            variant="ghost"
                            size="icon"
                            className="absolute right-4 top-4 h-8 w-8 rounded-full bg-background/50 backdrop-blur-sm hover:bg-muted text-muted-foreground transition-all z-50 border border-muted-foreground/10"
                            onClick={() => onOpenChange(false)}
                        >
                            <X className="h-4 w-4" />
                        </Button>

                        <div className="flex items-center justify-between mb-2 sm:mb-3 pr-8">
                            <Badge variant="outline" className="text-[10px] font-black uppercase tracking-[0.2em] border-primary/30 text-primary bg-primary/5 px-2.5 py-1">
                                Investment Alert
                            </Badge>
                            {ipo.scraped_at && (
                                <div className="hidden sm:flex items-center gap-1.5 opacity-50">
                                    <Clock className="w-3 h-3" />
                                    <span className="text-[10px] font-black uppercase tracking-widest">
                                        Data Sync: {new Date(ipo.scraped_at).toLocaleDateString()}
                                    </span>
                                </div>
