"use client"

import { useEffect, useState, useCallback, useRef } from 'react'
import { toast } from 'sonner'

export function usePWAUpdate() {
  const [isSupported, setIsSupported] = useState<boolean>(false)
  const [isUpdateAvailable, setIsUpdateAvailable] = useState<boolean>(false)
  const [waitingWorker, setWaitingWorker] = useState<ServiceWorker | null>(null)
  const [autoUpdate, setAutoUpdateState] = useState<boolean>(() => {
    try {
      const v = localStorage.getItem('pwa_auto_update')
      // default to enabled unless explicitly set to '0'
      if (v === null) return true
      return v === '1'
    } catch (e) {
      return true
    }
  })
  const updateInitiatedRef = useRef<boolean>(false)
  const reloadingRef = useRef(false)
  const lastUpdateCheckRef = useRef<number>(0)

  useEffect(() => {
    setIsSupported('serviceWorker' in navigator)

    if (!('serviceWorker' in navigator)) return

    let regReady = false

    const handleReg = async () => {
      try {
        const reg = await navigator.serviceWorker.getRegistration()
        if (!reg) return

        // if a waiting worker already exists
        if (reg.waiting) {
          setWaitingWorker(reg.waiting)
          setIsUpdateAvailable(true)
        }

        reg.addEventListener('updatefound', () => {
           const installing = reg.installing
           if (!installing) return
           installing.addEventListener('statechange', () => {
             if (installing.state === 'installed') {
               if (reg.waiting) {
                 setWaitingWorker(reg.waiting)
                 setIsUpdateAvailable(true)
                 // Only auto-apply update if autoUpdate is enabled
                 if (autoUpdate) {
                   toast.info('Update detected, auto updating...')
                   reg.waiting.postMessage({ type: 'SKIP_WAITING' })
                   updateInitiatedRef.current = true
                   try { localStorage.setItem('sw:update:requested', Date.now().toString()) } catch (e) {}
                 }
               }
             }
           })
         })

        regReady = true
      } catch (e) {
        // ignore
      }
    }

    handleReg()

    // helper: delete only known SW/app caches to avoid deleting user data
    const clearSWCaches = async () => {
      if (!('caches' in window)) return
      try {
        const keys = await caches.keys()
        const toDelete = keys.filter(name => /workbox|precache|next|static-resources|next-static|images|start-url|runtime/i.test(name))
        await Promise.all(toDelete.map(k => caches.delete(k)))
      } catch (e) {
        // ignore
      }
    }

    // reload when the new SW takes control; clear old caches first
    const onControllerChange = async () => {
      // Reload only for updates we initiated (manual or auto), not for first install.
      if (!updateInitiatedRef.current || reloadingRef.current) return
      reloadingRef.current = true
      try {
        await clearSWCaches()
      } catch (e) {
        // ignore
      }
      // mark that update was applied so UI can show success after reload (other tabs may read this)
      try { localStorage.setItem('sw:update:applied', Date.now().toString()) } catch (e) {}
      window.location.reload()
    }
    navigator.serviceWorker.addEventListener('controllerchange', onControllerChange)
  // on online, check for updates (with rate limiting)
    const onOnline = async () => {
      const now = Date.now()
      // Only check for updates if it's been more than 5 minutes since last check
      if (now - lastUpdateCheckRef.current < 5 * 60 * 1000) return
      lastUpdateCheckRef.current = now
      try {
        const reg = await navigator.serviceWorker.getRegistration()
        if (!reg) return
        await reg.update()
      } catch (e) {
        // ignore
      }
    }

    window.addEventListener('online', onOnline)

    // listen for update requests from other tabs so we can reflect update state
    const onStorage = (ev: StorageEvent) => {
      if (!ev.key) return
      if (ev.key === 'sw:update:requested') {
        // another tab asked to update; re-check registration so we update UI
        (async () => {
          try {
            const reg = await navigator.serviceWorker.getRegistration()
            if (reg && reg.waiting) {
              setWaitingWorker(reg.waiting)
              setIsUpdateAvailable(true)
            }
          } catch (e) {}
        })()
      }
      if (ev.key === 'sw:update:applied') {
        // ensure UI state clears in case a different tab applied update
        setIsUpdateAvailable(false)
        setWaitingWorker(null)
      }
    }
    window.addEventListener('storage', onStorage)

    return () => {
      navigator.serviceWorker.removeEventListener('controllerchange', onControllerChange)
      window.removeEventListener('online', onOnline)
      window.removeEventListener('storage', onStorage)
    }
  }, [autoUpdate])

  const applyUpdate = useCallback(async () => {
    try {
      const reg = await navigator.serviceWorker.getRegistration()
      if (reg && reg.waiting) {
        try {
          reg.waiting.postMessage({ type: 'SKIP_WAITING' })
          updateInitiatedRef.current = true
          try { localStorage.setItem('sw:update:requested', Date.now().toString()) } catch (e) {}
        } catch (e) {}
      }
    } catch (e) {
      // ignore
    }
  }, [])

  const checkForUpdate = useCallback(async () => {
    try {
      const reg = await navigator.serviceWorker.getRegistration()
      if (!reg) return
      await reg.update()
      if (reg.waiting) {
        setWaitingWorker(reg.waiting)
        setIsUpdateAvailable(true)
      } else {
        setIsUpdateAvailable(false)
      }
    } catch (e) {
      // ignore
    }
  }, [])

  const setAutoUpdate = useCallback((v: boolean) => {
    try { localStorage.setItem('pwa_auto_update', v ? '1' : '0') } catch {}
    setAutoUpdateState(v)
  }, [])

  return {
    isSupported,
    isUpdateAvailable,
    waitingWorker,
    autoUpdate,
    setAutoUpdate,
    applyUpdate,
    checkForUpdate
  }
}

export default usePWAUpdate

"use client"

import { useState, useEffect } from "react"
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card"
import { Button } from "@/components/ui/button"
import { Badge } from "@/components/ui/badge"
import { Dialog, DialogContent, DialogHeader, DialogTitle, DialogTrigger } from "@/components/ui/dialog"
import { Alert, AlertDescription } from "@/components/ui/alert"
import {
  Fingerprint,
  Shield,
  CheckCircle2,
  AlertTriangle,
  Settings,
  Lock,
  Unlock
} from "lucide-react"
import { SecureKeyManager } from "@/lib/key-manager"
import {
  clearBiometricKeyData,
  ensureBiometricPrfSalt,
  getBiometricCredentialId,
  hasWrappedBiometricPin,
  setBiometricEnabled,
  unwrapPinWithBiometric,
  wrapPinWithBiometric,
} from "@/lib/biometric-key"

interface BiometricAuthProps {
  pinEnabled?: boolean
  onAuthenticated?: () => void
  onError?: (error: string) => void
}

export function BiometricAuth({ pinEnabled = false, onAuthenticated, onError }: BiometricAuthProps) {
  const [isSupported, setIsSupported] = useState(false)
  const [isEnrolled, setIsEnrolled] = useState(false)
  const [isKeyWrapped, setIsKeyWrapped] = useState(false)
  const [isAuthenticating, setIsAuthenticating] = useState(false)
  const [authError, setAuthError] = useState<string | null>(null)
  const [credentialId, setCredentialId] = useState<string | null>(null)

  useEffect(() => {
    checkBiometricSupport()
    checkExistingCredentials()
  }, [])

  const checkBiometricSupport = async () => {
    // Check if we're in a secure context
    const isSecureContext = window.location.protocol === 'https:' || window.location.hostname === 'localhost'

    if (!isSecureContext) {
      setIsSupported(false)
      setAuthError('Biometric authentication requires HTTPS or localhost. Please access the app securely.')
      return
    }

    if (!window.PublicKeyCredential) {
      setIsSupported(false)
      setAuthError('Your browser does not support Web Authentication API.')
      return
    }

    try {
      const available = await PublicKeyCredential.isUserVerifyingPlatformAuthenticatorAvailable()
      setIsSupported(available)
      if (!available) {
        setAuthError('No biometric authenticator available on this device. Please ensure you have a screen lock (PIN, pattern, or fingerprint) set up in your device settings.')
      }
    } catch (error) {
      setIsSupported(false)
      setAuthError('Error checking biometric support. This can happen if the site is not served over HTTPS or if biometric hardware is not available.')
    }
  }

  const checkExistingCredentials = () => {
    const storedCredentialId = getBiometricCredentialId()
    if (storedCredentialId) {
      setIsEnrolled(true)
      setCredentialId(storedCredentialId)
      setIsKeyWrapped(hasWrappedBiometricPin())
    } else {
      setIsEnrolled(false)
      setIsKeyWrapped(false)
    }
  }

  const getConsistentUserId = () => {
    let userId = localStorage.getItem('wallet_biometric_user_id')
    if (!userId) {
      // Generate a consistent user ID and store it
      const array = new Uint8Array(16)
      crypto.getRandomValues(array)
      userId = btoa(String.fromCharCode(...array))
      localStorage.setItem('wallet_biometric_user_id', userId)
    }
    return Uint8Array.from(atob(userId), c => c.charCodeAt(0))
  }

  const enrollBiometric = async () => {
    if (!isSupported) {
      const error = 'Biometric authentication is not supported on this device'
      setAuthError(error)
      onError?.(error)
      return
    }

    try {
      setIsAuthenticating(true)
      setAuthError(null)

      // Create credential creation options
      const challenge = new Uint8Array(32)
      crypto.getRandomValues(challenge)

      const prfSalt = ensureBiometricPrfSalt()

      const createCredentialOptions: PublicKeyCredentialCreationOptions = {
        challenge,
        rp: {
          name: 'MyWallet',
          id: window.location.hostname
        },
        user: {
          id: getConsistentUserId(),
          name: 'wallet-user',
          displayName: 'MyWallet User'
        },
        pubKeyCredParams: [
          { alg: -7, type: 'public-key' }, // ES256
          { alg: -257, type: 'public-key' } // RS256
        ],
        authenticatorSelection: {
          authenticatorAttachment: 'platform',
          userVerification: 'required',
          requireResidentKey: false
        },
        timeout: 60000,
        attestation: 'direct',
        extensions: {
          prf: { eval: { first: prfSalt } },
          hmacCreateSecret: true,
        } as any,
      }

      const credential = await navigator.credentials.create({
        publicKey: createCredentialOptions
      }) as PublicKeyCredential

      if (credential) {
        // Store credential ID for future authentication
        const credentialId = btoa(String.fromCharCode(...new Uint8Array(credential.rawId)))
        localStorage.setItem('wallet_biometric_credential_id', credentialId)

        setIsEnrolled(true)
        setCredentialId(credentialId)

        const cachedPin = SecureKeyManager.getCachedSessionPin()
        if (!cachedPin) {
          setBiometricEnabled(false)
          setIsKeyWrapped(false)
          setAuthError("Biometric enrolled. Unlock once with your PIN to finish setup.")
          return
        }

        const wrapped = await wrapPinWithBiometric(cachedPin)
        if (!wrapped) {
          setBiometricEnabled(false)
          setIsKeyWrapped(false)
          setAuthError("Biometric enrolled, but secure key storage isn't supported on this device.")
          return
        }

        setIsKeyWrapped(true)
        console.log('Biometric enrollment successful')
      }

    } catch (error) {
      console.error('Biometric enrollment failed:', error)
      let errorMessage = 'Biometric enrollment failed'

      if (error instanceof Error) {
        switch (error.name) {
          case 'NotAllowedError':
            errorMessage = 'Biometric enrollment was cancelled or denied. Please try again and allow access.'
            break
          case 'NotSupportedError':
            errorMessage = 'This device does not support biometric authentication.'
            break
          case 'SecurityError':
            errorMessage = 'Security error: Please ensure you\'re accessing the app securely (HTTPS or localhost).'
            break
          case 'AbortError':
            errorMessage = 'Biometric enrollment was cancelled.'
            break
          case 'InvalidStateError':
            errorMessage = 'Biometric credentials already exist. Please disable first if you want to re-enroll.'
            break
          default:
            errorMessage = `Enrollment failed: ${error.message}`
        }
      }

      setAuthError(errorMessage)
      if (error instanceof Error && (error.name === 'NotAllowedError' || error.name === 'AbortError')) {
        setAuthError(errorMessage + " Tip: Make sure your device screen lock (PIN/Biometric) is enabled in device settings.")
      }
      onError?.(errorMessage)
    } finally {
      setIsAuthenticating(false)
    }
  }

  const authenticateBiometric = async () => {
    if (!isSupported || !isEnrolled || !credentialId) {
      const error = 'Biometric authentication is not properly configured'
      setAuthError(error)
      onError?.(error)
      return
    }

    try {
      setIsAuthenticating(true)
      setAuthError(null)
      const pin = await unwrapPinWithBiometric()
      if (!pin) {
        setAuthError("Biometric unlock is not available. Please unlock once with your PIN.")
        onError?.("Biometric unlock failed")
        return
      }
      onAuthenticated?.()

    } catch (error) {
      let errorMessage = 'Biometric authentication failed'

      if (error instanceof Error) {
        switch (error.name) {
          case 'NotAllowedError':
            errorMessage = 'Biometric authentication was cancelled or denied. Please try again.'
            break
          case 'SecurityError':
            errorMessage = 'Security error: Please ensure you\'re accessing the app securely (HTTPS or localhost).'
            break
          case 'AbortError':
            errorMessage = 'Biometric authentication was cancelled.'
            break
          case 'NotSupportedError':
            errorMessage = 'Biometric authentication is not supported on this device.'
            break
          default:
            errorMessage = `Authentication failed: ${error.message}`
        }
      }

      setAuthError(errorMessage)
      if (error instanceof Error && (error.name === 'NotAllowedError' || error.name === 'AbortError')) {
        setAuthError(errorMessage + " Tip: Make sure your device is unlocked and screen lock is configured.")
      }
      onError?.(errorMessage)
    } finally {
      setIsAuthenticating(false)
    }
  }

  const disableBiometric = () => {
    clearBiometricKeyData()
    setIsEnrolled(false)
    setCredentialId(null)
    setIsKeyWrapped(false)
    setAuthError(null)
  }

  const getBrowserSupportInfo = () => {
    const userAgent = navigator.userAgent
    const isChrome = /Chrome/.test(userAgent) && /Google Inc/.test(navigator.vendor)
    const isFirefox = /Firefox/.test(userAgent)
    const isSafari = /Safari/.test(userAgent) && /Apple Computer/.test(navigator.vendor)
    const isEdge = /Edg/.test(userAgent)

    return { isChrome, isFirefox, isSafari, isEdge }
  }

  if (!pinEnabled) {
    return (
      <Card>
        <CardHeader>
          <CardTitle className="flex items-center gap-2">
            <Fingerprint className="w-5 h-5" />
            Biometric Authentication
          </CardTitle>
        </CardHeader>
        <CardContent className="space-y-4">
          <Alert className="border-primary/20 bg-primary/5">
            <AlertTriangle className="w-4 h-4 text-primary" />
            <AlertDescription className="text-primary">
              <strong>PIN Required</strong>Biometric authentication requires PIN protection to be enabled first. Please set up your PIN in the section above.
            </AlertDescription>
          </Alert>
        </CardContent>
      </Card>
    )
  }

  return (
    <div className="space-y-4">
      <Card>
        <CardHeader>
          <CardTitle className="flex items-center gap-2">
            <Fingerprint className="w-5 h-5" />
            Biometric Authentication
          </CardTitle>
        </CardHeader>
        <CardContent className="space-y-4">
          {/* Status */}
          <div className="flex items-center justify-between">
            <div className="flex items-center gap-2">
              <div className={`w-3 h-3 rounded-full ${
                isSupported ? (isEnrolled ? 'bg-green-500' : 'bg-yellow-500') : 'bg-red-500'
              }`} />
              <span className="text-sm">
                {isSupported
                  ? (isEnrolled
                    ? (isKeyWrapped ? 'Biometric authentication enabled' : 'Biometric enrolled; finish setup with PIN')
                    : 'Biometric available but not enrolled')
                  : 'Biometric authentication not supported'
                }
              </span>
            </div>
            <Badge variant={isEnrolled ? 'default' : 'secondary'}>
              {isEnrolled ? (isKeyWrapped ? 'Enabled' : 'Pending') : 'Disabled'}
            </Badge>
          </div>

          {/* Browser Info */}
          {!isSupported && (
            <div className="p-3 bg-blue-50 border border-blue-200 rounded-lg">
              <div className="flex items-center gap-2">
                <Settings className="w-4 h-4 text-blue-600" />
                <span className="text-sm text-blue-700">
                  For best compatibility, use Chrome, Firefox, Safari, or Edge on a secure connection (HTTPS).
                </span>
              </div>
            </div>
          )}

          {/* Error Message */}
          {authError && (
            <div className="p-3 bg-red-50 border border-red-200 rounded-lg">
              <div className="flex items-center gap-2">
                <AlertTriangle className="w-4 h-4 text-red-600" />
                <span className="text-sm text-red-700">{authError}</span>
              </div>
            </div>
          )}

          {/* Actions */}
          <div className="flex gap-2">
            {!isEnrolled ? (
              <Button
                onClick={enrollBiometric}
                disabled={!isSupported || isAuthenticating}
                className="flex items-center gap-2"
              >
                <Shield className="w-4 h-4" />
                {isAuthenticating ? 'Enrolling...' : 'Enable Biometric'}
              </Button>
            ) : (
              <>
                <Button
                  onClick={authenticateBiometric}
                  disabled={isAuthenticating || !isKeyWrapped}
                  className="flex items-center gap-2"
                >
                  <Unlock className="w-4 h-4" />
                  {isAuthenticating ? 'Authenticating...' : 'Authenticate'}
                </Button>
                {!isKeyWrapped && (
                  <Button
                    variant="outline"
                    onClick={async () => {
                      const cachedPin = SecureKeyManager.getCachedSessionPin()
                      if (!cachedPin) {
                        setAuthError("Please unlock once with your PIN to finish setup.")
                        return
                      }
                      setIsAuthenticating(true)
                      try {
                        const wrapped = await wrapPinWithBiometric(cachedPin)
                        if (!wrapped) {
                          setAuthError("Secure biometric storage isn't supported on this device.")
                          return
                        }
                        setIsKeyWrapped(true)
                        setAuthError(null)
                      } finally {
                        setIsAuthenticating(false)
                      }
                    }}
                    className="flex items-center gap-2"
                  >
                    <Shield className="w-4 h-4" />
                    Finish Setup
                  </Button>
                )}
                <Button
                  variant="outline"
                  onClick={disableBiometric}
                  className="flex items-center gap-2"
                >
                  <Lock className="w-4 h-4" />
                  Disable
                </Button>
              </>
            )}
          </div>

          {/* Information */}
          <div className="text-xs text-muted-foreground space-y-1">
            <p>• Biometric authentication uses your device's fingerprint or face recognition</p>
            <p>• Your biometric data never leaves your device and is stored securely</p>
            <p>• You can disable biometric authentication at any time</p>
            <p>• Requires HTTPS connection or localhost for security</p>
            <p>• Works with Chrome, Firefox, Safari, and Edge browsers</p>
          </div>
        </CardContent>
      </Card>
    </div>
  )
}

"use client"

import { useState, useEffect } from "react"
import { SessionManager } from "@/lib/session-manager"
import { useAuthentication } from "@/hooks/use-authentication"
import { SecurePinManager } from "@/lib/secure-pin-manager"
import { isBiometricKeyConfigured, unwrapPinWithBiometric } from "@/lib/biometric-key"
import { Card, CardContent, CardDescription, CardHeader, CardTitle } from "@/components/ui/card"
import { Button } from "@/components/ui/button"
import { InputOTP, InputOTPGroup, InputOTPSlot } from "@/components/ui/input-otp"
import { Badge } from "@/components/ui/badge"
import { Lock, AlertCircle, Shield, Fingerprint } from "lucide-react"
import { toast } from "@/hooks/use-toast"

import { playSound } from "@/lib/sound-utils"
import { SecurityLogger } from "@/lib/security-logger"

interface SessionGuardProps {
  children: React.ReactNode
}

interface SessionPinScreenProps {
  onUnlock: (pin: string, emergencyMode?: boolean) => Promise<void>
  onError?: () => void
  onEmergencyPinUsed?: () => void
  onNewPinSetupComplete?: () => void
  showNewPinSetup?: boolean
}

function SessionPinScreen({ onUnlock, onError, onEmergencyPinUsed, onNewPinSetupComplete, showNewPinSetup }: SessionPinScreenProps) {
  const [pin, setPin] = useState("")
  const [isSubmitting, setIsSubmitting] = useState(false)
  const [authStatus, setAuthStatus] = useState(SecurePinManager.getAuthStatus())
  const [emergencyAuthStatus, setEmergencyAuthStatus] = useState(SecurePinManager.getEmergencyAuthStatus())
  const [biometricEnabled, setBiometricEnabled] = useState(false)
  const [biometricSupported, setBiometricSupported] = useState(false)
  const [isBiometricAuthenticating, setIsBiometricAuthenticating] = useState(false)
  const [rememberDevice, setRememberDevice] = useState(false)
  const [emergencyMode, setEmergencyMode] = useState(false)
  const [hasEmergencyPin, setHasEmergencyPin] = useState(SecurePinManager.hasEmergencyPin())
  const [pinError, setPinError] = useState(false)
  const [errorMessage, setErrorMessage] = useState<string | null>(null)
  const [emergencyPinUsed, setEmergencyPinUsed] = useState(false)
  const [newRegularPin, setNewRegularPin] = useState("")
  const [confirmNewRegularPin, setConfirmNewRegularPin] = useState("")
  const [newPinStep, setNewPinStep] = useState<"new" | "confirm">("new")
  const [isSettingNewPin, setIsSettingNewPin] = useState(false)

  // Get current auth status based on mode
  const getCurrentAuthStatus = () => {
    if (emergencyMode) {
      const emergencyStatus = SecurePinManager.getEmergencyAuthStatus()
      return {
        isLocked: emergencyStatus.isLocked,
        attemptsRemaining: emergencyStatus.attemptsRemaining,
        lockoutTimeRemaining: emergencyStatus.lockoutTimeRemaining,
        securityLevel: emergencyStatus.securityLevel,
      }
    }
    return authStatus
  }

  const currentAuthStatus = getCurrentAuthStatus()

  // Format time remaining in MM:SS format
  const formatTimeRemaining = (milliseconds: number) => {
    const minutes = Math.floor(milliseconds / 60000)
    const seconds = Math.floor((milliseconds % 60000) / 1000)
    return `${minutes}:${seconds.toString().padStart(2, '0')}`
  }

  // Real-time updates for emergency mode status
  useEffect(() => {
    if (emergencyMode) {
      const updateEmergencyAuthStatus = () => {
        // Force re-render by updating a dummy state
        setAuthStatus(prev => ({ ...prev }))
      }

      const interval = setInterval(updateEmergencyAuthStatus, 1000)
      return () => clearInterval(interval)
    }
  }, [emergencyMode])

  useEffect(() => {
    // Check if biometrics are enabled
    setBiometricEnabled(isBiometricKeyConfigured())

    // Check biometric support
    const checkBiometricSupport = async () => {
      const isSecureContext = window.location.protocol === 'https:' || window.location.hostname === 'localhost'
      if (!isSecureContext || !window.PublicKeyCredential) {
        setBiometricSupported(false)
        return
      }

      try {
        const available = await PublicKeyCredential.isUserVerifyingPlatformAuthenticatorAvailable()
        setBiometricSupported(available)
      } catch (error) {
        setBiometricSupported(false)
      }
    }

    checkBiometricSupport()
  }, [])

  // Real-time updates for auth status (every 1 second)
  useEffect(() => {
    const updateAuthStatus = () => {
      setAuthStatus(SecurePinManager.getAuthStatus())
      setEmergencyAuthStatus(SecurePinManager.getEmergencyAuthStatus())
    }

    // Update immediately
    updateAuthStatus()

    // Update every second for real-time timer
    const interval = setInterval(updateAuthStatus, 1000)

    return () => clearInterval(interval)
  }, [])

  // Real-time updates for emergency PIN status
  useEffect(() => {
    const updateEmergencyStatus = () => {
      setHasEmergencyPin(SecurePinManager.hasEmergencyPin())
    }

    // Update immediately
    updateEmergencyStatus()

    // Update every 2 seconds for emergency PIN status
    const interval = setInterval(updateEmergencyStatus, 2000)

    return () => clearInterval(interval)
  }, [])

  const handleBiometricAuth = async () => {
    if (!biometricEnabled || !biometricSupported) return

    setIsBiometricAuthenticating(true)

    try {
      const pin = await unwrapPinWithBiometric()
      if (!pin) {
        throw new Error("Biometric unlock is not available")
      }

      SecurityLogger.logEvent({ type: 'biometric_success' })
      await onUnlock(pin)
      // Set authentication timestamp to prevent duplicate PIN screen
      localStorage.setItem("wallet_last_auth", Date.now().toString())
    } catch (error) {
      // Play failed sound for biometric authentication
      playSound("pin-failed")
      const errorMessage = error instanceof Error ? error.message : "Biometric authentication failed"
      SecurityLogger.logEvent({ type: 'biometric_failed', details: errorMessage })
      setErrorMessage(errorMessage)
      toast({
        title: "Biometric Authentication Failed",
        description: "Please use your PIN to unlock the wallet.",
        variant: "destructive",
      })
    } finally {
      setIsBiometricAuthenticating(false)
    }
  }

  const handleSubmit = async () => {
    if (isSubmitting || pin.length !== 6) return

    setIsSubmitting(true)
    try {
      await onUnlock(pin, emergencyMode)
      // If emergency PIN was used successfully, notify parent component
      if (emergencyMode && onEmergencyPinUsed) {
        onEmergencyPinUsed()
      }
    } catch (error) {
      // Trigger error animation on failed validation
      triggerErrorAnimation()
      if (onError) onError()
    } finally {
      setIsSubmitting(false)
    }
  }

  // Function to trigger error animation
  const triggerErrorAnimation = () => {
    playSound("pin-failed")
    setPinError(true)
    setPin("") // Clear the PIN input
    setErrorMessage(emergencyMode ? "Incorrect Emergency PIN" : "Incorrect PIN")

    // Remove error state after animation completes
    setTimeout(() => {
      setPinError(false)
      setErrorMessage(null)
    }, 600) // Match animation duration
  }

  // Handle new regular PIN setup after emergency PIN use
  const handleNewPinSetup = async () => {
    setIsSettingNewPin(true)

    try {
      if (newPinStep === "new") {
        if (newRegularPin.length === 6) {
          setNewPinStep("confirm")
        }
      } else if (newPinStep === "confirm") {
        if (newRegularPin === confirmNewRegularPin) {
          const success = await SecurePinManager.updatePinForRecovery(newRegularPin)

          if (success) {
            // Clear emergency PIN usage flag and allow access to dashboard
            setEmergencyPinUsed(false)

            // Reset states
            setNewRegularPin("")
            setConfirmNewRegularPin("")
            setNewPinStep("new")

            toast({
              title: "New PIN Set Successfully",
              description: "Your wallet is now secured with a new regular PIN.",
            })
            SessionManager.createSession()

            // Notify parent component to allow dashboard access
            if (onNewPinSetupComplete) {
              onNewPinSetupComplete()
            }
          } else {
            toast({
              title: "PIN Setup Failed",
              description: "Failed to set up new PIN. Please try again.",
              variant: "destructive",
            })
          }
        } else {
          toast({
            title: "PINs Don't Match",
            description: "Please make sure both PINs are identical.",
            variant: "destructive",
          })
        }
      }
    } catch (error) {
      toast({
        title: "PIN Setup Error",
        description: "Failed to process new PIN. Please try again.",
        variant: "destructive",
      })
    } finally {
      setIsSettingNewPin(false)
    }
  }

  // Show new PIN setup screen if emergency PIN was used
  if (showNewPinSetup) {
    return (
      <div className="min-h-screen flex items-center justify-center bg-gradient-to-br from-primary/5 to-primary/10 p-4">
        <Card className="w-full max-w-md">
          <CardHeader className="text-center">
            <div className="w-16 h-16 bg-orange-500 rounded-full flex items-center justify-center mx-auto mb-4">
              <Shield className="w-8 h-8 text-white" />
            </div>
            <CardTitle>Security Update Required</CardTitle>
            <CardDescription>
              {newPinStep === "new"
                ? "Set up a new regular PIN to secure your wallet"
                : "Confirm your new regular PIN"}
            </CardDescription>
          </CardHeader>
          <CardContent className="space-y-6">
            <div className="p-4 bg-orange-50 dark:bg-orange-950/20 rounded-lg border border-orange-200 dark:border-orange-800">
              <div className="flex items-center gap-2 text-orange-700 dark:text-orange-400 mb-2">
                <AlertCircle className="w-4 h-4" />
                <span className="text-sm font-medium">Emergency Access Used</span>
              </div>
              <p className="text-sm text-orange-600 dark:text-orange-500">
                You accessed your wallet using the emergency PIN. For security, you must now set up a new regular PIN.
              </p>
            </div>

            <div className="text-center">
              <p className="text-sm text-muted-foreground mb-4">
                Enter your new 6-digit regular PIN
              </p>
            </div>

            <div className="flex justify-center">
              <InputOTP
                maxLength={6}
                value={newPinStep === "new" ? newRegularPin : confirmNewRegularPin}
                onChange={newPinStep === "new" ? setNewRegularPin : setConfirmNewRegularPin}
                disabled={isSettingNewPin}
                onKeyDown={(e) => {
                  if (e.key === "Enter") {
                    if (newPinStep === "new" && newRegularPin.length === 6) {
                      e.preventDefault()
                      document.getElementById("new-pin-submit-btn")?.click() || handleNewPinSetup()
                    } else if (newPinStep === "confirm" && confirmNewRegularPin.length === 6) {
                      e.preventDefault()
                      handleNewPinSetup()
                    }
                  }
                }}
              >
                <InputOTPGroup>
                  <InputOTPSlot index={0} />
                  <InputOTPSlot index={1} />
                  <InputOTPSlot index={2} />
                  <InputOTPSlot index={3} />
                  <InputOTPSlot index={4} />
                  <InputOTPSlot index={5} />
                </InputOTPGroup>
              </InputOTP>
            </div>

            <Button
              onClick={handleNewPinSetup}
              disabled={(newPinStep === "new" ? newRegularPin.length !== 6 : confirmNewRegularPin.length !== 6) || isSettingNewPin}
              className="w-full"
            >
              {isSettingNewPin ? "Setting up PIN..." : newPinStep === "new" ? "Continue" : "Set New PIN"}
            </Button>
          </CardContent>
        </Card>
      </div>
    )
  }

  return (
    <div className="min-h-screen flex items-center justify-center bg-gradient-to-br from-primary/5 to-primary/10 p-4">
      <Card className={`w-full max-w-md ${pinError ? 'ring-2 ring-destructive shadow-lg shadow-destructive/20' : ''} transition-all duration-300`}>
        <CardHeader className="text-center">
          <div className="w-16 h-16 bg-primary rounded-full flex items-center justify-center mx-auto mb-4">
            <Shield className="w-8 h-8 text-accent-foreground" />
          </div>
          <CardTitle className="flex items-center justify-center gap-2">
            <Lock className="w-5 h-5" />
            {emergencyMode ? "Emergency Access" : "MyWallet Locked"}
          </CardTitle>
          <CardDescription>
            {emergencyMode ? "Enter your emergency PIN" : "Choose your preferred authentication method"}
          </CardDescription>
        </CardHeader>
        <CardContent className="space-y-6">
          {/* Authentication Methods */}
          <div className="space-y-4">
            {biometricEnabled && biometricSupported && (
              <div className="space-y-3">
                <Button
                  onClick={handleBiometricAuth}
                  disabled={isBiometricAuthenticating || currentAuthStatus.isLocked || emergencyMode}
                  className="w-full flex items-center justify-center gap-3 h-12"
                  variant="outline"
                >
                  <Fingerprint className="w-5 h-5" />
                  <span>Use Biometric</span>
                </Button>
                <p className="w-full flex items-center justify-center gap-3 h-12">or</p>
              </div>
            )}

            {/* Emergency PIN Toggle - Only show when user has failed regular PIN attempts (level > 0) */}
            {hasEmergencyPin && !emergencyMode && currentAuthStatus.securityLevel > 0 && (
              <div className="space-y-3">
                <Button
                  onClick={() => setEmergencyMode(true)}
                  className="w-full flex items-center justify-center gap-3 h-12"
                  variant="outline"
                >
                  <AlertCircle className="w-5 h-5" />
                  <span>Use Emergency PIN</span>
                </Button>
                <p className="text-xs text-muted-foreground text-center">
                  Available after failed regular PIN attempts
                </p>
              </div>
            )}

            {/* PIN Input - Always Available */}
            <div className="space-y-4">
              <div className="text-center">
                <p className="text-sm text-muted-foreground mb-4">
                  {emergencyMode ? "Enter your 6-digit emergency PIN" : "Enter your 6-digit PIN"}
                </p>
              </div>

              <div className="flex justify-center">
                <InputOTP
                  maxLength={6}
                  value={pin}
                  onChange={setPin}
                  disabled={isSubmitting}
                  className={pinError ? "animate-shake" : ""}
                  onKeyDown={(e) => {
                    if (e.key === "Enter" && pin.length === 6) {
                      e.preventDefault()
                      handleSubmit()
                    }
                  }}
                >
                  <InputOTPGroup className={pinError ? "border-destructive/60 bg-destructive/5 shadow-lg shadow-destructive/20" : ""}>
                    <InputOTPSlot
                      index={0}
                      className={pinError ? "border-destructive/60 bg-destructive/5 text-destructive shadow-sm" : ""}
                    />
                    <InputOTPSlot
                      index={1}
                      className={pinError ? "border-destructive/60 bg-destructive/5 text-destructive shadow-sm" : ""}
                    />
                    <InputOTPSlot
                      index={2}
                      className={pinError ? "border-destructive/60 bg-destructive/5 text-destructive shadow-sm" : ""}
                    />
                    <InputOTPSlot
                      index={3}
                      className={pinError ? "border-destructive/60 bg-destructive/5 text-destructive shadow-sm" : ""}
                    />
                    <InputOTPSlot
                      index={4}
                      className={pinError ? "border-destructive/60 bg-destructive/5 text-destructive shadow-sm" : ""}
                    />
                    <InputOTPSlot
                      index={5}
                      className={pinError ? "border-destructive/60 bg-destructive/5 text-destructive shadow-sm" : ""}
                    />
                  </InputOTPGroup>
                </InputOTP>
              </div>

              <div className={`text-destructive text-sm text-center mt-2 transition-opacity duration-300 ${errorMessage ? 'opacity-100' : 'opacity-0'}`}>
                {errorMessage && <><AlertCircle className="w-4 h-4 inline mr-1" />{errorMessage}</>}
              </div>

              <div className="space-y-2">
                <Button
                  onClick={handleSubmit}
                  disabled={pin.length !== 6 || currentAuthStatus.isLocked || isSubmitting}
                  className="w-full"
                >
                  {isSubmitting ? "Verifying..." : currentAuthStatus.isLocked ? "Locked" : emergencyMode ? "Unlock with Emergency PIN" : "Unlock Wallet"}
                </Button>

                {emergencyMode && (
                  <Button
                    onClick={() => setEmergencyMode(false)}
                    variant="ghost"
                    className="w-full"
                  >
                    Back to Regular PIN
                  </Button>
                )}
              </div>
            </div>
          </div>

          {/* Status Messages */}
          {!currentAuthStatus.isLocked && (
            <div className="flex flex-col items-center gap-2 text-muted-foreground text-sm">
              <div className="flex items-center gap-2 justify-center">
                <span>{currentAuthStatus.attemptsRemaining} {emergencyMode ? "emergency" : ""} attempts remaining</span>
              </div>
              {/* Security Level Display */}
              {'securityLevel' in currentAuthStatus && (
                <div className="flex items-center gap-2">
                  <Badge variant={currentAuthStatus.securityLevel > 0 ? "destructive" : "secondary"} className="text-xs">
                    <Shield className="w-3 h-3 mr-1" />
                    Level {currentAuthStatus.securityLevel}
                  </Badge>
                </div>
              )}
            </div>
          )}

          {currentAuthStatus.isLocked && (
            <div className="flex items-center gap-2 text-destructive text-sm justify-center">
              <AlertCircle className="w-4 h-4" />
              <span>
                {emergencyMode ? "Emergency" : "Account"} locked. Please wait {formatTimeRemaining(currentAuthStatus.lockoutTimeRemaining || 0)}.
              </span>
            </div>
          )}

          {/* Security Footer */}
          <div className="text-center text-xs text-muted-foreground">
            Your data is protected with PBKDF2 encryption and secure key management
          </div>
        </CardContent>
      </Card>
    </div>
  )
}

export function SessionGuard({ children }: SessionGuardProps) {
  const { isAuthenticated, hasPin, validatePin, validateEmergencyPin } = useAuthentication()
  const [showPinScreen, setShowPinScreen] = useState(false)
  const [emergencyPinUsed, setEmergencyPinUsed] = useState(false)
  const [showNewPinSetup, setShowNewPinSetup] = useState(false)

  useEffect(() => {

    // If no PIN is set up, allow access
    if (!hasPin) {
      setShowPinScreen(false)
      return
    }

    // If PIN is set up, check authentication status
    if (isAuthenticated) {
      setShowPinScreen(false)
    } else {
      setShowPinScreen(true)
    }

    // Listen for session expiry events
    const handleSessionExpiry = () => {
      setShowPinScreen(true)
    }

    // Listen for window focus events to validate session
    const handleWindowFocus = () => {
      if (hasPin && !SessionManager.isSessionValid()) {
        setShowPinScreen(true)
      }
    }

    window.addEventListener('wallet-session-expired', handleSessionExpiry)
    window.addEventListener('focus', handleWindowFocus)

    return () => {
      window.removeEventListener('wallet-session-expired', handleSessionExpiry)
      window.removeEventListener('focus', handleWindowFocus)
    }
  }, [isAuthenticated, hasPin])

  // If no PIN is required or user is authenticated with valid session, show children
  if (!hasPin || (isAuthenticated && !showPinScreen && !showNewPinSetup)) {
    return <>{children}</>
  }

  // Show PIN screen when no active session or not authenticated
  return (
    <SessionPinScreen
      onUnlock={async (pin: string, emergencyMode?: boolean) => {
        const result = emergencyMode ? await validateEmergencyPin(pin) : await validatePin(pin)
        if (result.success) {
          playSound("pin-success")
          if (emergencyMode) {
            setEmergencyPinUsed(true)
            setShowNewPinSetup(true)
          } else {
            SessionManager.createSession()
            setShowPinScreen(false)
          }
        } else {
          throw new Error("PIN validation failed") // Throw error to trigger visual feedback
        }
      }}
      onEmergencyPinUsed={() => {
        setEmergencyPinUsed(true)
        setShowNewPinSetup(true)
      }}
      onNewPinSetupComplete={() => {
        setShowPinScreen(false)
        setShowNewPinSetup(false)
        setEmergencyPinUsed(false)
      }}
      onError={() => {
      }}
      showNewPinSetup={showNewPinSetup}
    />
  )
}

"use client"

import type React from "react"

import { useState, useEffect, useRef } from "react"
import { Card, CardContent, CardDescription, CardHeader, CardTitle } from "@/components/ui/card"
import { Switch } from "@/components/ui/switch"
import { Label } from "@/components/ui/label"
import { Slider } from "@/components/ui/slider"
import { Button } from "@/components/ui/button"
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from "@/components/ui/select"
import { Input } from "@/components/ui/input"
import { Accessibility, Type, Volume2, Eye, RotateCcw, Upload, Play } from "lucide-react"
import { useToast } from "@/hooks/use-toast"

import { playSound, PRESET_SOUNDS, SoundActivity } from "@/lib/sound-utils"

export function AccessibilitySettings() {
  const [screenReader, setScreenReader] = useState(false)
  const [keyboardNav, setKeyboardNav] = useState(false)
  const [fontSize, setFontSize] = useState([16])
  const [soundEffects, setSoundEffects] = useState(true)
  const [focusIndicators, setFocusIndicators] = useState(false)
  const [tooltips, setTooltips] = useState(false)
  const [selectedSound, setSelectedSound] = useState("gentle-chime")
  const [customSoundUrl, setCustomSoundUrl] = useState("")

  // Per-activity sound settings
  const [transactionSuccessEnabled, setTransactionSuccessEnabled] = useState(true)
  const [transactionFailedEnabled, setTransactionFailedEnabled] = useState(true)
  const [budgetWarningEnabled, setBudgetWarningEnabled] = useState(true)
  const [pinSuccessEnabled, setPinSuccessEnabled] = useState(true)
  const [pinFailedEnabled, setPinFailedEnabled] = useState(true)
  const [transactionSuccessSelectedSound, setTransactionSuccessSelectedSound] = useState("success-tone")
  const [transactionFailedSelectedSound, setTransactionFailedSelectedSound] = useState("notification")
  const [budgetWarningSelectedSound, setBudgetWarningSelectedSound] = useState("notification")
  const [pinSuccessSelectedSound, setPinSuccessSelectedSound] = useState("success-tone")
  const [pinFailedSelectedSound, setPinFailedSelectedSound] = useState("notification")
  const [transactionSuccessCustomUrl, setTransactionSuccessCustomUrl] = useState("")
  const [transactionFailedCustomUrl, setTransactionFailedCustomUrl] = useState("")
  const [budgetWarningCustomUrl, setBudgetWarningCustomUrl] = useState("")
  const [pinSuccessCustomUrl, setPinSuccessCustomUrl] = useState("")
  const [pinFailedCustomUrl, setPinFailedCustomUrl] = useState("")
  const [numberFormat, setNumberFormat] = useState("us")

  const audioRef = useRef<HTMLAudioElement | null>(null)
  const fileInputRef = useRef<HTMLInputElement>(null)
  const transactionSuccessFileInputRef = useRef<HTMLInputElement>(null)
  const transactionFailedFileInputRef = useRef<HTMLInputElement>(null)
  const budgetWarningFileInputRef = useRef<HTMLInputElement>(null)
  const pinSuccessFileInputRef = useRef<HTMLInputElement>(null)
  const pinFailedFileInputRef = useRef<HTMLInputElement>(null)
  const { toast } = useToast()

  function applyAccessibilitySettings(sr: boolean, kn: boolean, fs: number, fi: boolean) {
    if (sr) {
      document.documentElement.classList.add("screen-reader-optimized")
    } else {
      document.documentElement.classList.remove("screen-reader-optimized")
    }

    if (kn) {
      document.documentElement.classList.add("keyboard-nav-enabled")
    } else {
      document.documentElement.classList.remove("keyboard-nav-enabled")
    }

    if (fi) {
      document.documentElement.classList.add("enhanced-focus")
    } else {
      document.documentElement.classList.remove("enhanced-focus")
    }

    document.documentElement.style.setProperty("--base-font-size", `${fs}px`)
  }

  useEffect(() => {
    // Load saved accessibility preferences
    const savedScreenReader = localStorage.getItem("wallet_screen_reader") === "true"
    const savedKeyboardNav = localStorage.getItem("wallet_keyboard_nav") === "true"
    const savedFontSize = Number.parseInt(localStorage.getItem("wallet_font_size") || "16")
    const savedSoundEffectsValue = localStorage.getItem("wallet_sound_effects")
    const savedSoundEffects = savedSoundEffectsValue === null ? true : savedSoundEffectsValue === "true"
    const savedFocusIndicators = localStorage.getItem("wallet_focus_indicators") === "true"
    const savedTooltips = localStorage.getItem("wallet_tooltips") === "true"
    const savedSelectedSound = localStorage.getItem("wallet_selected_sound") || "gentle-chime"
    const savedCustomSoundUrl = localStorage.getItem("wallet_custom_sound_url") || ""

    // Load per-activity settings with defaults
    const savedTransactionSuccessEnabled = localStorage.getItem("wallet_transaction_success_enabled")
    const savedTransactionFailedEnabled = localStorage.getItem("wallet_transaction_failed_enabled")
    const savedBudgetWarningEnabled = localStorage.getItem("wallet_budget_warning_enabled")
    const savedPinSuccessEnabled = localStorage.getItem("wallet_pin_success_enabled")
    const savedPinFailedEnabled = localStorage.getItem("wallet_pin_failed_enabled")
    const savedTransactionSuccessSelectedSound = localStorage.getItem("wallet_transaction_success_selected_sound") || "success-tone"
    const savedTransactionFailedSelectedSound = localStorage.getItem("wallet_transaction_failed_selected_sound") || "notification"
    const savedBudgetWarningSelectedSound = localStorage.getItem("wallet_budget_warning_selected_sound") || "notification"
    const savedPinSuccessSelectedSound = localStorage.getItem("wallet_pin_success_selected_sound") || "success-tone"
    const savedPinFailedSelectedSound = localStorage.getItem("wallet_pin_failed_selected_sound") || "notification"
    const savedTransactionSuccessCustomUrl = localStorage.getItem("wallet_transaction_success_custom_url") || ""
    const savedTransactionFailedCustomUrl = localStorage.getItem("wallet_transaction_failed_custom_url") || ""
    const savedBudgetWarningCustomUrl = localStorage.getItem("wallet_budget_warning_custom_url") || ""
    const savedPinSuccessCustomUrl = localStorage.getItem("wallet_pin_success_custom_url") || ""
    const savedPinFailedCustomUrl = localStorage.getItem("wallet_pin_failed_custom_url") || ""
    const savedNumberFormat = localStorage.getItem("wallet_number_format") || "us"

    setScreenReader(savedScreenReader)
    setKeyboardNav(savedKeyboardNav)
    setFontSize([savedFontSize])
    setSoundEffects(savedSoundEffects)
    setFocusIndicators(savedFocusIndicators)
    setTooltips(savedTooltips)
    setSelectedSound(savedSelectedSound)
    setCustomSoundUrl(savedCustomSoundUrl)

    setTransactionSuccessEnabled(savedTransactionSuccessEnabled === null ? true : savedTransactionSuccessEnabled === "true")
    setTransactionFailedEnabled(savedTransactionFailedEnabled === null ? true : savedTransactionFailedEnabled === "true")
    setBudgetWarningEnabled(savedBudgetWarningEnabled === null ? true : savedBudgetWarningEnabled === "true")
    setPinSuccessEnabled(savedPinSuccessEnabled === null ? true : savedPinSuccessEnabled === "true")
    setPinFailedEnabled(savedPinFailedEnabled === null ? true : savedPinFailedEnabled === "true")
    setTransactionSuccessSelectedSound(savedTransactionSuccessSelectedSound)
    setTransactionFailedSelectedSound(savedTransactionFailedSelectedSound)
    setBudgetWarningSelectedSound(savedBudgetWarningSelectedSound)
    setPinSuccessSelectedSound(savedPinSuccessSelectedSound)
    setPinFailedSelectedSound(savedPinFailedSelectedSound)
    setTransactionSuccessCustomUrl(savedTransactionSuccessCustomUrl)
    setTransactionFailedCustomUrl(savedTransactionFailedCustomUrl)
    setBudgetWarningCustomUrl(savedBudgetWarningCustomUrl)
    setPinSuccessCustomUrl(savedPinSuccessCustomUrl)
    setPinFailedCustomUrl(savedPinFailedCustomUrl)
    setNumberFormat(savedNumberFormat)

    applyAccessibilitySettings(savedScreenReader, savedKeyboardNav, savedFontSize, savedFocusIndicators)

    // Listen for authentication success events
    const handleAuthSuccess = () => playSound('pin-success')
    window.addEventListener('wallet-auth-success', handleAuthSuccess)

    return () => {
      window.removeEventListener('wallet-auth-success', handleAuthSuccess)
    }
  }, [])

  const announceToScreenReader = (message: string) => {
    if (screenReader) {
      const announcement = document.createElement("div")
      announcement.setAttribute("aria-live", "polite")
      announcement.setAttribute("aria-atomic", "true")
      announcement.className = "sr-only"
      announcement.textContent = message
      document.body.appendChild(announcement)
      setTimeout(() => document.body.removeChild(announcement), 1000)
    }
  }

  const handlePlaySound = (activity: any = "default") => {
    playSound(activity as SoundActivity)
  }

  const handleScreenReaderChange = (enabled: boolean) => {
    setScreenReader(enabled)
    localStorage.setItem("wallet_screen_reader", enabled.toString())

    // Apply screen reader optimizations
    if (enabled) {
      document.documentElement.classList.add("screen-reader-optimized")
      announceToScreenReader("Screen reader mode enabled")
    } else {
      document.documentElement.classList.remove("screen-reader-optimized")
    }
    handlePlaySound("toggle")
  }

  const handleKeyboardNavChange = (enabled: boolean) => {
    setKeyboardNav(enabled)
    localStorage.setItem("wallet_keyboard_nav", enabled.toString())

    // Apply keyboard navigation styles
    if (enabled) {
      document.documentElement.classList.add("keyboard-nav-enabled")
    } else {
      document.documentElement.classList.remove("keyboard-nav-enabled")
    }
    handlePlaySound("toggle")
    announceToScreenReader(`Keyboard navigation ${enabled ? "enabled" : "disabled"}`)
  }

  const handleFontSizeChange = (value: number[]) => {
    setFontSize(value)
    localStorage.setItem("wallet_font_size", value[0].toString())

    // Apply font size
    document.documentElement.style.setProperty("--base-font-size", `${value[0]}px`)
    announceToScreenReader(`Font size changed to ${value[0]} pixels`)
  }

  const handleSoundEffectsChange = (enabled: boolean) => {
    setSoundEffects(enabled)
    localStorage.setItem("wallet_sound_effects", enabled.toString())

    if (enabled) {
      handlePlaySound("enable")
    }
    announceToScreenReader(`Sound effects ${enabled ? "enabled" : "disabled"}`)
  }

  const handleFocusIndicatorsChange = (enabled: boolean) => {
    setFocusIndicators(enabled)
    localStorage.setItem("wallet_focus_indicators", enabled.toString())

    // Apply focus indicator styles
    if (enabled) {
      document.documentElement.classList.add("enhanced-focus")
    } else {
      document.documentElement.classList.remove("enhanced-focus")
    }
    handlePlaySound("toggle")
    announceToScreenReader(`Enhanced focus indicators ${enabled ? "enabled" : "disabled"}`)
  }

  const handleTooltipsChange = (enabled: boolean) => {
    setTooltips(enabled)
    localStorage.setItem("wallet_tooltips", enabled.toString())
    handlePlaySound("toggle")
    announceToScreenReader(`Enhanced tooltips ${enabled ? "enabled" : "disabled"}`)
  }

  const handleSoundChange = (value: string) => {
    setSelectedSound(value)
    localStorage.setItem("wallet_selected_sound", value)

    // Play preview of selected sound
    if (value !== "none" && value !== "custom") {
      try {
        const soundConfig = PRESET_SOUNDS[value as keyof typeof PRESET_SOUNDS]
        if (soundConfig?.generator) {
          soundConfig.generator()
        }
      } catch (error) {
        console.error("Error playing preview sound:", error)
      }
    }
  }

  const handleCustomSoundUpload = (event: React.ChangeEvent<HTMLInputElement>) => {
    const file = event.target.files?.[0]
    if (file) {
      if (file.type.startsWith("audio/")) {
        const url = URL.createObjectURL(file)
        setCustomSoundUrl(url)
        setSelectedSound("custom")
        localStorage.setItem("wallet_custom_sound_url", url)
        localStorage.setItem("wallet_selected_sound", "custom")
        toast({
          title: "Custom sound uploaded",
          description: "Your custom sound effect has been set successfully.",
        })
      } else {
        toast({
          title: "Invalid file type",
          description: "Please upload an audio file (MP3, WAV, etc.)",
          variant: "destructive",
        })
      }
    }
  }

  const handleActivityToggle = (activity: string) => (enabled: boolean) => {
    switch (activity) {
      case "transaction-success":
        setTransactionSuccessEnabled(enabled)
        localStorage.setItem("wallet_transaction_success_enabled", enabled.toString())
        break
      case "transaction-failed":
        setTransactionFailedEnabled(enabled)
        localStorage.setItem("wallet_transaction_failed_enabled", enabled.toString())
        break
      case "budget-warning":
        setBudgetWarningEnabled(enabled)
        localStorage.setItem("wallet_budget_warning_enabled", enabled.toString())
        break
      case "pin-success":
        setPinSuccessEnabled(enabled)
        localStorage.setItem("wallet_pin_success_enabled", enabled.toString())
        break
      case "pin-failed":
        setPinFailedEnabled(enabled)
        localStorage.setItem("wallet_pin_failed_enabled", enabled.toString())
        break
    }
    announceToScreenReader(`${activity.replace("-", " ").replace("pin", "auth")} sound ${enabled ? "enabled" : "disabled"}`)
  }

  const handleActivitySoundChange = (activity: string) => (value: string) => {
    switch (activity) {
      case "transaction-success":
        setTransactionSuccessSelectedSound(value)
        localStorage.setItem("wallet_transaction_success_selected_sound", value)
        break
      case "transaction-failed":
        setTransactionFailedSelectedSound(value)
        localStorage.setItem("wallet_transaction_failed_selected_sound", value)
        break
      case "budget-warning":
        setBudgetWarningSelectedSound(value)
        localStorage.setItem("wallet_budget_warning_selected_sound", value)
        break
      case "pin-success":
        setPinSuccessSelectedSound(value)
        localStorage.setItem("wallet_pin_success_selected_sound", value)
        break
      case "pin-failed":
        setPinFailedSelectedSound(value)
        localStorage.setItem("wallet_pin_failed_selected_sound", value)
        break
    }

    // Play preview if not none or custom
    if (value !== "none" && value !== "custom") {
      try {
        const soundConfig = PRESET_SOUNDS[value as keyof typeof PRESET_SOUNDS]
        if (soundConfig?.generator) {
          soundConfig.generator()
        }
      } catch (error) {
        console.error("Error playing preview sound:", error)
      }
    }
  }

  const handleActivityCustomSoundUpload = (activity: string) => (event: React.ChangeEvent<HTMLInputElement>) => {
    const file = event.target.files?.[0]
    if (file) {
      if (file.type.startsWith("audio/")) {
        const url = URL.createObjectURL(file)
        switch (activity) {
          case "transaction-success":
            setTransactionSuccessCustomUrl(url)
            setTransactionSuccessSelectedSound("custom")
            localStorage.setItem("wallet_transaction_success_custom_url", url)
            localStorage.setItem("wallet_transaction_success_selected_sound", "custom")
            break
          case "transaction-failed":
            setTransactionFailedCustomUrl(url)
            setTransactionFailedSelectedSound("custom")
            localStorage.setItem("wallet_transaction_failed_custom_url", url)
            localStorage.setItem("wallet_transaction_failed_selected_sound", "custom")
            break
          case "budget-warning":
            setBudgetWarningCustomUrl(url)
            setBudgetWarningSelectedSound("custom")
            localStorage.setItem("wallet_budget_warning_custom_url", url)
            localStorage.setItem("wallet_budget_warning_selected_sound", "custom")
            break
          case "pin-success":
            setPinSuccessCustomUrl(url)
            setPinSuccessSelectedSound("custom")
            localStorage.setItem("wallet_pin_success_custom_url", url)
            localStorage.setItem("wallet_pin_success_selected_sound", "custom")
            break
          case "pin-failed":
            setPinFailedCustomUrl(url)
            setPinFailedSelectedSound("custom")
            localStorage.setItem("wallet_pin_failed_custom_url", url)
            localStorage.setItem("wallet_pin_failed_selected_sound", "custom")
            break
        }
        toast({
          title: "Custom sound uploaded",
          description: "Your custom sound effect has been set successfully.",
        })
      } else {
        toast({
          title: "Invalid file type",
          description: "Please upload an audio file (MP3, WAV, etc.)",
          variant: "destructive",
        })
      }
    }
  }

  const resetToDefaults = () => {
    const defaults = {
      screenReader: false,
      keyboardNav: false,
      fontSize: 16,
      soundEffects: true,
      focusIndicators: false,
      tooltips: false,
      selectedSound: "gentle-chime",
      customSoundUrl: "",
      transactionSuccessEnabled: true,
      transactionFailedEnabled: true,
      budgetWarningEnabled: true,
      pinSuccessEnabled: true,
      pinFailedEnabled: true,
      transactionSuccessSelectedSound: "success-tone",
      transactionFailedSelectedSound: "notification",
      budgetWarningSelectedSound: "notification",
      pinSuccessSelectedSound: "success-tone",
      pinFailedSelectedSound: "notification",
      transactionSuccessCustomUrl: "",
      transactionFailedCustomUrl: "",
      budgetWarningCustomUrl: "",
      pinSuccessCustomUrl: "",
      pinFailedCustomUrl: "",
      numberFormat: "us",
    }

    setScreenReader(defaults.screenReader)
    setKeyboardNav(defaults.keyboardNav)
    setFontSize([defaults.fontSize])
    setSoundEffects(defaults.soundEffects)
    setFocusIndicators(defaults.focusIndicators)
    setTooltips(defaults.tooltips)
    setSelectedSound(defaults.selectedSound)
    setCustomSoundUrl(defaults.customSoundUrl)
    setTransactionSuccessEnabled(defaults.transactionSuccessEnabled)
    setTransactionFailedEnabled(defaults.transactionFailedEnabled)
    setBudgetWarningEnabled(defaults.budgetWarningEnabled)
    setPinSuccessEnabled(defaults.pinSuccessEnabled)
    setPinFailedEnabled(defaults.pinFailedEnabled)
    setTransactionSuccessSelectedSound(defaults.transactionSuccessSelectedSound)
    setTransactionFailedSelectedSound(defaults.transactionFailedSelectedSound)
    setBudgetWarningSelectedSound(defaults.budgetWarningSelectedSound)
    setPinSuccessSelectedSound(defaults.pinSuccessSelectedSound)
    setPinFailedSelectedSound(defaults.pinFailedSelectedSound)
    setTransactionSuccessCustomUrl(defaults.transactionSuccessCustomUrl)
    setTransactionFailedCustomUrl(defaults.transactionFailedCustomUrl)
    setBudgetWarningCustomUrl(defaults.budgetWarningCustomUrl)
    setPinSuccessCustomUrl(defaults.pinSuccessCustomUrl)
    setPinFailedCustomUrl(defaults.pinFailedCustomUrl)
    setNumberFormat(defaults.numberFormat)

    // Clear localStorage
    Object.keys(defaults).forEach((key) => {
      localStorage.removeItem(`wallet_${key.replace(/([A-Z])/g, "_$1").toLowerCase()}`)
    })

    // Apply default settings
    applyAccessibilitySettings(defaults.screenReader, defaults.keyboardNav, defaults.fontSize, defaults.focusIndicators)

    toast({
      title: "Settings reset",
      description: "All accessibility settings have been reset to defaults.",
    })
    announceToScreenReader("All accessibility settings have been reset to default values")
  }

  return (
    <div className="space-y-6">
      <div className="flex justify-end">
        <Button variant="outline" onClick={resetToDefaults} className="flex items-center gap-2 bg-transparent">
          <RotateCcw className="w-4 h-4" />
          Reset to Defaults
        </Button>
      </div>

      {/* Screen Reader Support */}
      <Card>
        <CardHeader>
          <CardTitle className="flex items-center gap-2">
            <Accessibility className="w-5 h-5" />
            Screen Reader Support
          </CardTitle>
          <CardDescription>Optimize the interface for screen readers</CardDescription>
        </CardHeader>
        <CardContent className="space-y-4">
          <div className="flex items-center justify-between">
            <div className="space-y-1">
              <Label htmlFor="screen-reader">Screen Reader Mode</Label>
              <p className="text-sm text-muted-foreground">Enhanced ARIA labels and live announcements</p>
            </div>
            <Switch id="screen-reader" checked={screenReader} onCheckedChange={handleScreenReaderChange} />
          </div>

          <div className="flex items-center justify-between">
            <div className="space-y-1">
              <Label htmlFor="tooltips">Enhanced Tooltips</Label>
              <p className="text-sm text-muted-foreground">Show detailed explanations for time calculations</p>
            </div>
            <Switch id="tooltips" checked={tooltips} onCheckedChange={handleTooltipsChange} />
          </div>
        </CardContent>
      </Card>

      {/* Navigation */}
      <Card>
        <CardHeader>
          <CardTitle className="flex items-center gap-2">
            <Eye className="w-5 h-5" />
            Navigation & Focus
          </CardTitle>
          <CardDescription>Keyboard navigation and focus management</CardDescription>
        </CardHeader>
        <CardContent className="space-y-4">
          <div className="flex items-center justify-between">
            <div className="space-y-1">
              <Label htmlFor="keyboard-nav">Keyboard Navigation</Label>
              <p className="text-sm text-muted-foreground">Navigate using Tab, Enter, and arrow keys</p>
            </div>
            <Switch id="keyboard-nav" checked={keyboardNav} onCheckedChange={handleKeyboardNavChange} />
          </div>

          <div className="flex items-center justify-between">
            <div className="space-y-1">
              <Label htmlFor="focus-indicators">Enhanced Focus Indicators</Label>
              <p className="text-sm text-muted-foreground">More visible focus outlines for better navigation</p>
            </div>
            <Switch id="focus-indicators" checked={focusIndicators} onCheckedChange={handleFocusIndicatorsChange} />
          </div>
        </CardContent>
      </Card>

      {/* Typography */}
      <Card>
        <CardHeader>
          <CardTitle className="flex items-center gap-2">
            <Type className="w-5 h-5" />
            Typography
          </CardTitle>
          <CardDescription>Adjust text size and readability</CardDescription>
        </CardHeader>
        <CardContent className="space-y-4">
          <div className="space-y-3">
            <Label htmlFor="font-size">Base Font Size: {fontSize[0]}px</Label>
            <Slider
              id="font-size"
              min={12}
              max={24}
              step={1}
              value={fontSize}
              onValueChange={handleFontSizeChange}
              className="w-full"
            />
            <div className="flex justify-between text-sm text-muted-foreground">
              <span>Small (12px)</span>
              <span>Default (16px)</span>
              <span>Large (24px)</span>
            </div>
          </div>

          <div className="p-4 border rounded-lg">
            <p className="font-medium mb-2">Preview Text</p>
            <p style={{ fontSize: `${fontSize[0]}px` }}>
              This is how your text will appear with the selected font size. Transaction amounts and time calculations
              will scale accordingly.
            </p>
          </div>
        </CardContent>
      </Card>

      {/* Number Formatting */}
      <Card>
        <CardHeader>
          <CardTitle className="flex items-center gap-2">
            <span className="text-2xl">🔢</span>
            Number Formatting
          </CardTitle>
          <CardDescription>Choose how numbers are displayed and formatted</CardDescription>
        </CardHeader>
        <CardContent className="space-y-4">
          <div className="space-y-3">
            <Label htmlFor="number-format">Number Format Style</Label>
            <Select value={numberFormat} onValueChange={(value) => {
              setNumberFormat(value)
              localStorage.setItem("wallet_number_format", value)
              // Dispatch custom event to notify other components
              window.dispatchEvent(new CustomEvent('numberFormatChange'))
              announceToScreenReader(`Number format changed to ${value === 'us' ? 'US style' : value === 'eu' ? 'European style' : 'Indian style'}`)
            }}>
              <SelectTrigger>
                <SelectValue placeholder="Choose number format" />
              </SelectTrigger>
              <SelectContent>
                <SelectItem value="us">International Style (1,111,111)</SelectItem>
                <SelectItem value="ne">Nepali Style (11,11,111)</SelectItem>
              </SelectContent>
            </Select>
            <p className="text-sm text-muted-foreground">
              This affects how numbers are displayed in transaction inputs and throughout the app.
            </p>
          </div>

          <div className="p-4 border rounded-lg bg-muted/50">
            <p className="font-medium mb-2">Preview</p>
            <div className="space-y-2">
              <div className="flex justify-between">
                <span>International Style:</span>
                <span className="font-mono">1,111,111.50</span>
              </div>
              <div className="flex justify-between">
                <span>Nepali Style:</span>
                <span className="font-mono">11,11,111.50</span>
              </div>
            </div>
          </div>
        </CardContent>
      </Card>

      <Card>
        <CardHeader>
          <CardTitle className="flex items-center gap-2">
            <Volume2 className="w-5 h-5" />
            Audio Feedback
          </CardTitle>
          <CardDescription>Sound effects and audio cues for specific actions</CardDescription>
