"use client"

import { useEffect, useState } from "react"
import { Button } from "@/components/ui/button"
import { Badge } from "@/components/ui/badge"
import { Card, CardContent, CardDescription, CardHeader, CardTitle } from "@/components/ui/card"
import { Dialog, DialogContent, DialogHeader, DialogTitle } from "@/components/ui/dialog"
import { Input } from "@/components/ui/input"
import { Label } from "@/components/ui/label"
import { useWalletData } from "@/contexts/wallet-data-context"
import { Download, Upload, Trash2, Database, FileText, ShieldCheck, Workflow, Cloud, Loader2, RefreshCw, Info } from "lucide-react"
import { toast } from "@/hooks/use-toast"
import { DeleteDataDialog } from "./delete-data-dialog"
import { BackupModal } from "./data-settings/backup-modal"
import { ImportModal } from "./data-settings/import-modal"
import { buildDropboxAuthUrl, clearDropboxToken, downloadDropboxFile, getDropboxAccount, getDropboxAppKey, getDropboxToken, getLatestDropboxBackup, storeDropboxToken, uploadToDropbox, type DropboxAccount } from "@/lib/dropbox"
import { SecureKeyManager } from "@/lib/key-manager"
import { SecurePinManager } from "@/lib/secure-pin-manager"
import { loadFromLocalStorage, saveToLocalStorage } from "@/lib/storage"
import { DEFAULT_BACKUP_PIN } from "@/lib/backup"

export function DataSettings() {
  const {
    userProfile,
    transactions,
    budgets,
    goals,
    debtAccounts,
    creditAccounts,
    debtCreditTransactions,
    categories,
    emergencyFund,
    portfolio,
    shareTransactions,
    portfolios,
    activePortfolioId,
    clearAllData,
    importData,
  } = useWalletData()

  const [showBackupModal, setShowBackupModal] = useState(false)
  const [showImportModal, setShowImportModal] = useState(false)
  const [backupDestination, setBackupDestination] = useState<"download" | "dropbox">("download")
  const [dropboxAccount, setDropboxAccount] = useState<DropboxAccount | null>(null)
  const [dropboxError, setDropboxError] = useState<string | null>(null)
  const [hasDropboxToken, setHasDropboxToken] = useState(false)
  const [isDropboxConnecting, setIsDropboxConnecting] = useState(false)
  const [isDropboxPushing, setIsDropboxPushing] = useState(false)
  const [isDropboxPulling, setIsDropboxPulling] = useState(false)
  const [isDropboxRefreshing, setIsDropboxRefreshing] = useState(false)
  const [showDropboxInfo, setShowDropboxInfo] = useState(false)
  const [showTombstoneInfo, setShowTombstoneInfo] = useState(false)
  const [isTombstoneLoading, setIsTombstoneLoading] = useState(false)
  const [tombstoneStats, setTombstoneStats] = useState<{ label: string; count: number }[]>([])
  const [showDropboxBackupPinPrompt, setShowDropboxBackupPinPrompt] = useState(false)
  const [showDropboxLocalPinPrompt, setShowDropboxLocalPinPrompt] = useState(false)
  const [dropboxBackupPin, setDropboxBackupPin] = useState("")
  const [dropboxLocalPin, setDropboxLocalPin] = useState("")
  const [backupSizeMode, setBackupSizeMode] = useState<"essential" | "full">("essential")
  const [pendingDropboxContent, setPendingDropboxContent] = useState<string | null>(null)
  const [pendingDecryptedBackup, setPendingDecryptedBackup] = useState<any | null>(null)
  const [dropboxBackupPinAction, setDropboxBackupPinAction] = useState<"pull">("pull")
  const [dropboxLocalPinAction, setDropboxLocalPinAction] = useState<"import" | "push">("import")
  const dropboxAppKey = getDropboxAppKey()
  const hasDropboxConfig = Boolean(dropboxAppKey)
  const backupSizeModeKey = "wallet_dropbox_backup_size_mode"
  const nonEssentialBackupKeys = [
    "qrScanHistory",
    "receiptScanHistory",
    "transaction-dialog-form",
    "wallet_pending_transactions",
    "wallet_pending_budgets",
    "wallet_pending_goals",
  ] as const

  type TombstoneRecord = { id: string; deletedAt: string }
  const TOMBSTONE_RETENTION_MS = 30 * 24 * 60 * 60 * 1000
  const TOMBSTONE_KEYS = [
    "deleted_transactions",
    "deleted_budgets",
    "deleted_goals",
    "deleted_debtAccounts",
    "deleted_creditAccounts",
    "deleted_debtCreditTransactions",
    "deleted_categories",
    "deleted_shareTransactions",
    "deleted_portfolios",
  ] as const
  const TOMBSTONE_LABELS: Record<(typeof TOMBSTONE_KEYS)[number], string> = {
    deleted_transactions: "Transactions",
    deleted_budgets: "Budgets",
    deleted_goals: "Goals",
    deleted_debtAccounts: "Debt Accounts",
    deleted_creditAccounts: "Credit Accounts",
    deleted_debtCreditTransactions: "Debt/Credit History",
    deleted_categories: "Categories",
    deleted_shareTransactions: "Share Transactions",
    deleted_portfolios: "Portfolios",
  }

  const handleCreateBackup = (destination: "download" | "dropbox") => {
    if (destination === "dropbox" && !hasDropboxConfig) {
      toast({
        title: "Dropbox Not Configured",
        description: "Set NEXT_PUBLIC_DROPBOX_APP_KEY to enable Dropbox backups.",
        variant: "destructive",
      })
      return
    }
    setBackupDestination(destination)
    setShowBackupModal(true)
  }

  const ensureDropboxToken = async () => {
    const existing = getDropboxToken()
    if (existing) return existing
    if (!dropboxAppKey) {
      throw new Error("Dropbox is not configured")
    }

    const redirectUri = `${window.location.origin}/dropbox-callback`
    const authUrl = buildDropboxAuthUrl(dropboxAppKey, redirectUri)
    const authWindow = window.open(authUrl, "dropbox-auth", "width=480,height=640")

    if (!authWindow) {
      throw new Error("Popup blocked. Please allow popups to connect Dropbox.")
    }

    return await new Promise<string>((resolve, reject) => {
      let resolved = false
      const cleanup = () => {
        window.removeEventListener("message", handleMessage)
        clearInterval(timer)
      }
      const handleMessage = (event: MessageEvent) => {
        if (event.origin !== window.location.origin) return
        if (event.data?.type !== "dropbox-auth") return
        resolved = true
        cleanup()
        if (event.data?.token) {
          storeDropboxToken(event.data.token, event.data.expiresIn)
          resolve(event.data.token)
        } else {
          reject(new Error("Dropbox authorization failed"))
        }
      }
      const timer = window.setInterval(() => {
        if (authWindow.closed && !resolved) {
          cleanup()
          reject(new Error("Dropbox authorization cancelled"))
        }
      }, 500)

      window.addEventListener("message", handleMessage)
    })
  }

  const refreshDropboxAccount = async (token: string) => {
    setIsDropboxRefreshing(true)
    try {
      const account = await getDropboxAccount(token)
      setDropboxAccount(account)
      setDropboxError(null)
      return account
    } catch (error) {
      setDropboxAccount(null)
      setDropboxError(error instanceof Error ? error.message : "Unable to load Dropbox account")
      return null
    } finally {
      setIsDropboxRefreshing(false)
    }
  }

  useEffect(() => {
    const token = getDropboxToken()
    if (!token) {
      setHasDropboxToken(false)
      return
    }
    setHasDropboxToken(true)
    void refreshDropboxAccount(token)
  }, [])

  useEffect(() => {
    if (typeof window === "undefined") return
    const storedMode = localStorage.getItem(backupSizeModeKey)
    if (storedMode === "full" || storedMode === "essential") {
      setBackupSizeMode(storedMode)
    }
  }, [])

  const handleDropboxConnect = async () => {
    if (!hasDropboxConfig) {
      toast({
        title: "Dropbox Not Configured",
        description: "Set NEXT_PUBLIC_DROPBOX_APP_KEY to enable Dropbox backups.",
        variant: "destructive",
      })
      return
    }
    setIsDropboxConnecting(true)
    try {
      const token = await ensureDropboxToken()
      setHasDropboxToken(true)
      const account = await refreshDropboxAccount(token)
      toast({
        title: "Dropbox Connected (Beta)",
        description: account?.email ? `Connected as ${account.email}` : "Dropbox connected.",
      })
      void handleDropboxDownload(undefined, { auto: true })
    } catch (error) {
      toast({
        title: "Dropbox Connection Failed",
        description: error instanceof Error ? error.message : "Unable to connect Dropbox.",
        variant: "destructive",
      })
    } finally {
      setIsDropboxConnecting(false)
    }
  }

  const handleDropboxDisconnect = () => {
    clearDropboxToken()
    setDropboxAccount(null)
    setDropboxError(null)
    setHasDropboxToken(false)
    toast({
      title: "Dropbox Disconnected",
      description: "Dropbox access has been removed from this device.",
    })
  }

  const loadTombstones = async () => {
    const stored = await loadFromLocalStorage([...TOMBSTONE_KEYS])
    return TOMBSTONE_KEYS.reduce<Record<string, TombstoneRecord[]>>((acc, key) => {
      acc[key] = Array.isArray(stored[key]) ? stored[key] : []
      return acc
    }, {})
  }

  const refreshTombstoneStats = async () => {
    setIsTombstoneLoading(true)
    try {
      const stored = await loadFromLocalStorage([...TOMBSTONE_KEYS])
      const stats = TOMBSTONE_KEYS.map((key) => {
        const list = Array.isArray(stored[key]) ? stored[key] : []
        return { label: TOMBSTONE_LABELS[key], count: list.length }
      })
      setTombstoneStats(stats)
    } finally {
      setIsTombstoneLoading(false)
    }
  }

  const clearAllTombstones = async () => {
    setIsTombstoneLoading(true)
    try {
      for (const key of TOMBSTONE_KEYS) {
        await saveToLocalStorage(key, [], true)
      }
      await refreshTombstoneStats()
      toast({
        title: "Tombstones Cleared",
        description: "Deletion sync history has been cleared for this device.",
      })
    } finally {
      setIsTombstoneLoading(false)
    }
  }

  const mergeTombstoneLists = (localList: TombstoneRecord[], remoteList: TombstoneRecord[]) => {
    const map = new Map<string, TombstoneRecord>()
    const add = (entry: TombstoneRecord) => {
      const existing = map.get(entry.id)
      if (!existing) {
        map.set(entry.id, entry)
        return
      }
      const existingTime = Date.parse(existing.deletedAt || "")
      const entryTime = Date.parse(entry.deletedAt || "")
      if (!Number.isFinite(existingTime) || entryTime > existingTime) {
        map.set(entry.id, entry)
      }
    }
    localList.forEach(add)
    remoteList.forEach(add)
    const cutoff = Date.now() - TOMBSTONE_RETENTION_MS
    return Array.from(map.values()).filter((entry) => Date.parse(entry.deletedAt || "") >= cutoff)
  }

  const getItemTimestamp = (item: any) => {
    const candidate = item?.updatedAt || item?.lastUpdated || item?.createdAt || item?.date || item?.timestamp
    if (!candidate) return 0
    const time = Date.parse(candidate)
    return Number.isFinite(time) ? time : 0
  }

  const mergeById = <T extends { id?: string }>(localList: T[], remoteList: T[]) => {
    const map = new Map<string, T>()
    const extras: T[] = []
    remoteList.forEach((item) => {
      if (!item?.id) {
        extras.push(item)
        return
      }
      map.set(item.id, item)
    })
    localList.forEach((item) => {
      if (!item?.id) {
        extras.push(item)
        return
      }
      const existing = map.get(item.id)
      if (!existing) {
        map.set(item.id, item)
        return
      }
      const existingTime = getItemTimestamp(existing)
      const itemTime = getItemTimestamp(item)
      if (itemTime > existingTime) {
        map.set(item.id, item)
      }
    })
    return [...map.values(), ...extras]
  }

  const applyTombstones = <T extends { id?: string }>(items: T[], tombstones: TombstoneRecord[]) => {
    if (tombstones.length === 0) return items
    const tombstoneMap = new Map<string, number>()
    tombstones.forEach((entry) => {
      const time = Date.parse(entry.deletedAt || "")
      tombstoneMap.set(entry.id, Number.isFinite(time) ? time : 0)
    })
    return items.filter((item) => {
      if (!item?.id) return true
      const deletedAt = tombstoneMap.get(item.id)
      if (!deletedAt) return true
      const itemTime = getItemTimestamp(item)
      return itemTime > deletedAt
    })
  }

  const buildBackupData = async (mode: "essential" | "full") => {
    const customCategoriesOnly = categories.filter((category) => !category?.isDefault)
    const tombstones = await loadTombstones()
    const data: any = {
      exportDate: new Date().toISOString(),
      version: "2.0",
      backupOptions: {
        backupSize: mode,
        userProfile: true,
        transactions: true,
        budgets: true,
        goals: true,
        debtAccounts: true,
        creditAccounts: true,
        debtCreditTransactions: true,
        categories: true,
        emergencyFund: true,
        portfolio: true,
        shareTransactions: true,
        portfolios: true,
        activePortfolioId: true,
        showScrollbars: true,
      },
      userProfile,
      transactions,
      budgets,
      goals,
      debtAccounts,
      creditAccounts,
      debtCreditTransactions,
      categories: customCategoriesOnly,
      emergencyFund,
      portfolio,
      shareTransactions,
      portfolios,
      activePortfolioId,
      tombstones,
    }

    const showScrollbars = localStorage.getItem("wallet_show_scrollbars") !== "false"
    data.settings = { ...data.settings, showScrollbars }

    if (mode === "full") {
      const extras = await loadFromLocalStorage([...nonEssentialBackupKeys])
      nonEssentialBackupKeys.forEach((key) => {
        if (!Object.prototype.hasOwnProperty.call(extras, key)) return
        const value = extras[key]
        if (value === null || typeof value === "undefined") return
        data[key] = value
      })
    }

    return data
  }

  const mergeDropboxData = async (remoteData: any) => {
    const localTombstones = await loadTombstones()
    const remoteTombstones = typeof remoteData?.tombstones === "object" && remoteData.tombstones ? remoteData.tombstones : {}
    const mergedTombstones = TOMBSTONE_KEYS.reduce<Record<string, TombstoneRecord[]>>((acc, key) => {
      const localList = Array.isArray(localTombstones[key]) ? localTombstones[key] : []
      const remoteList = Array.isArray(remoteTombstones[key]) ? remoteTombstones[key] : []
      acc[key] = mergeTombstoneLists(localList, remoteList)
      return acc
    }, {})

    const mergedTransactions = applyTombstones(
      mergeById(transactions, Array.isArray(remoteData?.transactions) ? remoteData.transactions : []),
      mergedTombstones.deleted_transactions,
    )
    const mergedBudgets = applyTombstones(
      mergeById(budgets, Array.isArray(remoteData?.budgets) ? remoteData.budgets : []),
      mergedTombstones.deleted_budgets,
    )
    const mergedGoals = applyTombstones(
      mergeById(goals, Array.isArray(remoteData?.goals) ? remoteData.goals : []),
      mergedTombstones.deleted_goals,
    )
    const mergedDebtAccounts = applyTombstones(
      mergeById(debtAccounts, Array.isArray(remoteData?.debtAccounts) ? remoteData.debtAccounts : []),
      mergedTombstones.deleted_debtAccounts,
    )
    const mergedCreditAccounts = applyTombstones(
      mergeById(creditAccounts, Array.isArray(remoteData?.creditAccounts) ? remoteData.creditAccounts : []),
      mergedTombstones.deleted_creditAccounts,
    )
    const mergedDebtCreditTransactions = applyTombstones(
      mergeById(debtCreditTransactions, Array.isArray(remoteData?.debtCreditTransactions) ? remoteData.debtCreditTransactions : []),
      mergedTombstones.deleted_debtCreditTransactions,
    )
    const mergedCategories = applyTombstones(
      mergeById(categories, Array.isArray(remoteData?.categories) ? remoteData.categories : []),
      mergedTombstones.deleted_categories,
    )
    const mergedShareTransactions = applyTombstones(
      mergeById(shareTransactions, Array.isArray(remoteData?.shareTransactions) ? remoteData.shareTransactions : []),
      mergedTombstones.deleted_shareTransactions,
    )
    const mergedPortfolios = applyTombstones(
      mergeById(portfolios, Array.isArray(remoteData?.portfolios) ? remoteData.portfolios : []),
      mergedTombstones.deleted_portfolios,
    )
    const mergedPortfolio = mergeById(portfolio, Array.isArray(remoteData?.portfolio) ? remoteData.portfolio : [])

    const mergedEmergencyFund = typeof remoteData?.emergencyFund !== "undefined"
      ? remoteData.emergencyFund
      : emergencyFund

    return {
      ...remoteData,
      userProfile: remoteData?.userProfile ?? userProfile,
      transactions: mergedTransactions,
      budgets: mergedBudgets,
      goals: mergedGoals,
      debtAccounts: mergedDebtAccounts,
      creditAccounts: mergedCreditAccounts,
      debtCreditTransactions: mergedDebtCreditTransactions,
      categories: mergedCategories,
      portfolio: mergedPortfolio,
      shareTransactions: mergedShareTransactions,
      portfolios: mergedPortfolios,
      activePortfolioId: activePortfolioId ?? remoteData?.activePortfolioId ?? null,
      emergencyFund: mergedEmergencyFund,
      tombstones: mergedTombstones,
    }
  }

  const persistTombstones = async (tombstones: Record<string, TombstoneRecord[]>) => {
    for (const key of TOMBSTONE_KEYS) {
      const list = Array.isArray(tombstones[key]) ? tombstones[key] : []
      await saveToLocalStorage(key, list, true)
    }
  }

  const persistOptionalBackupData = async (data: any) => {
    for (const key of nonEssentialBackupKeys) {
      if (!Object.prototype.hasOwnProperty.call(data, key)) continue
      const value = data[key]
      if (value === null || typeof value === "undefined") continue
      await saveToLocalStorage(key, value, true)
    }
  }

  const runDropboxImport = async (decrypted: any, localPinOverride?: string) => {
    setIsDropboxPulling(true)
    try {
      const requiresUnlock = SecurePinManager.hasPin() && !SecureKeyManager.isKeyCacheValid()
      const cachedPin = SecureKeyManager.getCachedSessionPin() ?? undefined
      const localPin = localPinOverride ?? cachedPin
      if (requiresUnlock && !localPin) {
        setPendingDecryptedBackup(decrypted)
        setDropboxLocalPinAction("import")
        setShowDropboxLocalPinPrompt(true)
        return
      }

      const merged = await mergeDropboxData(decrypted)
      await importData(merged, localPin)
      if (merged?.tombstones) {
        await persistTombstones(merged.tombstones)
      }
      await persistOptionalBackupData(decrypted)

      toast({
        title: "Dropbox Backup Restored (Beta)",
        description: "Your wallet data has been imported successfully.",
      })
    } catch (error) {
      toast({
        title: "Dropbox Restore Failed",
        description: error instanceof Error ? error.message : "Failed to restore backup from Dropbox.",
        variant: "destructive",
      })
    } finally {
      setIsDropboxPulling(false)
    }
  }

  const handleBackupSuccess = async (data: any, pin: string) => {
    try {
      const { createEncryptedBackup } = await import("@/lib/backup")
      const backupJson = await createEncryptedBackup(data, pin)
      const filename = `mywallet-selective-backup-${new Date().toISOString().split("T")[0]}.json`

      if (backupDestination === "dropbox") {
        const token = await ensureDropboxToken()
        await uploadToDropbox(backupJson, filename, token)
        toast({
          title: "Backup Uploaded to Dropbox (Beta)",
          description: "Your encrypted backup has been saved to your Dropbox.",
        })
      } else {
        const blob = new Blob([backupJson], { type: "application/json" })
        const url = URL.createObjectURL(blob)
        const a = document.createElement("a")
        a.href = url
        a.download = filename
        document.body.appendChild(a)
        a.click()
        document.body.removeChild(a)
        URL.revokeObjectURL(url)

        toast({
          title: "Selective Backup Created",
          description: "Your selected wallet data has been encrypted and downloaded successfully.",
        })
      }
    } catch (error) {
      console.error("Backup creation failed:", error)
      toast({
        title: "Backup Failed",
        description: "Failed to create encrypted backup. Please try again.",
        variant: "destructive",
      })
      throw error
    }
  }

  const handleDropboxPush = async (overridePin?: string) => {
    if (!hasDropboxConfig) {
      toast({
        title: "Dropbox Not Configured",
        description: "Set NEXT_PUBLIC_DROPBOX_APP_KEY to enable Dropbox backups.",
        variant: "destructive",
      })
      return
    }

    const cachedPin = SecureKeyManager.getCachedSessionPin()
    const pinToUse = overridePin || cachedPin || (SecurePinManager.hasPin() ? "" : DEFAULT_BACKUP_PIN)
    if (!pinToUse) {
      setDropboxLocalPinAction("push")
      setShowDropboxLocalPinPrompt(true)
      return
    }

    try {
      setIsDropboxPushing(true)
      const { createEncryptedBackup } = await import("@/lib/backup")
      const data = await buildBackupData(backupSizeMode)
      const backupJson = await createEncryptedBackup(data, pinToUse)
      const filename = "mywallet-backup.json"

      const token = await ensureDropboxToken()
      await uploadToDropbox(backupJson, filename, token, { overwrite: true })
      toast({
        title: "Backup Uploaded to Dropbox (Beta)",
        description: "Your encrypted backup has been saved to your Dropbox.",
      })
    } catch (error) {
      toast({
        title: "Dropbox Backup Failed",
        description: error instanceof Error ? error.message : "Failed to upload backup to Dropbox.",
        variant: "destructive",
      })
    } finally {
      setIsDropboxPushing(false)
    }
  }

  const handleDropboxDownload = async (overridePin?: string, options?: { auto?: boolean }) => {
    try {
      setIsDropboxPulling(true)
      const token = await ensureDropboxToken()
      const latest = await getLatestDropboxBackup(token)
      if (!latest) {
        if (!options?.auto) {
          toast({
            title: "No Dropbox Backup Found",
            description: "Upload a backup first to download it.",
            variant: "destructive",
          })
        }
        return
      }

      const content = await downloadDropboxFile(latest.path_lower, token)
      const cachedPin = SecureKeyManager.getCachedSessionPin()
      const pinToUse = overridePin || cachedPin
      if (!pinToUse) {
        try {
          const { restoreEncryptedBackup } = await import("@/lib/backup")
          const decrypted = await restoreEncryptedBackup(content, DEFAULT_BACKUP_PIN)
          setIsDropboxPulling(false)
          await runDropboxImport(decrypted, DEFAULT_BACKUP_PIN)
          return
        } catch (error) {
          const message = error instanceof Error ? error.message : String(error)
          if (message.toLowerCase().includes("decryption failed")) {
            setPendingDropboxContent(content)
            setDropboxBackupPinAction("pull")
            setIsDropboxPulling(false)
            setShowDropboxBackupPinPrompt(true)
            return
          }
          throw error
        }
      }

      const { restoreEncryptedBackup } = await import("@/lib/backup")
      let decrypted: any
      try {
        decrypted = await restoreEncryptedBackup(content, pinToUse)
      } catch (error) {
        const message = error instanceof Error ? error.message : String(error)
        if (message.toLowerCase().includes("decryption failed")) {
          setPendingDropboxContent(content)
          setDropboxBackupPinAction("pull")
          setIsDropboxPulling(false)
          setShowDropboxBackupPinPrompt(true)
          return
        }
        throw error
      }

      setIsDropboxPulling(false)
      await runDropboxImport(decrypted, pinToUse)
    } catch (error) {
      toast({
        title: "Dropbox Restore Failed",
        description: error instanceof Error ? error.message : "Failed to restore backup from Dropbox.",
        variant: "destructive",
      })
    } finally {
      setIsDropboxPulling(false)
    }
  }

  const handleClearAllData = () => {
    clearAllData()
    toast({
      title: "Data Cleared",
      description: "All your wallet data has been permanently deleted.",
      variant: "destructive",
    })
  }

  const getDataStats = () => {
    const totalTransactions = transactions.length
    const totalBudgets = budgets.length
    const totalGoals = goals.length
    const totalPortfolios = portfolios.length
    const dataSize = new Blob([JSON.stringify({ userProfile, transactions, budgets, goals })]).size

    return {
      totalTransactions,
      totalBudgets,
      totalGoals,
      totalPortfolios,
      dataSize: `${(dataSize / 1024).toFixed(2)} KB`,
    }
  }

  const stats = getDataStats()

  return (
    <div className="space-y-6">
      <Card>
        <CardHeader>
          <CardTitle className="flex items-center gap-2">
            <Database className="h-5 w-5" />
            Data Overview
          </CardTitle>
          <CardDescription>Current wallet data snapshot</CardDescription>
        </CardHeader>
        <CardContent>
          <div className="grid grid-cols-2 gap-3 md:grid-cols-5">
            <div className="rounded-lg border bg-muted p-3 text-center">
              <p className="text-2xl font-bold text-primary">{stats.totalTransactions}</p>
              <p className="text-xs text-muted-foreground">Transactions</p>
            </div>
            <div className="rounded-lg border bg-muted p-3 text-center">
              <p className="text-2xl font-bold text-primary">{stats.totalBudgets}</p>
              <p className="text-xs text-muted-foreground">Budgets</p>
            </div>
            <div className="rounded-lg border bg-muted p-3 text-center">
              <p className="text-2xl font-bold text-primary">{stats.totalGoals}</p>
              <p className="text-xs text-muted-foreground">Goals</p>
            </div>
            <div className="rounded-lg border bg-muted p-3 text-center">
              <p className="text-2xl font-bold text-primary">{stats.totalPortfolios}</p>
              <p className="text-xs text-muted-foreground">Portfolios</p>
            </div>
            <div className="rounded-lg border bg-muted p-3 text-center">
              <p className="text-2xl font-bold text-primary">{stats.dataSize}</p>
              <p className="text-xs text-muted-foreground">Approx Size</p>
            </div>
          </div>
        </CardContent>
      </Card>

      <Card>
        <CardHeader>
          <CardTitle className="flex items-center gap-2">
            <FileText className="h-5 w-5" />
            Backup & Restore
          </CardTitle>
          <CardDescription>Export your data securely or restore it with guided import</CardDescription>
        </CardHeader>
        <CardContent className="p-6">
          <div className="grid grid-cols-1 gap-6 lg:grid-cols-2">
            <div className="relative overflow-hidden rounded-xl border border-primary/20 bg-gradient-to-br from-primary/5 via-primary/10 to-primary/5 p-6">
              <div className="absolute -right-10 -top-10 h-20 w-20 rounded-full bg-primary/10" />
              <div className="relative z-10 space-y-4">
                <div className="flex items-center gap-3">
                  <div className="rounded-lg bg-primary/10 p-2">
                    <Download className="h-5 w-5 text-primary" />
                  </div>
                  <div>
                    <h3 className="text-lg font-semibold">Export Data</h3>
                    <p className="text-sm text-muted-foreground">Create secure backup</p>
                  </div>
                </div>

                <p className="text-sm text-muted-foreground">
                  Create an encrypted backup of your wallet data. You can choose all data or only selected sections.
                </p>
                <div className="rounded-lg border bg-background/80 p-3">
                  <div className="flex items-center gap-2 text-sm font-medium">
                    <ShieldCheck className="h-4 w-4 text-primary" />
                    Backup Flow
                  </div>
                  <p className="mt-1 text-xs text-muted-foreground">
                    Select sections, verify wallet PIN, and download your encrypted backup.
                  </p>
                </div>

                <Button
                  onClick={() => handleCreateBackup("download")}
                  className="w-full bg-gradient-to-r from-primary to-primary/80 hover:from-primary/90 hover:to-primary/70"
                  size="lg"
                >
                  <Download className="mr-2 h-4 w-4" />
                  Create Selective Backup
                </Button>
              </div>
            </div>

            <div className="relative overflow-hidden rounded-xl border border-green-500/20 bg-gradient-to-br from-green-500/5 via-green-500/10 to-green-500/5 p-6">
              <div className="absolute -right-10 -top-10 h-20 w-20 rounded-full bg-green-500/10" />
              <div className="relative z-10 space-y-4">
                <div className="flex items-center gap-3">
                  <div className="rounded-lg bg-green-500/10 p-2">
                    <Upload className="h-5 w-5 text-green-600" />
                  </div>
                  <div>
                    <h3 className="text-lg font-semibold">Import Data</h3>
                    <p className="text-sm text-muted-foreground">Restore from backup</p>
                  </div>
                </div>

                <p className="text-sm text-muted-foreground">
                  Import now uses a guided flow to avoid errors and keep recovery simple.
                </p>

                <div className="rounded-lg border bg-background/80 p-3">
                  <div className="flex items-center gap-2 text-sm font-medium">
                    <Workflow className="h-4 w-4 text-green-600" />
                    Guided Import
                  </div>
                  <ul className="mt-1 space-y-1 text-xs text-muted-foreground">
                    <li>1. Upload backup file</li>
                    <li>2. Enter PIN if encrypted</li>
                    <li>3. Import all by default or customize</li>
                  </ul>
                </div>

                <Button
                  onClick={() => setShowImportModal(true)}
                  className="w-full bg-gradient-to-r from-green-600 to-green-500 hover:from-green-700 hover:to-green-600"
                  size="lg"
                >
                  <Upload className="mr-2 h-4 w-4" />
                  Start Import
                </Button>
              </div>
            </div>
          </div>
        </CardContent>
      </Card>

      <Card>
        <CardHeader>
          <CardTitle className="flex items-center justify-between gap-2">
            <span className="flex items-center gap-2">
              <Cloud className="h-5 w-5" />
              Dropbox Backup
              <Badge variant="outline" className="text-[10px] font-black uppercase tracking-wider">
                Beta
              </Badge>
            </span>
            <div className="flex items-center gap-1">
              <Button
                onClick={() => setShowDropboxInfo((prev) => !prev)}
                variant="ghost"
                size="icon"
                aria-label={showDropboxInfo ? "Hide Dropbox details" : "Show Dropbox details"}
              >
                <Info className="h-4 w-4" />
              </Button>
              <Button
                onClick={() => {
                  const token = getDropboxToken()
                  if (token) {
                    void refreshDropboxAccount(token)
                  }
                }}
                variant="ghost"
                size="icon"
                aria-label="Refresh Dropbox status"
                disabled={!hasDropboxToken}
              >
                <RefreshCw className={`h-4 w-4 ${isDropboxRefreshing ? "animate-spin" : ""}`} />
              </Button>
            </div>
          </CardTitle>
          <CardDescription>Manual push/pull backups to your Dropbox.</CardDescription>
        </CardHeader>
        <CardContent className="space-y-4">
          {showDropboxInfo && (
            <div className="rounded-lg border bg-muted/20 p-4 space-y-3">
              <div className="flex items-center gap-2 text-sm font-medium">
                <Info className="h-4 w-4 text-primary" />
                Dropbox backup details
              </div>
              <p className="text-xs text-muted-foreground">
                We store one encrypted file named <span className="font-mono">mywallet-backup.json</span> in your Dropbox App folder.
              </p>
              {!hasDropboxConfig && (
                <p className="text-xs text-muted-foreground">
                  Set <span className="font-mono">NEXT_PUBLIC_DROPBOX_APP_KEY</span> to enable Dropbox backups.
                </p>
              )}
              {hasDropboxToken && (
                <div className="rounded-md border bg-background/70 p-3">
                  <p className="text-xs font-medium text-foreground">Backup size mode</p>
                  <p className="mt-1 text-xs text-muted-foreground">
                    Essential skips scan history, drafts, and offline queues.
                  </p>
                  <div className="mt-2 grid grid-cols-2 gap-2">
                    <Button
                      type="button"
                      variant={backupSizeMode === "essential" ? "default" : "outline"}
                      size="sm"
                      onClick={() => {
                        setBackupSizeMode("essential")
                        localStorage.setItem(backupSizeModeKey, "essential")
                      }}
                    >
                      Essential
                    </Button>
                    <Button
                      type="button"
                      variant={backupSizeMode === "full" ? "default" : "outline"}
                      size="sm"
                      onClick={() => {
                        setBackupSizeMode("full")
                        localStorage.setItem(backupSizeModeKey, "full")
                      }}
                    >
                      Full
                    </Button>
                  </div>
                </div>
              )}
            </div>
          )}
          {!hasDropboxToken ? (
            <div className="rounded-lg border bg-muted/20 p-4 space-y-3">
              <p className="text-sm text-muted-foreground">
                Connect your Dropbox account to enable manual backup uploads and downloads.
              </p>
              <Button onClick={handleDropboxConnect} disabled={!hasDropboxConfig || isDropboxConnecting}>
                <Cloud className="mr-2 h-4 w-4" />
                {isDropboxConnecting ? "Connecting..." : "Connect Dropbox"}
              </Button>
            </div>
          ) : (
            <div className="rounded-lg border bg-muted/20 p-4 space-y-3">
              <div className="flex items-center justify-between gap-3">
                <div>
                  <p className="text-sm font-medium">Connected Dropbox</p>
                  <p className="text-xs text-muted-foreground">{dropboxAccount?.email || "Account details unavailable"}</p>
                </div>
                <Badge variant="secondary">Connected</Badge>
              </div>
              {dropboxError && (
                <p className="text-xs text-destructive">
                  {dropboxError}
                </p>
              )}
              <div className="grid grid-cols-1 gap-2 sm:grid-cols-2">
                <Button onClick={() => void handleDropboxPush()} variant="outline" disabled={isDropboxPushing || isDropboxPulling}>
                  {isDropboxPushing ? (
                    <Loader2 className="mr-2 h-4 w-4 animate-spin" />
                  ) : (
                    <Cloud className="mr-2 h-4 w-4" />
                  )}
                  {isDropboxPushing ? "Pushing..." : "Push Backup"}
                </Button>
                <Button onClick={() => void handleDropboxDownload()} variant="outline" disabled={isDropboxPulling || isDropboxPushing}>
                  {isDropboxPulling ? (
                    <Loader2 className="mr-2 h-4 w-4 animate-spin" />
                  ) : (
                    <Download className="mr-2 h-4 w-4" />
                  )}
                  {isDropboxPulling ? "Pulling..." : "Pull Backup"}
                </Button>
              </div>
              {showDropboxInfo && (
                <div className="space-y-2">
                  <p className="text-xs text-muted-foreground">
                    Push overwrites <span className="font-mono">mywallet-backup.json</span>. Pull downloads it for Import.
                  </p>
                  <Button onClick={handleDropboxDisconnect} variant="ghost" size="sm" className="w-full">
                    Disconnect Dropbox
                  </Button>
                </div>
              )}
            </div>
          )}
        </CardContent>
      </Card>

      <Dialog open={showDropboxBackupPinPrompt} onOpenChange={(open) => setShowDropboxBackupPinPrompt(open)}>
        <DialogContent>
          <DialogHeader>
            <DialogTitle>Enter Backup PIN</DialogTitle>
          </DialogHeader>
          <div className="space-y-4">
            <div className="space-y-2">
              <Label htmlFor="dropbox-backup-pin">Backup PIN</Label>
              <Input
                id="dropbox-backup-pin"
                type="password"
                inputMode="numeric"
                value={dropboxBackupPin}
                onChange={(e) => setDropboxBackupPin(e.target.value)}
                placeholder="Enter the PIN used to create the backup"
              />
            </div>
            <div className="flex gap-2">
              <Button
                onClick={() => {
                  setShowDropboxBackupPinPrompt(false)
                  setDropboxBackupPin("")
                }}
                variant="outline"
                className="flex-1"
              >
                Cancel
              </Button>
              <Button
                onClick={() => {
                  const pin = dropboxBackupPin.trim()
                  if (!pin) {
                    toast({
                      title: "PIN Required",
                      description: "Please enter the backup PIN.",
                      variant: "destructive",
                    })
                    return
                  }
                  setShowDropboxBackupPinPrompt(false)
                  setDropboxBackupPin("")
                  const content = pendingDropboxContent
                  if (!content) {
                    toast({
                      title: "Backup Missing",
                      description: "Please try pulling again.",
                      variant: "destructive",
                    })
                    return
                  }
                  setPendingDropboxContent(null)
                  void (async () => {
                    setIsDropboxPulling(true)
                    try {
                      const { restoreEncryptedBackup } = await import("@/lib/backup")
                      const decrypted = await restoreEncryptedBackup(content, pin)
                      setIsDropboxPulling(false)
                      await runDropboxImport(decrypted)
                    } catch (error) {
                      setIsDropboxPulling(false)
                      toast({
                        title: "Invalid Backup PIN",
                        description: error instanceof Error ? error.message : "Failed to decrypt backup.",
                        variant: "destructive",
                      })
                    }
                  })()
                }}
                className="flex-1"
              >
                Continue
              </Button>
            </div>
          </div>
        </DialogContent>
      </Dialog>

      <Dialog open={showDropboxLocalPinPrompt} onOpenChange={(open) => setShowDropboxLocalPinPrompt(open)}>
        <DialogContent>
          <DialogHeader>
            <DialogTitle>
              {dropboxLocalPinAction === "push" ? "Unlock Wallet to Push" : "Unlock Wallet to Import"}
            </DialogTitle>
          </DialogHeader>
          <div className="space-y-4">
            <div className="space-y-2">
              <Label htmlFor="dropbox-local-pin">Wallet PIN</Label>
              <Input
                id="dropbox-local-pin"
                type="password"
                inputMode="numeric"
                value={dropboxLocalPin}
                onChange={(e) => setDropboxLocalPin(e.target.value)}
                placeholder="Enter your wallet PIN"
              />
            </div>
            <div className="flex gap-2">
              <Button
                onClick={() => {
                  setShowDropboxLocalPinPrompt(false)
                  setDropboxLocalPin("")
                }}
                variant="outline"
                className="flex-1"
              >
                Cancel
              </Button>
              <Button
                onClick={() => {
                  const pin = dropboxLocalPin.trim()
                  if (!pin) {
                    toast({
                      title: "PIN Required",
                      description: "Please enter your wallet PIN.",
                      variant: "destructive",
                    })
                    return
                  }
                  const decrypted = pendingDecryptedBackup
                  if (dropboxLocalPinAction === "push") {
                    void (async () => {
                      const validation = await SecurePinManager.validatePin(pin)
                      if (!validation.success) {
                        toast({
                          title: "Invalid Wallet PIN",
                          description: "Please enter the correct PIN to continue.",
                          variant: "destructive",
                        })
                        return
                      }
                      SecureKeyManager.cacheSessionPin(pin)
                      setShowDropboxLocalPinPrompt(false)
                      setDropboxLocalPin("")
                      void handleDropboxPush(pin)
                    })()
                    return
                  }
                  if (!decrypted) {
                    toast({
                      title: "Backup Missing",
                      description: "Please try pulling again.",
                      variant: "destructive",
                    })
                    return
                  }
                  setShowDropboxLocalPinPrompt(false)
                  setDropboxLocalPin("")
                  setPendingDecryptedBackup(null)
                  void runDropboxImport(decrypted, pin)
                }}
                className="flex-1"
              >
                Continue
              </Button>
            </div>
          </div>
        </DialogContent>
      </Dialog>

      <Card className="border-destructive">
        <CardHeader>
          <CardTitle className="flex items-center gap-2 text-destructive">
            <Trash2 className="h-5 w-5" />
            Data Management
          </CardTitle>
          <CardDescription>Manage or remove local wallet data</CardDescription>
        </CardHeader>
        <CardContent>
          <div className="flex flex-col gap-4 rounded-lg border border-destructive p-4 sm:flex-row sm:items-center sm:justify-between">
            <div>
              <p className="font-medium text-destructive">Clear All Data</p>
              <p className="text-sm text-muted-foreground">
                Permanently delete all transactions, budgets, goals, portfolios, and settings.
              </p>
            </div>
            <DeleteDataDialog
              trigger={
                <Button variant="destructive">
                  <Trash2 className="mr-2 h-4 w-4" />
                  Clear All
                </Button>
              }
              title="Clear All Data"
              description="This will permanently delete all your wallet data including transactions, budgets, goals, and settings. Your PIN and security data will also be completely removed."
              onConfirm={handleClearAllData}
              type="data"
            />
          </div>
        </CardContent>
      </Card>

      <Card>
        <CardHeader>
          <CardTitle className="flex items-center gap-2">
            <ShieldCheck className="h-5 w-5" />
            Deletion Sync (Tombstones)
          </CardTitle>
          <CardDescription>Tracks deletions to keep devices in sync.</CardDescription>
        </CardHeader>
        <CardContent className="space-y-3">
          <Button
            variant="ghost"
            size="sm"
            className="w-full"
            onClick={() => {
              const next = !showTombstoneInfo
              setShowTombstoneInfo(next)
              if (next) {
                void refreshTombstoneStats()
              }
            }}
          >
            {showTombstoneInfo ? "Hide details" : "Learn more"}
          </Button>
          {showTombstoneInfo && (
            <div className="space-y-2 text-xs text-muted-foreground">
              <p>
                Tombstones are kept for 30 days to propagate deletions across devices.
              </p>
              <Button
                variant="outline"
                size="sm"
                className="w-full"
                onClick={clearAllTombstones}
                disabled={isTombstoneLoading}
              >
                Clear Tombstones
              </Button>
              {isTombstoneLoading ? (
                <p>Loading tombstone stats...</p>
              ) : (
                <div className="grid grid-cols-2 gap-2 sm:grid-cols-3">
                  {tombstoneStats.map((stat) => (
                    <div key={stat.label} className="rounded-md border bg-background/70 p-2">
                      <p className="font-medium text-foreground">{stat.label}</p>
                      <p>{stat.count} records</p>
                    </div>
                  ))}
                </div>
              )}
            </div>
          )}
        </CardContent>
      </Card>

      <BackupModal
        isOpen={showBackupModal}
        onClose={() => setShowBackupModal(false)}
        onBackupComplete={() => {
          setShowBackupModal(false)
          toast({
            title: "Backup Created",
            description: "Your selective backup has been created successfully.",
          })
        }}
        onBackupSuccess={handleBackupSuccess}
        userProfile={userProfile}
        transactions={transactions}
        budgets={budgets}
        goals={goals}
        debtAccounts={debtAccounts}
        creditAccounts={creditAccounts}
        debtCreditTransactions={debtCreditTransactions}
        categories={categories}
        emergencyFund={emergencyFund}
        portfolio={portfolio}
        shareTransactions={shareTransactions}
        portfolios={portfolios}
        activePortfolioId={activePortfolioId}
      />

      <ImportModal
        isOpen={showImportModal}
        onClose={() => setShowImportModal(false)}
        onImportComplete={() => {
          setShowImportModal(false)
          toast({
            title: "Data Imported",
            description: "Your selected wallet data has been restored successfully.",
          })
        }}
        onImportData={importData}
      />
    </div>
  )
}

"use client"

import React, { useEffect, useMemo, useState } from "react"
import { Badge } from "@/components/ui/badge"
import { Button } from "@/components/ui/button"
import { Checkbox } from "@/components/ui/checkbox"
import {
  Dialog,
  DialogContent,
  DialogDescription,
  DialogFooter,
  DialogHeader,
  DialogTitle,
} from "@/components/ui/dialog"
import { Input } from "@/components/ui/input"
import { Label } from "@/components/ui/label"
import { toast } from "@/hooks/use-toast"
import { SecurePinManager } from "@/lib/secure-pin-manager"
import { SecureKeyManager } from "@/lib/key-manager"

type ImportOptions = {
  userProfile: boolean
  transactions: boolean
  budgets: boolean
  goals: boolean
  debtAccounts: boolean
  creditAccounts: boolean
  debtCreditTransactions: boolean
  categories: boolean
  emergencyFund: boolean
  portfolio: boolean
  shareTransactions: boolean
  portfolios: boolean
  activePortfolioId: boolean
  showScrollbars: boolean
}

type ImportMode = "all" | "custom"

type ImportStep = "file" | "pin" | "review"

interface ImportModalProps {
  isOpen: boolean
  onClose: () => void
  onImportComplete: () => void
  onImportData: (data: any, unlockPin?: string) => Promise<boolean>
}

const defaultOptions: ImportOptions = {
  userProfile: false,
  transactions: false,
  budgets: false,
  goals: false,
  debtAccounts: false,
  creditAccounts: false,
  debtCreditTransactions: false,
  categories: false,
  emergencyFund: false,
  portfolio: false,
  shareTransactions: false,
  portfolios: false,
  activePortfolioId: false,
  showScrollbars: false,
}

function getAvailableOptions(data: any): ImportOptions {
  return {
    userProfile: !!data?.userProfile,
    transactions: Array.isArray(data?.transactions),
    budgets: Array.isArray(data?.budgets),
    goals: Array.isArray(data?.goals),
    debtAccounts: Array.isArray(data?.debtAccounts),
    creditAccounts: Array.isArray(data?.creditAccounts),
    debtCreditTransactions: Array.isArray(data?.debtCreditTransactions),
    categories: Array.isArray(data?.categories),
    emergencyFund: typeof data?.emergencyFund === "number" || typeof data?.emergencyFund === "string",
    portfolio: Array.isArray(data?.portfolio),
    shareTransactions: Array.isArray(data?.shareTransactions),
    portfolios: Array.isArray(data?.portfolios),
    activePortfolioId: Object.prototype.hasOwnProperty.call(data ?? {}, "activePortfolioId"),
    showScrollbars: data?.settings?.showScrollbars !== undefined,
  }
}

function buildSelectiveData(source: any, options: ImportOptions) {
  const selectiveData: any = {
    exportDate: source.exportDate || new Date().toISOString(),
    version: source.version || "2.0",
  }

  if (options.userProfile && source.userProfile) selectiveData.userProfile = source.userProfile
  if (options.transactions && source.transactions) selectiveData.transactions = source.transactions
  if (options.budgets && source.budgets) selectiveData.budgets = source.budgets
  if (options.goals && source.goals) selectiveData.goals = source.goals
  if (options.debtAccounts && source.debtAccounts) selectiveData.debtAccounts = source.debtAccounts
  if (options.creditAccounts && source.creditAccounts) selectiveData.creditAccounts = source.creditAccounts
  if (options.debtCreditTransactions && Array.isArray(source.debtCreditTransactions)) {
    selectiveData.debtCreditTransactions = source.debtCreditTransactions
  }
  if (options.categories && source.categories) selectiveData.categories = source.categories
  if (options.emergencyFund && (typeof source.emergencyFund === "number" || typeof source.emergencyFund === "string")) {
    selectiveData.emergencyFund = source.emergencyFund
  }
  if (options.portfolio && Array.isArray(source.portfolio)) selectiveData.portfolio = source.portfolio
  if (options.shareTransactions && Array.isArray(source.shareTransactions)) {
    selectiveData.shareTransactions = source.shareTransactions
  }
  if (options.portfolios && Array.isArray(source.portfolios)) selectiveData.portfolios = source.portfolios
  if (options.activePortfolioId && Object.prototype.hasOwnProperty.call(source, "activePortfolioId")) {
    selectiveData.activePortfolioId = source.activePortfolioId
  }
  if (options.showScrollbars && source.settings?.showScrollbars !== undefined) {
    selectiveData.settings = {
      ...selectiveData.settings,
      showScrollbars: source.settings.showScrollbars,
    }
  }

  return selectiveData
}

export function ImportModal({ isOpen, onClose, onImportComplete, onImportData }: ImportModalProps) {
  const [step, setStep] = useState<ImportStep>("file")
  const [importFile, setImportFile] = useState<File | null>(null)
  const [backupText, setBackupText] = useState("")
  const [importPin, setImportPin] = useState("")
  const [walletPin, setWalletPin] = useState("")
  const [importError, setImportError] = useState("")
  const [isEncrypted, setIsEncrypted] = useState(false)
  const [isBusy, setIsBusy] = useState(false)
  const [availableImportData, setAvailableImportData] = useState<any>(null)
  const [importMode, setImportMode] = useState<ImportMode>("all")
  const [importOptions, setImportOptions] = useState<ImportOptions>(defaultOptions)
  const [needsWalletPin, setNeedsWalletPin] = useState(false)

  const availableOptions = useMemo(() => getAvailableOptions(availableImportData), [availableImportData])

  useEffect(() => {
    if (!availableImportData) return
    setImportOptions(availableOptions)
    setImportMode("all")
  }, [availableImportData, availableOptions])

  const refreshNeedsWalletPin = () => {
    const requiresUnlock = SecurePinManager.hasPin() && !SecureKeyManager.isKeyCacheValid()
    setNeedsWalletPin(requiresUnlock)
    return requiresUnlock
  }

  useEffect(() => {
    if (!isOpen) return
    refreshNeedsWalletPin()
  }, [isOpen])

  const resetState = () => {
    setStep("file")
    setImportFile(null)
    setBackupText("")
    setImportPin("")
    setWalletPin("")
    setImportError("")
    setIsEncrypted(false)
    setIsBusy(false)
    setAvailableImportData(null)
    setImportMode("all")
    setImportOptions(defaultOptions)
    setNeedsWalletPin(false)
  }

  const handleClose = () => {
    resetState()
    onClose()
  }

  const parseOrRouteEncrypted = async () => {
    if (!importFile) return

    setIsBusy(true)
    setImportError("")

    try {
      const text = await importFile.text()
      setBackupText(text)

      const parsedData = JSON.parse(text)
      const encrypted = !!(parsedData?.version && parsedData?.salt && parsedData?.payload)

      if (encrypted) {
        setIsEncrypted(true)
        setStep("pin")
      } else {
        if (!parsedData || (typeof parsedData === "object" && Object.keys(parsedData).length === 0)) {
          throw new Error("Backup file contains no data to import")
        }
        setAvailableImportData(parsedData)
        setStep("review")
        refreshNeedsWalletPin()
      }
    } catch (error) {
      const message = error instanceof Error ? error.message : "Invalid backup file"
      const normalizedMessage = message.includes("JSON") ? "Invalid backup file format - not valid JSON" : message
      setImportError(normalizedMessage)
      toast({
        title: "Import Analysis Failed",
        description: normalizedMessage,
        variant: "destructive",
      })
    } finally {
      setIsBusy(false)
    }
  }

  const decryptBackup = async () => {
    if (!backupText || !importPin.trim()) {
      const message = "PIN is required to decrypt this backup"
      setImportError(message)
      toast({
        title: "PIN Required",
        description: message,
        variant: "destructive",
      })
      return
    }

    setIsBusy(true)
    setImportError("")

    try {
      const { restoreEncryptedBackup } = await import("@/lib/backup")
      const decrypted = await restoreEncryptedBackup(backupText, importPin)

      if (!decrypted || (typeof decrypted === "object" && Object.keys(decrypted).length === 0)) {
        throw new Error("Backup file contains no data to import")
      }

      setAvailableImportData(decrypted)
      setStep("review")
      const requiresUnlock = refreshNeedsWalletPin()
      if (requiresUnlock && !walletPin.trim() && importPin.trim()) {
        setWalletPin(importPin)
      }
    } catch (error) {
      const message = error instanceof Error ? error.message : "Failed to decrypt backup"
      setImportError(message)
      toast({
        title: "Decryption Failed",
        description: message,
        variant: "destructive",
      })
    } finally {
      setIsBusy(false)
    }
  }

  const handleImport = async () => {
    if (!availableImportData) return

    const finalOptions = importMode === "all" ? availableOptions : importOptions
    const payload = buildSelectiveData(availableImportData, finalOptions)

    setIsBusy(true)
    setImportError("")

    try {
      if (needsWalletPin && !walletPin.trim()) {
        throw new Error("Wallet PIN required to save restored data")
      }
      const success = await onImportData(payload, walletPin.trim() || undefined)
      if (!success) {
        throw new Error("Import failed - data could not be processed")
      }
      onImportComplete()
      resetState()
    } catch (error) {
      const message = error instanceof Error ? error.message : "Import failed"
      setImportError(message)
      toast({
        title: "Import Failed",
        description: message,
        variant: "destructive",
      })
    } finally {
      setIsBusy(false)
    }
  }

  const renderFileStep = () => (
    <div className="space-y-4">
      <div className="space-y-2">
        <Label htmlFor="import-backup-file">Backup File</Label>
        <Input
          id="import-backup-file"
          type="file"
          accept=".json"
          onChange={(e) => {
            setImportFile(e.target.files?.[0] || null)
            setImportError("")
          }}
        />
      </div>
      <p className="text-xs text-muted-foreground">Step 1 of 3: Select backup file to analyze.</p>
    </div>
  )

  const renderPinStep = () => (
    <div className="space-y-4">
      <div className="rounded-lg border bg-amber-50 px-3 py-2 text-xs text-amber-700 dark:bg-amber-950/30 dark:text-amber-300">
        This backup is encrypted. Enter your backup PIN to continue.
      </div>
      <div className="space-y-2">
        <Label htmlFor="import-pin">PIN</Label>
        <Input
          id="import-pin"
          type="password"
          placeholder="Enter backup PIN"
          value={importPin}
          onChange={(e) => {
            setImportPin(e.target.value)
            setImportError("")
          }}
        />
      </div>
      <p className="text-xs text-muted-foreground">Step 2 of 3: Decrypt backup.</p>
    </div>
  )

  const renderReviewStep = () => (
    <div className="space-y-4">
      <div className="flex items-center justify-between">
        <p className="text-sm font-medium">Import Mode</p>
        <Badge variant="outline" className="text-[10px] font-black uppercase tracking-wider">
          Schema v{availableImportData?.version || "1.0"}
        </Badge>
      </div>

      <div className="grid grid-cols-1 gap-2 sm:grid-cols-2">
        <button
          type="button"
          onClick={() => setImportMode("all")}
          className={`rounded-lg border p-3 text-left transition ${
            importMode === "all" ? "border-primary bg-primary/5" : "border-border"
          }`}
        >
          <p className="text-sm font-semibold">Import All (Default)</p>
          <p className="text-xs text-muted-foreground">Restore every available section from this backup.</p>
        </button>
        <button
          type="button"
          onClick={() => setImportMode("custom")}
          className={`rounded-lg border p-3 text-left transition ${
            importMode === "custom" ? "border-primary bg-primary/5" : "border-border"
          }`}
        >
          <p className="text-sm font-semibold">On-demand Import</p>
          <p className="text-xs text-muted-foreground">Pick specific sections to restore.</p>
        </button>
      </div>

      {importMode === "custom" && (
        <div className="max-h-64 space-y-2 overflow-y-auto rounded-lg border p-3">
          {[
            ["userProfile", "User Profile & Settings", availableImportData?.userProfile ? "Available" : "Not in backup"],
            ["transactions", "Transaction Data", Array.isArray(availableImportData?.transactions) ? `${availableImportData.transactions.length} items` : "Not in backup"],
            ["budgets", "Budget Data", Array.isArray(availableImportData?.budgets) ? `${availableImportData.budgets.length} items` : "Not in backup"],
            ["goals", "Goals & Savings", Array.isArray(availableImportData?.goals) ? `${availableImportData.goals.length} items` : "Not in backup"],
            ["debtAccounts", "Debt Accounts", Array.isArray(availableImportData?.debtAccounts) ? `${availableImportData.debtAccounts.length} items` : "Not in backup"],
            ["creditAccounts", "Credit Accounts", Array.isArray(availableImportData?.creditAccounts) ? `${availableImportData.creditAccounts.length} items` : "Not in backup"],
            ["debtCreditTransactions", "Debt/Credit History", Array.isArray(availableImportData?.debtCreditTransactions) ? `${availableImportData.debtCreditTransactions.length} items` : "Not in backup"],
            ["categories", "Categories", Array.isArray(availableImportData?.categories) ? `${availableImportData.categories.length} items` : "Not in backup"],
            ["emergencyFund", "Emergency Fund", (typeof availableImportData?.emergencyFund === "number" || typeof availableImportData?.emergencyFund === "string") ? String(availableImportData.emergencyFund) : "Not in backup"],
            ["portfolio", "Portfolio Holdings", Array.isArray(availableImportData?.portfolio) ? `${availableImportData.portfolio.length} items` : "Not in backup"],
            ["shareTransactions", "Share Transactions", Array.isArray(availableImportData?.shareTransactions) ? `${availableImportData.shareTransactions.length} items` : "Not in backup"],
            ["portfolios", "Portfolio Lists", Array.isArray(availableImportData?.portfolios) ? `${availableImportData.portfolios.length} items` : "Not in backup"],
            ["activePortfolioId", "Active Portfolio Selection", Object.prototype.hasOwnProperty.call(availableImportData ?? {}, "activePortfolioId") ? "Available" : "Not in backup"],
            ["showScrollbars", "Scrollbar Settings", availableImportData?.settings?.showScrollbars !== undefined ? "Available" : "Not in backup"],
          ].map(([key, label, description]) => {
            const typedKey = key as keyof ImportOptions
            return (
              <div key={key} className="flex items-center space-x-2">
                <Checkbox
                  id={`import-${key}`}
                  checked={importOptions[typedKey]}
                  onCheckedChange={(checked) => setImportOptions((prev) => ({ ...prev, [typedKey]: !!checked }))}
                  disabled={!availableOptions[typedKey]}
                />
                <Label htmlFor={`import-${key}`} className="text-sm">
                  {label} ({description})
                </Label>
              </div>
            )
          })}
        </div>
      )}

      {needsWalletPin && (
        <div className="space-y-2 rounded-lg border bg-muted/30 p-3">
          <Label htmlFor="wallet-pin" className="text-sm font-medium">
            Wallet PIN (to save restored data)
          </Label>
          <Input
            id="wallet-pin"
            type="password"
            placeholder="Enter your current wallet PIN"
            value={walletPin}
            onChange={(e) => {
              setWalletPin(e.target.value)
              setImportError("")
            }}
          />
          <p className="text-xs text-muted-foreground">
            This is required to re-encrypt your data on this device. If your backup PIN is the same, you can reuse it.
          </p>
        </div>
      )}

      <p className="text-xs text-muted-foreground">Step 3 of 3: Choose default import all or on-demand sections.</p>
    </div>
  )

  return (
    <Dialog open={isOpen} onOpenChange={(open) => !open && handleClose()}>
      <DialogContent className="max-w-xl">
        <DialogHeader>
          <DialogTitle>Import Backup</DialogTitle>
          <DialogDescription>
            Upload backup file first. If encrypted, enter PIN. Then import all by default or choose on-demand sections.
          </DialogDescription>
        </DialogHeader>

        {step === "file" && renderFileStep()}
        {step === "pin" && renderPinStep()}
        {step === "review" && renderReviewStep()}

        {importError && (
          <div className="rounded-lg border border-destructive/40 bg-destructive/10 px-3 py-2 text-sm text-destructive">
            {importError}
          </div>
        )}

        <DialogFooter>
          <Button variant="outline" onClick={handleClose} disabled={isBusy}>
            Cancel
          </Button>

          {step === "file" && (
            <Button onClick={parseOrRouteEncrypted} disabled={!importFile || isBusy}>
              {isBusy ? "Analyzing..." : "Continue"}
            </Button>
          )}

          {step === "pin" && (
            <>
              <Button variant="outline" onClick={() => setStep("file")} disabled={isBusy}>
                Back
              </Button>
              <Button onClick={decryptBackup} disabled={!importPin.trim() || isBusy}>
                {isBusy ? "Decrypting..." : "Decrypt & Continue"}
              </Button>
            </>
          )}

          {step === "review" && (
            <>
              <Button
                variant="outline"
                onClick={() => {
                  if (isEncrypted) {
                    setStep("pin")
                    return
                  }
                  setStep("file")
                }}
                disabled={isBusy}
              >
                Back
              </Button>
              <Button onClick={handleImport} disabled={isBusy}>
                {isBusy ? "Importing..." : "Import Data"}
              </Button>
            </>
          )}
        </DialogFooter>
      </DialogContent>
    </Dialog>
  )
}

"use client"

import { useState } from "react"
import { Button } from "@/components/ui/button"
import { Input } from "@/components/ui/input"
import { Label } from "@/components/ui/label"
import {
  AlertDialog,
  AlertDialogAction,
  AlertDialogCancel,
  AlertDialogContent,
  AlertDialogDescription,
  AlertDialogFooter,
  AlertDialogHeader,
  AlertDialogTitle,
  AlertDialogTrigger,
} from "@/components/ui/alert-dialog"
import { Checkbox } from "@/components/ui/checkbox"
import { useWalletData } from "@/contexts/wallet-data-context"
import { Download, Trash2, Shield, AlertTriangle } from "lucide-react"
import { toast } from "@/hooks/use-toast"
import { createEncryptedBackup } from "@/lib/backup"
import { SecurePinManager } from "@/lib/secure-pin-manager"

interface DeleteDataDialogProps {
  trigger: React.ReactNode
  title: string
  description: string
  onConfirm: () => void
  type: "account" | "data"
}

export function DeleteDataDialog({ trigger, title, description, onConfirm, type }: DeleteDataDialogProps) {
  const { userProfile, transactions, budgets, goals, debtAccounts, creditAccounts, debtCreditTransactions, categories, emergencyFund } = useWalletData()
  const [showDialog, setShowDialog] = useState(false)
  const [backupDownloaded, setBackupDownloaded] = useState(false)
  const [pin, setPin] = useState("")
  const [isProcessing, setIsProcessing] = useState(false)
  const [step, setStep] = useState<"warning" | "backup" | "confirm">("warning")

  const hasSecurityData = userProfile?.pin || SecurePinManager.hasPin()

  const handleDownloadBackup = async () => {
    if (!pin) {
      toast({
        title: "PIN Required",
        description: "Please enter your PIN to create a secure backup.",
        variant: "destructive",
      })
      return
    }

    setIsProcessing(true)
    try {
      // Validate PIN if security is enabled
      if (hasSecurityData) {
        const validation = await SecurePinManager.validatePin(pin)
        if (!validation.success) {
          toast({
            title: "Invalid PIN",
            description: "The PIN you entered is incorrect.",
            variant: "destructive",
          })
          return
        }
      }

      // Prepare data for backup
      const backupData = {
        userProfile,
        transactions,
        budgets,
        goals,
        debtAccounts,
        creditAccounts,
        debtCreditTransactions,
        categories,
        emergencyFund,
        exportDate: new Date().toISOString(),
        version: "1.0",
        type: "encrypted_backup"
      }

      // Create encrypted backup
      const backupJson = await createEncryptedBackup(backupData, pin)

      // Download the backup
      const blob = new Blob([backupJson], { type: "application/json" })
      const url = URL.createObjectURL(blob)
      const a = document.createElement("a")
      a.href = url
      a.download = `mywallet-encrypted-backup-${new Date().toISOString().split("T")[0]}.json`
      document.body.appendChild(a)
      a.click()
      document.body.removeChild(a)
      URL.revokeObjectURL(url)

      setBackupDownloaded(true)
      setStep("confirm")
      toast({
        title: "Backup Downloaded",
        description: "Your encrypted backup has been downloaded successfully.",
      })
    } catch (error) {
      console.error("Backup creation failed:", error)
      toast({
        title: "Backup Failed",
        description: "Failed to create backup. Please try again.",
        variant: "destructive",
      })
    } finally {
      setIsProcessing(false)
    }
  }

  const handleSkipBackup = () => {
    setStep("confirm")
  }

  const handleConfirmDelete = () => {
    onConfirm()
    setShowDialog(false)
    setStep("warning")
    setBackupDownloaded(false)
    setPin("")
  }

  const resetDialog = () => {
    setShowDialog(false)
    setStep("warning")
    setBackupDownloaded(false)
    setPin("")
  }

  return (
    <AlertDialog open={showDialog} onOpenChange={setShowDialog}>
      <AlertDialogTrigger asChild>
        {trigger}
      </AlertDialogTrigger>
      <AlertDialogContent className="max-w-md">
        <AlertDialogHeader>
          <div className="flex items-center gap-2">
            <AlertTriangle className="w-5 h-5 text-destructive" />
            <AlertDialogTitle>{title}</AlertDialogTitle>
          </div>
          <div className="text-sm text-muted-foreground">
            {step === "warning" && (
              <div className="space-y-2">
                <p>{description}</p>
                <div className="bg-destructive/10 border border-destructive/20 rounded-lg p-3 mt-4">
                  <div className="flex items-center gap-2 text-destructive font-medium">
                    <Shield className="w-4 h-4" />
                    <span>Security Data Warning</span>
                  </div>
                  <p className="text-sm text-destructive/80 mt-1">
                    This will permanently delete all your data including PIN, encryption keys, and security settings.
                    This action cannot be undone.
                  </p>
                </div>
              </div>
            )}
            {step === "backup" && (
              <div className="space-y-2">
                <p>Before proceeding, we recommend downloading a secure backup of your data.</p>
                <p className="text-sm text-muted-foreground">
                  Your backup will be encrypted with your PIN and can only be restored with the same PIN.
                </p>
              </div>
            )}
            {step === "confirm" && (
              <div className="space-y-2">
                <p>Are you absolutely sure you want to proceed?</p>
                <p className="text-sm text-muted-foreground">
                  {backupDownloaded
                    ? "Your backup has been downloaded. You can restore your data later if needed."
                    : "No backup was created. All your data will be permanently lost."
                  }
                </p>
              </div>
            )}
          </div>
        </AlertDialogHeader>

        <div className="space-y-4">
          {step === "warning" && (
            <div className="flex gap-2">
              <Button onClick={() => setStep("backup")} className="flex-1">
                <Download className="w-4 h-4 mr-2" />
                Create Backup First
              </Button>
              <Button onClick={handleSkipBackup} variant="outline" className="flex-1">
                Skip Backup
              </Button>
            </div>
          )}

          {step === "backup" && (
            <div className="space-y-4">
              <div>
                <Label htmlFor="backup-pin">Enter your PIN to create encrypted backup</Label>
                <Input
                  id="backup-pin"
                  type="password"
                  placeholder="Enter PIN"
                  value={pin}
                  onChange={(e) => setPin(e.target.value)}
                  className="mt-1"
                />
              </div>
              <div className="flex gap-2">
                <Button
                  onClick={handleDownloadBackup}
                  disabled={!pin || isProcessing}
                  className="flex-1"
                >
                  {isProcessing ? "Creating..." : "Download Backup"}
                </Button>
                <Button onClick={handleSkipBackup} variant="outline">
                  Skip
                </Button>
              </div>
            </div>
          )}

          {step === "confirm" && (
            <AlertDialogFooter>
              <AlertDialogCancel onClick={resetDialog}>Cancel</AlertDialogCancel>
              <AlertDialogAction
                onClick={handleConfirmDelete}
                className="bg-destructive text-destructive-foreground hover:bg-destructive/90"
              >
                <Trash2 className="w-4 h-4 mr-2" />
                {type === "account" ? "Delete Account" : "Delete All Data"}
              </AlertDialogAction>
            </AlertDialogFooter>
          )}
        </div>

        {step !== "confirm" && (
          <AlertDialogFooter>
            <AlertDialogCancel onClick={resetDialog}>Cancel</AlertDialogCancel>
          </AlertDialogFooter>
        )}
      </AlertDialogContent>
    </AlertDialog>
  )
}

"use client"

import { useState, useEffect } from "react"
import { Button } from "@/components/ui/button"
import { Input } from "@/components/ui/input"
import { Label } from "@/components/ui/label"
import { Card, CardContent, CardDescription, CardHeader, CardTitle } from "@/components/ui/card"
import { Badge } from "@/components/ui/badge"
import { Switch } from "@/components/ui/switch"
import { useWalletData } from "@/contexts/wallet-data-context"
import { Shield, Lock, User, Key, Building2, Save, Fingerprint, Eye, EyeOff, AlertCircle, Rocket, RefreshCw, Sparkles } from "lucide-react"
import { toast } from "sonner"
import { Check, ChevronsUpDown } from "lucide-react"
import {
    Command,
    CommandEmpty,
    CommandGroup,
    CommandInput,
    CommandItem,
    CommandList,
} from "@/components/ui/command"
import {
    Popover,
    PopoverContent,
    PopoverTrigger,
} from "@/components/ui/popover"
import {
    Select,
    SelectContent,
    SelectItem,
    SelectTrigger,
    SelectValue,
} from "@/components/ui/select"
import { cn } from "@/lib/utils"

const MEROSHARE_DEV_MODE_KEY = "wallet_meroshare_dev_mode"

export function MeroShareSettings() {
    const { userProfile, updateUserProfile, upcomingIPOs, syncMeroSharePortfolio, portfolios, activePortfolioId, checkIPOAllotment, applyMeroShareIPO } = useWalletData()
    const [showPassword, setShowPassword] = useState(false)
    const [dps, setDps] = useState<{ id: string, name: string, code: string }[]>([])
    const [isLoadingDps, setIsLoadingDps] = useState(false)
    const [isTesting, setIsTesting] = useState(false)
    const [isApplying, setIsApplying] = useState(false)
    const [isCheckingResult, setIsCheckingResult] = useState(false)
    const [isSyncing, setIsSyncing] = useState(false)
    const [open, setOpen] = useState(false)
    const [selectedTestIpo, setSelectedTestIpo] = useState("")
    const [testMode, setTestMode] = useState<'apply' | 'result'>('apply')
    const [targetPortfolio, setTargetPortfolio] = useState(activePortfolioId || (portfolios.length > 0 ? portfolios[0].id : ""))
    const [customIpoName, setCustomIpoName] = useState("")
    const [isCustomMode, setIsCustomMode] = useState(false)
    const [showLiveBrowserForTest, setShowLiveBrowserForTest] = useState(false)
    const [isDevMode, setIsDevMode] = useState(false)

    const [formData, setFormData] = useState({
        dpId: userProfile?.meroShare?.dpId || "",
        username: userProfile?.meroShare?.username || "",
        password: userProfile?.meroShare?.password || "",
        crn: userProfile?.meroShare?.crn || "",
        pin: userProfile?.meroShare?.pin || "",
        shareFeaturesEnabled: userProfile?.meroShare?.shareFeaturesEnabled || false,
        shareNotificationsEnabled: userProfile?.meroShare?.shareNotificationsEnabled || false,
        preferredKitta: userProfile?.meroShare?.preferredKitta || 0,
        applyMode: userProfile?.meroShare?.applyMode || "on-demand",
        showLiveBrowser: userProfile?.meroShare?.showLiveBrowser || false,
        isAutomatedEnabled: userProfile?.meroShare?.isAutomatedEnabled || false
    })
    const openIpos = upcomingIPOs.filter(ipo => ipo.status === 'open')
    const recentApplicationLogs = (userProfile?.meroShare?.applicationLogs ?? []).slice(0, 10)
    const requiredFields: Array<keyof typeof formData> = ["dpId", "username", "password", "crn", "pin"]
    const missingRequiredFields = requiredFields.filter((key) => {
        const value = formData[key]
        return typeof value !== "string" || value.trim().length === 0
    })
    const isCredentialComplete = missingRequiredFields.length === 0
    const isAutomationReady = formData.isAutomatedEnabled && isCredentialComplete
    const savedMeroShare = userProfile?.meroShare
    const hasUnsavedChanges = JSON.stringify({
        dpId: formData.dpId,
        username: formData.username,
        password: formData.password,
        crn: formData.crn,
        pin: formData.pin,
        shareFeaturesEnabled: formData.shareFeaturesEnabled,
        shareNotificationsEnabled: formData.shareNotificationsEnabled,
        preferredKitta: formData.preferredKitta,
        applyMode: formData.applyMode,
        showLiveBrowser: formData.showLiveBrowser,
        isAutomatedEnabled: formData.isAutomatedEnabled,
    }) !== JSON.stringify({
        dpId: savedMeroShare?.dpId || "",
        username: savedMeroShare?.username || "",
        password: savedMeroShare?.password || "",
        crn: savedMeroShare?.crn || "",
        pin: savedMeroShare?.pin || "",
        shareFeaturesEnabled: savedMeroShare?.shareFeaturesEnabled || false,
        shareNotificationsEnabled: savedMeroShare?.shareNotificationsEnabled || false,
        preferredKitta: savedMeroShare?.preferredKitta || 0,
        applyMode: savedMeroShare?.applyMode || "on-demand",
        showLiveBrowser: savedMeroShare?.showLiveBrowser || false,
        isAutomatedEnabled: savedMeroShare?.isAutomatedEnabled || false,
    })

    useEffect(() => {
        // Fetch DP list
        const fetchDps = async () => {
            setIsLoadingDps(true)
            try {
                // In a real scenario, this would be an API call to Mero Share
                // For now, we'll provide a few common ones or fetch from our API
                const response = await fetch("/api/meroshare/dps")
                if (response.ok) {
                    const data = await response.json()
                    setDps(data)
                } else {
                    // Fallback to a few common ones if CORS fails
                    setDps([
                        { id: "13100", name: "NIC ASIA Bank Limited", code: "NIC" },
                        { id: "10200", name: "Nabil Bank Limited", code: "NABIL" },
                        { id: "11600", name: "Global IME Bank Limited", code: "GBIME" },
                    ])
                }
            } catch (error) {
                setDps([
                    { id: "13100", name: "NIC ASIA Bank Limited", code: "NIC" },
                    { id: "10200", name: "Nabil Bank Limited", code: "NABIL" },
                    { id: "11600", name: "Global IME Bank Limited", code: "GBIME" },
                ])
            } finally {
                setIsLoadingDps(false)
            }
        }
        fetchDps()
    }, [])

    useEffect(() => {
        if (typeof window === "undefined") return
        const stored = localStorage.getItem(MEROSHARE_DEV_MODE_KEY)
        setIsDevMode(stored === "true")

        const onKeyDown = (event: KeyboardEvent) => {
            const isToggle = (event.ctrlKey || event.metaKey) && event.key.toLowerCase() === "d"
            if (!isToggle) return

            event.preventDefault()
            setIsDevMode((prev) => {
                const next = !prev
                localStorage.setItem(MEROSHARE_DEV_MODE_KEY, String(next))
                toast(next ? "Developer mode enabled" : "Developer mode disabled", {
                    description: "Automation Tools visibility updated."
                })
                return next
            })
        }

        window.addEventListener("keydown", onKeyDown)
        return () => window.removeEventListener("keydown", onKeyDown)
    }, [])

    useEffect(() => {
        setFormData({
            dpId: userProfile?.meroShare?.dpId || "",
            username: userProfile?.meroShare?.username || "",
            password: userProfile?.meroShare?.password || "",
            crn: userProfile?.meroShare?.crn || "",
            pin: userProfile?.meroShare?.pin || "",
            shareFeaturesEnabled: userProfile?.meroShare?.shareFeaturesEnabled || false,
            shareNotificationsEnabled: userProfile?.meroShare?.shareNotificationsEnabled || false,
            preferredKitta: userProfile?.meroShare?.preferredKitta || 0,
            applyMode: userProfile?.meroShare?.applyMode || "on-demand",
            showLiveBrowser: userProfile?.meroShare?.showLiveBrowser || false,
            isAutomatedEnabled: userProfile?.meroShare?.isAutomatedEnabled || false,
        })
    }, [userProfile?.meroShare])

    const handleSave = () => {
        updateUserProfile({
            meroShare: {
                ...(userProfile?.meroShare || {}),
                ...formData
            }
        })
        toast("Mero Share Settings Saved", {
            description: "Your credentials are stored securely in your local storage.",
        })
    }

    const testConnection = async () => {
        if (!formData.dpId || !formData.username || !formData.password) {
            toast.error("Incomplete Credentials", {
                description: "Please enter DP, Username and Password to test."
            })
            return
        }

        setIsTesting(true)
        const promise = fetch('/api/meroshare/test-login', {
            method: 'POST',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify({
                credentials: formData,
                options: { showBrowser: Boolean(formData.showLiveBrowser) }
            })
        }).then(async (res) => {
            const data = await res.json()
            if (!res.ok) throw new Error(data.error || "Login Failed")
            return data
        })

        toast.promise(promise, {
            loading: "Testing login credentials...",
            success: (data: any) => {
                setIsTesting(false)
                return data.message || "Connection Success!"
            },
            error: (err: any) => {
                setIsTesting(false)
                return err.message
            }
        })
    }

    const updateField = (key: string, value: any) => {
        setFormData(prev => ({ ...prev, [key]: value }))
    }

    const toggleShareFeatures = (enabled: boolean) => {
        setFormData(prev => ({
            ...prev,
            shareFeaturesEnabled: enabled,
            shareNotificationsEnabled: enabled,
            isAutomatedEnabled: enabled ? prev.isAutomatedEnabled : false,
        }))
    }

    const testApplication = async () => {
        const ipoToTest = isCustomMode ? customIpoName : selectedTestIpo
        if (!ipoToTest) {
            toast.error("Select or enter an IPO", { description: "Please provide an IPO name to test the automation." })
            return
        }

        if (testMode === 'result') {
            setIsCheckingResult(true)
            const promise = checkIPOAllotment(formData, ipoToTest, "settings-check")
            toast.promise(promise, {
                loading: `Testing allotment check for ${ipoToTest}...`,
                success: (data) => {
                    setIsCheckingResult(false)
                    return data.isAllotted ? `Allotted ${data.allottedQuantity} units!` : `Not Allotted: ${data.status}`
                },
                error: (err) => {
                    setIsCheckingResult(false)
                    return err.message
                }
            })
            return
        }

        setIsApplying(true)
        const promise = applyMeroShareIPO(
            formData,
            ipoToTest,
            formData.preferredKitta || 0,
            "settings-test",
            { showBrowser: showLiveBrowserForTest || Boolean(formData.showLiveBrowser) }
        )

        toast.promise(promise, {
            loading: `Testing automation for ${ipoToTest}...`,
            success: (data: any) => {
                setIsApplying(false)
                if (data?.alreadyApplied) {
                    return data.message || "Already applied earlier. No new apply action was submitted."
                }
                return data.message || "Automation Success!"
            },
            error: (err: any) => {
                setIsApplying(false)
                return err.message
            }
        })
    }

    const handleSyncPortfolio = async () => {
        if (!formData.dpId || !formData.username || !formData.password) {
            toast.error("Credentials missing", { description: "Save your credentials first to sync." })
            return
        }

        setIsSyncing(true)
        const promise = syncMeroSharePortfolio(formData, targetPortfolio)

        toast.promise(promise, {
            loading: "Logging into Mero Share and fetching portfolio...",
            success: (data) => {
                setIsSyncing(false)
                return `Successfully synced! Updated ${data.updatedCount} and added ${data.addedCount} holdings.`
            },
            error: (err) => {
                setIsSyncing(false)
                return err.message || "Failed to sync portfolio."
            }
        })
    }

    return (
        <div className="space-y-6">
            <Card className="border-primary/20 bg-gradient-to-br from-card to-primary/5">
                <CardHeader>
                    <div className="flex items-center gap-3">
                        <div className="w-10 h-10 bg-primary/10 rounded-xl flex items-center justify-center text-primary">
                            <Shield className="w-6 h-6" />
                        </div>
                        <div>
                            <CardTitle>Mero Share Credentials</CardTitle>
                            <CardDescription>Setup your credentials for automated IPO application</CardDescription>
                        </div>
                    </div>
                </CardHeader>
                <CardContent className="space-y-6">
                    <div className="flex items-center justify-between p-4 rounded-xl bg-primary/5 border border-primary/20">
                        <div className="space-y-1">
                            <Label className="text-sm font-bold flex items-center gap-2">
                                <Sparkles className="w-4 h-4 text-primary" />
                                Enable Share Features
                            </Label>
                            <p className="text-xs text-muted-foreground">
                                Master switch for Portfolio section and share-related notifications.
                            </p>
                        </div>
                        <Switch
                            checked={formData.shareFeaturesEnabled}
                            onCheckedChange={toggleShareFeatures}
                        />
                    </div>
                    <div className="flex items-center justify-between p-4 rounded-xl bg-primary/5 border border-primary/20">
                        <div className="space-y-1">
                            <Label className="text-sm font-bold flex items-center gap-2">
                                <Fingerprint className="w-4 h-4 text-primary" />
                                Automated IPO Application
                            </Label>
                            <p className="text-xs text-muted-foreground">When enabled, you'll be able to apply for IPOs with one click.</p>
                        </div>
                        <Switch
                            checked={formData.isAutomatedEnabled}
                            onCheckedChange={(checked) => updateField("isAutomatedEnabled", checked)}
                            disabled={!formData.shareFeaturesEnabled}
                        />
                    </div>
                    <div className="p-4 rounded-xl bg-background/60 border border-border space-y-2">
                        <Label className="text-sm font-bold">Apply Mode</Label>
                        <p className="text-xs text-muted-foreground">
                            Choose whether user-triggered applies run on demand only, or auto-run when opening an IPO modal.
                        </p>
                        <Select
                            value={formData.applyMode}
                            onValueChange={(value) => updateField("applyMode", value)}
                            disabled={!formData.shareFeaturesEnabled}
                        >
                            <SelectTrigger className="h-10 bg-background/80">
                                <SelectValue />
                            </SelectTrigger>
                            <SelectContent>
                                <SelectItem value="on-demand">On Demand</SelectItem>
                                <SelectItem value="automatic">Automatic</SelectItem>
                            </SelectContent>
                        </Select>
                    </div>
                    <div className="flex items-center justify-between p-4 rounded-xl bg-background/60 border border-border">
                        <div className="space-y-1">
                            <Label className="text-sm font-bold">Show Browser While Automating</Label>
                            <p className="text-xs text-muted-foreground">On-demand visual mode. Useful for debugging or trust checks.</p>
                        </div>
                        <Switch
                            checked={Boolean(formData.showLiveBrowser)}
                            onCheckedChange={(checked) => updateField("showLiveBrowser", checked)}
                            disabled={!formData.shareFeaturesEnabled}
                        />
                    </div>
                    <div className={cn(
                        "p-4 rounded-xl border flex flex-col gap-2",
                        isAutomationReady ? "bg-success/5 border-success/20" : "bg-muted/40 border-muted"
                    )}>
                        <div className="flex items-center justify-between gap-2">
                            <div className="text-sm font-semibold">Integration Status</div>
                            <Badge variant={isAutomationReady ? "default" : "secondary"}>
                                {isAutomationReady ? "Ready" : "Needs Setup"}
                            </Badge>
                        </div>
                        <p className="text-xs text-muted-foreground">
                            {!formData.shareFeaturesEnabled
                                ? "Share features are disabled. Turn on 'Enable Share Features' to use Portfolio and share notifications."
                                : formData.isAutomatedEnabled
                                ? isCredentialComplete
                                    ? "Automation is enabled and credentials are complete."
                                    : `Automation is enabled, but ${missingRequiredFields.length} required field(s) are missing.`
                                : "Automation is disabled. Enable it to apply/check directly from IPO cards."}
                        </p>
                        <p className="text-xs text-muted-foreground">
                            Open IPOs detected: <span className="font-semibold text-foreground">{openIpos.length}</span>
                        </p>
                    </div>

                    <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                        <div className="space-y-2">
                            <Label className="text-xs font-black uppercase tracking-widest text-muted-foreground flex items-center gap-2">
                                <Building2 className="w-3 h-3" /> Depository Participant (DP)
                            </Label>
                            <Popover open={open} onOpenChange={setOpen}>
                                <PopoverTrigger asChild>
                                    <Button
                                        variant="outline"
                                        role="combobox"
                                        aria-expanded={open}
                                        className="w-full h-11 justify-between bg-background/50 font-normal border-input"
                                    >
                                        <span className="truncate">
                                            {formData.dpId
                                                ? dps.find((dp) => dp.id === formData.dpId)?.name
                                                : "Select your DP..."}
                                        </span>
                                        <ChevronsUpDown className="ml-2 h-4 w-4 shrink-0 opacity-50" />
                                    </Button>
                                </PopoverTrigger>
                                <PopoverContent className="w-[--radix-popover-trigger-width] p-0" align="start">
                                    <Command className="w-full">
                                        <CommandInput placeholder="Search bank or DP..." className="h-9" />
                                        <CommandList className="max-h-[300px]">
                                            <CommandEmpty>No DP found.</CommandEmpty>
                                            <CommandGroup>
                                                {dps.map((dp) => (
                                                    <CommandItem
                                                        key={dp.id}
                                                        value={`${dp.name} ${dp.id}`}
                                                        onSelect={() => {
                                                            updateField("dpId", dp.id)
                                                            setOpen(false)
                                                        }}
                                                        className="flex items-center justify-between"
                                                    >
                                                        <div className="flex flex-col">
                                                            <span className="font-medium">{dp.name}</span>
                                                            <span className="text-xs text-muted-foreground">{dp.id}</span>
                                                        </div>
                                                        <Check
                                                            className={cn(
                                                                "h-4 w-4",
                                                                formData.dpId === dp.id ? "opacity-100" : "opacity-0"
                                                            )}
                                                        />
                                                    </CommandItem>
                                                ))}
                                            </CommandGroup>
                                        </CommandList>
                                    </Command>
                                </PopoverContent>
                            </Popover>
                        </div>

                        <div className="space-y-2">
                            <Label className="text-xs font-black uppercase tracking-widest text-muted-foreground flex items-center gap-2">
                                <User className="w-3 h-3" /> Username
                            </Label>
                            <Input
                                placeholder="Enter Mero Share username"
                                value={formData.username}
                                onChange={(e) => updateField("username", e.target.value)}
                                className="h-11 bg-background/50"
                            />
                        </div>

                        <div className="space-y-2">
                            <Label className="text-xs font-black uppercase tracking-widest text-muted-foreground flex items-center gap-2">
                                <Lock className="w-3 h-3" /> Password
                            </Label>
                            <div className="relative">
                                <Input
                                    type={showPassword ? "text" : "password"}
                                    placeholder="Enter password"
                                    value={formData.password}
                                    onChange={(e) => updateField("password", e.target.value)}
                                    className="h-11 pr-10 bg-background/50"
                                />
                                <Button
                                    variant="ghost"
                                    size="icon"
                                    className="absolute right-1 top-1 h-9 w-9 text-muted-foreground"
                                    onClick={() => setShowPassword(!showPassword)}
                                >
                                    {showPassword ? <EyeOff className="w-4 h-4" /> : <Eye className="w-4 h-4" />}
                                </Button>
                            </div>
                        </div>

                        <div className="space-y-2 border-l-2 border-primary/20 pl-4 md:col-start-1">
                            <Label className="text-xs font-black uppercase tracking-widest text-primary flex items-center gap-2">
                                <Key className="w-3 h-3" /> CRN Number
                            </Label>
                            <Input
                                placeholder="Enter CRN number"
                                value={formData.crn}
                                onChange={(e) => updateField("crn", e.target.value)}
                                className="h-11 border-primary/20 bg-primary/5"
                            />
                        </div>

                        <div className="space-y-2 border-l-2 border-primary/20 pl-4">
                            <Label className="text-xs font-black uppercase tracking-widest text-primary flex items-center gap-2">
                                <Shield className="w-3 h-3" /> Transaction PIN
                            </Label>
                            <Input
                                type="password"
                                maxLength={4}
                                placeholder="4-digit PIN"
                                value={formData.pin}
                                onChange={(e) => updateField("pin", e.target.value.replace(/\D/g, ''))}
                                className="h-11 border-primary/20 bg-primary/5"
                            />
                        </div>

                        <div className="space-y-2 md:col-span-2">
                            <Label className="text-xs font-black uppercase tracking-widest text-muted-foreground flex items-center gap-2">
                                <Rocket className="w-3 h-3" /> Preferred Kitta (Optional)
                            </Label>
                            <Input
                                type="number"
                                min="0"
                                placeholder="0 = Auto-detect minimum"
                                value={formData.preferredKitta || ""}
                                onChange={(e) => updateField("preferredKitta", parseInt(e.target.value) || 0)}
                                className="h-11 bg-background/50"
                            />
                            <p className="text-[10px] text-muted-foreground italic">
                                Leave at 0 to automatically use the minimum quantity from each IPO. Set a specific number (e.g., 20, 50) to always apply for that amount.
                            </p>
                        </div>
                    </div>

                    <div className="p-4 rounded-xl bg-amber-500/10 border border-amber-500/20 flex gap-3">
                        <AlertCircle className="w-5 h-5 text-amber-500 shrink-0 mt-0.5" />
                        <div className="space-y-1">
                            <h4 className="text-sm font-bold text-amber-700 dark:text-amber-400">Security Note</h4>
                            <p className="text-xs text-amber-600/80 dark:text-amber-400/80 leading-relaxed">
                                Your credentials are saved <strong>only on this device</strong>. They are never sent to our servers except when performing the automated application. We recommend using a PIN for the app itself under the "Security" tab.
                            </p>
                        </div>
                    </div>

                    <div className="grid grid-cols-2 gap-3 pt-4">
                        <Button
                            variant="outline"
                            onClick={testConnection}
                            disabled={isTesting}
                            className="h-12 rounded-xl font-bold border-primary/20 hover:bg-primary/5 transition-all"
                        >
                            {isTesting ? "Testing..." : "Test Connection"}
                        </Button>
                        <Button
                            onClick={handleSave}
                            disabled={!hasUnsavedChanges}
                            className="h-12 rounded-xl font-bold bg-primary shadow-lg shadow-primary/20 hover:scale-[1.01] active:scale-95 transition-all"
                        >
                            <Save className="w-4 h-4 mr-2" />
                            {hasUnsavedChanges ? "Save Settings" : "Saved"}
                        </Button>
                    </div>
                </CardContent>
            </Card>

            <Card className="border-info/20 bg-info/5">
                <CardHeader className="pb-3">
                    <div className="flex items-center gap-3">
                        <div className="w-8 h-8 bg-info/20 rounded-lg flex items-center justify-center text-info">
                            <RefreshCw className={cn("w-5 h-5", isSyncing && "animate-spin")} />
                        </div>
                        <div>
                            <CardTitle className="text-base">Portfolio Sync</CardTitle>
                            <CardDescription className="text-xs text-info/60">Automatically import your current holdings from Mero Share</CardDescription>
                        </div>
                    </div>
                </CardHeader>
                <CardContent className="space-y-6">
                    <div className="flex flex-col gap-4">
                        {portfolios.length > 1 && (
                            <div className="space-y-2">
                                <Label className="text-[10px] font-black uppercase tracking-widest text-muted-foreground">Select Target Portfolio</Label>
                                <Select value={targetPortfolio} onValueChange={setTargetPortfolio}>
                                    <SelectTrigger className="w-full sm:w-[240px] h-10 rounded-xl bg-background/50 border-info/20">
                                        <SelectValue placeholder="Select Portfolio" />
                                    </SelectTrigger>
                                    <SelectContent>
                                        {portfolios.map(p => (
                                            <SelectItem key={p.id} value={p.id}>{p.name}</SelectItem>
                                        ))}
                                    </SelectContent>
                                </Select>
                            </div>
                        )}

                        <div className="flex flex-col sm:flex-row items-start sm:items-center justify-between gap-4 py-2">
                            <div className="text-xs text-muted-foreground leading-relaxed max-w-sm">
                                This will fetch your latest scrips and units.
                                Existing scrips will have their units updated, while new ones will be added to
                                <span className="font-bold text-info"> {portfolios.find(p => p.id === targetPortfolio)?.name || "your portfolio"}</span>.
                            </div>
                            <Button
                                onClick={handleSyncPortfolio}
                                disabled={isSyncing || !targetPortfolio}
                                className="bg-info hover:bg-info/90 text-white shadow-lg shadow-info/20 px-8 rounded-xl font-bold h-11 shrink-0 w-full sm:w-auto border-0"
                            >
                                {isSyncing ? "Syncing..." : "Sync Now"}
                            </Button>
                        </div>
                    </div>

                    <p className="text-[10px] text-muted-foreground mt-2 italic flex items-center gap-1.5 opacity-60">
                        <AlertCircle className="w-3 h-3 text-warning" />
                        Cost price (Buy Price) won't be updated automatically. You may need to update them manually.
                    </p>
                </CardContent>
            </Card>

            {isDevMode && (
                <Card className="border-dashed border-primary/40 bg-primary/5">
                    <CardHeader className="pb-3">
                        <div className="flex items-center gap-3">
                            <div className="w-8 h-8 bg-primary/20 rounded-lg flex items-center justify-center text-primary">
                                <Rocket className="w-5 h-5" />
                            </div>
                            <div>
                                <CardTitle className="text-base">Automation Tools</CardTitle>
                                <CardDescription className="text-xs text-primary/60">Run a safe test before using live IPO actions</CardDescription>
                            </div>
                        </div>
                    </CardHeader>
                    <CardContent className="space-y-4">
                        <div className="flex items-center justify-between">
                            <div className="flex p-1 bg-muted rounded-xl gap-1">
                                <Button
                                    size="sm"
                                    variant={testMode === 'apply' ? 'secondary' : 'ghost'}
                                    onClick={() => setTestMode('apply')}
                                    className="text-[10px] font-black uppercase tracking-widest h-8"
                                >
                                    Apply Test
                                </Button>
                                <Button
                                    size="sm"
                                    variant={testMode === 'result' ? 'secondary' : 'ghost'}
                                    onClick={() => setTestMode('result')}
                                    className="text-[10px] font-black uppercase tracking-widest h-8"
                                >
                                    Result Test
                                </Button>
                            </div>
                            <div className="flex items-center gap-3">
                                <Label className="text-[10px] font-black uppercase tracking-widest text-muted-foreground">Force Manual</Label>
                                <Switch
                                    checked={isCustomMode}
                                    onCheckedChange={setIsCustomMode}
                                />
                            </div>
                        </div>
                        {testMode === "apply" && (
                            <div className="flex items-center justify-between p-3 rounded-xl bg-background/70 border">
                                <Label className="text-[10px] font-black uppercase tracking-widest text-muted-foreground">Watch Browser For This Test</Label>
                                <Switch
                                    checked={showLiveBrowserForTest}
                                    onCheckedChange={setShowLiveBrowserForTest}
                                />
                            </div>
                        )}

                        <div className="space-y-4 pt-2">
                            <Label className="text-xs font-bold uppercase tracking-wider text-muted-foreground">
                                {isCustomMode ? "Enter Custom IPO Name" : "Select IPO to Test"}
                            </Label>
                            <div className="flex flex-col sm:flex-row gap-3">
                                {isCustomMode ? (
                                    <Input
                                        placeholder="Enter exact name as in MeroShare"
                                        value={customIpoName}
                                        onChange={(e) => setCustomIpoName(e.target.value)}
                                        className="bg-background/80 h-11"
                                    />
                                ) : (
                                    <Select
                                        value={selectedTestIpo}
                                        onValueChange={setSelectedTestIpo}
                                    >
                                        <SelectTrigger className="bg-background/80 h-11 flex-1">
                                            <SelectValue placeholder={testMode === 'apply' ? (openIpos.length > 0 ? "Select an open IPO" : "No open IPOs found") : "Select a closed IPO"} />
                                        </SelectTrigger>
                                        <SelectContent>
                                            {(testMode === 'apply' ? openIpos : upcomingIPOs.filter(i => i.status === 'closed')).map((ipo, index) => {
                                                const ipoKey = [ipo.company, ipo.url, ipo.date_range, ipo.scraped_at, String(index)]
                                                    .filter(Boolean)
                                                    .join("|")
                                                return (
                                                    <SelectItem key={ipoKey} value={ipo.company}>
                                                        {ipo.company}
                                                    </SelectItem>
                                                )
                                            })}
                                        </SelectContent>
                                    </Select>
                                )}
                                <Button
                                    onClick={testApplication}
                                    disabled={isApplying || isCheckingResult || (isCustomMode ? !customIpoName : !selectedTestIpo)}
                                    className={cn(
                                        "h-11 px-8 gap-2 shrink-0 font-bold shadow-lg transition-all",
                                        testMode === 'apply' ? "bg-primary hover:bg-primary/90 shadow-primary/20" : "bg-indigo-600 hover:bg-indigo-700 shadow-indigo-600/20 text-white"
                                    )}
                                >
                                    {testMode === 'apply' ? <Rocket className="w-4 h-4" /> : <Sparkles className="w-4 h-4" />}
                                    {testMode === 'apply' ? (isApplying ? "Running..." : "Run Apply Test") : (isCheckingResult ? "Checking..." : "Check Result")}
                                </Button>
                            </div>
                            <p className="text-[10px] text-muted-foreground mt-2 italic flex items-center gap-1.5">
                                <AlertCircle className="w-3 h-3" />
                                {isCustomMode
                                    ? `Careful: Enter the EXACT name as shown in MeroShare ${testMode === 'apply' ? "'Apply'" : "'Report'"} list.`
                                    : `This runs automation in the background and attempts to ${testMode === 'apply' ? "apply for the share" : "check allotment results"}.`}
                            </p>
                        </div>
                    </CardContent>
                </Card>
            )}

            <Card className="border-muted bg-muted/20">
                <CardHeader className="pb-3">
                    <div className="flex items-center justify-between gap-3">
                        <div>
                            <CardTitle className="text-base">Application Logs</CardTitle>
                            <CardDescription className="text-xs">Latest IPO apply and report-check attempts</CardDescription>
                        </div>
                        <Badge variant="secondary">{recentApplicationLogs.length}</Badge>
                    </div>
                </CardHeader>
                <CardContent className="space-y-3">
                    {recentApplicationLogs.length === 0 ? (
                        <p className="text-xs text-muted-foreground">No application attempts logged yet.</p>
                    ) : (
                        recentApplicationLogs.map((log) => (
                            <div key={log.id} className="rounded-xl border bg-background/70 p-3 flex items-start justify-between gap-3">
                                <div className="space-y-1">
                                    <div className="text-sm font-semibold">{log.ipoName}</div>
                                    <div className="text-[11px] text-muted-foreground">
                                        {new Date(log.createdAt).toLocaleString()} | Action: {log.action === "apply" ? "Apply" : "Report Check"}{typeof log.requestedKitta === "number" ? ` | Kitta: ${log.requestedKitta}` : ""} | Source: {log.source === "live-apply" ? "Live Apply" : log.source === "live-auto" ? "Live Auto" : log.source === "settings-test" ? "Settings Test" : log.source === "live-check" ? "Live Check" : "Settings Check"}
                                    </div>
                                    <div className="text-xs text-muted-foreground">{log.message}</div>
                                </div>
                                <Badge variant={log.status === "success" ? "default" : "destructive"} className="shrink-0">
                                    {log.status === "success" ? "Success" : "Failed"}
                                </Badge>
                            </div>
                        ))
                    )}
                </CardContent>
            </Card>
        </div>
    )
}

"use client"

import { useState, useMemo, useEffect, useRef } from "react"
import { Button } from "@/components/ui/button"
import { Input } from "@/components/ui/input"
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card"
import { Avatar, AvatarFallback, AvatarImage } from "@/components/ui/avatar"
import { Switch } from "@/components/ui/switch"
import { UserProfileSettings } from "./user-settings"
import { SecuritySettings } from "./security-settings"
import { ThemeSettings } from "./theme-settings"
import { DataSettings } from "./data-settings"
import { AccessibilitySettings } from "./accessibility-settings"
import { AboutSettings } from "./about-settings"
import { MeroShareSettings } from "./mero-share-settings"
import { NotificationSettings } from "./notification-settings"
import { SecurePinManager } from "@/lib/secure-pin-manager"
import { useWalletData } from "@/contexts/wallet-data-context"
import InstallButton from "@/components/pwa/install-button"
import { getCurrencySymbol } from "@/lib/currency"
import { useRouter } from "next/navigation"
import {
  ArrowLeft,
  Search,
  User,
  Shield,
  Palette,
  Database,
  Accessibility,
  Info,
  Wifi,
  Bluetooth,
  Volume2,
  Battery,
  Moon,
  Lock,
  Star,
  ChevronRight,
  Home,
  Share2,
  Bell
} from "lucide-react"

interface MobileSettingsPageProps {
  onClose: () => void
  initialView?: SettingsView
}

type SettingsView = "main" | "profile" | "security" | "notifications" | "meroshare" | "theme" | "data" | "accessibility" | "about"

export function MobileSettingsPage({ onClose, initialView = "main" }: MobileSettingsPageProps) {
  const [currentView, setCurrentView] = useState<SettingsView>(initialView)
  const [searchQuery, setSearchQuery] = useState("")
  const [highlightQuery, setHighlightQuery] = useState("")
  const { userProfile } = useWalletData()
  const router = useRouter()

  const [dismissedSuggestions, setDismissedSuggestions] = useState<string[]>([])
  useEffect(() => {
    setCurrentView(initialView)
  }, [initialView])

  useEffect(() => {
    const dismissed = localStorage.getItem('dismissedSuggestions')
    if (dismissed) {
      setDismissedSuggestions(JSON.parse(dismissed))
    }
  }, [])

  const dismissSuggestion = (id: string) => {
    const newDismissed = [...dismissedSuggestions, id]
    setDismissedSuggestions(newDismissed)
    localStorage.setItem('dismissedSuggestions', JSON.stringify(newDismissed))
  }

  const isAppDownloaded = () => {
    if (typeof window !== 'undefined') {
      return window.matchMedia('(display-mode: standalone)').matches
    }
    return false
  }

  const isSecurityEnabled = () => {
    return !!userProfile?.securityEnabled && (!!userProfile?.pin || SecurePinManager.hasPin())
  }

  const isNotificationEnabled = () => {
    if (typeof window === "undefined") return true
    
    // Check both browser permission and app settings
    const browserPerm = "Notification" in window ? Notification.permission === "granted" : true
    const appSettings = userProfile?.notificationSettings?.enabled ?? true
    
    return browserPerm && appSettings
  }

  const suggestions: Suggestion[] = [
    {
      id: 'download',
      title: 'Download MyWallet App',
      description: 'Get the full experience',
      action: () => {
        const deferredPrompt = (window as any).__deferredPrompt
        if (deferredPrompt) {
          deferredPrompt.prompt()
          deferredPrompt.userChoice.then(() => {
            try { delete (window as any).__deferredPrompt } catch { }
          })
        } else {
          alert(
            'Install is not available right now. Please open browser menu and choose "Install" or visit this site on a supported browser.'
          );
        }
      },
      condition: !isAppDownloaded()
    },
    {
      id: 'security',
      title: 'Enable Security',
      description: 'Protect your data with PIN or biometric',
      action: () => setCurrentView('security'),
      condition: !isSecurityEnabled()
    },
    {
      id: 'notifications',
      title: 'Turn On Notifications',
      description: 'Get budget and goal reminders',
      action: () => setCurrentView('notifications'),
      condition: !isNotificationEnabled()
    },
    {
      id: 'backup',
      title: 'Backup Your Data',
      description: 'Keep your data safe',
      action: () => setCurrentView('data'),
      condition: true
    }
  ].filter(s => s.condition && !dismissedSuggestions.includes(s.id))

  const getInitials = () => {
    return userProfile?.name
      ? userProfile.name
        .split(" ")
        .map((n: string) => n[0])
        .join("")
        .toUpperCase()
        .slice(0, 2)
      : "U"
  }

  const getCurrentCurrencySymbol = () => {
    return getCurrencySymbol(userProfile?.currency || "USD", userProfile?.customCurrency)
  }

  // Settings items data
  const allSettingsItems = [
    {
      id: "profile",
      icon: <User className="w-6 h-6" />,
      iconBg: "bg-blue-600",
      title: "Profile",
      subtitle: "Personal info • Currency",
      category: "account",
      keywords: ["profile", "account", "personal", "info", "currency", "name", "avatar"]
    },
    {
      id: "security",
      icon: <Shield className="w-6 h-6" />,
      iconBg: "bg-red-600",
      title: "Security",
      subtitle: "PIN • Biometric • Emergency access",
      category: "account",
      keywords: ["security", "pin", "biometric", "emergency", "access", "password", "lock"]
    },
    {
      id: "notifications",
      icon: <Bell className="w-6 h-6" />,
      iconBg: "bg-amber-600",
      title: "Notifications",
      subtitle: "Reminders • Browser permission • Delivery",
      category: "account",
      keywords: ["notifications", "alerts", "reminders", "budget alerts", "goals", "permission"]
    },
    {
      id: "meroshare",
      icon: <Share2 className="w-6 h-6" />,
      iconBg: "bg-indigo-600",
      title: "MeroShare",
      subtitle: "IPO Automation • Credentials",
      category: "account",
      keywords: ["meroshare", "ipo", "automation", "invest", "share"]
    },
    {
      id: "theme",
      icon: <Palette className="w-6 h-6" />,
      iconBg: "bg-pink-600",
      title: "Theme",
      subtitle: "Appearance • Colors • Accessibility",
      category: "personalization",
      keywords: ["theme", "appearance", "colors", "dark", "light", "accessibility", "visual"]
    },
    {
      id: "data",
      icon: <Database className="w-6 h-6" />,
      iconBg: "bg-teal-600",
      title: "Data",
      subtitle: "Backup • Import • Export",
      category: "system",
      keywords: ["data", "backup", "import", "export", "sync", "storage"]
    },
    {
      id: "accessibility",
      icon: <Accessibility className="w-6 h-6" />,
      iconBg: "bg-orange-600",
      title: "Accessibility",
      subtitle: "Audio • Visual • Motion",
      category: "system",
      keywords: ["accessibility", "audio", "visual", "motion", "screen reader", "keyboard"]
    },
    {
      id: "about",
      icon: <Info className="w-6 h-6" />,
      iconBg: "bg-gray-600",
      title: "About",
      subtitle: "Version • Support • Legal",
      category: "system",
      keywords: ["about", "version", "support", "legal", "help", "info"]
    },

  ]

  // Filter settings items based on search query
  const filteredSettingsItems = useMemo(() => {
    if (!searchQuery.trim()) {
      return allSettingsItems
    }

    const query = searchQuery.toLowerCase()
    return allSettingsItems.filter(item =>
      item.title.toLowerCase().includes(query) ||
      item.subtitle.toLowerCase().includes(query) ||
      item.keywords.some(keyword => keyword.toLowerCase().includes(query))
    )
  }, [searchQuery])

  const renderMainView = () => (
    <div className="flex flex-col h-full">
      <div className="flex justify-between items-center px-4 py-2 bg-background text-sm font-medium text-muted-foreground sticky top-0 z-10">
        <Button
          size="sm"
          onClick={onClose}
          className="mr-1 p-1"
        >
          <ArrowLeft className="w-5 h-5" />
        </Button>
        <h1 className="text-3xl mr-1 p-1 mt-4 font-normal text-primary mb-4">Settings</h1>
      </div>

      {/* Header */}
      <div className="px-4 py-6 bg-background">
        {/* Search Bar */}
        <div className="relative mb-6">
          <div className="absolute left-4 top-1/2 transform -translate-y-1/2 text-card-500">
            <Search className="w-4 h-4" />
          </div>
          <Input
            type="text"
            placeholder="Search settings..."
            value={searchQuery}
            onChange={(e) => setSearchQuery(e.target.value)}
            className="pl-12 pr-12 py-3 rounded-full bg-card-100 dark:bg-gray-700 border-0"
          />
          {searchQuery && (
            <button
              onClick={() => setSearchQuery("")}
              className="absolute right-4 top-1/2 transform -translate-y-1/2 text-gray-500 hover:text-gray-700 dark:hover:text-gray-300 transition-colors"
              aria-label="Clear search"
            >
              <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M6 18L18 6M6 6l12 12" />
              </svg>
            </button>
          )}
        </div>
        {!searchQuery.trim() && (
          <>
            {/* User Profile */}
            <div className="flex items-center p-4 mb-1 bg-card rounded-xl cursor-pointer hover:bg-muted transition-colors"
              onClick={() => setCurrentView("profile")}>
              <div className="flex-1">
                <div className="font-medium text-lg text-gray-900 dark:text-white mb-1">
                  {userProfile?.name || "Mr/Ms lovely user"}
                </div>
                <div className="text-sm text-gray-500 dark:text-gray-400">
                  {getCurrentCurrencySymbol()} • myWallet lovelyUser
                </div>
              </div>
              <Avatar className="w-12 h-12 mr-4">
                <AvatarImage src={userProfile?.avatar} />
                <AvatarFallback className="bg-gradient-to-br from-primary/20 via-primary/10 to-primary/5 text-primary font-bold text-2xl shadow-inner">
                  {getInitials()}
                </AvatarFallback>
              </Avatar>
            </div>

            {/* Suggestions */}
            {suggestions.length > 0 && (
              <SuggestionsCarousel suggestions={suggestions} onDismiss={dismissSuggestion} />
            )}
          </>
        )}
      </div>

      {/* Content */}
      <div className=" px-4 pb-4 bg-background overflow-y-auto scrollbar-hide">
        {/* Settings Items */}
        <div className="space-y-1">
          {filteredSettingsItems.length > 0 ? (
            filteredSettingsItems.map((item) => (
              <SettingsItem
                key={item.id}
                icon={item.icon}
                iconBg={item.iconBg}
                title={item.title}
                subtitle={item.subtitle}
                onClick={() => {
                  if (item.id === "profile" || item.id === "security" || item.id === "meroshare" || item.id === "theme" ||
                    item.id === "notifications" || item.id === "data" || item.id === "accessibility" || item.id === "about") {
                    setCurrentView(item.id as SettingsView)
                    setHighlightQuery(searchQuery)
                  }
                  // For other items, you could add navigation or actions here
                }}
              />
            ))
          ) : searchQuery.trim() ? (
            <div className="text-center py-8">
              <div className="text-gray-400 dark:text-gray-500 mb-2">
                <Search className="w-12 h-12 mx-auto mb-4 opacity-50" />
              </div>
              <p className="text-gray-500 dark:text-gray-400 text-sm">
                No settings found for "{searchQuery}"
              </p>
              <Button
                variant="ghost"
                size="sm"
                onClick={() => setSearchQuery("")}
                className="mt-2 text-primary"
              >
                Clear search
              </Button>
            </div>
          ) : null}
        </div>
      </div>
    </div>
  )

  const renderDetailView = () => {
    const getTitle = () => {
      switch (currentView) {
        case "profile": return "Profile"
        case "security": return "Security"
        case "notifications": return "Notifications"
        case "meroshare": return "MeroShare"
        case "theme": return "Theme"
        case "data": return "Data"
        case "accessibility": return "Accessibility"
        case "about": return "About"
        default: return "Settings"
      }
    }

    const renderContent = () => {
      switch (currentView) {
        case "profile": return <UserProfileSettings highlightQuery={highlightQuery} />
        case "security": return <SecuritySettings />
        case "notifications": return <NotificationSettings />
        case "meroshare": return <MeroShareSettings />
        case "theme": return <ThemeSettings />
        case "data": return <DataSettings />
        case "accessibility": return <AccessibilitySettings />
        case "about": return <AboutSettings />
        default: return null
      }
    }

    return (
      <div className="flex flex-col h-full">
        {/* Header */}
        <div className="flex items-center px-4 py-4 bg-card border-b border-border sticky top-0 z-10">
          <Button
            variant="ghost"
            size="sm"
            onClick={() => setCurrentView("main")}
            className="mr-4 p-2"
          >
            <ArrowLeft className="w-5 h-5" />
          </Button>
          <h1 className="text-xl font-medium text-gray-900 dark:text-white">{getTitle()}</h1>
        </div>

        {/* Content */}
        <div className="flex-1 overflow-y-auto bg-muted scrollbar-hide">
          <div className="p-4">
            {renderContent()}
          </div>
        </div>
      </div>
    )
  }

  return (
    <div className="fixed inset-0 bg-background z-50 overflow-hidden">
      {currentView === "main" ? renderMainView() : renderDetailView()}
    </div>
  )
}

interface Suggestion {
  id: string
  title: string
  description: string
  action: () => void
  condition?: boolean
}

function SuggestionsCarousel({ suggestions, onDismiss }: { suggestions: Suggestion[], onDismiss: (id: string) => void }) {
  const [currentIndex, setCurrentIndex] = useState(0)
  const scrollRef = useRef<HTMLDivElement>(null)

  // Handle scroll to update currentIndex
  useEffect(() => {
    const handleScroll = () => {
      if (scrollRef.current) {
        const scrollLeft = scrollRef.current.scrollLeft
        const itemWidth = scrollRef.current.clientWidth
        const index = Math.round(scrollLeft / itemWidth)
        setCurrentIndex(index)
      }
    }
    scrollRef.current?.addEventListener('scroll', handleScroll)
    return () => scrollRef.current?.removeEventListener('scroll', handleScroll)
  }, [])

  // Swipe handling
  const [touchStart, setTouchStart] = useState(0)
  const [touchEnd, setTouchEnd] = useState(0)
  const minSwipeDistance = 50

  const onTouchStart = (e: React.TouchEvent) => {
    setTouchEnd(0)
    setTouchStart(e.targetTouches[0].clientX)
  }

  const onTouchMove = (e: React.TouchEvent) => {
    setTouchEnd(e.targetTouches[0].clientX)
  }

  const onTouchEnd = () => {
    if (!touchStart || !touchEnd) return
    const distance = touchStart - touchEnd
    const isLeftSwipe = distance > minSwipeDistance
    const isRightSwipe = distance < -minSwipeDistance
    if (isLeftSwipe && currentIndex < suggestions.length - 1) {
      setCurrentIndex(currentIndex + 1)
      scrollRef.current?.scrollTo({ left: (currentIndex + 1) * scrollRef.current.clientWidth, behavior: 'smooth' })
    }
    if (isRightSwipe && currentIndex > 0) {
      setCurrentIndex(currentIndex - 1)
      scrollRef.current?.scrollTo({ left: (currentIndex - 1) * scrollRef.current.clientWidth, behavior: 'smooth' })
    }
  }

  return (
    <div className="mb-1">
      <div
        ref={scrollRef}
        className="flex overflow-x-auto hide-scrollbars snap-x snap-mandatory"
        onTouchStart={onTouchStart}
        onTouchMove={onTouchMove}
        onTouchEnd={onTouchEnd}
      >
        {suggestions.map((suggestion, index) => (
          <div key={suggestion.id} className="flex-shrink-0 w-full snap-center p-3 bg-card rounded-xl shadow-sm mr-2 last:mr-0">
            <div className="flex items-center">
              <div className="flex-1 cursor-pointer" onClick={suggestion.action}>
                <div className="font-small text-gray-900 dark:text-white mb-1">
                  {suggestion.title}
                </div>
                <div className="text-sm text-gray-500 dark:text-gray-400">
                  {suggestion.description}
                </div>
              </div>
              <button
                type="button"
                aria-label={`Dismiss ${suggestion.title}`}
                title="Dismiss"
                onClick={() => onDismiss(suggestion.id)}
                className="ml-2 text-gray-400 hover:text-gray-600"
              >
                ×
              </button>
            </div>
          </div>
        ))}
      </div>
      <div className="flex justify-center mt-2">
        {suggestions.map((_, index) => (
          <div
            key={index}
            className={`w-2 h-2 rounded-full mx-1 ${index === currentIndex ? 'bg-primary' : 'bg-gray-300'}`}
          />
        ))}
      </div>
    </div>
  )
}

interface SettingsItemProps {
  icon: React.ReactNode
  iconBg: string
  title: string
  subtitle: string
  hasToggle?: boolean
  toggleOff?: boolean
  onClick: () => void
}

function SettingsItem({ icon, iconBg, title, subtitle, hasToggle, toggleOff, onClick }: SettingsItemProps) {
  return (
    <div
      className="flex items-center p-4 bg-card rounded-xl cursor-pointer hover:bg-muted transition-colors"
      onClick={onClick}
    >
      <div className={`w-12 h-12 rounded-xl flex items-center justify-center text-white mr-4 ${iconBg}`}>
        {icon}
      </div>
      <div className="flex-1">
        <div className="font-medium text-gray-900 dark:text-white">{title}</div>
        <div className="text-sm text-gray-500 dark:text-gray-400">{subtitle}</div>
      </div>
      {hasToggle ? (
        <div className="mr-4" onClick={(e) => e.stopPropagation()}>
          <Switch checked={!toggleOff} />
        </div>
      ) : (
        <ChevronRight className="w-5 h-5 text-gray-400" />
      )}
    </div>
  )
}

"use client"

import { useState, useEffect } from "react"
import { Button } from "@/components/ui/button"
import { Card, CardContent, CardDescription, CardHeader, CardTitle } from "@/components/ui/card"
import { Switch } from "@/components/ui/switch"
import { Label } from "@/components/ui/label"
import { InputOTP, InputOTPGroup, InputOTPSlot } from "@/components/ui/input-otp"
import { Dialog, DialogContent, DialogDescription, DialogHeader, DialogTitle } from "@/components/ui/dialog"
import { useWalletData } from "@/contexts/wallet-data-context"
import { useAuthentication } from "@/hooks/use-authentication"
import { SecureWallet } from "@/lib/security"
import { SecureKeyManager } from "@/lib/key-manager"
import { SecurePinManager } from "@/lib/secure-pin-manager"
import { SessionManager } from "@/lib/session-manager"
import { SecurityLogger, SecurityEvent } from "@/lib/security-logger"
import { BiometricAuth } from "../security/biometric-auth"
import { Shield, Lock, Key, Volume2, AlertTriangle, CheckCircle2, Info } from "lucide-react"
import { Badge } from "@/components/ui/badge"
import { Alert, AlertDescription, AlertTitle } from "@/components/ui/alert"
import { Progress } from "@/components/ui/progress"
import { toast } from "@/hooks/use-toast"

interface SecuritySettingsProps {
  onLock?: () => void
}

export function SecuritySettings({ onLock }: SecuritySettingsProps) {
  const { userProfile, updateUserProfile } = useWalletData()
  const { isAuthenticated, hasPin, lockApp } = useAuthentication()

  const [pinEnabled, setPinEnabled] = useState(!!userProfile?.securityEnabled && !!userProfile?.pin)
  const [showPinDialog, setShowPinDialog] = useState(false)
  const [currentPin, setCurrentPin] = useState("")
  const [newPin, setNewPin] = useState("")
  const [confirmPin, setConfirmPin] = useState("")
  const [step, setStep] = useState<"current" | "new" | "confirm">("current")
  const [isProcessing, setIsProcessing] = useState(false)

  // Emergency PIN states
  const [emergencyPinEnabled, setEmergencyPinEnabled] = useState(SecurePinManager.hasEmergencyPin())
  const [showEmergencyPinDialog, setShowEmergencyPinDialog] = useState(false)
  const [showEmergencyWarningModal, setShowEmergencyWarningModal] = useState(false)
  const [emergencyCurrentPin, setEmergencyCurrentPin] = useState("")
  const [emergencyNewPin, setEmergencyNewPin] = useState("")
  const [emergencyConfirmPin, setEmergencyConfirmPin] = useState("")
  const [emergencyStep, setEmergencyStep] = useState<"current" | "new" | "confirm">("new")
  const [isEmergencyProcessing, setIsEmergencyProcessing] = useState(false)
  
  // Audit states
  const [securityAudit, setSecurityAudit] = useState<{
    vulnerabilities: string[]
    recommendations: string[]
    overallRisk: 'low' | 'medium' | 'high'
  } | null>(null)
  const [securityLogs, setSecurityLogs] = useState<SecurityEvent[]>([])

  // Update pinEnabled state when userProfile changes
  useEffect(() => {
    if (userProfile) {
      setPinEnabled(!!userProfile.securityEnabled && !!userProfile.pin)
    }
  }, [userProfile])

  // Update emergency PIN status
  useEffect(() => {
    const updateEmergencyStatus = () => {
      setEmergencyPinEnabled(SecurePinManager.hasEmergencyPin())
    }

    updateEmergencyStatus()

    // Update audit info
    setSecurityAudit(SecureKeyManager.performSecurityAudit())
    setSecurityLogs(SecurityLogger.getLogs())

    // Update when dialog opens or settings change
    if (showEmergencyPinDialog || showPinDialog) {
      updateEmergencyStatus()
      setSecurityAudit(SecureKeyManager.performSecurityAudit())
      setSecurityLogs(SecurityLogger.getLogs())
    }
  }, [showEmergencyPinDialog, showPinDialog])

  if (!userProfile) {
    return (
      <div className="flex items-center justify-center p-8">
        <p className="text-muted-foreground">Loading security settings...</p>
      </div>
    )
  }

  const securityStatus = SecureKeyManager.getSecurityStatus()

  const handleTogglePin = () => {
    if (pinEnabled) {
      // Disable PIN
      setShowPinDialog(true)
      setStep("current")
    } else {
      // Enable PIN
      setShowPinDialog(true)
      setStep("new")
    }
  }

  const handlePinSubmit = async () => {
    setIsProcessing(true)

    try {
      if (step === "current") {
        let isValid = false

        if (userProfile.pin && userProfile.pinSalt) {
          // Use new secure validation
          isValid = await SecureWallet.validatePin(currentPin, userProfile.pin, userProfile.pinSalt)
        } else if (userProfile.pin) {
          // Legacy validation for backward compatibility
          const { validatePin } = await import("@/lib/security")
          isValid = validatePin(currentPin, userProfile.pin)
        } else {
          isValid = true // No PIN set
        }

        if (isValid) {
          if (pinEnabled) {
            // Disabling PIN - clear ALL security data completely
            SecureKeyManager.clearAllKeys()
            SecurePinManager.clearAllSecurityData() // Comprehensive security data cleanup

            updateUserProfile({
              ...userProfile,
              pin: undefined,
              pinSalt: undefined,
              securityEnabled: false,
            })
            setPinEnabled(false)
            setShowPinDialog(false)

            toast({
              title: "PIN Disabled",
              description: "Your PIN, biometric data, security keys, and session data have been completely removed. The app is now unlocked.",
            })
          } else {
            setStep("new")
          }
        } else {
          toast({
            title: "Invalid PIN",
            description: "The current PIN you entered is incorrect.",
            variant: "destructive",
          })
        }
      } else if (step === "new") {
        if (newPin.length === 6) {
          setStep("confirm")
        }
      } else if (step === "confirm") {
        if (newPin === confirmPin) {
          // Use SecurePinManager.setupPin() for consistent behavior with onboarding
          const pinSetupSuccess = await SecurePinManager.setupPin(newPin)

          if (pinSetupSuccess) {
            // Get the PIN data from localStorage (set by SecurePinManager)
            const pinHash = localStorage.getItem('wallet_pin_hash')
            const pinSalt = localStorage.getItem('wallet_pin_salt')

            updateUserProfile({
              ...userProfile,
              pin: pinHash || undefined,
              pinSalt: pinSalt || undefined,
              securityEnabled: true,
            })
            setPinEnabled(true)
            setShowPinDialog(false)
            resetPinDialog()

            // Create session for consistent behavior with onboarding
            SessionManager.createSession()

            toast({
              title: "PIN Set Successfully",
              description: "Your PIN has been secured with military-grade encryption and session-based locking enabled.",
            })
          } else {
            toast({
              title: "PIN Setup Failed",
              description: "Failed to set up PIN. Please try again.",
              variant: "destructive",
            })
          }
        } else {
          toast({
            title: "PINs Don't Match",
            description: "Please make sure both PINs are identical.",
            variant: "destructive",
          })
        }
      }
    } catch (error) {
      toast({
        title: "Security Error",
        description: "Failed to process PIN. Please try again.",
        variant: "destructive",
      })
    } finally {
      setIsProcessing(false)
    }
  }

  const resetPinDialog = () => {
    setCurrentPin("")
    setNewPin("")
    setConfirmPin("")
    setStep("current")
  }

  const handleDialogClose = () => {
    setShowPinDialog(false)
    resetPinDialog()
  }

  // Emergency PIN handlers
  const handleEmergencyPinSubmit = async () => {
    setIsEmergencyProcessing(true)

    try {
      if (emergencyStep === "current") {
        // Validate current emergency PIN before disabling
        const isValid = await SecurePinManager.validateEmergencyPin(emergencyCurrentPin)
        if (isValid.success) {
          // Clear emergency PIN data
          localStorage.removeItem('wallet_emergency_pin_hash')
          localStorage.removeItem('wallet_emergency_pin_salt')
          localStorage.removeItem('wallet_emergency_pin_attempts')
          localStorage.removeItem('wallet_emergency_pin_lockout')
          localStorage.removeItem('wallet_emergency_security_level')

          setEmergencyPinEnabled(false)
          setShowEmergencyPinDialog(false)
          resetEmergencyPinDialog()

          toast({
            title: "Emergency PIN Disabled",
            description: "Your emergency PIN has been completely removed.",
          })
        } else {
          toast({
            title: "Invalid Emergency PIN",
            description: "The emergency PIN you entered is incorrect.",
            variant: "destructive",
          })
        }
      } else if (emergencyStep === "new") {
        if (emergencyNewPin.length === 6) {
          setEmergencyStep("confirm")
        }
      } else if (emergencyStep === "confirm") {
        if (emergencyNewPin === emergencyConfirmPin) {
          // Setup emergency PIN
          const success = await SecurePinManager.setupEmergencyPin(emergencyNewPin)

          if (success) {
            setEmergencyPinEnabled(true)
            setShowEmergencyPinDialog(false)
            resetEmergencyPinDialog()

            toast({
              title: "Emergency PIN Set Successfully",
              description: "Your emergency PIN is now configured for backup access.",
            })
          } else {
            toast({
              title: "Emergency PIN Setup Failed",
              description: "Failed to set up emergency PIN. Please try again.",
              variant: "destructive",
            })
          }
        } else {
          toast({
            title: "Emergency PINs Don't Match",
            description: "Please make sure both emergency PINs are identical.",
            variant: "destructive",
          })
        }
      }
    } catch (error) {
      toast({
        title: "Emergency PIN Error",
        description: "Failed to process emergency PIN. Please try again.",
        variant: "destructive",
      })
    } finally {
      setIsEmergencyProcessing(false)
    }
  }

  const resetEmergencyPinDialog = () => {
    setEmergencyCurrentPin("")
    setEmergencyNewPin("")
    setEmergencyConfirmPin("")
    setEmergencyStep(emergencyPinEnabled ? "current" : "new")
  }

  const handleEmergencyDialogClose = () => {
    setShowEmergencyPinDialog(false)
    resetEmergencyPinDialog()
  }

  return (
    <div className="space-y-6">
      {/* PIN Security */}
      <Card>
        <CardHeader>
          <CardTitle className="flex items-center gap-2">
            <Shield className="w-5 h-5" />
            PIN Security
          </CardTitle>
          <CardDescription>
            Protect your wallet with a 6-digit PIN using AES-256 encryption and PBKDF2 key derivation.
          </CardDescription>
        </CardHeader>
        <CardContent className="space-y-4">
          <div className="flex items-center justify-between">
            <div className="space-y-1">
              <Label htmlFor="pin-toggle">Enable PIN Protection</Label>
              <p className="text-sm text-muted-foreground">
                {pinEnabled ? "PIN protection is active" : "PIN protection is disabled"}
              </p>
            </div>
            <Switch id="pin-toggle" checked={pinEnabled} onCheckedChange={handleTogglePin} />
          </div>

          {pinEnabled && (
            <div className="p-4 bg-green-50 dark:bg-green-950/20 rounded-lg border border-green-200 dark:border-green-800">
              <div className="flex items-center gap-2 text-green-700 dark:text-green-400">
                <Lock className="w-4 h-4" />
                <span className="text-sm font-medium">Security Active</span>
              </div>
              <p className="text-sm text-green-600 dark:text-green-500 mt-1">
                Your wallet is protected with military-grade encryption
              </p>
            </div>
          )}

          {securityStatus.hasMasterKey && (
            <Card className="bg-blue-50 dark:bg-blue-950/20 border-blue-200 dark:border-blue-800">
              <CardContent className="pt-4">
                <div className="flex items-center gap-2 text-blue-700 dark:text-blue-400 mb-2">
                  <Key className="w-4 h-4" />
                  <span className="text-sm font-medium">Encryption Status</span>
                </div>
                <div className="space-y-1 text-xs text-blue-600 dark:text-blue-500">
                  <p>• AES-256-GCM encryption active</p>
                  <p>• PBKDF2 key derivation (100,000 iterations)</p>
                  <p>• Master key cached: {securityStatus.cacheValid ? "Yes" : "No"}</p>
                  {securityStatus.lastUsed && <p>• Last used: {new Date(securityStatus.lastUsed).toLocaleString()}</p>}
                </div>
              </CardContent>
            </Card>
          )}

          <Dialog open={showPinDialog} onOpenChange={handleDialogClose}>
            <DialogContent>
              <DialogHeader>
                <DialogTitle>
                  {step === "current"
                    ? pinEnabled
                      ? "Disable PIN"
                      : "Enter Current PIN"
                    : step === "new"
                      ? "Set New PIN"
