                      (step === "confirm" && confirmPin.length !== 6)
                    }
                  >
                    {isProcessing
                      ? "Processing..."
                      : step === "current"
                        ? pinEnabled
                          ? "Disable"
                          : "Continue"
                        : step === "new"
                          ? "Continue"
                          : "Set PIN"}
                  </Button>
                </div>
              </div>
            </DialogContent>
          </Dialog>
        </CardContent>
      </Card>

      {/* Emergency PIN */}
      <Card>
