            </div>
            <Switch
              id="emergency-pin-toggle"
              checked={emergencyPinEnabled}
              onCheckedChange={() => {
                if (!emergencyPinEnabled) {
                  // Show warning modal before setting up emergency PIN
                  setShowEmergencyWarningModal(true)
                } else {
