                      </p>
                    </div>
                  </div>
                </div>

                <div className="flex gap-2">
                  <Button
                    variant="outline"
                    onClick={() => setShowEmergencyWarningModal(false)}
                    className="flex-1"
                  >
                    Cancel
                  </Button>
                  <Button
                    onClick={() => {
                      setShowEmergencyWarningModal(false)
                      setShowEmergencyPinDialog(true)
                    }}
                    className="flex-1"
                  >
                    I Understand - Continue
                  </Button>
                </div>
              </div>
            </DialogContent>
          </Dialog>
        </CardContent>
      </Card>

      {/* Biometric Authentication */}
      <BiometricAuth pinEnabled={pinEnabled} />

      <Card>
        <CardHeader>
          <CardTitle className="flex items-center gap-2">
            <Shield className={`w-5 h-5 ${
              securityAudit?.overallRisk === 'high' ? 'text-destructive' : 
              securityAudit?.overallRisk === 'medium' ? 'text-orange-500' : 
              'text-primary'
            }`} />
            Security Health Audit
          </CardTitle>
          <CardDescription>
            Comprehensive analysis of your wallet's security configuration.
          </CardDescription>
        </CardHeader>
        <CardContent className="space-y-4">
          {securityAudit && (
            <>
              <div className="flex items-center justify-between p-3 bg-muted/50 rounded-lg">
                <span className="text-sm font-medium">Overall Risk Level</span>
                <Badge variant={
                  securityAudit.overallRisk === 'high' ? 'destructive' : 
                  securityAudit.overallRisk === 'medium' ? 'outline' : 
                  'default'
                } className={
                  securityAudit.overallRisk === 'medium' ? 'border-orange-500 text-orange-500' : ''
                }>
                  {securityAudit.overallRisk.toUpperCase()}
                </Badge>
              </div>

              {securityAudit.vulnerabilities.length > 0 && (
                <Alert variant="destructive" className="bg-destructive/5">
                  <AlertTriangle className="h-4 w-4" />
                  <AlertTitle>Vulnerabilities Detected</AlertTitle>
                  <AlertDescription>
                    <ul className="list-disc ml-4 mt-1 text-xs">
                      {securityAudit.vulnerabilities.map((v, i) => (
                        <li key={i}>{v}</li>
                      ))}
                    </ul>
                  </AlertDescription>
                </Alert>
              )}

              {securityAudit.recommendations.length > 0 && (
                <div className="space-y-2">
                  <h4 className="text-sm font-medium flex items-center gap-2">
                    <CheckCircle2 className="w-4 h-4 text-primary" />
                    Recommendations
                  </h4>
                  <div className="space-y-2">
                    {securityAudit.recommendations.map((r, i) => (
                      <div key={i} className="flex items-start gap-2 p-2 bg-primary/5 rounded border border-primary/10">
                        <Info className="w-3.5 h-3.5 text-primary mt-0.5 flex-shrink-0" />
                        <span className="text-xs">{r}</span>
                      </div>
                    ))}
                  </div>
                </div>
              )}

              <div className="pt-2">
                <div className="flex justify-between text-xs mb-1 text-muted-foreground">
                  <span>Encryption Strength</span>
                  <span>{securityStatus.strength?.toUpperCase() || 'N/A'}</span>
                </div>
                <Progress value={
                  securityStatus.strength === 'strong' ? 100 : 
                  securityStatus.strength === 'medium' ? 60 : 30
                } className="h-1" />
              </div>
            </>
          )}
        </CardContent>
      </Card>

      {/* Security Activity Logs */}
      <Card>
        <CardHeader>
          <CardTitle className="flex items-center gap-2 text-sm">
            <Info className="w-4 h-4" />
            Recent Security Activity
          </CardTitle>
          <CardDescription>Last 10 security-related events for auditing.</CardDescription>
        </CardHeader>
        <CardContent className="space-y-3">
          {securityLogs.length > 0 ? (
            <div className="space-y-2">
              {securityLogs.map((log, i) => (
                <div key={i} className="flex items-center justify-between text-xs p-2 bg-muted/30 rounded border border-muted">
                  <div className="flex flex-col">
                    <span className="font-medium capitalize">{log.type.replace(/_/g, " ")}</span>
                    <span className="text-[10px] text-muted-foreground">{new Date(log.timestamp).toLocaleString()}</span>
                  </div>
                  {log.details && (
                    <span className="text-[10px] bg-muted px-1.5 py-0.5 rounded">{log.details}</span>
                  )}
                </div>
              ))}
            </div>
          ) : (
            <p className="text-xs text-muted-foreground text-center py-4">No recent activity logged.</p>
          )}
          <Button 
            variant="ghost" 
            size="sm" 
            className="w-full text-xs h-8"
            onClick={() => {
              SecurityLogger.clearLogs()
              setSecurityLogs([])
            }}
          >
            Clear Activity Logs
          </Button>
        </CardContent>
      </Card>

      {/* Audio Feedback for Authentication */}
      <Card>
        <CardHeader>
          <CardTitle className="flex items-center gap-2">
            <Volume2 className="w-5 h-5" />
            Authentication Sounds
          </CardTitle>
          <CardDescription>Sound feedback for PIN and biometric authentication</CardDescription>
        </CardHeader>
        <CardContent className="space-y-4">
          <div className="p-4 bg-blue-50 dark:bg-blue-950/20 rounded-lg border border-blue-200 dark:border-blue-800">
            <div className="flex items-center gap-2 text-blue-700 dark:text-blue-400 mb-2">
              <Volume2 className="w-4 h-4" />
              <span className="text-sm font-medium">Sound Settings</span>
            </div>
            <p className="text-sm text-blue-600 dark:text-blue-500">
              Authentication sounds are configured in Accessibility Settings. Both PIN and biometric authentication use the same success and failure sound settings.
            </p>
            <p className="text-sm text-blue-600 dark:text-blue-500 mt-2">
              Go to Settings → Accessibility → Audio Feedback to customize sounds for Auth success, Auth failure, and other activities.
            </p>
          </div>
        </CardContent>
      </Card>

      {/* Lock App */}
      {isAuthenticated && hasPin && (
        <Card>
          <CardHeader>
            <CardTitle className="flex items-center gap-2">
              <Lock className="w-5 h-5" />
              App Lock
            </CardTitle>
            <CardDescription>
              Manually lock the app and return to the PIN lock screen
            </CardDescription>
          </CardHeader>
          <CardContent>
            <Button
              onClick={() => {
                lockApp()
                onLock?.()
              }}
              variant="outline"
              className="w-full"
            >
              <Lock className="w-4 h-4 mr-2" />
              Lock App Now
            </Button>
          </CardContent>
        </Card>
      )}

      {/* Security Tips */}
      <Card>
        <CardHeader>
          <CardTitle>Security Tips</CardTitle>
          <CardDescription>Best practices to keep your wallet secure</CardDescription>
        </CardHeader>
        <CardContent className="space-y-3">
          <div className="flex items-start gap-3">
            <div className="w-2 h-2 bg-primary rounded-full mt-2 flex-shrink-0" />
            <p className="text-sm">Use a PIN that's not easily guessable (avoid birthdays, simple patterns)</p>
          </div>
          <div className="flex items-start gap-3">
            <div className="w-2 h-2 bg-primary rounded-full mt-2 flex-shrink-0" />
            <p className="text-sm">Your data is encrypted with AES-256 and stored locally only</p>
          </div>
          <div className="flex items-start gap-3">
            <div className="w-2 h-2 bg-primary rounded-full mt-2 flex-shrink-0" />
            <p className="text-sm">PIN is hashed with PBKDF2 (100,000 iterations) for maximum security</p>
          </div>
          <div className="flex items-start gap-3">
            <div className="w-2 h-2 bg-primary rounded-full mt-2 flex-shrink-0" />
            <p className="text-sm">Don't share your PIN with anyone</p>
          </div>
          <div className="flex items-start gap-3">
            <div className="w-2 h-2 bg-primary rounded-full mt-2 flex-shrink-0" />
            <p className="text-sm">Keep your browser and device updated for security</p>
          </div>
        </CardContent>
      </Card>
    </div>
  )
}

"use client"

import { useState, useEffect, useMemo, useRef } from "react"
import { Button } from "@/components/ui/button"
import { Input } from "@/components/ui/input"
import { Label } from "@/components/ui/label"
import { Avatar, AvatarFallback, AvatarImage } from "@/components/ui/avatar"
import { Card, CardContent, CardDescription, CardHeader, CardTitle } from "@/components/ui/card"
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from "@/components/ui/select"
import { Separator } from "@/components/ui/separator"
import { Dialog, DialogContent, DialogDescription, DialogHeader, DialogTitle, DialogTrigger } from "@/components/ui/dialog"
import { Switch } from "@/components/ui/switch"
import { useWalletData } from "@/contexts/wallet-data-context"
import { LogOut, Trash2, Upload, Save, Plus, PencilLine, Camera, X, User, ImageIcon } from "lucide-react"
import { toast } from "@/hooks/use-toast"
import { CURRENCIES, getCurrencySymbol, getCurrencyLabel } from "@/lib/currency"
import { DeleteDataDialog } from "./delete-data-dialog"
import { useAchievements } from "@/hooks/use-achievements"
import { AchievementsProfile } from "@/components/achievements/achievements-profile"
import { compressImageToDataUrl } from "@/lib/image-utils"

export function UserProfileSettings({ highlightQuery = "" }: { highlightQuery?: string }) {
  const {
    userProfile,
    updateUserProfile,
    clearAllData,
    goals,
    transactions,
    budgets,
    debtAccounts
  } = useWalletData()

  const {
    achievements,
    unlockedAchievements,
    lockedAchievements,
    celebration,
    dismissCelebration
  } = useAchievements({
    goals,
    transactions,
    budgets,
    debtAccounts,
    userProfile: userProfile!
  })
  const [formData, setFormData] = useState<any>(
    userProfile || {
      name: "",
      currency: "USD",
      customCurrency: { code: "", symbol: "", name: "" },
      monthlyEarning: 0,
      workingHoursPerDay: 8,
      workingDaysPerMonth: 22,
    },
  )
  const [hasChanges, setHasChanges] = useState(false)
  const [showCustomCurrency, setShowCustomCurrency] = useState(false)
  const [editMode, setEditMode] = useState(false)
  const [avatarPreview, setAvatarPreview] = useState<string | null>(null)
  const [showAvatarDialog, setShowAvatarDialog] = useState(false)
  const [showWorkDataDialog, setShowWorkDataDialog] = useState(false)

  const fileInputRef = useRef<HTMLInputElement>(null)
  const cameraInputRef = useRef<HTMLInputElement>(null)

  useEffect(() => {
    if (userProfile) {
      // merge to ensure customCurrency exists
      setFormData({ ...userProfile, customCurrency: userProfile.customCurrency || { code: "", symbol: "", name: "" } })
      setShowCustomCurrency(userProfile.currency === "CUSTOM")
    }
  }, [userProfile])

  useEffect(() => {
    setHasChanges(JSON.stringify(formData) !== JSON.stringify(userProfile))
  }, [formData, userProfile])

  const updateField = (key: string, value: any) => {
    setFormData((prev: any) => ({ ...prev, [key]: value }))
  }

  const handleCurrencyChange = (value: string) => {
    updateField("currency", value)
    setShowCustomCurrency(value === "CUSTOM")
  }

  const getCurrentCurrencySymbol = useMemo(() => {
    return getCurrencySymbol(formData?.currency, formData?.customCurrency)
  }, [formData?.currency, formData?.customCurrency])

  const hourlyRate = useMemo(() => {
    const hours = formData.workingHoursPerDay * formData.workingDaysPerMonth
    const rate = hours > 0 ? formData.monthlyEarning / hours : 0
    return isNaN(rate) ? 0 : rate
  }, [formData.monthlyEarning, formData.workingHoursPerDay, formData.workingDaysPerMonth])

  const perMinuteRate = useMemo(() => {
    const rate = hourlyRate > 0 ? hourlyRate / 60 : 0
    return isNaN(rate) ? 0 : rate
  }, [hourlyRate])

  const isTimeWalletEnabled = useMemo(() => {
    return formData.monthlyEarning > 0 && formData.workingHoursPerDay > 0 && formData.workingDaysPerMonth > 0
  }, [formData.monthlyEarning, formData.workingHoursPerDay, formData.workingDaysPerMonth])

  const handleSave = () => {
    updateUserProfile(formData)
    toast({ title: "Profile Updated", description: "Your profile settings have been saved successfully." })
    setEditMode(false)
  }

  const handleTimeWalletToggle = (enabled: boolean) => {
    if (enabled) {
      // Enable: Show dialog to enter work data
      setShowWorkDataDialog(true)
    } else {
      // Disable: Clear work data to empty values
      updateField("monthlyEarning", 0)
      updateField("workingHoursPerDay", 0)
      updateField("workingDaysPerMonth", 0)
      toast({
        title: "Time Wallet Disabled",
        description: "Work data has been cleared and time-based calculations are now disabled.",
      })
    }
  }

  const handleSaveWorkData = () => {
    if (formData.monthlyEarning > 0 && formData.workingHoursPerDay > 0 && formData.workingDaysPerMonth > 0) {
      updateUserProfile(formData)
      setShowWorkDataDialog(false)
      toast({
        title: "Time Wallet Enabled",
        description: "Time-based value calculations are now active.",
      })
    } else {
      toast({
        title: "Invalid Data",
        description: "Please fill in all work information fields.",
        variant: "destructive",
      })
    }
  }
  const handleCancelChanges = () => {
    if (userProfile) {
      // Reset form data to original values
      setFormData({ ...userProfile, customCurrency: userProfile.customCurrency || { code: "", symbol: "", name: "" } })
      setShowCustomCurrency(userProfile.currency === "CUSTOM")
      setAvatarPreview(null)
      setShowAvatarDialog(false)
    }
    toast({ title: "Changes Cancelled", description: "All unsaved changes have been reverted." })
    setEditMode(false)
  }

  const handleLogout = () => {
    localStorage.removeItem("wallet_session")
    window.location.reload()
  }

  const handleDeleteAccount = () => {
    clearAllData()
    toast({
      title: "Account Deleted",
      description: "All your data has been permanently deleted.",
      variant: "destructive",
    })
    setTimeout(() => window.location.reload(), 1000)
  }

  const handleFileUpload = () => {
    if (fileInputRef.current) fileInputRef.current.click()
  }

  const handleCameraCapture = () => {
    if (cameraInputRef.current) cameraInputRef.current.click()
  }

  const handleImageSelect = (event: React.ChangeEvent<HTMLInputElement>) => {
    const file = event.target.files?.[0]
    if (file) {
      // Validate file type
      if (!file.type.startsWith('image/')) {
        toast({
          title: "Invalid file type",
          description: "Please select an image file.",
          variant: "destructive",
        })
        return
      }

      // Validate file size (max 5MB)
      if (file.size > 5 * 1024 * 1024) {
        toast({
          title: "File too large",
          description: "Please select an image smaller than 5MB.",
          variant: "destructive",
        })
        return
      }

      void (async () => {
        try {
          const result = await compressImageToDataUrl(file, {
            maxSize: 512,
            maxBytes: 500 * 1024,
            mimeType: "image/jpeg",
            quality: 0.9,
          })
          setAvatarPreview(result)
          updateField("avatar", result)
          setShowAvatarDialog(true)
        } catch {
          toast({
            title: "Image processing failed",
            description: "Please try a different image.",
            variant: "destructive",
          })
        }
      })()
    }
  }

  const handleRemoveAvatar = () => {
    setAvatarPreview(null)
    updateField("avatar", null)
    setShowAvatarDialog(false)
    toast({
      title: "Avatar removed",
      description: "Your profile picture has been removed.",
    })
  }

  const handleSaveAvatar = () => {
    if (avatarPreview) {
      updateField("avatar", avatarPreview)
    }
    setShowAvatarDialog(false)
    toast({
      title: "Avatar updated",
      description: "Your profile picture has been updated successfully.",
    })
  }

  const getAvatarSrc = () => {
    return avatarPreview || formData.avatar || null
  }

  const getInitials = () => {
    return formData.name
      ? formData.name
        .split(" ")
        .map((n: string) => n[0])
        .join("")
        .toUpperCase()
        .slice(0, 2)
      : "U"
  }

  if (!userProfile) {
    return (
      <div className="flex items-center justify-center p-8">
        <p className="animate-pulse text-muted-foreground">Loading profile...</p>
      </div>
    )
  }

  return (
    <div className="space-y-8">
      {/* Profile Card */}
      <Card>
        <CardHeader className="flex flex-row items-center justify-between">
          <div>
            <CardTitle>Profile</CardTitle>
            <CardDescription>Switch to edit mode to edit</CardDescription>
          </div>
          <Button variant="outline" size="sm" onClick={() => setEditMode(!editMode)}>
            <PencilLine className="w-4 h-4 mr-2" />
            {editMode ? "Cancel" : "Edit Profile"}
          </Button>
        </CardHeader>

        <CardContent className="grid grid-cols-1 lg:grid-cols-4 gap-8 items-start">
          {/* Enhanced Avatar Section */}
          <div className="flex flex-col items-center gap-6 lg:col-span-1">
            <div className="relative group">
              {/* Hidden file inputs */}
              {editMode && (
                <>
                  <input
                    ref={fileInputRef}
                    type="file"
                    accept="image/*"
                    onChange={handleImageSelect}
                    className="hidden"
                    aria-label="Upload avatar image"
                  />
                  <input
                    ref={cameraInputRef}
                    type="file"
                    accept="image/*"
                    capture="environment"
                    onChange={handleImageSelect}
                    className="hidden"
                    aria-label="Take photo"
                  />
                </>
              )}

              {/* Avatar with interactive overlay */}
              <div
                className={`relative ${editMode ? 'cursor-pointer' : ''}`}
                onClick={() => editMode && !getAvatarSrc() && handleFileUpload()}
              >
                <Avatar className={`w-32 h-32 ring-4 ${highlightQuery.toLowerCase().includes("avatar") ? "ring-primary" : "ring-primary/10"} shadow-xl transition-all duration-300 group-hover:ring-primary/30 group-hover:shadow-2xl group-hover:scale-105`}>
                  <AvatarImage
                    src={getAvatarSrc() || undefined}
                    className="object-cover"
                  />
                  <AvatarFallback className="bg-gradient-to-br from-primary/20 via-primary/10 to-primary/5 text-primary font-bold text-2xl shadow-inner">
                    {getInitials()}
                  </AvatarFallback>
                </Avatar>

                {/* Interactive hover overlay */}
                {editMode && (
                  <div className="absolute inset-0 bg-black/70 rounded-full opacity-0 group-hover:opacity-100 transition-all duration-300 flex items-center justify-center backdrop-blur-sm">
                    <div className="flex gap-3">
                      {!getAvatarSrc() ? (
                        <>
                          <button
                            onClick={(e) => {
                              e.stopPropagation();
                              handleFileUpload();
                            }}
                            className="w-12 h-12 bg-white/90 rounded-full flex items-center justify-center text-primary hover:bg-white hover:scale-110 transition-all duration-200 shadow-lg"
                            title="Upload from gallery"
                          >
                            <ImageIcon className="w-6 h-6" />
                          </button>
                          <button
                            onClick={(e) => {
                              e.stopPropagation();
                              handleCameraCapture();
                            }}
                            className="w-12 h-12 bg-white/90 rounded-full flex items-center justify-center text-primary hover:bg-white hover:scale-110 transition-all duration-200 shadow-lg"
                            title="Take photo"
                          >
                            <Camera className="w-6 h-6" />
                          </button>
                        </>
                      ) : (
                        <button
                          onClick={(e) => {
                            e.stopPropagation();
                            handleRemoveAvatar();
                          }}
                          className="w-12 h-12 bg-destructive/90 rounded-full flex items-center justify-center text-white hover:bg-destructive hover:scale-110 transition-all duration-200 shadow-lg"
                          title="Remove avatar"
                        >
                          <X className="w-6 h-6" />
                        </button>
                      )}
                    </div>
                  </div>
                )}
              </div>
            </div>
          </div>

          {/* Enhanced Info Section */}
          <div className="lg:col-span-3 space-y-6">
            {!editMode ? (
              <div className="space-y-4">
                <div className="space-y-2">
                  <h2 className="text-2xl font-bold text-foreground">{formData.name || "Unnamed User"}</h2>
                  <div className="flex items-center gap-2">
                    <div className="inline-flex items-center gap-2 px-3 py-1 rounded-full bg-primary/5 border border-primary/10">
                      <div className="w-2 h-2 bg-primary rounded-full"></div>
                      <span className="text-sm font-medium text-primary">
                        {getCurrencyLabel(formData.currency, formData.customCurrency)}
                      </span>
                    </div>
                  </div>
                </div>

                {/* Profile Stats - Only show if time wallet is enabled */}
                {isTimeWalletEnabled && (
                  <div className="grid grid-cols-3 md:grid-cols-3 gap-4">
                    <div className="p-4 rounded-lg bg-gradient-to-br from-info/5 to-info/10 dark:from-info/20 dark:to-info/30 border border-info/20 dark:border-info/80">
                      <div className="text-xl font-bold text-info">
                        {getCurrentCurrencySymbol}{hourlyRate.toFixed(2)}
                      </div>
                      <div className="text-sm text-info/70">Hourly Rate</div>
                    </div>
                    <div className="p-4 rounded-lg bg-gradient-to-br from-success/5 to-success/10 dark:from-success/20 dark:to-success/30 border border-success/20 dark:border-success/80">
                      <div className="text-xl font-bold text-success">
                        {formData.workingHoursPerDay}h
                      </div>
                      <div className="text-sm text-success/70">Daily Hours</div>
                    </div>
                    <div className="p-4 rounded-lg bg-gradient-to-br from-warning/5 to-warning/10 dark:from-warning/20 dark:to-warning/30 border border-warning/20 dark:border-warning/80">
                      <div className="text-xl font-bold text-warning">
                        {formData.workingDaysPerMonth}
                      </div>
                      <div className="text-sm text-warning/70">Work Days</div>
                    </div>
                  </div>
                )}
              </div>
            ) : (
              <div className="space-y-6">
                <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                  <div className="space-y-2">
                    <Label htmlFor="full-name" className="text-sm font-medium">Full Name</Label>
                    <Input
                      id="full-name"
                      placeholder="Enter your full name"
                      value={formData.name}
                      onChange={(e) => updateField("name", e.target.value)}
                      className={`h-11 ${highlightQuery.toLowerCase().includes("name") ? "ring-2 ring-primary" : ""}`}
                    />
                  </div>
                  <div className="space-y-2">
                    <Label htmlFor="currency" className="text-sm font-medium">Currency</Label>
                    <Select value={formData.currency} onValueChange={handleCurrencyChange}>
                      <SelectTrigger className={`h-11 ${highlightQuery.toLowerCase().includes("currency") ? "ring-2 ring-primary" : ""}`}>
                        <SelectValue />
                      </SelectTrigger>
                      <SelectContent>
                        {CURRENCIES.map((currency) => (
                          <SelectItem key={currency.value} value={currency.value}>
                            {currency.label}
                          </SelectItem>
                        ))}
                      </SelectContent>
                    </Select>
                  </div>
                </div>

                {showCustomCurrency && (
                  <div className="p-4 rounded-lg bg-muted/50 border border-dashed">
                    <h4 className="text-sm font-medium mb-3">Custom Currency Details</h4>
                    <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
                      <div className="space-y-2">
                        <Label htmlFor="custom-code" className="text-xs">Currency Code</Label>
                        <Input
                          id="custom-code"
                          placeholder="BTC"
                          value={formData.customCurrency?.code || ""}
                          onChange={(e) =>
                            updateField("customCurrency", {
                              ...formData.customCurrency,
                              code: e.target.value.toUpperCase(),
                            })
                          }
                          className="h-9"
                        />
                      </div>
                      <div className="space-y-2">
                        <Label htmlFor="custom-symbol" className="text-xs">Symbol</Label>
                        <Input
                          id="custom-symbol"
                          placeholder="₿"
                          value={formData.customCurrency?.symbol || ""}
                          onChange={(e) =>
                            updateField("customCurrency", {
                              ...formData.customCurrency,
                              symbol: e.target.value,
                            })
                          }
                          className="h-9"
                        />
                      </div>
                      <div className="space-y-2">
                        <Label htmlFor="custom-name" className="text-xs">Full Name</Label>
                        <Input
                          id="custom-name"
                          placeholder="Bitcoin"
                          value={formData.customCurrency?.name || ""}
                          onChange={(e) =>
                            updateField("customCurrency", {
                              ...formData.customCurrency,
                              name: e.target.value,
                            })
                          }
                          className="h-9"
                        />
                      </div>
                    </div>
                  </div>
                )}
              </div>
            )}
          </div>
        </CardContent>
      </Card>

      {/* Enhanced Work Information */}
      <Card className="border-0 shadow-sm bg-gradient-to-br from-card to-card/50">
        <CardHeader className="pb-4">
          <div className="flex items-center gap-3">
            <div className="w-10 h-10 bg-primary/10 rounded-lg flex items-center justify-center">
              <svg className="w-5 h-5 text-primary" fill="none" stroke="currentColor" viewBox="0 0 24 24">
