"use client"

import React, { useState, useEffect, useCallback, useRef } from "react"
import { Button } from "@/components/ui/button"
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card"
import { Badge } from "@/components/ui/badge"
import { RotateCcw, Play, Pause, Home, Cpu } from "lucide-react"
import { useIsMobile } from "@/hooks/use-mobile"
import { toast } from "sonner"

interface PingPongGameProps {
  isOpen: boolean
  onClose: () => void
}

interface GameState {
  ball: { x: number; y: number; dx: number; dy: number }
  paddle1: { y: number; score: number }
  paddle2: { y: number; score: number }
  isPlaying: boolean
  isPaused: boolean
  gameMode: 'normal' | 'infinity' | 'ai'
  winner: string | null
}

const CANVAS_WIDTH = 400
const CANVAS_HEIGHT = 300
const PADDLE_WIDTH = 10
const PADDLE_HEIGHT = 80
const BALL_SIZE = 10
const PADDLE_SPEED = 5
const BALL_SPEED = 3

export function PingPongGame({ isOpen, onClose }: PingPongGameProps) {
  const canvasRef = useRef<HTMLCanvasElement>(null)
  const animationRef = useRef<number>()
  const isMobile = useIsMobile()

  const [gameState, setGameState] = useState<GameState>({
    ball: { x: CANVAS_WIDTH / 2, y: CANVAS_HEIGHT / 2, dx: BALL_SPEED, dy: BALL_SPEED },
    paddle1: { y: CANVAS_HEIGHT / 2 - PADDLE_HEIGHT / 2, score: 0 },
    paddle2: { y: CANVAS_HEIGHT / 2 - PADDLE_HEIGHT / 2, score: 0 },
    isPlaying: false,
    isPaused: false,
    gameMode: 'normal',
    winner: null
  })

  const [keys, setKeys] = useState<Set<string>>(new Set())

  // Handle keyboard input
  useEffect(() => {
    const handleKeyDown = (e: KeyboardEvent) => {
      setKeys(prev => new Set(prev).add(e.key.toLowerCase()))
    }

    const handleKeyUp = (e: KeyboardEvent) => {
      setKeys(prev => {
        const newKeys = new Set(prev)
        newKeys.delete(e.key.toLowerCase())
        return newKeys
      })
    }

    window.addEventListener('keydown', handleKeyDown)
    window.addEventListener('keyup', handleKeyUp)

    return () => {
      window.removeEventListener('keydown', handleKeyDown)
      window.removeEventListener('keyup', handleKeyUp)
    }
  }, [])

  // Game loop
  const gameLoop = useCallback(() => {
    if (!gameState.isPlaying || gameState.isPaused || gameState.winner) return

    setGameState(prev => {
      const newState = { ...prev }

      // Move paddles
      if (keys.has('w') && newState.paddle1.y > 0) {
        newState.paddle1.y -= PADDLE_SPEED
      }
      if (keys.has('s') && newState.paddle1.y < CANVAS_HEIGHT - PADDLE_HEIGHT) {
        newState.paddle1.y += PADDLE_SPEED
      }
      if (keys.has('arrowup') && newState.paddle2.y > 0) {
        newState.paddle2.y -= PADDLE_SPEED
      }
      if (keys.has('arrowdown') && newState.paddle2.y < CANVAS_HEIGHT - PADDLE_HEIGHT) {
        newState.paddle2.y += PADDLE_SPEED
      }

      // Move ball
      newState.ball.x += newState.ball.dx
      newState.ball.y += newState.ball.dy

      // Ball collision with top/bottom walls
      if (newState.ball.y <= 0 || newState.ball.y >= CANVAS_HEIGHT - BALL_SIZE) {
        newState.ball.dy = -newState.ball.dy
      }

      // Ball collision with paddles
      if (
        newState.ball.x <= PADDLE_WIDTH &&
        newState.ball.y + BALL_SIZE >= newState.paddle1.y &&
        newState.ball.y <= newState.paddle1.y + PADDLE_HEIGHT
      ) {
        newState.ball.dx = -newState.ball.dx
        newState.ball.x = PADDLE_WIDTH
      }

      if (
        newState.ball.x + BALL_SIZE >= CANVAS_WIDTH - PADDLE_WIDTH &&
        newState.ball.y + BALL_SIZE >= newState.paddle2.y &&
        newState.ball.y <= newState.paddle2.y + PADDLE_HEIGHT
      ) {
        newState.ball.dx = -newState.ball.dx
        newState.ball.x = CANVAS_WIDTH - PADDLE_WIDTH - BALL_SIZE
      }

      // Score points
      if (newState.ball.x < 0) {
        newState.paddle2.score++
        newState.ball = { x: CANVAS_WIDTH / 2, y: CANVAS_HEIGHT / 2, dx: BALL_SPEED, dy: BALL_SPEED }
      }

      if (newState.ball.x > CANVAS_WIDTH) {
        newState.paddle1.score++
        newState.ball = { x: CANVAS_WIDTH / 2, y: CANVAS_HEIGHT / 2, dx: -BALL_SPEED, dy: BALL_SPEED }
      }

      // AI movement for AI mode
      if (newState.gameMode === 'ai' && newState.isPlaying) {
        // Simple AI: follow the ball with some delay
        const aiPaddleCenter = newState.paddle2.y + PADDLE_HEIGHT / 2
        const ballCenter = newState.ball.y + BALL_SIZE / 2
        const aiSpeed = PADDLE_SPEED * 0.8 // Slightly slower than human

        if (ballCenter < aiPaddleCenter - 10 && newState.paddle2.y > 0) {
          newState.paddle2.y -= aiSpeed
        } else if (ballCenter > aiPaddleCenter + 10 && newState.paddle2.y < CANVAS_HEIGHT - PADDLE_HEIGHT) {
          newState.paddle2.y += aiSpeed
        }
      }

      // Check for winner (normal mode)
      if (newState.gameMode === 'normal' && (newState.paddle1.score >= 5 || newState.paddle2.score >= 5)) {
        newState.winner = newState.paddle1.score >= 5 ? 'Player 1' : 'Player 2'
        newState.isPlaying = false
      }

      return newState
    })

    animationRef.current = requestAnimationFrame(gameLoop)
  }, [gameState.isPlaying, gameState.isPaused, gameState.winner, keys])

  // Start game loop
  useEffect(() => {
    if (gameState.isPlaying && !gameState.isPaused && !gameState.winner) {
      animationRef.current = requestAnimationFrame(gameLoop)
    }

    return () => {
      if (animationRef.current) {
        cancelAnimationFrame(animationRef.current)
      }
    }
  }, [gameLoop, gameState.isPlaying, gameState.isPaused, gameState.winner])

  // Draw game
  useEffect(() => {
    const canvas = canvasRef.current
    if (!canvas) return

    const ctx = canvas.getContext('2d')
    if (!ctx) return

    // Clear canvas
    ctx.fillStyle = '#000'
    ctx.fillRect(0, 0, CANVAS_WIDTH, CANVAS_HEIGHT)

    // Draw center line
    ctx.strokeStyle = '#fff'
    ctx.setLineDash([5, 5])
    ctx.beginPath()
    ctx.moveTo(CANVAS_WIDTH / 2, 0)
    ctx.lineTo(CANVAS_WIDTH / 2, CANVAS_HEIGHT)
    ctx.stroke()
    ctx.setLineDash([])

    // Draw paddles
    ctx.fillStyle = '#fff'
    ctx.fillRect(0, gameState.paddle1.y, PADDLE_WIDTH, PADDLE_HEIGHT)
    ctx.fillRect(CANVAS_WIDTH - PADDLE_WIDTH, gameState.paddle2.y, PADDLE_WIDTH, PADDLE_HEIGHT)

    // Draw ball
    ctx.beginPath()
    ctx.arc(gameState.ball.x + BALL_SIZE / 2, gameState.ball.y + BALL_SIZE / 2, BALL_SIZE / 2, 0, Math.PI * 2)
    ctx.fill()

    // Draw scores
    ctx.font = '24px Arial'
    ctx.textAlign = 'center'
    ctx.fillText(gameState.paddle1.score.toString(), CANVAS_WIDTH / 4, 40)
    ctx.fillText(gameState.paddle2.score.toString(), (3 * CANVAS_WIDTH) / 4, 40)
  }, [gameState])

  const startGame = useCallback(() => {
    setGameState(prev => ({
      ...prev,
      ball: { x: CANVAS_WIDTH / 2, y: CANVAS_HEIGHT / 2, dx: BALL_SPEED, dy: BALL_SPEED },
      paddle1: { y: CANVAS_HEIGHT / 2 - PADDLE_HEIGHT / 2, score: 0 },
      paddle2: { y: CANVAS_HEIGHT / 2 - PADDLE_HEIGHT / 2, score: 0 },
      isPlaying: true,
      isPaused: false,
      winner: null
    }))
  }, [])

  const togglePause = useCallback(() => {
    setGameState(prev => ({ ...prev, isPaused: !prev.isPaused }))
  }, [])

  const resetGame = useCallback(() => {
    setGameState({
      ball: { x: CANVAS_WIDTH / 2, y: CANVAS_HEIGHT / 2, dx: BALL_SPEED, dy: BALL_SPEED },
      paddle1: { y: CANVAS_HEIGHT / 2 - PADDLE_HEIGHT / 2, score: 0 },
      paddle2: { y: CANVAS_HEIGHT / 2 - PADDLE_HEIGHT / 2, score: 0 },
      isPlaying: false,
      isPaused: false,
      gameMode: gameState.gameMode,
      winner: null
    })
  }, [gameState.gameMode])

  const toggleGameMode = useCallback(() => {
    setGameState(prev => ({
      ...prev,
      gameMode: prev.gameMode === 'normal' ? 'infinity' : prev.gameMode === 'infinity' ? 'ai' : 'normal'
    }))
  }, [])

  if (!isOpen) return null

  return (
    <Card className="w-full max-w-md mx-auto">
      <CardHeader className="pb-3">
        <div className="flex items-center justify-between">
          <CardTitle className="flex items-center gap-2 text-lg">
            <Home className="w-5 h-5 text-info" />
            Ping Pong
          </CardTitle>
          <Button variant="ghost" size="sm" onClick={onClose}>
            ✕
          </Button>
        </div>
      </CardHeader>

      <CardContent className="space-y-4">
        {/* Game Mode Toggle */}
        <div className="flex items-center justify-between">
          <span className="text-sm font-medium">Mode:</span>
          <Badge
            variant="outline"
            className="cursor-pointer"
            onClick={toggleGameMode}
          >
            {gameState.gameMode === 'normal' ? 'First to 5' : gameState.gameMode === 'infinity' ? 'Infinity' : 'vs AI'}
          </Badge>
        </div>

        {/* Game Canvas */}
        <div className="flex justify-center">
          <div className="relative">
            <canvas
              ref={canvasRef}
              width={CANVAS_WIDTH}
              height={CANVAS_HEIGHT}
              className="border-2 border-border rounded-xl bg-black shadow-lg"
            />
            {/* Mobile Controls Overlay */}
            {isMobile && (
              <div className="absolute inset-0 pointer-events-none">
                <div className="absolute bottom-4 left-4 right-4 flex justify-between pointer-events-auto">
                  <Button
                    size="lg"
                    className="bg-info hover:bg-info/90 text-white font-bold px-6 py-3 rounded-full shadow-lg"
                    onTouchStart={(e) => {
                      e.preventDefault()
                      setKeys(prev => new Set(prev).add('w'))
                    }}
                    onTouchEnd={(e) => {
                      e.preventDefault()
                      setKeys(prev => {
                        const newKeys = new Set(prev)
                        newKeys.delete('w')
                        return newKeys
                      })
                    }}
                    onMouseDown={() => setKeys(prev => new Set(prev).add('w'))}
                    onMouseUp={() => setKeys(prev => {
                      const newKeys = new Set(prev)
                      newKeys.delete('w')
                      return newKeys
                    })}
                  >
                    ↑
                  </Button>
                  <Button
                    size="lg"
                    className="bg-info hover:bg-info/90 text-white font-bold px-6 py-3 rounded-full shadow-lg"
                    onTouchStart={(e) => {
                      e.preventDefault()
                      setKeys(prev => new Set(prev).add('s'))
                    }}
                    onTouchEnd={(e) => {
                      e.preventDefault()
                      setKeys(prev => {
                        const newKeys = new Set(prev)
                        newKeys.delete('s')
                        return newKeys
                      })
                    }}
                    onMouseDown={() => setKeys(prev => new Set(prev).add('s'))}
                    onMouseUp={() => setKeys(prev => {
                      const newKeys = new Set(prev)
                      newKeys.delete('s')
                      return newKeys
                    })}
                  >
                    ↓
                  </Button>
                </div>
                <div className="absolute top-4 right-4 text-white text-sm bg-black/50 px-2 py-1 rounded">
                  P1
                </div>
                <div className="absolute top-4 left-4 text-white text-sm bg-black/50 px-2 py-1 rounded">
                  {gameState.gameMode === 'ai' ? 'AI' : 'P2'}
                </div>
              </div>
            )}
          </div>
        </div>

        {/* Controls */}
        <div className="text-center space-y-2">
          {!isMobile && (
            <div className="text-sm text-muted-foreground bg-muted p-2 rounded-lg">
              Player 1: W/S | Player 2: ↑/↓
            </div>
          )}
          {isMobile && (
            <div className="text-sm text-muted-foreground bg-muted p-2 rounded-lg">
              Use the on-screen buttons or tilt your device to control paddles
            </div>
          )}

          {!gameState.isPlaying && !gameState.winner && (
            <Button onClick={startGame}>
              <Play className="w-4 h-4 mr-2" />
              Start Game
            </Button>
          )}

          {gameState.isPlaying && !gameState.winner && (
            <Button onClick={togglePause} variant="outline">
              {gameState.isPaused ? (
                <>
                  <Play className="w-4 h-4 mr-2" />
                  Resume
                </>
              ) : (
                <>
                  <Pause className="w-4 h-4 mr-2" />
                  Pause
                </>
              )}
            </Button>
          )}

          {gameState.winner && (
            <div className="space-y-2">
              <div className="text-xl font-bold text-success">
                🎉 {gameState.winner} Wins! 🎉
              </div>
              <Button onClick={startGame}>
                <RotateCcw className="w-4 h-4 mr-2" />
                Play Again
              </Button>
            </div>
          )}

          <Button onClick={resetGame} variant="outline" size="sm">
            <RotateCcw className="w-4 h-4 mr-2" />
            Reset
          </Button>
        </div>
      </CardContent>
    </Card>
  )
}

"use client"

import { useState } from "react"
import { Button } from "@/components/ui/button"
import { Card, CardContent } from "@/components/ui/card"
import {
  Plus,
  Receipt,
  Target,
  PiggyBank,
  TrendingUp,
  X,
  Camera,
  Mic,
  Calculator,
  Plane
} from "lucide-react"
import { useWalletData } from "@/contexts/wallet-data-context"
import { GamingPlaceModal } from "./gaming-place-modal"

interface QuickAction {
  id: string
  label: string
  icon: React.ReactNode
  action: () => void
  color: string
}

export function QuickActionsWidget() {
  const [isExpanded, setIsExpanded] = useState(false)
  const [showGamingPlace, setShowGamingPlace] = useState(false)
  const { balance } = useWalletData()

  const quickActions: QuickAction[] = [
    {
      id: 'add-transaction',
      label: 'Add Transaction',
      icon: <Plus className="w-4 h-4" />,
      action: () => {
        // Trigger transaction dialog
        setIsExpanded(false)
      },
      color: 'bg-primary hover:bg-primary/90'
    },
    {
      id: 'scan-receipt',
      label: 'Scan Receipt',
      icon: <Camera className="w-4 h-4" />,
      action: () => {
        // Trigger receipt scanning
        setIsExpanded(false)
      },
      color: 'bg-success hover:bg-success/90'
    },
    {
      id: 'voice-command',
      label: 'Voice Command',
      icon: <Mic className="w-4 h-4" />,
      action: () => {
        // Trigger voice command
        setIsExpanded(false)
      },
      color: 'bg-info hover:bg-info/90'
    },
    {
      id: 'quick-calc',
      label: 'Quick Calc',
      icon: <Calculator className="w-4 h-4" />,
      action: () => {
        // Open calculator
        setIsExpanded(false)
      },
      color: 'bg-warning hover:bg-warning/90'
    },
    {
      id: 'gaming-place',
      label: 'Gaming Place',
      icon: <Plane className="w-4 h-4" />,
      action: () => {
        setShowGamingPlace(true)
        setIsExpanded(false)
      },
      color: 'bg-destructive hover:bg-destructive/90'
    },
  ]

  return (
    <>
      <div className="fixed bottom-20 right-4 z-50 md:hidden">
        {/* Expanded Actions */}
        {isExpanded && (
          <Card className="mb-2 p-2 shadow-lg">
            <CardContent className="p-2">
              <div className="grid grid-cols-2 gap-2">
                {quickActions.map((action) => (
                  <Button
                    key={action.id}
                    variant="ghost"
                    size="sm"
                    onClick={action.action}
                    className="flex flex-col items-center gap-1 h-auto p-3"
                  >
                    <div className={`p-2 rounded-full ${action.color} text-white`}>
                      {action.icon}
                    </div>
                    <span className="text-xs text-center">{action.label}</span>
                  </Button>
                ))}
              </div>
            </CardContent>
          </Card>
        )}

        {/* Main FAB */}
        <Button
          onClick={() => setIsExpanded(!isExpanded)}
          className={`h-14 w-14 rounded-full shadow-lg transition-all duration-300 ${isExpanded ? 'rotate-45' : ''
            }`}
          size="lg"
        >
          {isExpanded ? (
            <X className="w-6 h-6" />
          ) : (
            <Plus className="w-6 h-6" />
          )}
        </Button>
      </div>

      {/* Gaming Place Modal */}
      <GamingPlaceModal
        isOpen={showGamingPlace}
        onClose={() => setShowGamingPlace(false)}
      />
    </>
  )
}

"use client"

import React, { useState, useCallback } from "react"
import { Button } from "@/components/ui/button"
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card"
import { Badge } from "@/components/ui/badge"
import { RotateCcw, Play, Cpu, Users } from "lucide-react"
import { toast } from "sonner"
import { cn } from "@/lib/utils"

interface TicTacToeGameProps {
  isOpen: boolean
  onClose: () => void
}

type Player = 'X' | 'O' | null
type Board = Player[]
type GameMode = 'human' | 'ai'
type Difficulty = 'normal' | 'infinity'

interface GameState {
  board: Board
  currentPlayer: Player
  winner: Player
  isDraw: boolean
  gameMode: GameMode
  difficulty: Difficulty
  isPlaying: boolean
  scores: { X: number; O: number; draws: number }
}

const WINNING_COMBINATIONS = [
  [0, 1, 2], [3, 4, 5], [6, 7, 8], // rows
  [0, 3, 6], [1, 4, 7], [2, 5, 8], // columns
  [0, 4, 8], [2, 4, 6] // diagonals
]

export function TicTacToeGame({ isOpen, onClose }: TicTacToeGameProps) {
  const [gameState, setGameState] = useState<GameState>({
    board: Array(9).fill(null),
    currentPlayer: 'X',
    winner: null,
    isDraw: false,
    gameMode: 'human',
    difficulty: 'normal',
    isPlaying: false,
    scores: { X: 0, O: 0, draws: 0 }
  })

  const checkWinner = useCallback((board: Board): Player => {
    for (const combination of WINNING_COMBINATIONS) {
      const [a, b, c] = combination
      if (board[a] && board[a] === board[b] && board[a] === board[c]) {
        return board[a]
      }
    }
    return null
  }, [])

  const isBoardFull = useCallback((board: Board): boolean => {
    return board.every(cell => cell !== null)
  }, [])

  const getBestMove = useCallback((board: Board): number => {
    // Simple AI: try to win, block opponent, or take center/corners
    const opponent = gameState.currentPlayer === 'X' ? 'O' : 'X'

    // Check if AI can win
    for (let i = 0; i < 9; i++) {
      if (board[i] === null) {
        const testBoard = [...board]
        testBoard[i] = gameState.currentPlayer
        if (checkWinner(testBoard) === gameState.currentPlayer) {
          return i
        }
      }
    }

    // Check if AI needs to block opponent
    for (let i = 0; i < 9; i++) {
      if (board[i] === null) {
        const testBoard = [...board]
        testBoard[i] = opponent
        if (checkWinner(testBoard) === opponent) {
          return i
        }
      }
    }

    // Take center if available
    if (board[4] === null) return 4

    // Take corners
    const corners = [0, 2, 6, 8]
    for (const corner of corners) {
      if (board[corner] === null) return corner
    }

    // Take any available spot
    for (let i = 0; i < 9; i++) {
      if (board[i] === null) return i
    }

    return -1
  }, [gameState.currentPlayer, checkWinner])

  const makeMove = useCallback((index: number) => {
    if (gameState.board[index] || gameState.winner || gameState.isDraw) return

    const newBoard = [...gameState.board]
    newBoard[index] = gameState.currentPlayer

    const winner = checkWinner(newBoard)
    const isDraw = !winner && isBoardFull(newBoard)

    setGameState(prev => ({
      ...prev,
      board: newBoard,
      currentPlayer: prev.currentPlayer === 'X' ? 'O' : 'X',
      winner,
      isDraw
    }))

    // AI move for human vs AI mode
    if (gameState.gameMode === 'ai' && !winner && !isDraw && gameState.currentPlayer === 'X') {
      setTimeout(() => {
        const aiMove = getBestMove(newBoard)
        if (aiMove !== -1) {
          const aiBoard = [...newBoard]
          aiBoard[aiMove] = 'O'

          const aiWinner = checkWinner(aiBoard)
          const aiIsDraw = !aiWinner && isBoardFull(aiBoard)

          setGameState(prev => ({
            ...prev,
            board: aiBoard,
            currentPlayer: 'X',
            winner: aiWinner,
            isDraw: aiIsDraw
          }))
        }
      }, 500)
    }
  }, [gameState.board, gameState.currentPlayer, gameState.winner, gameState.isDraw, gameState.gameMode, checkWinner, isBoardFull, getBestMove])

  const startGame = useCallback(() => {
    setGameState(prev => ({
      ...prev,
      board: Array(9).fill(null),
      currentPlayer: 'X',
      winner: null,
      isDraw: false,
      isPlaying: true
    }))
  }, [])

  const resetGame = useCallback(() => {
    setGameState(prev => ({
      ...prev,
      board: Array(9).fill(null),
      currentPlayer: 'X',
      winner: null,
      isDraw: false,
      isPlaying: false
    }))
  }, [])

  const resetScores = useCallback(() => {
    setGameState(prev => ({
      ...prev,
      scores: { X: 0, O: 0, draws: 0 }
    }))
  }, [])

  const toggleGameMode = useCallback(() => {
    setGameState(prev => ({
      ...prev,
      gameMode: prev.gameMode === 'human' ? 'ai' : 'human'
    }))
  }, [])

  const toggleDifficulty = useCallback(() => {
    setGameState(prev => ({
      ...prev,
      difficulty: prev.difficulty === 'normal' ? 'infinity' : 'normal'
    }))
  }, [])

  // Update scores when game ends
  React.useEffect(() => {
    if (gameState.winner || gameState.isDraw) {
      setGameState(prev => ({
        ...prev,
        scores: {
          ...prev.scores,
          [gameState.winner || 'draws']: prev.scores[gameState.winner || 'draws'] + 1
        }
      }))

      if (gameState.winner) {
        toast.success(`${gameState.winner} wins!`)
      } else if (gameState.isDraw) {
        toast.info("It's a draw!")
      }
    }
  }, [gameState.winner, gameState.isDraw])

  if (!isOpen) return null

  return (
    <Card className="w-full max-w-md mx-auto">
      <CardHeader className="pb-3">
        <div className="flex items-center justify-between">
          <CardTitle className="flex items-center gap-2 text-lg">
            <Users className="w-5 h-5 text-success" />
            Tic Tac Toe
          </CardTitle>
          <Button variant="ghost" size="sm" onClick={onClose}>
            ✕
          </Button>
        </div>
      </CardHeader>

      <CardContent className="space-y-4">
        {/* Game Settings */}
        <div className="flex items-center justify-between gap-2">
          <div className="flex items-center gap-2">
            <span className="text-sm font-medium">Mode:</span>
            <Badge
              variant={gameState.gameMode === 'human' ? 'default' : 'secondary'}
              className="cursor-pointer"
              onClick={toggleGameMode}
            >
              {gameState.gameMode === 'human' ? (
                <>
                  <Users className="w-3 h-3 mr-1" />
                  Human vs Human
                </>
              ) : (
                <>
                  <Cpu className="w-3 h-3 mr-1" />
                  Human vs AI
                </>
              )}
            </Badge>
          </div>
          <div className="flex items-center gap-2">
            <span className="text-sm font-medium">Type:</span>
            <Badge
              variant={gameState.difficulty === 'normal' ? 'default' : 'secondary'}
              className="cursor-pointer"
              onClick={toggleDifficulty}
            >
              {gameState.difficulty === 'normal' ? 'Normal' : 'Infinity'}
            </Badge>
          </div>
        </div>

        {/* Scores */}
        <div className="grid grid-cols-3 gap-2 text-center">
          <div>
            <div className="text-lg font-bold text-info">{gameState.scores.X}</div>
            <div className="text-xs text-muted-foreground">Player X</div>
          </div>
          <div>
            <div className="text-lg font-bold text-muted-foreground">{gameState.scores.draws}</div>
            <div className="text-xs text-muted-foreground">Draws</div>
          </div>
          <div>
            <div className="text-lg font-bold text-error">{gameState.scores.O}</div>
            <div className="text-xs text-muted-foreground">
              {gameState.gameMode === 'ai' ? 'AI' : 'Player O'}
            </div>
          </div>
        </div>

        {/* Game Board */}
        <div className="flex justify-center">
          <div className="grid grid-cols-3 gap-2 w-full max-w-64 h-auto mx-auto bg-gradient-to-br from-blue-50 to-purple-50 dark:from-blue-950/20 dark:to-purple-950/20 p-4 rounded-2xl border-2 border-border">
            {gameState.board.map((cell, index) => (
              <Button
                key={index}
                variant="ghost"
                className={cn(
                  "aspect-square text-4xl font-bold h-full rounded-xl transition-all duration-200",
                  "hover:bg-white/80 hover:scale-105 active:scale-95",
                  "border-2 border-border/80 hover:border-primary/20",
                  cell === 'X' && "text-info hover:text-info/90",
                  cell === 'O' && "text-error hover:text-error/90",
                  "disabled:cursor-not-allowed disabled:hover:scale-100"
                )}
                onClick={() => makeMove(index)}
                disabled={!!cell || !!gameState.winner || gameState.isDraw || (gameState.gameMode === 'ai' && gameState.currentPlayer === 'O')}
              >
                {cell && (
                  <span className={cn(
                    "drop-shadow-sm",
                    cell === 'X' && "text-info",
                    cell === 'O' && "text-error"
                  )}>
                    {cell}
                  </span>
                )}
              </Button>
            ))}
          </div>
        </div>

        {/* Game Status */}
        <div className="text-center space-y-2">
          {gameState.winner ? (
            <div className="space-y-2">
              <div className="text-2xl">🎉</div>
              <div className="text-xl font-bold text-success">
                {gameState.winner === 'X' ? 'Player X' : gameState.gameMode === 'ai' && gameState.winner === 'O' ? 'AI' : 'Player O'} Wins!
              </div>
              <div className="text-sm text-muted-foreground">
                Great game! 🎮
              </div>
            </div>
          ) : gameState.isDraw ? (
            <div className="space-y-2">
              <div className="text-2xl">🤝</div>
              <div className="text-xl font-bold text-warning">
                It's a Draw!
              </div>
              <div className="text-sm text-muted-foreground">
                Well played both sides! ⚖️
              </div>
            </div>
          ) : (
            <div className="space-y-2">
              {gameState.gameMode === 'ai' && gameState.currentPlayer === 'O' ? (
                <div className="flex items-center justify-center gap-2 text-lg font-medium">
                  <Cpu className="w-5 h-5 animate-pulse" />
                  AI is thinking...
                </div>
              ) : (
                <div className="space-y-1">
                  <div className="text-lg font-medium">
                    Player {gameState.currentPlayer}'s Turn
                  </div>
                  <div className={cn(
                    "inline-flex items-center gap-2 px-3 py-1 rounded-full text-sm font-medium",
                    gameState.currentPlayer === 'X' ? "bg-info/10 text-info" : "bg-error/10 text-error"
                  )}>
                    <span className="text-lg">{gameState.currentPlayer}</span>
                    <span>Turn</span>
                  </div>
                </div>
              )}
            </div>
          )}
        </div>

        {/* Controls */}
        <div className="flex gap-2">
          {!gameState.isPlaying && (
            <Button onClick={startGame} className="flex-1">
              <Play className="w-4 h-4 mr-2" />
              Start Game
            </Button>
          )}

          {(gameState.winner || gameState.isDraw) && gameState.difficulty === 'normal' && (
            <Button onClick={startGame} className="flex-1">
              <RotateCcw className="w-4 h-4 mr-2" />
              Next Round
            </Button>
          )}

          <Button onClick={resetGame} variant="outline">
            <RotateCcw className="w-4 h-4 mr-2" />
            Reset Board
          </Button>
        </div>

        <Button onClick={resetScores} variant="outline" size="sm" className="w-full">
          Reset Scores
        </Button>
      </CardContent>
    </Card>
  )
}

"use client"

// Inspired by react-hot-toast library
import * as React from "react"

import type {
  ToastActionElement,
  ToastProps,
} from "@/components/ui/toast"

const TOAST_LIMIT = 1
const TOAST_REMOVE_DELAY = 1000000

type ToasterToast = ToastProps & {
  id: string
  title?: React.ReactNode
  description?: React.ReactNode
  action?: ToastActionElement
}

const actionTypes = {
  ADD_TOAST: "ADD_TOAST",
  UPDATE_TOAST: "UPDATE_TOAST",
  DISMISS_TOAST: "DISMISS_TOAST",
  REMOVE_TOAST: "REMOVE_TOAST",
} as const

let count = 0

function genId() {
  count = (count + 1) % Number.MAX_SAFE_INTEGER
  return count.toString()
}

type ActionType = typeof actionTypes

type Action =
  | {
      type: ActionType["ADD_TOAST"]
      toast: ToasterToast
    }
  | {
      type: ActionType["UPDATE_TOAST"]
      toast: Partial<ToasterToast>
    }
  | {
      type: ActionType["DISMISS_TOAST"]
      toastId?: ToasterToast["id"]
    }
  | {
      type: ActionType["REMOVE_TOAST"]
      toastId?: ToasterToast["id"]
    }

interface State {
  toasts: ToasterToast[]
}

const toastTimeouts = new Map<string, ReturnType<typeof setTimeout>>()

const addToRemoveQueue = (toastId: string) => {
  if (toastTimeouts.has(toastId)) {
    return
  }

  const timeout = setTimeout(() => {
    toastTimeouts.delete(toastId)
    dispatch({
      type: "REMOVE_TOAST",
      toastId: toastId,
    })
  }, TOAST_REMOVE_DELAY)

  toastTimeouts.set(toastId, timeout)
}

export const reducer = (state: State, action: Action): State => {
  switch (action.type) {
    case "ADD_TOAST":
      return {
        ...state,
        toasts: [action.toast, ...state.toasts].slice(0, TOAST_LIMIT),
      }

    case "UPDATE_TOAST":
      return {
        ...state,
        toasts: state.toasts.map((t) =>
          t.id === action.toast.id ? { ...t, ...action.toast } : t
        ),
      }

    case "DISMISS_TOAST": {
      const { toastId } = action

      // ! Side effects ! - This could be extracted into a dismissToast() action,
      // but I'll keep it here for simplicity
      if (toastId) {
        addToRemoveQueue(toastId)
      } else {
        state.toasts.forEach((toast) => {
          addToRemoveQueue(toast.id)
        })
      }

      return {
        ...state,
        toasts: state.toasts.map((t) =>
          t.id === toastId || toastId === undefined
            ? {
                ...t,
                open: false,
              }
            : t
        ),
      }
    }
    case "REMOVE_TOAST":
      if (action.toastId === undefined) {
        return {
          ...state,
          toasts: [],
        }
      }
      return {
        ...state,
        toasts: state.toasts.filter((t) => t.id !== action.toastId),
      }
  }
}

const listeners: Array<(state: State) => void> = []

let memoryState: State = { toasts: [] }

function dispatch(action: Action) {
  memoryState = reducer(memoryState, action)
  listeners.forEach((listener) => {
    listener(memoryState)
  })
}

type Toast = Omit<ToasterToast, "id">

function toast({ ...props }: Toast) {
  const id = genId()

  const update = (props: ToasterToast) =>
    dispatch({
      type: "UPDATE_TOAST",
      toast: { ...props, id },
    })
  const dismiss = () => dispatch({ type: "DISMISS_TOAST", toastId: id })

  dispatch({
    type: "ADD_TOAST",
    toast: {
      ...props,
      id,
      open: true,
      onOpenChange: (open) => {
        if (!open) dismiss()
      },
    },
  })

  return {
    id: id,
    dismiss,
    update,
  }
}

function useToast() {
  const [state, setState] = React.useState<State>(memoryState)

  React.useEffect(() => {
    listeners.push(setState)
    return () => {
      const index = listeners.indexOf(setState)
      if (index > -1) {
        listeners.splice(index, 1)
      }
    }
  }, [state])

  return {
    ...state,
    toast,
    dismiss: (toastId?: string) => dispatch({ type: "DISMISS_TOAST", toastId }),
  }
}

export { useToast, toast }
